SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The Lyman series of hydrogen spectrum lies in the:", "explanation": "The Lyman series corresponds to transitions from higher energy levels (n = 2, 3, 4, ...) to n = 1 (ground state). The wavelengths of the Lyman series range from 912 A to 1216 A, which fall in the ultraviolet (UV) region of the electromagnetic spectrum.", "payload": {"question_id": "cuet-phy-atom-spectra-01", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "remember", "options": [{"key": "A", "text": "Ultraviolet region", "is_correct": true}, {"key": "B", "text": "Visible region", "is_correct": false}, {"key": "C", "text": "Infrared region", "is_correct": false}, {"key": "D", "text": "Microwave region", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The visible region corresponds to the Balmer series (transitions to n = 2), not the Lyman series.", "misconception": "Confusing Balmer and Lyman series regions"}, {"option_key": "C", "hint": "The infrared region corresponds to the Paschen, Brackett, and Pfund series, not the Lyman series.", "misconception": "Confusing Paschen and Lyman series regions"}, {"option_key": "D", "hint": "Microwave wavelengths are much longer than the Lyman series wavelengths. No hydrogen spectral series falls in the microwave region.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["lyman-series", "ultraviolet-region", "hydrogen-spectrum"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The ratio of the maximum wavelength to the minimum wavelength of the Balmer series of hydrogen is:", "explanation": "The maximum wavelength of the Balmer series corresponds to the first line (n = 3 to n = 2): 1/lambda_max = R(1/4 - 1/9) = R(5/36), so lambda_max = 36/(5R). The minimum wavelength (series limit) corresponds to n = infinity to n = 2: 1/lambda_min = R(1/4 - 0) = R/4, so lambda_min = 4/R. Ratio = lambda_max/lambda_min = (36/5R)/(4/R) = 36/(5 x 4) = 36/20 = 9/5.", "payload": {"question_id": "cuet-phy-atom-spectra-02", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "analyze", "options": [{"key": "A", "text": "4/3", "is_correct": false}, {"key": "B", "text": "5/4", "is_correct": false}, {"key": "C", "text": "9/5", "is_correct": true}, {"key": "D", "text": "27/5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4/3 is the ratio of quantum numbers (n = 4 to n = 3), not the ratio of wavelengths. The calculation requires the full Rydberg formula.", "misconception": "Using ratio of quantum numbers instead of the Rydberg formula"}, {"option_key": "B", "hint": "5/4 does not arise from any correct combination of the Rydberg terms for the Balmer series.", "misconception": null}, {"option_key": "D", "hint": "27/5 would result from an incorrect calculation. The correct ratio is lambda_max/lambda_min = (36/5R)/(4/R) = 9/5.", "misconception": "Arithmetic error in simplifying the ratio"}]}, "correct_answer": "C", "concept_tags": ["balmer-series", "wavelength-ratio", "series-limit", "first-line", "rydberg-formula"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The first line of the Balmer series of hydrogen corresponds to the transition:", "explanation": "The Balmer series corresponds to transitions from higher levels to n = 2. The first line (longest wavelength, lowest energy) corresponds to the transition from the nearest higher level, i.e., n = 3 to n = 2. This line is called H-alpha and has a wavelength of 6563 A (red colour).", "payload": {"question_id": "cuet-phy-atom-spectra-03", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "remember", "options": [{"key": "A", "text": "n = 2 to n = 1", "is_correct": false}, {"key": "B", "text": "n = 3 to n = 2", "is_correct": true}, {"key": "C", "text": "n = infinity to n = 2", "is_correct": false}, {"key": "D", "text": "n = 4 to n = 2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The transition from n = 2 to n = 1 belongs to the Lyman series, not the Balmer series.", "misconception": "Confusing Lyman and Balmer series"}, {"option_key": "C", "hint": "The transition from n = infinity to n = 2 gives the series limit (shortest wavelength), not the first line of the Balmer series.", "misconception": "Confusing series limit with the first line"}, {"option_key": "D", "hint": "The transition from n = 4 to n = 2 gives the second line (H-beta) of the Balmer series, not the first line.", "misconception": "Incorrect ordering of spectral lines"}]}, "correct_answer": "B", "concept_tags": ["balmer-series", "first-line", "h-alpha", "hydrogen-transitions"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The energy of the hydrogen atom in the ground state is -13.6 eV. The energy of the hydrogen atom in the second excited state is:", "explanation": "The energy of the hydrogen atom in the nth level is given by E_n = -13.6/n^2 eV. The second excited state corresponds to n = 3 (ground state is n = 1, first excited state is n = 2, second excited state is n = 3). So E_3 = -13.6/3^2 = -13.6/9 = -1.51 eV.", "payload": {"question_id": "cuet-phy-atom-spectra-04", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "apply", "options": [{"key": "A", "text": "-13.6 eV", "is_correct": false}, {"key": "B", "text": "-3.4 eV", "is_correct": false}, {"key": "C", "text": "-0.85 eV", "is_correct": false}, {"key": "D", "text": "-1.51 eV", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "-13.6 eV is the ground state energy (n = 1), not the second excited state.", "misconception": null}, {"option_key": "B", "hint": "-3.4 eV corresponds to n = 2 (first excited state). The second excited state is n = 3, not n = 2.", "misconception": "Confusing first excited state with second excited state"}, {"option_key": "C", "hint": "-0.85 eV corresponds to n = 4 (third excited state). Remember: second excited state means n = 3.", "misconception": "Incorrect identification of quantum number for excited states"}]}, "correct_answer": "D", "concept_tags": ["energy-levels", "hydrogen-atom", "second-excited-state"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The wavelength of the first line of the Lyman series of hydrogen is 1216 A. The wavelength of the second line of the Balmer series is:", "explanation": "For the first line of the Lyman series (n = 2 to n = 1): 1/lambda_L = R(1/1^2 - 1/2^2) = R(1 - 1/4) = 3R/4. So lambda_L = 4/(3R). For the second line of the Balmer series (n = 4 to n = 2): 1/lambda_B = R(1/2^2 - 1/4^2) = R(1/4 - 1/16) = R(3/16) = 3R/16. So lambda_B = 16/(3R). Taking the ratio: lambda_B/lambda_L = (16/3R)/(4/3R) = 16/4 = 4. Therefore lambda_B = 4 x 1216 = 4864 A.", "payload": {"question_id": "cuet-phy-atom-spectra-05", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "apply", "options": [{"key": "A", "text": "3648 A", "is_correct": false}, {"key": "B", "text": "4864 A", "is_correct": true}, {"key": "C", "text": "6568 A", "is_correct": false}, {"key": "D", "text": "1216 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3648 A would correspond to a ratio of 3, but the correct wavelength ratio between the second Balmer line and the first Lyman line is 4.", "misconception": "Incorrect application of the Rydberg formula"}, {"option_key": "C", "hint": "6568 A is close to the first line of the Balmer series (H-alpha), not the second line.", "misconception": "Confusing first and second lines of Balmer series"}, {"option_key": "D", "hint": "1216 A is the given wavelength of the first Lyman line. The Balmer series lines have longer wavelengths since they involve lower energy transitions.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["lyman-series", "balmer-series", "wavelength-ratio", "rydberg-formula"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the shortest wavelength of the Balmer series to the shortest wavelength of the Lyman series of hydrogen is:", "explanation": "The shortest wavelength (series limit) of any series corresponds to the transition from n = infinity. For the Lyman series limit: 1/lambda_L = R(1/1^2 - 0) = R, so lambda_L = 1/R. For the Balmer series limit: 1/lambda_B = R(1/2^2 - 0) = R/4, so lambda_B = 4/R. Ratio = lambda_B/lambda_L = (4/R)/(1/R) = 4.", "payload": {"question_id": "cuet-phy-atom-spectra-06", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "apply", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "2", "is_correct": false}, {"key": "C", "text": "4", "is_correct": true}, {"key": "D", "text": "1/4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A ratio of 1 would mean both series have the same shortest wavelength, which is incorrect since the Balmer series transitions involve less energy.", "misconception": null}, {"option_key": "B", "hint": "A ratio of 2 would correspond to the ratio of the quantum numbers, but the wavelength depends on 1/n^2, giving a ratio of n^2 = 2^2 = 4.", "misconception": "Using n instead of n^2 in the formula"}, {"option_key": "D", "hint": "1/4 would mean the Balmer series limit has a shorter wavelength than the Lyman series limit, which contradicts the fact that Lyman series photons have higher energy.", "misconception": "Inverting the ratio"}]}, "correct_answer": "C", "concept_tags": ["series-limit", "balmer-series", "lyman-series", "wavelength-ratio"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The excitation energy required to excite a hydrogen atom from the ground state to the first excited state is:", "explanation": "The excitation energy is the difference between the energy of the excited state and the ground state. E_1 = -13.6 eV (ground state, n = 1). E_2 = -13.6/4 = -3.4 eV (first excited state, n = 2). Excitation energy = E_2 - E_1 = -3.4 - (-13.6) = -3.4 + 13.6 = 10.2 eV.", "payload": {"question_id": "cuet-phy-atom-spectra-07", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "apply", "options": [{"key": "A", "text": "10.2 eV", "is_correct": true}, {"key": "B", "text": "13.6 eV", "is_correct": false}, {"key": "C", "text": "3.4 eV", "is_correct": false}, {"key": "D", "text": "1.89 eV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "13.6 eV is the ionization energy from the ground state (energy needed to completely remove the electron), not the excitation energy to the first excited state.", "misconception": "Confusing ionization energy with excitation energy"}, {"option_key": "C", "hint": "3.4 eV is the magnitude of the energy of the first excited state, not the energy required to reach it from the ground state.", "misconception": "Confusing energy of a state with the excitation energy"}, {"option_key": "D", "hint": "1.89 eV is the energy difference between n = 3 and n = 2 (corresponding to the first Balmer line), not the excitation energy from the ground state.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["excitation-energy", "ground-state", "first-excited-state", "hydrogen-atom"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ionization energy of the hydrogen atom from its second excited state is:", "explanation": "The second excited state corresponds to n = 3. The energy of this state is E_3 = -13.6/3^2 = -13.6/9 = -1.51 eV. The ionization energy is the energy required to remove the electron from this state to n = infinity (E = 0). So ionization energy = 0 - (-1.51) = 1.51 eV.", "payload": {"question_id": "cuet-phy-atom-spectra-08", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "apply", "options": [{"key": "A", "text": "13.6 eV", "is_correct": false}, {"key": "B", "text": "3.4 eV", "is_correct": false}, {"key": "C", "text": "0.85 eV", "is_correct": false}, {"key": "D", "text": "1.51 eV", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "13.6 eV is the ionization energy from the ground state (n = 1), not from the second excited state (n = 3).", "misconception": "Not adjusting ionization energy for the starting level"}, {"option_key": "B", "hint": "3.4 eV is the ionization energy from the first excited state (n = 2), not the second excited state (n = 3).", "misconception": "Confusing first and second excited states"}, {"option_key": "C", "hint": "0.85 eV is the ionization energy from n = 4 (third excited state), not n = 3 (second excited state).", "misconception": "Using wrong quantum number for the second excited state"}]}, "correct_answer": "D", "concept_tags": ["ionization-energy", "second-excited-state", "hydrogen-atom"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The wavelength of the first line of the Lyman series of a hydrogen-like ion He+ is:", "explanation": "For hydrogen-like ions, 1/lambda = RZ^2(1/n1^2 - 1/n2^2). For the first line of the Lyman series of He+ (Z = 2): 1/lambda = R(2)^2(1/1^2 - 1/2^2) = 4R(3/4) = 3R. For hydrogen, the first Lyman line: 1/lambda_H = R(3/4), so lambda_H = 4/(3R). For He+: 1/lambda_He = 3R, so lambda_He = 1/(3R). Ratio: lambda_He/lambda_H = (1/3R)/(4/3R) = 1/4. Since lambda_H = 1216 A, lambda_He = 1216/4 = 304 A.", "payload": {"question_id": "cuet-phy-atom-spectra-09", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "apply", "options": [{"key": "A", "text": "304 A", "is_correct": true}, {"key": "B", "text": "608 A", "is_correct": false}, {"key": "C", "text": "1216 A", "is_correct": false}, {"key": "D", "text": "152 A", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "608 A would result from dividing the hydrogen wavelength by 2 (using Z instead of Z^2). The correct formula uses Z^2 = 4 as the scaling factor.", "misconception": "Using Z instead of Z^2 in the Rydberg formula for hydrogen-like ions"}, {"option_key": "C", "hint": "1216 A is the first Lyman line of hydrogen (Z = 1). For He+ (Z = 2), the wavelength is scaled down by Z^2 = 4.", "misconception": "Ignoring the Z^2 factor for hydrogen-like ions"}, {"option_key": "D", "hint": "152 A would result from dividing by Z^3 = 8 instead of Z^2 = 4.", "misconception": "Using incorrect power of Z"}]}, "correct_answer": "A", "concept_tags": ["hydrogen-like-ions", "helium-ion", "lyman-series", "rydberg-formula"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The wavelength of the first line of the Balmer series of hydrogen is 6563 A. The wavelength of the first line of the Lyman series of the same atom is approximately:", "explanation": "For the first Balmer line (n = 3 to n = 2): 1/lambda_B = R(1/4 - 1/9) = R(5/36). For the first Lyman line (n = 2 to n = 1): 1/lambda_L = R(1 - 1/4) = R(3/4). Ratio: lambda_L/lambda_B = (5/36)/(3/4) = (5/36) x (4/3) = 20/108 = 5/27. Therefore lambda_L = (5/27) x 6563 = 32815/27 = 1215.4 A, which is approximately 1215 A.", "payload": {"question_id": "cuet-phy-atom-spectra-10", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "analyze", "options": [{"key": "A", "text": "912 A", "is_correct": false}, {"key": "B", "text": "1215 A", "is_correct": true}, {"key": "C", "text": "1640 A", "is_correct": false}, {"key": "D", "text": "3282 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "912 A is the series limit (shortest wavelength) of the Lyman series, not the first line.", "misconception": "Confusing the series limit with the first spectral line"}, {"option_key": "C", "hint": "This value does not correspond to any standard hydrogen spectral line. Check the ratio calculation using the Rydberg formula.", "misconception": null}, {"option_key": "D", "hint": "3282 A would be half of 6563, suggesting a simple halving, but the relationship between spectral lines requires the full Rydberg formula.", "misconception": "Assuming a simple integer ratio between different series"}]}, "correct_answer": "B", "concept_tags": ["balmer-series", "lyman-series", "wavelength-ratio", "rydberg-formula"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A hydrogen atom in the ground state absorbs a photon of energy 12.75 eV. The number of different spectral lines that can be emitted when the atom returns to the ground state is:", "explanation": "The energy of the ground state is -13.6 eV. After absorbing 12.75 eV, the total energy becomes -13.6 + 12.75 = -0.85 eV. Using E_n = -13.6/n^2: -0.85 = -13.6/n^2, so n^2 = 13.6/0.85 = 16, giving n = 4. The atom is excited to n = 4. The number of possible spectral lines emitted when it de-excites is n(n-1)/2 = 4(3)/2 = 6.", "payload": {"question_id": "cuet-phy-atom-spectra-11", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "analyze", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "3", "is_correct": false}, {"key": "C", "text": "6", "is_correct": true}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 line would mean only a direct transition from the excited state to the ground state. But the atom can also de-excite through intermediate levels.", "misconception": "Considering only direct transitions to the ground state"}, {"option_key": "B", "hint": "3 would be the number of direct transitions from n = 4 (to n = 3, 2, 1), but transitions between intermediate levels (3->2, 3->1, 2->1) must also be counted.", "misconception": "Counting only transitions from the highest excited level"}, {"option_key": "D", "hint": "10 corresponds to n = 5 using the formula n(n-1)/2. First verify that the absorbed energy takes the atom to n = 4, not n = 5.", "misconception": "Incorrect calculation of the excited state quantum number"}]}, "correct_answer": "C", "concept_tags": ["photon-absorption", "energy-levels", "spectral-lines-formula", "hydrogen-atom"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following transitions in the hydrogen atom will emit a photon of the highest frequency?", "explanation": "The frequency of the emitted photon is proportional to the energy difference between the two levels. E_n = -13.6/n^2 eV. For n = 2 to n = 1: Delta E = -13.6(1/1 - 1/4) = -13.6 x 3/4 = 10.2 eV. For n = 6 to n = 5: Delta E = -13.6(1/25 - 1/36) = -13.6 x 11/900 = 0.166 eV. For n = 4 to n = 3: Delta E = -13.6(1/9 - 1/16) = -13.6 x 7/144 = 0.66 eV. For n = 3 to n = 2: Delta E = -13.6(1/4 - 1/9) = -13.6 x 5/36 = 1.89 eV. The transition n = 2 to n = 1 has the largest energy difference and hence the highest frequency.", "payload": {"question_id": "cuet-phy-atom-spectra-12", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "analyze", "options": [{"key": "A", "text": "n = 6 to n = 5", "is_correct": false}, {"key": "B", "text": "n = 4 to n = 3", "is_correct": false}, {"key": "C", "text": "n = 3 to n = 2", "is_correct": false}, {"key": "D", "text": "n = 2 to n = 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The energy gap between n = 6 and n = 5 is very small (about 0.17 eV) as higher energy levels are closely spaced.", "misconception": "Assuming higher quantum numbers give higher energy transitions"}, {"option_key": "B", "hint": "The n = 4 to n = 3 transition releases only 0.66 eV, much less than n = 2 to n = 1 which releases 10.2 eV.", "misconception": null}, {"option_key": "C", "hint": "While n = 3 to n = 2 gives 1.89 eV, the n = 2 to n = 1 transition gives 10.2 eV, which is much larger.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["transition-energy", "photon-frequency", "energy-level-diagram"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): The Balmer series of hydrogen spectrum is the only series that has some lines in the visible region. Reason (R): The wavelengths of the Balmer series range from 3646 A to 6563 A, which partially overlaps with the visible spectrum (3800 A to 7800 A).", "explanation": "The assertion is correct. Among all hydrogen spectral series, only the Balmer series has wavelengths in the visible range. The Lyman series is entirely in the UV region, while the Paschen, Brackett, and Pfund series are all in the infrared region. The reason is also correct and correctly explains the assertion. The Balmer series wavelengths (3646 A to 6563 A) do overlap with the visible range, which is why some Balmer lines (like H-alpha at 6563 A, H-beta at 4861 A) are visible to the human eye.", "payload": {"question_id": "cuet-phy-atom-spectra-13", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains why Balmer lines are visible — their wavelength range overlaps with the visible spectrum. So R is indeed the correct explanation of A.", "misconception": "Failing to see the causal connection between the wavelength range and visibility"}, {"option_key": "C", "hint": "The reason provides accurate wavelength data for the Balmer series. The range 3646 A to 6563 A is correct (series limit to first line).", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct — no other hydrogen series (Lyman, Paschen, etc.) falls in the visible range.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["balmer-series", "visible-spectrum", "hydrogen-spectral-series"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): The spectral lines of the Lyman series of hydrogen have shorter wavelengths than those of the Balmer series. Reason (R): In the Franck-Hertz experiment, electrons lose energy in discrete amounts when they collide with mercury atoms, confirming the existence of quantized energy levels.", "explanation": "The assertion is correct. The Lyman series (transitions to n = 1) involves larger energy differences than the Balmer series (transitions to n = 2), so Lyman series photons have higher energy and shorter wavelength. The reason is also correct — the Franck-Hertz experiment does confirm quantized energy levels. However, the reason is NOT the correct explanation of the assertion. The shorter wavelengths of the Lyman series are due to the larger energy gaps when transitioning to n = 1, not because of the Franck-Hertz experiment.", "payload": {"question_id": "cuet-phy-atom-spectra-14", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are independently correct, the Franck-Hertz experiment explains quantized energy levels in general — it does not specifically explain why the Lyman series has shorter wavelengths than the Balmer series.", "misconception": "Assuming any correct physics statement about energy levels is the explanation for spectral wavelength differences"}, {"option_key": "C", "hint": "The reason is correct — the Franck-Hertz experiment is a well-known experiment that demonstrated quantized energy levels in atoms.", "misconception": "Not recognizing the Franck-Hertz experiment as a valid confirmation of energy quantization"}, {"option_key": "D", "hint": "The assertion is correct — Lyman series wavelengths (912-1216 A) are indeed shorter than Balmer series wavelengths (3646-6563 A).", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["lyman-series", "balmer-series", "franck-hertz-experiment", "quantized-energy-levels"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the spectral series in Column I with the spectral region in Column II:\n\nColumn I:\nA. Lyman series\nB. Balmer series\nC. Paschen series\nD. Brackett series\n\nColumn II:\n1. Visible and near UV\n2. Ultraviolet\n3. Far infrared\n4. Near infrared", "explanation": "The Lyman series (transitions to n = 1) lies in the ultraviolet region (A-2). The Balmer series (transitions to n = 2) lies in the visible and near UV region (B-1). The Paschen series (transitions to n = 3) lies in the near infrared region (C-4). The Brackett series (transitions to n = 4) lies in the far infrared region (D-3).", "payload": {"question_id": "cuet-phy-atom-spectra-15", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "remember", "options": [{"key": "A", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-1, D-3", "is_correct": false}, {"key": "C", "text": "A-1, B-2, C-4, D-3", "is_correct": false}, {"key": "D", "text": "A-2, B-1, C-4, D-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This swaps C and D. Paschen series lies in the near infrared (C-4), and Brackett series lies in the far infrared (D-3), not the other way around.", "misconception": "Swapping Paschen and Brackett series spectral regions"}, {"option_key": "B", "hint": "This assigns the Balmer series to infrared, which is incorrect. The Balmer series falls in the visible/near UV region.", "misconception": "Incorrectly placing the Balmer series in the infrared region"}, {"option_key": "C", "hint": "This swaps A and B. The Lyman series is in the UV region (A-2), and the Balmer series is in the visible region (B-1).", "misconception": "Confusing Lyman and Balmer series regions"}]}, "correct_answer": "D", "concept_tags": ["lyman-series", "balmer-series", "paschen-series", "brackett-series", "spectral-regions"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the transitions in Column I with their spectral series in Column II:\n\nColumn I:\nA. n = 5 to n = 2\nB. n = 4 to n = 1\nC. n = 7 to n = 3\nD. n = 6 to n = 4\n\nColumn II:\n1. Lyman series\n2. Balmer series\n3. Paschen series\n4. Brackett series", "explanation": "A spectral line belongs to a series determined by its lower energy level. n = 5 to n = 2: lower level is n = 2, so it belongs to the Balmer series (A-2). n = 4 to n = 1: lower level is n = 1, so it belongs to the Lyman series (B-1). n = 7 to n = 3: lower level is n = 3, so it belongs to the Paschen series (C-3). n = 6 to n = 4: lower level is n = 4, so it belongs to the Brackett series (D-4).", "payload": {"question_id": "cuet-phy-atom-spectra-16", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-4, D-3", "is_correct": false}, {"key": "C", "text": "A-2, B-1, C-3, D-4", "is_correct": true}, {"key": "D", "text": "A-3, B-1, C-2, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns A to the Lyman series. The transition n = 5 to n = 2 has a lower level of n = 2, which corresponds to the Balmer series, not Lyman.", "misconception": "Identifying the series by the upper quantum number instead of the lower one"}, {"option_key": "B", "hint": "This swaps C and D. The transition n = 7 to n = 3 ends at n = 3 (Paschen), and n = 6 to n = 4 ends at n = 4 (Brackett).", "misconception": "Confusing Paschen and Brackett series"}, {"option_key": "D", "hint": "This assigns A to Paschen (n = 3), but the transition n = 5 to n = 2 ends at n = 2, making it a Balmer series line.", "misconception": "Incorrectly identifying the lower quantum number of the transition"}]}, "correct_answer": "C", "concept_tags": ["spectral-series-identification", "electron-transitions", "lyman-balmer-paschen-brackett"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The series limit (shortest wavelength) of the Lyman series of hydrogen corresponds to the ionization energy of 13.6 eV from the ground state.", "explanation": "This statement is true. The series limit of the Lyman series corresponds to the transition from n = infinity to n = 1. The energy of this photon is E = E_infinity - E_1 = 0 - (-13.6) = 13.6 eV, which is exactly the ionization energy of hydrogen from the ground state. The corresponding wavelength is 912 A.", "payload": {"question_id": "cuet-phy-atom-spectra-17", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The series limit of the Lyman series is the transition from n = infinity to n = 1, which releases exactly 13.6 eV — the ionization energy. The statement is true.", "misconception": "Not recognizing that the Lyman series limit equals the ionization energy from the ground state"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["series-limit", "lyman-series", "ionization-energy", "hydrogen-atom"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The Paschen series of hydrogen spectrum lies in the visible region of the electromagnetic spectrum.", "explanation": "This statement is false. The Paschen series corresponds to transitions from higher energy levels to n = 3. The wavelengths of the Paschen series range from approximately 8204 A to 18750 A, which fall entirely in the infrared region of the electromagnetic spectrum, not the visible region (3800 A to 7800 A). Only the Balmer series has lines in the visible region.", "payload": {"question_id": "cuet-phy-atom-spectra-18", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The Paschen series (transitions to n = 3) has wavelengths in the range 8204 A to 18750 A, which lies entirely in the infrared, not the visible region.", "misconception": "Confusing the spectral region of the Paschen series with the Balmer series"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["paschen-series", "infrared-region", "hydrogen-spectrum"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_blanks", "difficulty": "medium", "question_text": "The excitation potential required to excite a hydrogen atom from the ground state to the first excited state is _____ V.", "explanation": "The excitation energy from the ground state (n = 1) to the first excited state (n = 2) is: Delta E = E_2 - E_1 = (-13.6/4) - (-13.6) = -3.4 + 13.6 = 10.2 eV. The excitation potential is the potential difference through which an electron must be accelerated to gain this energy. Since the energy is 10.2 eV, the excitation potential is 10.2 V (because eV = eV, so V = 10.2 V).", "payload": {"question_id": "cuet-phy-atom-spectra-19", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "apply", "options": [{"key": "A", "text": "13.6 V", "is_correct": false}, {"key": "B", "text": "3.4 V", "is_correct": false}, {"key": "C", "text": "10.2 V", "is_correct": true}, {"key": "D", "text": "12.1 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "13.6 V is the ionization potential from the ground state, not the excitation potential to the first excited state.", "misconception": "Confusing ionization potential with excitation potential"}, {"option_key": "B", "hint": "3.4 V corresponds to the magnitude of the energy of the first excited state (-3.4 eV), not the energy difference from the ground state.", "misconception": "Using the energy of the final state instead of the energy difference"}, {"option_key": "D", "hint": "12.1 V is the excitation potential to the third energy level (n = 3), not the first excited state (n = 2). E_3 - E_1 = -1.51 + 13.6 = 12.09 eV.", "misconception": "Confusing the second excited state with the first excited state"}]}, "correct_answer": "C", "concept_tags": ["excitation-potential", "ground-state", "first-excited-state", "hydrogen-atom"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "medium", "question_text": "In a laboratory, a student is studying the emission spectrum of hydrogen gas using a discharge tube. The student observes that when the gas is excited, electrons jump to higher energy levels and then fall back, emitting radiation. The student records that the electron transitions from the 5th energy level produce spectral lines belonging to different series.\n\nHow many spectral lines in the Balmer series can be produced from transitions originating at the 5th energy level?", "explanation": "The Balmer series consists of transitions where the lower energy level is n = 2. From the 5th energy level, the possible transitions to n = 2 are: 5->2, 4->2, and 3->2. However, the question asks specifically for lines originating from transitions that start at n = 5. The direct transitions from n = 5 that belong to the Balmer series is only 5->2 (one line). But electrons from n = 5 can also cascade: 5->4->2, 5->3->2, etc. The Balmer series lines that can appear when electrons de-excite from n = 5 are: 5->2, 4->2, and 3->2. That gives 3 lines in the Balmer series. These are the transitions ending at n = 2 from levels 3, 4, and 5.", "payload": {"question_id": "cuet-phy-atom-spectra-20", "subtopic": "Spectral Series and Energy Levels", "topic_name": "Spectral Series and Energy Levels", "bloom_level": "apply", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "3", "is_correct": true}, {"key": "C", "text": "6", "is_correct": false}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 would be the count if only the direct transition 5->2 is considered. But through cascading, intermediate levels (n = 3, 4) also emit Balmer lines when they transition to n = 2.", "misconception": "Counting only the direct transition from n = 5 to n = 2"}, {"option_key": "C", "hint": "6 is the total number of spectral lines from all series when an electron de-excites from n = 4 using n(n-1)/2. This question asks only about Balmer series lines from n = 5.", "misconception": "Calculating total spectral lines instead of just Balmer series lines"}, {"option_key": "D", "hint": "10 is the total number of spectral lines from all series when an electron de-excites from n = 5. The question asks only about Balmer series lines.", "misconception": "Using n(n-1)/2 formula without restricting to Balmer series"}]}, "correct_answer": "B", "concept_tags": ["balmer-series", "spectral-lines", "electron-transitions", "emission-spectrum"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-2');

