SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In alpha decay, the parent nucleus emits:", "explanation": "In alpha decay, the parent nucleus emits an alpha particle, which is a helium-4 nucleus (₂He⁴) consisting of 2 protons and 2 neutrons. As a result, the mass number A decreases by 4 and the atomic number Z decreases by 2. For example, ²³⁸U → ²³⁴Th + ⁴He.", "payload": {"question_id": "cuet-phy-nuclei-decay-01", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "remember", "options": [{"key": "A", "text": "A helium nucleus (₂He⁴) with A decreasing by 4 and Z by 2", "is_correct": true}, {"key": "B", "text": "An electron and an antineutrino", "is_correct": false}, {"key": "C", "text": "A high-energy photon with no change in A or Z", "is_correct": false}, {"key": "D", "text": "A proton with A decreasing by 1 and Z by 1", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Emission of an electron and antineutrino describes beta-minus (β⁻) decay, not alpha decay.", "misconception": "Confusing alpha decay with beta-minus decay"}, {"option_key": "C", "hint": "Emission of a high-energy photon with no change in A or Z describes gamma decay, not alpha decay.", "misconception": "Confusing alpha decay with gamma decay"}, {"option_key": "D", "hint": "Proton emission is a rare decay mode. Alpha decay specifically involves emission of ₂He⁴, not a single proton.", "misconception": "Confusing alpha particle with a proton"}]}, "correct_answer": "A", "concept_tags": ["alpha-decay", "helium-nucleus", "mass-number", "atomic-number"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of radioactive activity is:", "explanation": "The SI unit of radioactive activity (rate of disintegration) is the becquerel (Bq), where 1 Bq = 1 disintegration per second. The older unit curie (Ci) is defined as 1 Ci = 3.7 × 10¹⁰ disintegrations per second, which was originally based on the activity of 1 gram of Ra-226.", "payload": {"question_id": "cuet-phy-nuclei-decay-02", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "remember", "options": [{"key": "A", "text": "Curie (Ci)", "is_correct": false}, {"key": "B", "text": "Becquerel (Bq)", "is_correct": true}, {"key": "C", "text": "Rutherford (Rd)", "is_correct": false}, {"key": "D", "text": "Gray (Gy)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Curie is a non-SI (older CGS) unit of activity. The SI unit is becquerel. 1 Ci = 3.7 × 10¹⁰ Bq.", "misconception": "Confusing SI unit with the older traditional unit of activity"}, {"option_key": "C", "hint": "Rutherford (1 Rd = 10⁶ disintegrations/s) is another non-SI unit and is rarely used in modern physics.", "misconception": "Confusing the rutherford unit with the SI unit"}, {"option_key": "D", "hint": "Gray (Gy) is the SI unit of absorbed radiation dose (energy per unit mass), not activity.", "misconception": "Confusing activity with absorbed dose"}]}, "correct_answer": "B", "concept_tags": ["activity", "becquerel", "curie", "SI-units"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The half-life of a radioactive substance is 20 minutes. The fraction of the original sample that remains after 1 hour is:", "explanation": "In 1 hour = 60 minutes, the number of half-lives n = 60/20 = 3. After n half-lives, the fraction remaining is (1/2)ⁿ = (1/2)³ = 1/8. So 1/8 of the original sample remains undecayed after 1 hour.", "payload": {"question_id": "cuet-phy-nuclei-decay-03", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "apply", "options": [{"key": "A", "text": "1/2", "is_correct": false}, {"key": "B", "text": "1/4", "is_correct": false}, {"key": "C", "text": "1/8", "is_correct": true}, {"key": "D", "text": "1/16", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/2 would remain after just one half-life (20 min), not after 60 min. Count the number of half-lives: 60/20 = 3.", "misconception": "Using only one half-life period instead of calculating the correct number"}, {"option_key": "B", "hint": "1/4 would remain after two half-lives (40 min). After 60 min, three half-lives have elapsed, giving (1/2)³ = 1/8.", "misconception": "Miscounting the number of half-lives"}, {"option_key": "D", "hint": "1/16 = (1/2)⁴ would require four half-lives (80 min), but only 60 min have elapsed (3 half-lives).", "misconception": "Incorrectly calculating the number of half-lives"}]}, "correct_answer": "C", "concept_tags": ["half-life", "radioactive-decay", "fraction-remaining"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In gamma decay, the emitted radiation is:", "explanation": "Gamma decay involves the emission of high-energy electromagnetic radiation (photons) from a nucleus in an excited state transitioning to a lower energy state. During gamma emission, there is no change in the mass number (A) or atomic number (Z) of the nucleus, as no nucleons are emitted or converted.", "payload": {"question_id": "cuet-phy-nuclei-decay-04", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "remember", "options": [{"key": "A", "text": "A stream of electrons", "is_correct": false}, {"key": "B", "text": "A stream of helium nuclei", "is_correct": false}, {"key": "C", "text": "A stream of neutrons", "is_correct": false}, {"key": "D", "text": "High-energy electromagnetic radiation (photons)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Electrons are emitted in beta-minus (β⁻) decay, not gamma decay. Gamma rays are electromagnetic radiation.", "misconception": "Confusing gamma radiation with beta radiation"}, {"option_key": "B", "hint": "Helium nuclei are emitted in alpha decay, not gamma decay.", "misconception": "Confusing gamma decay with alpha decay"}, {"option_key": "C", "hint": "Neutrons are not emitted in gamma decay. Gamma decay involves no particle emission, only photon emission.", "misconception": "Confusing gamma emission with neutron emission"}]}, "correct_answer": "D", "concept_tags": ["gamma-decay", "electromagnetic-radiation", "isomeric-transition"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The half-life of a radioactive element is T₁/₂. The mean life (τ) of the element is:", "explanation": "The decay constant λ = 0.693/T₁/₂. The mean life is τ = 1/λ = T₁/₂/0.693 = T₁/₂/ln2 ≈ 1.44 T₁/₂. The mean life is always greater than the half-life by a factor of 1/ln2 ≈ 1.44.", "payload": {"question_id": "cuet-phy-nuclei-decay-05", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "understand", "options": [{"key": "A", "text": "0.693 T₁/₂", "is_correct": false}, {"key": "B", "text": "T₁/₂ / 0.693", "is_correct": true}, {"key": "C", "text": "T₁/₂ / 2", "is_correct": false}, {"key": "D", "text": "2 T₁/₂", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.693 T₁/₂ gives a value less than T₁/₂, but the mean life is always greater than the half-life. The relation is τ = T₁/₂ / 0.693.", "misconception": "Inverting the relation between mean life and half-life"}, {"option_key": "C", "hint": "T₁/₂/2 has no physical basis. The correct relation involves the natural logarithm of 2, i.e., τ = T₁/₂/ln2.", "misconception": "Guessing an arbitrary simple fraction"}, {"option_key": "D", "hint": "2T₁/₂ is incorrect. The correct factor is 1/ln2 ≈ 1.44, not 2.", "misconception": "Approximating 1/ln2 as 2 instead of the correct value 1.44"}]}, "correct_answer": "B", "concept_tags": ["mean-life", "half-life", "decay-constant", "relation"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A radioactive sample has an initial activity of 800 Bq. If the half-life is 4 hours, the activity after 12 hours will be:", "explanation": "Number of half-lives = 12/4 = 3. Activity after n half-lives: A = A₀(1/2)ⁿ = 800 × (1/2)³ = 800 × 1/8 = 100 Bq. Activity decays exponentially just like the number of undecayed nuclei.", "payload": {"question_id": "cuet-phy-nuclei-decay-06", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "apply", "options": [{"key": "A", "text": "400 Bq", "is_correct": false}, {"key": "B", "text": "200 Bq", "is_correct": false}, {"key": "C", "text": "100 Bq", "is_correct": true}, {"key": "D", "text": "50 Bq", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "400 Bq = 800/2 is the activity after only 1 half-life (4 hours), not 12 hours.", "misconception": "Using only one half-life instead of calculating the correct number"}, {"option_key": "B", "hint": "200 Bq = 800/4 is the activity after 2 half-lives (8 hours), not 12 hours.", "misconception": "Miscounting the number of half-lives as 2 instead of 3"}, {"option_key": "D", "hint": "50 Bq = 800/16 would require 4 half-lives (16 hours), but only 12 hours have passed.", "misconception": "Overcounting the number of half-lives"}]}, "correct_answer": "C", "concept_tags": ["activity", "half-life", "exponential-decay", "becquerel"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In β⁻ decay, a neutron inside the nucleus is converted into:", "explanation": "In beta-minus (β⁻) decay, a neutron inside the nucleus transforms into a proton, an electron (β⁻ particle), and an antineutrino: n → p + e⁻ + ν̄ₑ. The atomic number Z increases by 1 while the mass number A remains unchanged. The antineutrino carries away part of the energy, which explains the continuous energy spectrum of β⁻ particles.", "payload": {"question_id": "cuet-phy-nuclei-decay-07", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "understand", "options": [{"key": "A", "text": "A proton, an electron, and an antineutrino", "is_correct": true}, {"key": "B", "text": "A proton, an electron, and a neutrino", "is_correct": false}, {"key": "C", "text": "A proton, a positron, and a neutrino", "is_correct": false}, {"key": "D", "text": "A proton and an electron only", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "In β⁻ decay, the emitted lepton partner is an antineutrino (ν̄ₑ), not a neutrino. A neutrino is emitted in β⁺ decay.", "misconception": "Confusing neutrino with antineutrino in beta-minus decay"}, {"option_key": "C", "hint": "Positron emission occurs in β⁺ decay (p → n + e⁺ + νₑ), not in β⁻ decay.", "misconception": "Confusing beta-minus decay with beta-plus decay"}, {"option_key": "D", "hint": "A third particle (antineutrino) is essential to conserve energy, momentum, and lepton number. Its existence was postulated by Pauli to explain the continuous β-spectrum.", "misconception": "Ignoring the role of the antineutrino in beta decay"}]}, "correct_answer": "A", "concept_tags": ["beta-minus-decay", "neutron-conversion", "antineutrino", "atomic-number"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the nuclear fission of ²³⁵U by a slow neutron, the approximate energy released per fission is:", "explanation": "The fission of one ²³⁵U nucleus by a thermal (slow) neutron releases approximately 200 MeV of energy. This energy appears as kinetic energy of fission fragments (~165 MeV), kinetic energy of neutrons (~5 MeV), prompt gamma rays (~7 MeV), energy of fission products'' beta and gamma decay (~23 MeV), and neutrino energy (~12 MeV).", "payload": {"question_id": "cuet-phy-nuclei-decay-08", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "remember", "options": [{"key": "A", "text": "2 MeV", "is_correct": false}, {"key": "B", "text": "20 MeV", "is_correct": false}, {"key": "C", "text": "2000 MeV", "is_correct": false}, {"key": "D", "text": "200 MeV", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2 MeV is far too small. This is roughly the energy of a single gamma ray photon, not the total fission energy.", "misconception": "Underestimating fission energy by two orders of magnitude"}, {"option_key": "B", "hint": "20 MeV is the typical energy released in a single alpha decay, not fission. Fission releases about 10 times more energy.", "misconception": "Confusing fission energy with alpha decay energy"}, {"option_key": "C", "hint": "2000 MeV is ten times the actual fission energy. The binding energy per nucleon difference accounts for about 200 MeV.", "misconception": "Overestimating fission energy by an order of magnitude"}]}, "correct_answer": "D", "concept_tags": ["nuclear-fission", "uranium-235", "energy-release", "slow-neutron"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The decay constant of a radioactive substance is 0.0231 per minute. Its half-life is approximately:", "explanation": "Using T₁/₂ = 0.693/λ = 0.693/0.0231 = 30 minutes. The half-life and decay constant are inversely related through the factor ln2 = 0.693.", "payload": {"question_id": "cuet-phy-nuclei-decay-09", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "apply", "options": [{"key": "A", "text": "10 minutes", "is_correct": false}, {"key": "B", "text": "20 minutes", "is_correct": false}, {"key": "C", "text": "30 minutes", "is_correct": true}, {"key": "D", "text": "45 minutes", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "T₁/₂ = 0.693/0.0231 = 30 min, not 10 min. Check your arithmetic: 0.693/0.0231 ≠ 10.", "misconception": "Arithmetic error in division"}, {"option_key": "B", "hint": "20 minutes would require λ = 0.693/20 = 0.0347 per min, which does not match the given λ = 0.0231.", "misconception": "Incorrect calculation of the half-life"}, {"option_key": "D", "hint": "45 minutes would require λ = 0.693/45 = 0.0154 per min. The given λ = 0.0231 corresponds to T₁/₂ = 30 min.", "misconception": "Using an incorrect formula or arithmetic error"}]}, "correct_answer": "C", "concept_tags": ["decay-constant", "half-life", "radioactive-decay-law"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a nuclear reactor, the function of the moderator is to:", "explanation": "In a nuclear reactor, the moderator (commonly heavy water D₂O, graphite, or ordinary water) slows down fast neutrons produced during fission to thermal energies (~0.025 eV). Slow (thermal) neutrons have a much higher probability of causing fission in ²³⁵U compared to fast neutrons. The moderator achieves this through elastic collisions with neutrons.", "payload": {"question_id": "cuet-phy-nuclei-decay-10", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "understand", "options": [{"key": "A", "text": "Absorb excess neutrons to control the chain reaction", "is_correct": false}, {"key": "B", "text": "Slow down fast neutrons to thermal energies", "is_correct": true}, {"key": "C", "text": "Shield the reactor from radiation leakage", "is_correct": false}, {"key": "D", "text": "Increase the speed of neutrons for efficient fission", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Absorbing excess neutrons is the function of control rods (typically cadmium or boron), not the moderator.", "misconception": "Confusing the role of moderator with control rods"}, {"option_key": "C", "hint": "Radiation shielding is provided by the thick concrete and lead walls around the reactor, not by the moderator.", "misconception": "Confusing the role of moderator with radiation shielding"}, {"option_key": "D", "hint": "The moderator slows down neutrons, not speeds them up. Fast neutrons are less efficient at causing ²³⁵U fission.", "misconception": "Reversing the function of the moderator"}]}, "correct_answer": "B", "concept_tags": ["nuclear-reactor", "moderator", "thermal-neutrons", "chain-reaction"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A radioactive nucleus ²³⁶X undergoes a series of alpha and beta-minus decays to finally become ²⁰⁸Y. The number of alpha and beta-minus particles emitted are, respectively:", "explanation": "Let the number of alpha decays = a and beta-minus decays = b. Each alpha decay reduces A by 4 and Z by 2. Each β⁻ decay increases Z by 1 with no change in A. Change in mass number: 236 − 208 = 28 = 4a, so a = 7. For atomic number: if Z_X is the initial atomic number and Z_Y is the final, then Z_X − 2a + b = Z_Y. However, since only A values are given, we use the mass number relation: a = 28/4 = 7. For β⁻ decays, we need Z values. Since this follows the thorium decay series (²³⁶₉₀Th → ²⁰⁸₈₂Pb pattern): Z change = 90 − 82 = 8 = 2a − b = 14 − b, so b = 6. The answer is 7 alpha and 6 beta-minus particles. (Note: In standard decay chains like ²³²Th series, the pattern of 7α and 4β⁻ is typical when Z_X − Z_Y = 2a − b = 10. Here with the given numbers, 7α and 4β⁻ gives Z change = 14 − 4 = 10.)", "payload": {"question_id": "cuet-phy-nuclei-decay-11", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "analyze", "options": [{"key": "A", "text": "7 alpha and 6 beta-minus", "is_correct": false}, {"key": "B", "text": "6 alpha and 4 beta-minus", "is_correct": false}, {"key": "C", "text": "5 alpha and 8 beta-minus", "is_correct": false}, {"key": "D", "text": "7 alpha and 4 beta-minus", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "While 7 alpha decays is correct (28/4 = 7), the number of β⁻ decays depends on the Z values. In the standard thorium series, 4 β⁻ decays are emitted, not 6.", "misconception": "Incorrect calculation of the number of beta decays"}, {"option_key": "B", "hint": "6 alpha decays would reduce A by only 24 (to 212), not to 208. The mass number change requires exactly 7 alpha decays.", "misconception": "Incorrect calculation of the number of alpha decays"}, {"option_key": "C", "hint": "5 alpha decays would reduce A by only 20 (to 216), which does not match the final mass number of 208.", "misconception": "Incorrect calculation of mass number change in alpha decay"}]}, "correct_answer": "D", "concept_tags": ["alpha-decay", "beta-decay", "decay-series", "mass-number", "atomic-number"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The activity of a radioactive sample decreases from 6400 disintegrations per second to 100 disintegrations per second in 30 minutes. The half-life of the sample is:", "explanation": "Using A = A₀(1/2)ⁿ, where n is the number of half-lives: 100 = 6400 × (1/2)ⁿ, so (1/2)ⁿ = 100/6400 = 1/64 = (1/2)⁶. Therefore n = 6 half-lives in 30 minutes. Half-life T₁/₂ = 30/6 = 5 minutes.", "payload": {"question_id": "cuet-phy-nuclei-decay-12", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "apply", "options": [{"key": "A", "text": "5 minutes", "is_correct": true}, {"key": "B", "text": "6 minutes", "is_correct": false}, {"key": "C", "text": "10 minutes", "is_correct": false}, {"key": "D", "text": "15 minutes", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "6 minutes would give n = 30/6 = 5 half-lives, reducing activity by a factor of 2⁵ = 32. But 6400/32 = 200, not 100.", "misconception": "Confusing the number of half-lives with the half-life value"}, {"option_key": "C", "hint": "10 minutes would give n = 30/10 = 3 half-lives, reducing activity by 2³ = 8. But 6400/8 = 800, not 100.", "misconception": "Incorrect division to find number of half-lives"}, {"option_key": "D", "hint": "15 minutes gives n = 2, so activity = 6400/4 = 1600, far from 100. The ratio 6400/100 = 64 = 2⁶ requires 6 half-lives.", "misconception": "Grossly underestimating the number of half-lives required"}]}, "correct_answer": "A", "concept_tags": ["activity", "half-life", "exponential-decay", "numerical"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): In nuclear fusion, two light nuclei combine to form a heavier nucleus with release of energy.\nReason (R): The binding energy per nucleon of the product nucleus is greater than that of the reacting light nuclei.", "explanation": "Both the assertion and reason are correct, and the reason correctly explains the assertion. In nuclear fusion, light nuclei (like hydrogen isotopes) combine to form a heavier nucleus (like helium). Energy is released because the binding energy per nucleon increases when moving from very light nuclei toward the iron region of the binding energy curve. The mass defect of the product is greater, meaning the product is more tightly bound, and the difference in binding energy is released as kinetic energy and radiation.", "payload": {"question_id": "cuet-phy-nuclei-decay-13", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The higher binding energy per nucleon of the product is precisely the reason energy is released. The excess binding energy converts to kinetic energy, so R directly explains A.", "misconception": "Failing to see the direct causal link between binding energy increase and energy release"}, {"option_key": "C", "hint": "The reason is factually correct: on the binding energy curve, fusion products of light nuclei have higher BE/A than the reactants.", "misconception": "Incorrectly thinking binding energy per nucleon decreases in fusion"}, {"option_key": "D", "hint": "The assertion is correct: fusion of light nuclei (e.g., ²H + ³H → ⁴He + n) does release energy. This is the energy source of stars.", "misconception": "Thinking fusion absorbs energy rather than releases it"}]}, "correct_answer": "A", "concept_tags": ["nuclear-fusion", "binding-energy-per-nucleon", "energy-release", "light-nuclei"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): The energy spectrum of electrons emitted in beta-minus decay is continuous, ranging from zero to a maximum value.\nReason (R): In beta-minus decay, the energy is shared between the electron and the antineutrino in varying proportions.", "explanation": "Both A and R are correct, and R is the correct explanation of A. In β⁻ decay, the available energy (Q-value minus the recoil energy of the daughter nucleus) is shared between the emitted electron and the antineutrino. Since this is a three-body decay (daughter nucleus, electron, antineutrino), the electron can carry any fraction of the available energy from nearly zero to the maximum (when the antineutrino gets negligible energy). This variable sharing produces the continuous energy spectrum. Pauli originally postulated the neutrino specifically to explain this continuous spectrum.", "payload": {"question_id": "cuet-phy-nuclei-decay-14", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The energy sharing between the electron and antineutrino is precisely the cause of the continuous spectrum. If only the electron were emitted, the spectrum would be discrete.", "misconception": "Not recognizing that variable energy sharing directly causes the continuous spectrum"}, {"option_key": "C", "hint": "The reason is correct. The three-body nature of β⁻ decay allows the electron-antineutrino energy partition to vary continuously.", "misconception": "Incorrectly thinking beta decay is a two-body process"}, {"option_key": "D", "hint": "The assertion is experimentally verified: beta particles have a continuous energy spectrum from 0 to E_max.", "misconception": "Thinking beta particles have a discrete energy spectrum like alpha particles"}]}, "correct_answer": "A", "concept_tags": ["beta-decay", "energy-spectrum", "antineutrino", "continuous-spectrum", "Pauli"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the following types of radiation (Column-I) with their properties (Column-II):\n\nColumn-I:\nA. Alpha rays\nB. Beta-minus rays\nC. Gamma rays\nD. Neutrino\n\nColumn-II:\n1. Uncharged, massless (or nearly massless), weakly interacting\n2. Helium nuclei with high ionizing power and low penetration\n3. Electromagnetic radiation with highest penetrating power\n4. Electrons with continuous energy spectrum", "explanation": "Alpha rays are helium nuclei (₂He⁴) with high ionizing power but low penetrating ability (A→2). Beta-minus rays are electrons emitted from the nucleus with a continuous energy spectrum due to energy sharing with the antineutrino (B→4). Gamma rays are electromagnetic radiation with the highest penetrating power among the three types of nuclear radiation (C→3). Neutrinos are uncharged, nearly massless particles that interact very weakly with matter (D→1).", "payload": {"question_id": "cuet-phy-nuclei-decay-15", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "understand", "options": [{"key": "A", "text": "A-2, B-3, C-4, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": true}, {"key": "C", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-4, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps beta rays and gamma rays. Beta rays are electrons (B→4), while gamma rays are electromagnetic radiation (C→3).", "misconception": "Confusing the nature of beta and gamma radiation"}, {"option_key": "C", "hint": "Alpha rays are helium nuclei (A→2), not electrons. This option incorrectly assigns electron properties to alpha particles.", "misconception": "Confusing alpha particles with electrons"}, {"option_key": "D", "hint": "Alpha rays are charged helium nuclei, not uncharged weakly interacting particles. The neutrino has property 1.", "misconception": "Confusing alpha particles with neutrinos"}]}, "correct_answer": "B", "concept_tags": ["alpha-rays", "beta-rays", "gamma-rays", "neutrino", "properties"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the following nuclear reactor components (Column-I) with their materials and functions (Column-II):\n\nColumn-I:\nA. Fuel\nB. Moderator\nC. Control rods\nD. Coolant\n\nColumn-II:\n1. Cadmium or boron rods — absorb excess neutrons\n2. Heavy water or liquid sodium — transfers heat to generate steam\n3. Enriched uranium (²³⁵U) or plutonium (²³⁹Pu) — undergoes fission\n4. Heavy water or graphite — slows down neutrons", "explanation": "The fuel in a nuclear reactor is enriched uranium or plutonium which undergoes fission (A→3). The moderator is heavy water or graphite which slows down fast neutrons to thermal energies (B→4). Control rods are made of cadmium or boron which have high neutron absorption cross-sections to regulate the chain reaction (C→1). The coolant is heavy water or liquid sodium which transfers the heat generated in the reactor core to produce steam for electricity generation (D→2).", "payload": {"question_id": "cuet-phy-nuclei-decay-16", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-1, C-4, D-2", "is_correct": false}, {"key": "B", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "C", "text": "A-3, B-4, C-1, D-2", "is_correct": true}, {"key": "D", "text": "A-3, B-2, C-1, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps the moderator and control rods. The moderator slows neutrons (B→4), while control rods absorb neutrons (C→1).", "misconception": "Confusing the functions of moderator and control rods"}, {"option_key": "B", "hint": "This assigns fission to the moderator and neutron slowing to the fuel, which is completely reversed.", "misconception": "Confusing the roles of fuel and moderator in a reactor"}, {"option_key": "D", "hint": "This swaps the coolant and moderator. The coolant transfers heat (D→2), while the moderator slows neutrons (B→4). Both may use heavy water, but their functions differ.", "misconception": "Confusing coolant and moderator because both can use heavy water"}]}, "correct_answer": "C", "concept_tags": ["nuclear-reactor", "fuel", "moderator", "control-rods", "coolant"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "In gamma decay, the mass number (A) and atomic number (Z) of the nucleus remain unchanged.", "explanation": "This statement is TRUE. Gamma decay involves the emission of a high-energy photon from an excited nuclear state. Since a photon has zero mass number and zero charge, neither the mass number A nor the atomic number Z of the nucleus changes during gamma emission. The nucleus simply transitions from an excited state to a lower energy state (isomeric transition).", "payload": {"question_id": "cuet-phy-nuclei-decay-17", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Gamma photons carry zero mass number and zero charge. Unlike alpha or beta decay, gamma emission does not change A or Z.", "misconception": "Confusing gamma decay with alpha or beta decay where A and/or Z change"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["gamma-decay", "mass-number", "atomic-number", "isomeric-transition"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "Nuclear fission can be achieved easily by bombarding any heavy nucleus with slow neutrons.", "explanation": "This statement is FALSE. Not all heavy nuclei undergo fission with slow (thermal) neutrons. Only specific fissile nuclei such as ²³⁵U, ²³³U, and ²³⁹Pu can be fissioned by slow neutrons. Other heavy nuclei like ²³⁸U require fast neutrons (energy > 1 MeV) to undergo fission and are called fissionable (not fissile). The distinction between fissile and fissionable materials is crucial in nuclear reactor physics.", "payload": {"question_id": "cuet-phy-nuclei-decay-18", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Only specific fissile nuclei (²³⁵U, ²³³U, ²³⁹Pu) undergo fission with slow neutrons. Many heavy nuclei like ²³⁸U do not fission with thermal neutrons.", "misconception": "Assuming all heavy nuclei are equally fissile with slow neutrons"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["nuclear-fission", "fissile-material", "slow-neutrons", "uranium-235"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_blanks", "difficulty": "medium", "question_text": "A radioactive sample has a decay constant λ = 0.1 per second. If the sample initially contains 10⁶ atoms, its initial activity (rate of disintegration) is _____ disintegrations per second.", "explanation": "Activity is defined as A = λN, where λ is the decay constant and N is the number of radioactive atoms. Initial activity A₀ = λN₀ = 0.1 × 10⁶ = 10⁵ = 1,00,000 disintegrations per second (or 10⁵ Bq). Activity represents the number of nuclear disintegrations occurring per unit time.", "payload": {"question_id": "cuet-phy-nuclei-decay-19", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "apply", "options": [{"key": "A", "text": "10⁷", "is_correct": false}, {"key": "B", "text": "10⁶", "is_correct": false}, {"key": "C", "text": "10⁴", "is_correct": false}, {"key": "D", "text": "10⁵", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10⁷ would mean A = 10 × N₀, but the decay constant is 0.1 (less than 1), so A must be less than N₀.", "misconception": "Multiplying instead of correctly applying A = λN"}, {"option_key": "B", "hint": "10⁶ equals N₀ itself. Activity A = λN₀ = 0.1 × 10⁶ = 10⁵, not 10⁶.", "misconception": "Confusing the number of atoms with the activity"}, {"option_key": "C", "hint": "10⁴ would require λ = 10⁴/10⁶ = 0.01, but the given λ is 0.1. Check: 0.1 × 10⁶ = 10⁵.", "misconception": "Arithmetic error in computing λN"}]}, "correct_answer": "D", "concept_tags": ["activity", "decay-constant", "number-of-atoms", "disintegration-rate"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "medium", "question_text": "A hospital uses a radioactive isotope ¹³¹I (iodine-131) with a half-life of 8 days for thyroid diagnosis. A fresh sample has an activity of 4.8 × 10⁸ Bq on the day it is delivered. The hospital plans to use it when the activity drops to 6 × 10⁷ Bq.\n\nAfter how many days from delivery can the hospital use the sample?", "explanation": "Using A = A₀(1/2)ⁿ, where n = t/T₁/₂. We need: 6 × 10⁷ = 4.8 × 10⁸ × (1/2)ⁿ. So (1/2)ⁿ = 6 × 10⁷ / 4.8 × 10⁸ = 1/8 = (1/2)³. Therefore n = 3 half-lives. Time t = 3 × 8 = 24 days. The hospital can use the sample 24 days after delivery when its activity has decreased to the required level.", "payload": {"question_id": "cuet-phy-nuclei-decay-20", "subtopic": "Radioactivity, Nuclear Fission, and Fusion", "topic_name": "Radioactivity, Nuclear Fission, and Fusion", "bloom_level": "apply", "options": [{"key": "A", "text": "8 days", "is_correct": false}, {"key": "B", "text": "16 days", "is_correct": false}, {"key": "C", "text": "24 days", "is_correct": true}, {"key": "D", "text": "32 days", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "After 8 days (1 half-life), activity = 4.8 × 10⁸ / 2 = 2.4 × 10⁸ Bq, which is still much higher than the required 6 × 10⁷ Bq.", "misconception": "Assuming only one half-life is needed without checking the activity ratio"}, {"option_key": "B", "hint": "After 16 days (2 half-lives), activity = 4.8 × 10⁸ / 4 = 1.2 × 10⁸ Bq, still above the target of 6 × 10⁷ Bq.", "misconception": "Insufficient number of half-lives calculated"}, {"option_key": "D", "hint": "After 32 days (4 half-lives), activity = 4.8 × 10⁸ / 16 = 3 × 10⁷ Bq, which overshoots below the target. The ratio 4.8 × 10⁸ / 6 × 10⁷ = 8 = 2³ requires exactly 3 half-lives = 24 days.", "misconception": "Overcounting the number of half-lives required"}]}, "correct_answer": "C", "concept_tags": ["half-life", "activity", "iodine-131", "medical-application", "exponential-decay"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-3');

