SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The value of 1 atomic mass unit (1 u) in terms of energy is approximately:", "explanation": "By Einstein''s mass-energy equivalence E = mc², 1 atomic mass unit (1 u = 1.66054 × 10⁻²⁷ kg) corresponds to an energy of 931.5 MeV. This conversion factor is fundamental in nuclear physics for calculating binding energies and mass defects.", "payload": {"question_id": "cuet-phy-nuclei-properties-01", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "931.5 keV", "is_correct": false}, {"key": "B", "text": "931.5 GeV", "is_correct": false}, {"key": "C", "text": "931.5 MeV", "is_correct": true}, {"key": "D", "text": "9.315 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "931.5 keV is a thousand times smaller than the correct value. The correct unit is MeV (mega electron volt), not keV (kilo electron volt).", "misconception": "Confusing keV with MeV; 1 MeV = 1000 keV"}, {"option_key": "B", "hint": "931.5 GeV is a thousand times larger than the correct value. 1 GeV = 1000 MeV, so this would be 931,500 MeV.", "misconception": "Confusing GeV with MeV"}, {"option_key": "D", "hint": "9.315 MeV is off by a factor of 100. The standard value is 931.5 MeV per atomic mass unit.", "misconception": "Misplacing the decimal point in the conversion factor"}]}, "correct_answer": "C", "concept_tags": ["atomic-mass-unit", "mass-energy-equivalence", "MeV"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The nuclear radius R is related to the mass number A by the relation R = R₀A^(1/3). The value of R₀ is approximately:", "explanation": "Experimentally, the nuclear radius follows the empirical formula R = R₀A^(1/3), where R₀ ≈ 1.2 fm (1.2 × 10⁻¹⁵ m). This relation shows that nuclear volume is directly proportional to the mass number A, implying constant nuclear density.", "payload": {"question_id": "cuet-phy-nuclei-properties-02", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "1.2 × 10⁻¹⁰ m", "is_correct": false}, {"key": "B", "text": "1.2 × 10⁻¹⁵ m", "is_correct": true}, {"key": "C", "text": "1.2 × 10⁻²⁰ m", "is_correct": false}, {"key": "D", "text": "1.2 × 10⁻⁸ m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10⁻¹⁰ m (1 Å) is the order of atomic size, not nuclear size. Nuclei are about 100,000 times smaller than atoms.", "misconception": "Confusing atomic radius with nuclear radius"}, {"option_key": "C", "hint": "10⁻²⁰ m is far too small even for a nucleus. Nuclear sizes are of the order of femtometres (10⁻¹⁵ m).", "misconception": "Using an incorrect order of magnitude for nuclear dimensions"}, {"option_key": "D", "hint": "10⁻⁸ m is the order of atomic diameter, not nuclear radius. The nucleus is roughly 10⁵ times smaller than the atom.", "misconception": "Confusing atomic dimensions with nuclear dimensions"}]}, "correct_answer": "B", "concept_tags": ["nuclear-radius", "mass-number", "fermi"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Nuclei having the same mass number but different atomic numbers are called:", "explanation": "Isobars are nuclei that share the same mass number (A) but have different atomic numbers (Z). For example, ¹⁴C (Z = 6) and ¹⁴N (Z = 7) are isobars. Isotopes have the same Z but different A; isotones have the same neutron number (A − Z).", "payload": {"question_id": "cuet-phy-nuclei-properties-03", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "Isobars", "is_correct": true}, {"key": "B", "text": "Isotopes", "is_correct": false}, {"key": "C", "text": "Isotones", "is_correct": false}, {"key": "D", "text": "Isomers", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Isotopes have the same atomic number (Z) but different mass numbers (A). The question states different atomic numbers, so these cannot be isotopes.", "misconception": "Confusing isotopes (same Z, different A) with isobars (same A, different Z)"}, {"option_key": "C", "hint": "Isotones have the same number of neutrons (N = A − Z) but different atomic numbers and mass numbers.", "misconception": "Confusing isotones (same N) with isobars (same A)"}, {"option_key": "D", "hint": "Isomers are nuclei with the same Z and A but in different energy states. They are not defined by having different atomic numbers.", "misconception": "Confusing nuclear isomers with isobars"}]}, "correct_answer": "A", "concept_tags": ["isobars", "mass-number", "atomic-number", "nuclear-terminology"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The density of nuclear matter is approximately:", "explanation": "Nuclear density is nearly constant for all nuclei and is approximately 2.3 × 10¹⁷ kg/m³. This follows from the relation R = R₀A^(1/3), which means volume V ∝ A. Since mass is also proportional to A (mass ≈ A × u), the density ρ = mass/volume is independent of A.", "payload": {"question_id": "cuet-phy-nuclei-properties-04", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "2.3 × 10³ kg/m³", "is_correct": false}, {"key": "B", "text": "2.3 × 10¹⁰ kg/m³", "is_correct": false}, {"key": "C", "text": "2.3 × 10²⁷ kg/m³", "is_correct": false}, {"key": "D", "text": "2.3 × 10¹⁷ kg/m³", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10³ kg/m³ is the density of water. Nuclear matter is about 10¹⁴ times denser than water.", "misconception": "Confusing ordinary matter density with nuclear density"}, {"option_key": "B", "hint": "10¹⁰ kg/m³ is too low for nuclear matter. The incredibly small nuclear volume leads to a much higher density (~10¹⁷ kg/m³).", "misconception": "Underestimating nuclear density by several orders of magnitude"}, {"option_key": "C", "hint": "10²⁷ kg/m³ is ten orders of magnitude too high. The correct nuclear density is about 2.3 × 10¹⁷ kg/m³.", "misconception": "Overestimating nuclear density"}]}, "correct_answer": "D", "concept_tags": ["nuclear-density", "nuclear-volume", "mass-number"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the nuclear radii of two nuclei with mass numbers 27 and 125 is:", "explanation": "Using R = R₀A^(1/3), the ratio R₁/R₂ = (A₁/A₂)^(1/3) = (27/125)^(1/3) = 3/5. Here, 27^(1/3) = 3 and 125^(1/3) = 5.", "payload": {"question_id": "cuet-phy-nuclei-properties-05", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "27 : 125", "is_correct": false}, {"key": "B", "text": "3 : 5", "is_correct": true}, {"key": "C", "text": "5 : 3", "is_correct": false}, {"key": "D", "text": "9 : 25", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The ratio of radii is not the same as the ratio of mass numbers. R ∝ A^(1/3), so the cube root must be taken.", "misconception": "Assuming nuclear radius is directly proportional to A instead of A^(1/3)"}, {"option_key": "C", "hint": "The ratio 5:3 is inverted. Since the first nucleus has the smaller mass number (27), it has the smaller radius, so the ratio is 3:5.", "misconception": "Reversing the order of the ratio"}, {"option_key": "D", "hint": "9:25 = (3:5)² corresponds to the ratio of surface areas, not radii. The radius ratio uses the cube root of A.", "misconception": "Using A^(2/3) instead of A^(1/3) for the radius relation"}]}, "correct_answer": "B", "concept_tags": ["nuclear-radius", "mass-number", "ratio-calculation"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mass defect of a helium nucleus ⁴He is 0.0304 u. The binding energy of the helium nucleus is approximately:", "explanation": "Binding energy = mass defect × 931.5 MeV/u = 0.0304 × 931.5 = 28.3 MeV. This is the energy required to completely separate all nucleons (2 protons and 2 neutrons) in the ⁴He nucleus.", "payload": {"question_id": "cuet-phy-nuclei-properties-06", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "28.3 keV", "is_correct": false}, {"key": "B", "text": "7.07 MeV", "is_correct": false}, {"key": "C", "text": "28.3 MeV", "is_correct": true}, {"key": "D", "text": "283 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "28.3 keV uses the wrong unit. The conversion factor 931.5 already gives MeV, not keV. The correct answer is 28.3 MeV.", "misconception": "Confusing MeV with keV in the mass-energy conversion"}, {"option_key": "B", "hint": "7.07 MeV is the binding energy per nucleon (28.3/4), not the total binding energy of the nucleus.", "misconception": "Confusing total binding energy with binding energy per nucleon"}, {"option_key": "D", "hint": "283 MeV is ten times too large. Check: 0.0304 × 931.5 ≈ 28.3 MeV, not 283 MeV.", "misconception": "Arithmetic error — misplacing the decimal point"}]}, "correct_answer": "C", "concept_tags": ["binding-energy", "mass-defect", "helium-nucleus", "numerical"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The binding energy per nucleon is maximum for nuclei in the vicinity of:", "explanation": "The binding energy per nucleon (BE/A) curve shows a maximum of about 8.75 MeV/nucleon near iron (A ≈ 56). This makes iron-56 one of the most stable nuclei. Lighter nuclei gain stability through fusion, while heavier nuclei gain stability through fission, both moving toward this peak.", "payload": {"question_id": "cuet-phy-nuclei-properties-07", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "Iron (A ≈ 56)", "is_correct": true}, {"key": "B", "text": "Uranium (A ≈ 238)", "is_correct": false}, {"key": "C", "text": "Helium (A = 4)", "is_correct": false}, {"key": "D", "text": "Hydrogen (A = 1)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Uranium has a lower BE/A (~7.6 MeV) than iron. Heavy nuclei beyond iron have decreasing BE/A, which is why fission of heavy nuclei releases energy.", "misconception": "Assuming the heaviest nuclei are the most stable"}, {"option_key": "C", "hint": "⁴He has an unusually high BE/A (~7.07 MeV) for its mass number but it is still less than that of iron (~8.75 MeV). ⁴He is a local peak, not the global maximum.", "misconception": "Confusing the local stability peak of He-4 with the overall maximum"}, {"option_key": "D", "hint": "Hydrogen (¹H) has no binding energy at all since it consists of only one proton — there is nothing to bind.", "misconception": "Not understanding that a single nucleon has zero binding energy"}]}, "correct_answer": "A", "concept_tags": ["binding-energy-per-nucleon", "nuclear-stability", "iron-56", "BE-curve"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the nucleus of ²⁷Al has a nuclear radius of approximately 3.6 fm, the nuclear radius of ¹²⁵Te is approximately:", "explanation": "Using R = R₀A^(1/3), R(Te)/R(Al) = (125/27)^(1/3) = 5/3. Therefore, R(Te) = (5/3) × 3.6 = 6.0 fm. We use the fact that 125^(1/3) = 5 and 27^(1/3) = 3.", "payload": {"question_id": "cuet-phy-nuclei-properties-08", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "16.7 fm", "is_correct": false}, {"key": "B", "text": "2.16 fm", "is_correct": false}, {"key": "C", "text": "10.0 fm", "is_correct": false}, {"key": "D", "text": "6.0 fm", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "16.7 fm results from using the ratio of mass numbers directly (3.6 × 125/27) instead of using the cube root relation R ∝ A^(1/3).", "misconception": "Assuming radius is directly proportional to mass number instead of A^(1/3)"}, {"option_key": "B", "hint": "2.16 fm is obtained by dividing instead of multiplying. Since Te has a larger A, its radius must be larger than Al''s radius of 3.6 fm.", "misconception": "Inverting the ratio — dividing by (5/3) instead of multiplying"}, {"option_key": "C", "hint": "10.0 fm is too large. The correct ratio is (125/27)^(1/3) = 5/3, giving 3.6 × 5/3 = 6.0 fm.", "misconception": "Using an incorrect cube root value"}]}, "correct_answer": "D", "concept_tags": ["nuclear-radius", "mass-number", "cube-root", "numerical"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following is NOT a property of nuclear forces?", "explanation": "Nuclear forces are charge-independent — they act equally between p-p, n-n, and p-n pairs. They are short-range (effective only up to ~few femtometres), strongly attractive, and saturated (each nucleon interacts only with its nearest neighbours). They are NOT long-range forces like gravity or electrostatic forces.", "payload": {"question_id": "cuet-phy-nuclei-properties-09", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "They are short-range forces", "is_correct": false}, {"key": "B", "text": "They obey the inverse square law", "is_correct": true}, {"key": "C", "text": "They are charge-independent", "is_correct": false}, {"key": "D", "text": "They show the property of saturation", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nuclear forces are indeed short-range, operating effectively within ~2–3 fm. This is a true property, so it cannot be the answer.", "misconception": null}, {"option_key": "C", "hint": "Nuclear forces are indeed charge-independent — the strong force between two protons equals that between two neutrons or a proton-neutron pair. This is a true property.", "misconception": null}, {"option_key": "D", "hint": "Saturation is a genuine property of nuclear forces meaning each nucleon interacts only with a limited number of neighbours. This explains why BE/A remains roughly constant.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["nuclear-forces", "short-range", "charge-independent", "saturation"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mass of a nucleus is always less than the sum of the masses of its constituent protons and neutrons. This difference in mass is called:", "explanation": "The mass defect (Δm) is the difference between the sum of masses of individual nucleons and the actual nuclear mass: Δm = [Zmₚ + (A − Z)mₙ] − M. This ''missing'' mass has been converted into binding energy (BE = Δm × c²) that holds the nucleus together.", "payload": {"question_id": "cuet-phy-nuclei-properties-10", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "Packing fraction", "is_correct": false}, {"key": "B", "text": "Binding energy", "is_correct": false}, {"key": "C", "text": "Mass defect", "is_correct": true}, {"key": "D", "text": "Mass excess", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Packing fraction is defined as (exact atomic mass − mass number)/mass number. It is related to but not the same as mass defect.", "misconception": "Confusing packing fraction with mass defect"}, {"option_key": "B", "hint": "Binding energy is the energy equivalent of the mass defect (BE = Δm × 931.5 MeV), not the mass difference itself.", "misconception": "Confusing the mass difference with its energy equivalent"}, {"option_key": "D", "hint": "Mass excess is defined as (atomic mass − A) in atomic mass units. It is a different quantity from mass defect.", "misconception": "Confusing mass excess with mass defect"}]}, "correct_answer": "C", "concept_tags": ["mass-defect", "binding-energy", "nucleons", "mass-energy-equivalence"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The masses of a proton, neutron, and the ¹⁶O nucleus are 1.00728 u, 1.00866 u, and 15.99053 u respectively. The binding energy per nucleon of ¹⁶O is approximately:", "explanation": "For ¹⁶O: Z = 8, A = 16, N = 8. Sum of masses = 8(1.00728) + 8(1.00866) = 8.05824 + 8.06928 = 16.12752 u. Mass defect Δm = 16.12752 − 15.99053 = 0.13699 u. Binding energy = 0.13699 × 931.5 = 127.6 MeV. BE per nucleon = 127.6/16 ≈ 7.97 MeV/nucleon.", "payload": {"question_id": "cuet-phy-nuclei-properties-11", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "7.97 MeV/nucleon", "is_correct": true}, {"key": "B", "text": "127.6 MeV/nucleon", "is_correct": false}, {"key": "C", "text": "0.137 MeV/nucleon", "is_correct": false}, {"key": "D", "text": "5.24 MeV/nucleon", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "127.6 MeV is the total binding energy of ¹⁶O, not the binding energy per nucleon. You must divide by A = 16 to get BE per nucleon.", "misconception": "Forgetting to divide total binding energy by the mass number"}, {"option_key": "C", "hint": "0.137 MeV/nucleon comes from dividing the mass defect in u by A without converting to MeV. You must multiply Δm by 931.5 MeV/u first.", "misconception": "Forgetting to convert mass defect from atomic mass units to MeV"}, {"option_key": "D", "hint": "5.24 MeV/nucleon does not match any correct calculation path. Recheck: Δm = 0.137 u → BE = 127.6 MeV → BE/A = 7.97 MeV.", "misconception": "Arithmetic error in computing sum of nucleon masses or mass defect"}]}, "correct_answer": "A", "concept_tags": ["binding-energy-per-nucleon", "mass-defect", "oxygen-16", "numerical-problem"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A nucleus has a radius of 3.6 fm. If the nuclear density is approximately 2.3 × 10¹⁷ kg/m³, the approximate mass number of this nucleus is:", "explanation": "Using R = R₀A^(1/3), A = (R/R₀)³ = (3.6/1.2)³ = (3)³ = 27. Alternatively, from density: mass = ρ × (4/3)πR³ and mass ≈ A × 1.66 × 10⁻²⁷ kg. Either way, A = 27, which corresponds to aluminium (²⁷Al).", "payload": {"question_id": "cuet-phy-nuclei-properties-12", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "8", "is_correct": false}, {"key": "B", "text": "27", "is_correct": true}, {"key": "C", "text": "64", "is_correct": false}, {"key": "D", "text": "125", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A = 8 gives R = 1.2 × 8^(1/3) = 1.2 × 2 = 2.4 fm, not 3.6 fm.", "misconception": "Incorrectly computing (R/R₀)³"}, {"option_key": "C", "hint": "A = 64 gives R = 1.2 × 64^(1/3) = 1.2 × 4 = 4.8 fm, which is larger than 3.6 fm.", "misconception": "Using R/R₀ = 4 instead of the correct value 3"}, {"option_key": "D", "hint": "A = 125 gives R = 1.2 × 125^(1/3) = 1.2 × 5 = 6.0 fm, much larger than 3.6 fm.", "misconception": "Using R/R₀ = 5 instead of the correct value 3"}]}, "correct_answer": "B", "concept_tags": ["nuclear-radius", "mass-number", "nuclear-density", "numerical-problem"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The density of nuclear matter is independent of the mass number A.\nReason (R): The nuclear radius is proportional to the cube root of the mass number, i.e., R = R₀A^(1/3).", "explanation": "Both A and R are correct, and R is the correct explanation of A. Since R ∝ A^(1/3), the nuclear volume V = (4/3)πR³ ∝ A. The nuclear mass is also proportional to A (mass ≈ A × u). Therefore, density ρ = mass/volume ∝ A/A = constant, independent of A. The R = R₀A^(1/3) relation directly leads to constant density.", "payload": {"question_id": "cuet-phy-nuclei-properties-13", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: the R ∝ A^(1/3) relation makes V ∝ A, and since mass ∝ A, density becomes independent of A. The reason is the correct explanation.", "misconception": "Failing to see the logical connection between R ∝ A^(1/3) and constant nuclear density"}, {"option_key": "C", "hint": "The reason R = R₀A^(1/3) is experimentally verified and is a well-established empirical formula. It is definitely correct.", "misconception": "Doubting the validity of the nuclear radius formula"}, {"option_key": "D", "hint": "The assertion is correct — nuclear density (~2.3 × 10¹⁷ kg/m³) is indeed the same for all nuclei regardless of mass number.", "misconception": "Incorrectly believing nuclear density varies with mass number"}]}, "correct_answer": "A", "concept_tags": ["nuclear-density", "nuclear-radius", "mass-number", "assertion-reasoning"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The binding energy per nucleon for ⁵⁶Fe is higher than that for ²³⁸U.\nReason (R): Nuclear forces obey the inverse square law similar to gravitational and electrostatic forces.", "explanation": "The assertion is correct — ⁵⁶Fe has the highest BE/A (~8.75 MeV) while ²³⁸U has a lower value (~7.6 MeV). However, the reason is incorrect — nuclear forces do NOT obey the inverse square law. Nuclear forces are short-range (effective only within ~2–3 fm) and do not follow any simple power law like 1/r².", "payload": {"question_id": "cuet-phy-nuclei-properties-14", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Even if both statements were correct, the inverse square law for nuclear forces would not explain why iron has the highest BE/A. But more importantly, the reason itself is factually wrong.", "misconception": "Incorrectly believing nuclear forces follow the inverse square law"}, {"option_key": "B", "hint": "The reason statement is factually incorrect — nuclear forces are short-range and do NOT obey the inverse square law. So option B cannot apply.", "misconception": "Accepting the inverse square law claim for nuclear forces as true"}, {"option_key": "D", "hint": "The assertion is correct — ⁵⁶Fe does have a higher BE/A than ²³⁸U. This is a well-known fact from the BE/A curve.", "misconception": "Not knowing the relative positions of Fe and U on the BE/A curve"}]}, "correct_answer": "C", "concept_tags": ["binding-energy-per-nucleon", "nuclear-forces", "iron-56", "uranium-238", "assertion-reasoning"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Isotopes\n(Q) Isobars\n(R) Isotones\n(S) Isomers\n\nColumn II:\n(1) Same mass number, different atomic number\n(2) Same atomic number, different mass number\n(3) Same neutron number, different atomic number\n(4) Same Z and A, different nuclear energy states", "explanation": "Isotopes have the same atomic number Z but different mass number A (P→2). Isobars have the same mass number A but different atomic number Z (Q→1). Isotones have the same neutron number N but different Z (R→3). Isomers have the same Z and A but exist in different excited nuclear energy states (S→4).", "payload": {"question_id": "cuet-phy-nuclei-properties-15", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "P→1, Q→2, R→3, S→4", "is_correct": false}, {"key": "B", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "C", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "D", "text": "P→2, Q→1, R→3, S→4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "P→1 means isotopes have the same mass number — this is wrong. Isotopes have the same atomic number (Z), not the same mass number. P should match with 2.", "misconception": "Confusing the definition of isotopes with isobars"}, {"option_key": "B", "hint": "R→4 implies isotones have different energy states — this is wrong. Isotones share the same neutron number. R should match with 3.", "misconception": "Confusing isotones with isomers"}, {"option_key": "C", "hint": "P→3 means isotopes have the same neutron number — this is wrong. Isotopes have the same atomic number (Z). P should match with 2.", "misconception": "Confusing isotopes with isotones"}]}, "correct_answer": "D", "concept_tags": ["isotopes", "isobars", "isotones", "isomers", "nuclear-terminology", "match-the-following"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Binding energy per nucleon of ²H\n(Q) Binding energy per nucleon of ⁴He\n(R) Binding energy per nucleon of ⁵⁶Fe\n(S) Binding energy per nucleon of ²³⁸U\n\nColumn II:\n(1) ~1.1 MeV\n(2) ~7.6 MeV\n(3) ~8.75 MeV\n(4) ~7.07 MeV", "explanation": "²H (deuteron) has BE/A ≈ 1.1 MeV (P→1), being the simplest bound nucleus. ⁴He has BE/A ≈ 7.07 MeV (Q→4), showing exceptional stability. ⁵⁶Fe has the highest BE/A ≈ 8.75 MeV (R→3), making it the most stable nucleus. ²³⁸U has BE/A ≈ 7.6 MeV (S→2), lower than iron due to greater Coulomb repulsion.", "payload": {"question_id": "cuet-phy-nuclei-properties-16", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→1, Q→4, R→2, S→3", "is_correct": false}, {"key": "B", "text": "P→1, Q→4, R→3, S→2", "is_correct": true}, {"key": "C", "text": "P→4, Q→1, R→3, S→2", "is_correct": false}, {"key": "D", "text": "P→1, Q→3, R→4, S→2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R→2 assigns 7.6 MeV to ⁵⁶Fe, but iron has the maximum BE/A (~8.75 MeV) on the curve. R should match with 3.", "misconception": "Not knowing that iron has the highest binding energy per nucleon"}, {"option_key": "C", "hint": "P→4 assigns ~7.07 MeV to deuterium, but ²H is the weakest bound nucleus with BE/A ≈ 1.1 MeV. P should match with 1.", "misconception": "Confusing deuterium''s BE/A with that of helium-4"}, {"option_key": "D", "hint": "Q→3 assigns ~8.75 MeV to ⁴He, but helium has BE/A ≈ 7.07 MeV. The maximum ~8.75 MeV belongs to ⁵⁶Fe.", "misconception": "Assigning the maximum BE/A to helium instead of iron"}]}, "correct_answer": "B", "concept_tags": ["binding-energy-per-nucleon", "BE-curve", "deuterium", "helium", "iron", "uranium", "match-the-following"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The nuclear force between two nucleons is independent of their electric charge.", "explanation": "This statement is TRUE. Nuclear forces are charge-independent, meaning the strong nuclear force between two protons, two neutrons, or a proton-neutron pair is essentially the same. This is a fundamental property of the strong nuclear interaction, confirmed by scattering experiments.", "payload": {"question_id": "cuet-phy-nuclei-properties-17", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Nuclear (strong) forces are indeed charge-independent. The nuclear force between p-p, n-n, and p-n pairs is the same. Do not confuse the nuclear force with the Coulomb force, which is charge-dependent.", "misconception": "Confusing nuclear force with electromagnetic force between protons"}]}, "correct_answer": "A", "concept_tags": ["nuclear-forces", "charge-independence", "true-false"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "The nuclear density increases with increasing mass number A.", "explanation": "This statement is FALSE. Nuclear density is approximately constant (~2.3 × 10¹⁷ kg/m³) for all nuclei, regardless of mass number. Since R = R₀A^(1/3), the volume V = (4/3)πR³ ∝ A, and mass ∝ A, so density ρ = mass/volume remains constant and is independent of A.", "payload": {"question_id": "cuet-phy-nuclei-properties-18", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nuclear density does NOT increase with A. Since volume ∝ A and mass ∝ A, the density remains constant. This is a direct consequence of R ∝ A^(1/3).", "misconception": "Assuming heavier nuclei are denser, similar to how denser elements exist in everyday life"}]}, "correct_answer": "B", "concept_tags": ["nuclear-density", "mass-number", "constant-density", "true-false"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The mass defect of a nucleus is defined as Δm = [Zmₚ + (A − Z)mₙ] − M. The binding energy of the nucleus is obtained by multiplying the mass defect by _____ MeV/u.", "explanation": "The binding energy is obtained by converting the mass defect from atomic mass units to energy using Einstein''s relation E = Δmc². The conversion factor is 1 u × c² = 931.5 MeV. Therefore, BE = Δm × 931.5 MeV/u. This factor comes from calculating (1.66054 × 10⁻²⁷ kg)(3 × 10⁸ m/s)² and converting joules to MeV.", "payload": {"question_id": "cuet-phy-nuclei-properties-19", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "1.5", "is_correct": false}, {"key": "B", "text": "93.15", "is_correct": false}, {"key": "C", "text": "931.5", "is_correct": true}, {"key": "D", "text": "9315", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.5 MeV/u is far too small. The correct conversion factor 1 u = 931.5 MeV/c² is a standard value that must be memorised.", "misconception": null}, {"option_key": "B", "hint": "93.15 is off by a factor of 10. The correct value is 931.5 MeV, not 93.15 MeV.", "misconception": "Misplacing the decimal point in the conversion factor"}, {"option_key": "D", "hint": "9315 is ten times too large. The standard conversion factor is 931.5 MeV per atomic mass unit.", "misconception": "Misplacing the decimal point in the conversion factor"}]}, "correct_answer": "C", "concept_tags": ["mass-defect", "binding-energy", "mass-energy-equivalence", "conversion-factor", "fill-in-blanks"]}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "In a nuclear physics laboratory, a researcher measures the mass of a ⁵⁶Fe nucleus to be 55.9207 u. Given that the mass of a proton is 1.00728 u and the mass of a neutron is 1.00866 u, and ⁵⁶Fe has Z = 26 and A = 56, the researcher wants to determine how tightly bound this nucleus is. What is the binding energy per nucleon of ⁵⁶Fe?", "explanation": "Step 1: Sum of nucleon masses = 26(1.00728) + 30(1.00866) = 26.18928 + 30.25980 = 56.44908 u.\nStep 2: Mass defect Δm = 56.44908 − 55.9207 = 0.52838 u.\nStep 3: Total binding energy = 0.52838 × 931.5 = 492.2 MeV.\nStep 4: BE per nucleon = 492.2/56 ≈ 8.79 MeV/nucleon.\nThis confirms that ⁵⁶Fe has one of the highest BE/A values, making it among the most stable nuclei.", "payload": {"question_id": "cuet-phy-nuclei-properties-20", "subtopic": "Nuclear Properties, Size, and Binding Energy", "topic_name": "Nuclear Properties, Size, and Binding Energy", "bloom_level": "evaluate", "options": [{"key": "A", "text": "492.2 MeV/nucleon", "is_correct": false}, {"key": "B", "text": "0.528 MeV/nucleon", "is_correct": false}, {"key": "C", "text": "18.93 MeV/nucleon", "is_correct": false}, {"key": "D", "text": "8.79 MeV/nucleon", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "492.2 MeV is the total binding energy of the ⁵⁶Fe nucleus, not the binding energy per nucleon. Divide by A = 56 to get BE/A.", "misconception": "Forgetting to divide total binding energy by the number of nucleons"}, {"option_key": "B", "hint": "0.528 MeV/nucleon results from dividing the mass defect in atomic mass units by A without converting to MeV. Multiply Δm by 931.5 first.", "misconception": "Forgetting to apply the 931.5 MeV/u conversion factor"}, {"option_key": "C", "hint": "18.93 MeV/nucleon is approximately twice the correct value. Recheck arithmetic: 492.2/56 ≈ 8.79, not 18.93.", "misconception": "Arithmetic error in the division step"}]}, "correct_answer": "D", "concept_tags": ["binding-energy-per-nucleon", "mass-defect", "iron-56", "numerical-problem", "scenario-based"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-4');

