SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A Wheatstone bridge is said to be balanced when the galvanometer shows:", "explanation": "A Wheatstone bridge is balanced when no current flows through the galvanometer, resulting in zero deflection (null reading). At this condition, the ratio of resistances in the two arms are equal: P/Q = R/S. The balanced condition makes the Wheatstone bridge a null method of measurement.", "payload": {"question_id": "cuet-phy-current-instruments-01", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "remember", "options": [{"key": "A", "text": "Zero deflection (null reading)", "is_correct": true}, {"key": "B", "text": "Maximum deflection", "is_correct": false}, {"key": "C", "text": "Half-scale deflection", "is_correct": false}, {"key": "D", "text": "Deflection proportional to the current", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Maximum deflection indicates maximum imbalance in the bridge. Balance means no current through the galvanometer and hence zero deflection.", "misconception": "Confusing balanced state with maximum sensitivity"}, {"option_key": "C", "hint": "Half-scale deflection is relevant to ammeter/voltmeter readings, not to the balanced condition of a Wheatstone bridge.", "misconception": null}, {"option_key": "D", "hint": "In a balanced bridge, no current flows through the galvanometer, so deflection proportional to current is not applicable.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["wheatstone-bridge", "balanced-condition", "galvanometer", "null-method"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The principle of a potentiometer is based on the fact that:", "explanation": "A potentiometer works on the principle that when a constant current flows through a wire of uniform cross-section, the potential difference across any length of the wire is directly proportional to that length (V = IR = I × ρl/A ∝ l for constant I). This makes it possible to compare EMFs without drawing current.", "payload": {"question_id": "cuet-phy-current-instruments-02", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "remember", "options": [{"key": "A", "text": "The resistance of the wire is inversely proportional to its length", "is_correct": false}, {"key": "B", "text": "The potential drop across a uniform wire is proportional to its length when a constant current flows", "is_correct": true}, {"key": "C", "text": "The EMF of a cell is proportional to the length of the wire", "is_correct": false}, {"key": "D", "text": "Current through the wire increases with its length", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Resistance is directly proportional to length (R = ρl/A), not inversely. This is a basic resistance formula, not the potentiometer principle.", "misconception": "Incorrectly stating the resistance-length relationship"}, {"option_key": "C", "hint": "EMF is a property of the cell, not the wire. The potentiometer relates the balancing length to the EMF, but EMF itself does not depend on wire length.", "misconception": "Confusing the measured quantity (EMF) with the wire property"}, {"option_key": "D", "hint": "For a potentiometer with a fixed driving cell, the current is constant throughout the wire and does not change with length.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["potentiometer", "principle", "potential-difference", "uniform-wire"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "To convert a galvanometer into an ammeter, one must connect:", "explanation": "A galvanometer is converted into an ammeter by connecting a low resistance (called a shunt) in parallel with it. The shunt diverts most of the current, allowing only a small fraction to pass through the sensitive galvanometer coil. The shunt value S = Ig × G/(I - Ig), where G is galvanometer resistance.", "payload": {"question_id": "cuet-phy-current-instruments-03", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "remember", "options": [{"key": "A", "text": "A high resistance in series", "is_correct": false}, {"key": "B", "text": "A high resistance in parallel", "is_correct": false}, {"key": "C", "text": "A low resistance in parallel", "is_correct": true}, {"key": "D", "text": "A low resistance in series", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A high resistance in series is used to convert a galvanometer into a voltmeter, not an ammeter.", "misconception": "Confusing ammeter and voltmeter conversion methods"}, {"option_key": "B", "hint": "A high resistance in parallel would not effectively bypass current around the galvanometer. The shunt must be of low resistance to carry most of the current.", "misconception": null}, {"option_key": "D", "hint": "A low resistance in series would slightly increase total resistance but would not protect the galvanometer from large currents like a parallel shunt does.", "misconception": "Confusing series and parallel connections for ammeter conversion"}]}, "correct_answer": "C", "concept_tags": ["galvanometer-conversion", "ammeter", "shunt-resistance", "parallel"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The balanced condition of a Wheatstone bridge with resistances P, Q, R, and S is:", "explanation": "In a Wheatstone bridge with four resistances P, Q, R, and S, the bridge is balanced (no current through galvanometer) when P/Q = R/S, or equivalently PS = QR. This condition is derived by applying Kirchhoff''s laws to the bridge circuit with the galvanometer current set to zero.", "payload": {"question_id": "cuet-phy-current-instruments-04", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "remember", "options": [{"key": "A", "text": "P/Q = S/R", "is_correct": false}, {"key": "B", "text": "P + Q = R + S", "is_correct": false}, {"key": "C", "text": "PQ = RS", "is_correct": false}, {"key": "D", "text": "P/Q = R/S", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "P/Q = S/R means PS = Q × something different. The correct condition is P/Q = R/S (not S/R). The order of R and S matters.", "misconception": "Swapping R and S in the balance condition"}, {"option_key": "B", "hint": "P + Q = R + S is not the balance condition. The bridge balances when ratios are equal (P/Q = R/S), not when sums are equal.", "misconception": "Thinking balance requires sum equality rather than ratio equality"}, {"option_key": "C", "hint": "PQ = RS involves the product of adjacent arms. The correct condition involves the ratio of adjacent arms: P/Q = R/S, or equivalently PS = QR.", "misconception": "Using wrong product combination"}]}, "correct_answer": "D", "concept_tags": ["wheatstone-bridge", "balanced-condition", "resistance-ratio"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a metre bridge, the balance point is obtained at 40 cm from the left end. If the known resistance in the right gap is 15 Ω, the unknown resistance in the left gap is:", "explanation": "In a metre bridge, at balance: X/R = l/(100 - l), where l is the balance length from the end where X is connected. Here X/15 = 40/(100 - 40) = 40/60 = 2/3. Therefore X = 15 × 2/3 = 10 Ω. The metre bridge is essentially a practical form of the Wheatstone bridge.", "payload": {"question_id": "cuet-phy-current-instruments-05", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "apply", "options": [{"key": "A", "text": "6 Ω", "is_correct": false}, {"key": "B", "text": "10 Ω", "is_correct": true}, {"key": "C", "text": "22.5 Ω", "is_correct": false}, {"key": "D", "text": "25 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 Ω results from using X/R = (100-l)/l² or another incorrect formula. The correct formula gives X = R × l/(100-l) = 15 × 40/60 = 10 Ω.", "misconception": null}, {"option_key": "C", "hint": "22.5 Ω results from using X = R × (100-l)/l = 15 × 60/40, which reverses the balance condition.", "misconception": "Inverting the metre bridge balance formula"}, {"option_key": "D", "hint": "25 Ω would result from an arithmetic error. X = 15 × (40/60) = 15 × 2/3 = 10 Ω.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["metre-bridge", "balance-point", "unknown-resistance", "wheatstone-bridge"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 Ω and gives full-scale deflection for a current of 1 mA. To convert it into a voltmeter of range 0–10 V, the resistance to be connected in series is:", "explanation": "For a voltmeter, V = Ig(G + R), where Ig is the full-scale deflection current, G is galvanometer resistance, and R is the series resistance. So R = V/Ig - G = 10/(1 × 10⁻³) - 50 = 10000 - 50 = 9950 Ω. A high series resistance limits current through the galvanometer.", "payload": {"question_id": "cuet-phy-current-instruments-06", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "apply", "options": [{"key": "A", "text": "10000 Ω", "is_correct": false}, {"key": "B", "text": "9900 Ω", "is_correct": false}, {"key": "C", "text": "9950 Ω", "is_correct": true}, {"key": "D", "text": "50 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10000 Ω = V/Ig does not account for the galvanometer''s own resistance of 50 Ω. R = V/Ig - G = 10000 - 50 = 9950 Ω.", "misconception": "Forgetting to subtract galvanometer resistance"}, {"option_key": "B", "hint": "9900 Ω would result from using G = 100 Ω instead of 50 Ω, or from a calculation error. R = 10000 - 50 = 9950 Ω.", "misconception": null}, {"option_key": "D", "hint": "50 Ω is the galvanometer resistance itself. The series resistance needed is much larger (9950 Ω) to limit current to 1 mA at 10 V.", "misconception": "Confusing the series resistance with galvanometer resistance"}]}, "correct_answer": "C", "concept_tags": ["galvanometer-to-voltmeter", "series-resistance", "full-scale-deflection"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A potentiometer wire of length 100 cm has a potential drop of 1 V across it. The balancing length for a cell of EMF 0.4 V is:", "explanation": "The potential gradient k = V/L = 1/100 = 0.01 V/cm. For balance, E = kl, so l = E/k = 0.4/0.01 = 40 cm. At the balance point, the potential drop across length l equals the EMF of the cell, and no current is drawn from the cell being measured.", "payload": {"question_id": "cuet-phy-current-instruments-07", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "apply", "options": [{"key": "A", "text": "40 cm", "is_correct": true}, {"key": "B", "text": "60 cm", "is_correct": false}, {"key": "C", "text": "25 cm", "is_correct": false}, {"key": "D", "text": "4 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "60 cm would correspond to an EMF of 0.6 V (60 × 0.01), not 0.4 V. The balancing length for 0.4 V is 40 cm.", "misconception": null}, {"option_key": "C", "hint": "25 cm would correspond to an EMF of 0.25 V. For 0.4 V, l = 0.4/(1/100) = 40 cm.", "misconception": null}, {"option_key": "D", "hint": "4 cm would result from using potential gradient as 0.1 V/cm instead of 0.01 V/cm. k = 1 V / 100 cm = 0.01 V/cm.", "misconception": "Error in calculating the potential gradient"}]}, "correct_answer": "A", "concept_tags": ["potentiometer", "balancing-length", "potential-gradient", "EMF"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer of resistance 100 Ω gives full-scale deflection at a current of 2 mA. To convert it into an ammeter of range 0–2 A, the shunt resistance required is:", "explanation": "Shunt resistance S = IgG/(I - Ig) = (2 × 10⁻³ × 100)/(2 - 0.002) = 0.2/1.998 ≈ 0.1 Ω. Since I >> Ig, we can approximate S ≈ IgG/I = 0.2/2 = 0.1 Ω. The low shunt resistance ensures most of the current bypasses the galvanometer.", "payload": {"question_id": "cuet-phy-current-instruments-08", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "apply", "options": [{"key": "A", "text": "100 Ω", "is_correct": false}, {"key": "B", "text": "1 Ω", "is_correct": false}, {"key": "C", "text": "0.01 Ω", "is_correct": false}, {"key": "D", "text": "0.1 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "100 Ω equals the galvanometer resistance and would only divide the current equally. The shunt must be much smaller to carry nearly all of the 2 A.", "misconception": "Thinking shunt should equal galvanometer resistance"}, {"option_key": "B", "hint": "1 Ω would carry about 100/101 of the total current but is 10 times too large. S = 0.002 × 100/2 ≈ 0.1 Ω.", "misconception": null}, {"option_key": "C", "hint": "0.01 Ω is too small. This would convert the galvanometer to a 20 A range ammeter, not 2 A.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["galvanometer-to-ammeter", "shunt-resistance", "full-scale-deflection"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a potentiometer experiment, two cells of EMF E₁ and E₂ give balancing lengths l₁ and l₂ respectively. The ratio E₁/E₂ is:", "explanation": "In a potentiometer, at the balance point, E = kl where k is the potential gradient (constant for a given setup). For cell 1: E₁ = kl₁, and for cell 2: E₂ = kl₂. Dividing: E₁/E₂ = l₁/l₂. This is the standard method for comparing EMFs using a potentiometer without drawing any current from the cells.", "payload": {"question_id": "cuet-phy-current-instruments-09", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "understand", "options": [{"key": "A", "text": "l₂/l₁", "is_correct": false}, {"key": "B", "text": "l₁/l₂", "is_correct": true}, {"key": "C", "text": "(l₁ + l₂)/(l₁ − l₂)", "is_correct": false}, {"key": "D", "text": "l₁ × l₂", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "l₂/l₁ = E₂/E₁, which is the inverse of what is asked. E₁/E₂ = l₁/l₂, not l₂/l₁.", "misconception": "Inverting the ratio"}, {"option_key": "C", "hint": "(l₁ + l₂)/(l₁ - l₂) is not the correct relation. The comparison formula is simply E₁/E₂ = l₁/l₂.", "misconception": "Confusing with sum-difference formulas used in other experiments"}, {"option_key": "D", "hint": "l₁ × l₂ is a product with units of cm², which cannot equal a dimensionless ratio like E₁/E₂.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["potentiometer", "comparison-of-EMFs", "balancing-length"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An ideal voltmeter has:", "explanation": "An ideal voltmeter should have infinite resistance so that when connected across a circuit element, it draws no current and does not disturb the circuit. This ensures that the voltmeter measures the true potential difference. In practice, voltmeters have very high but finite resistance.", "payload": {"question_id": "cuet-phy-current-instruments-10", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "understand", "options": [{"key": "A", "text": "Zero resistance", "is_correct": false}, {"key": "B", "text": "Low resistance", "is_correct": false}, {"key": "C", "text": "Infinite resistance", "is_correct": true}, {"key": "D", "text": "Resistance equal to the circuit resistance", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero resistance describes an ideal ammeter, not a voltmeter. A voltmeter with zero resistance would short-circuit the element.", "misconception": "Confusing ideal ammeter and voltmeter characteristics"}, {"option_key": "B", "hint": "Low resistance in a voltmeter would draw significant current, altering the circuit and giving an incorrect reading.", "misconception": null}, {"option_key": "D", "hint": "If the voltmeter resistance equals the circuit resistance, it would draw as much current as the circuit element and significantly disturb the measurement.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["voltmeter", "ideal-instrument", "resistance", "measurement"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a potentiometer experiment to measure the internal resistance of a cell, the balancing length without any external resistance is l₁ and with an external resistance R in the cell circuit it is l₂. The internal resistance of the cell is:", "explanation": "Without external resistance: E = kl₁. With external resistance R: V = kl₂, where V = ER/(R + r) is the terminal voltage. So E/V = l₁/l₂ = (R + r)/R. Solving: r = R(l₁ - l₂)/l₂. This method gives accurate results because the potentiometer draws no current at balance.", "payload": {"question_id": "cuet-phy-current-instruments-11", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "analyze", "options": [{"key": "A", "text": "R(l₁ − l₂)/l₂", "is_correct": true}, {"key": "B", "text": "R(l₁ − l₂)/l₁", "is_correct": false}, {"key": "C", "text": "Rl₂/(l₁ − l₂)", "is_correct": false}, {"key": "D", "text": "R(l₁ + l₂)/l₂", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R(l₁ - l₂)/l₁ incorrectly places l₁ in the denominator. The correct derivation gives l₂ in the denominator: r = R(l₁/l₂ - 1) = R(l₁ - l₂)/l₂.", "misconception": "Swapping l₁ and l₂ in the denominator"}, {"option_key": "C", "hint": "Rl₂/(l₁ - l₂) is the inverse of the correct expression. Since l₁/l₂ = (R + r)/R, solving for r gives r = R(l₁ - l₂)/l₂.", "misconception": "Inverting the expression during derivation"}, {"option_key": "D", "hint": "R(l₁ + l₂)/l₂ uses addition instead of subtraction. The correct formula involves l₁ - l₂ since l₁ > l₂ (EMF > terminal voltage).", "misconception": "Using addition instead of subtraction of balancing lengths"}]}, "correct_answer": "A", "concept_tags": ["potentiometer", "internal-resistance", "balancing-length", "cell"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a Wheatstone bridge, P = 100 Ω, Q = 1000 Ω, R = 40 Ω, and S = 400 Ω. If the galvanometer and battery are interchanged, the bridge will:", "explanation": "The balance condition P/Q = R/S gives 100/1000 = 1/10 and 40/400 = 1/10. Since P/Q = R/S, the bridge is balanced. Interchanging the galvanometer and battery does not affect the balance condition of a Wheatstone bridge. The balance depends only on the resistance ratios, which remain unchanged.", "payload": {"question_id": "cuet-phy-current-instruments-12", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Become unbalanced", "is_correct": false}, {"key": "B", "text": "Remain balanced", "is_correct": true}, {"key": "C", "text": "Show reduced sensitivity", "is_correct": false}, {"key": "D", "text": "Require different resistance values for balance", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The balance condition P/Q = R/S depends only on resistance values, not on the positions of galvanometer and battery. Interchanging them does not affect balance.", "misconception": "Thinking the balance depends on the position of the galvanometer"}, {"option_key": "C", "hint": "While sensitivity may change after interchange, the question asks about balance. The bridge remains balanced since P/Q = R/S still holds.", "misconception": "Confusing sensitivity with balance condition"}, {"option_key": "D", "hint": "The balance condition is a property of the four resistances only. No different values are needed since P/Q = R/S = 1/10 remains true.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["wheatstone-bridge", "balanced-condition", "galvanometer-battery-interchange"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): A potentiometer is preferred over a voltmeter for measuring the EMF of a cell.\nReason (R): A potentiometer draws no current from the cell at the balance point.", "explanation": "Both statements are correct, and R is the correct explanation of A. A voltmeter draws a small current, so it measures terminal voltage (V = E - Ir), not true EMF. A potentiometer, at balance, draws zero current from the cell (null method), so it measures the true EMF. This zero-current condition makes the potentiometer ideal for EMF measurement.", "payload": {"question_id": "cuet-phy-current-instruments-13", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Drawing no current is exactly why the potentiometer gives true EMF (no Ir drop). This is a direct cause-and-effect, making R the correct explanation of A.", "misconception": "Not recognizing that zero current directly explains the accuracy of EMF measurement"}, {"option_key": "C", "hint": "The reason is correct. At the balance point of a potentiometer, no current flows through the cell being tested, as the galvanometer reads zero.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. Potentiometers give more accurate EMF readings than voltmeters because they use a null method.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["potentiometer", "voltmeter", "EMF-measurement", "null-method"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): An ammeter is always connected in series with the circuit element through which current is to be measured.\nReason (R): An ammeter has very high resistance so that it does not alter the current in the circuit.", "explanation": "The assertion is correct: an ammeter must be connected in series so that the same current that flows through the element also flows through the ammeter. However, the reason is incorrect: an ammeter has very LOW resistance (ideally zero), not high resistance. If it had high resistance, it would significantly reduce the current being measured. The low resistance ensures minimal disturbance to the circuit.", "payload": {"question_id": "cuet-phy-current-instruments-14", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The reason is factually wrong: an ammeter has very LOW resistance, not high resistance. Therefore, A and B are both eliminated.", "misconception": "Thinking ammeters have high resistance"}, {"option_key": "B", "hint": "Since the reason is incorrect (ammeter has low resistance, not high), this option is also wrong.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. An ammeter must be in series to measure the current flowing through a component. Series connection ensures the same current passes through both.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["ammeter", "series-connection", "low-resistance", "measurement"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the instruments (Column-I) with their key characteristics (Column-II):\n\nColumn-I:\nA. Ammeter\nB. Voltmeter\nC. Potentiometer\nD. Galvanometer\n\nColumn-II:\n1. Measures EMF accurately using null method\n2. Connected in series; has low resistance\n3. Detects small currents; shows deflection\n4. Connected in parallel; has high resistance", "explanation": "An ammeter is connected in series and has low resistance (A→2). A voltmeter is connected in parallel and has high resistance (B→4). A potentiometer uses the null method to measure EMF accurately (C→1). A galvanometer is a sensitive device that detects small currents (D→3).", "payload": {"question_id": "cuet-phy-current-instruments-15", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "understand", "options": [{"key": "A", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "C", "text": "A-1, B-3, C-4, D-2", "is_correct": false}, {"key": "D", "text": "A-2, B-4, C-1, D-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This assigns high resistance/parallel (4) to ammeter and low resistance/series (2) to voltmeter, which is exactly reversed.", "misconception": "Swapping ammeter and voltmeter properties"}, {"option_key": "B", "hint": "This assigns galvanometer to null method (1) and potentiometer to detecting small currents (3). The potentiometer uses the null method, not the galvanometer.", "misconception": "Confusing potentiometer and galvanometer functions"}, {"option_key": "C", "hint": "This scrambles all matchings. Ammeter is connected in series (2), not null method (1).", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["ammeter", "voltmeter", "potentiometer", "galvanometer", "characteristics"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the following potentiometer applications (Column-I) with the relevant formula (Column-II):\n\nColumn-I:\nA. EMF of a cell\nB. Comparison of two EMFs\nC. Internal resistance of a cell\nD. Potential gradient of the wire\n\nColumn-II:\n1. k = V/L (V across wire, L is total length)\n2. E = kl (k = potential gradient, l = balancing length)\n3. r = R(l₁ − l₂)/l₂\n4. E₁/E₂ = l₁/l₂", "explanation": "EMF of a cell is found using E = kl (A→2). Comparison of EMFs uses E₁/E₂ = l₁/l₂ (B→4). Internal resistance of a cell is given by r = R(l₁ - l₂)/l₂ (C→3). Potential gradient is k = V/L (D→1). These are the fundamental formulas for all standard potentiometer experiments.", "payload": {"question_id": "cuet-phy-current-instruments-16", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-4, C-3, D-2", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": true}, {"key": "C", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "D", "text": "A-3, B-1, C-2, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns the potential gradient formula (k = V/L) to EMF measurement, but EMF is found using E = kl (2), not k = V/L (1).", "misconception": "Confusing the potential gradient formula with the EMF measurement formula"}, {"option_key": "C", "hint": "This assigns E₁/E₂ = l₁/l₂ to EMF of a single cell, but that formula is for comparing two EMFs, not measuring one.", "misconception": null}, {"option_key": "D", "hint": "This completely scrambles the matchings, assigning the internal resistance formula to EMF measurement and vice versa.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["potentiometer", "EMF", "internal-resistance", "potential-gradient", "comparison"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "A metre bridge is a practical form of the Wheatstone bridge.", "explanation": "This statement is TRUE. A metre bridge (also called a slide-wire bridge) is a practical implementation of the Wheatstone bridge. It uses a 1-metre uniform resistance wire to form two arms of the bridge, and the jockey can be slid along the wire to find the balance point. The ratio of wire lengths gives the ratio of resistances.", "payload": {"question_id": "cuet-phy-current-instruments-17", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A metre bridge is indeed a practical form of the Wheatstone bridge. It uses the same balance condition (P/Q = R/S) with a uniform wire replacing two resistance arms.", "misconception": "Not recognizing that the metre bridge is based on Wheatstone bridge principle"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["metre-bridge", "wheatstone-bridge", "practical-form"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "A voltmeter should be connected in series with the circuit element to measure the potential difference across it.", "explanation": "This statement is FALSE. A voltmeter must be connected in parallel (not series) with the circuit element across which the potential difference is to be measured. Parallel connection ensures the voltmeter measures the same potential difference as the element. If connected in series, it would measure something entirely different and disrupt the circuit.", "payload": {"question_id": "cuet-phy-current-instruments-18", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A voltmeter is always connected in parallel, not series. Series connection is for an ammeter. A voltmeter in series would have very high resistance and nearly stop the current.", "misconception": "Confusing voltmeter (parallel) and ammeter (series) connections"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["voltmeter", "parallel-connection", "measurement", "potential-difference"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_blanks", "difficulty": "medium", "question_text": "The sensitivity of a potentiometer can be increased by _____ the length of the potentiometer wire.", "explanation": "The sensitivity of a potentiometer is increased by increasing the length of the wire. A longer wire means a smaller potential gradient (k = V/L), so a given EMF corresponds to a larger balancing length. This larger balancing length can be measured more precisely, improving the sensitivity of the measurement. Hence, longer wires allow detection of smaller differences in EMF.", "payload": {"question_id": "cuet-phy-current-instruments-19", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "understand", "options": [{"key": "A", "text": "Decreasing", "is_correct": false}, {"key": "B", "text": "Halving", "is_correct": false}, {"key": "C", "text": "Increasing", "is_correct": true}, {"key": "D", "text": "Not changing", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Decreasing the wire length increases the potential gradient, which reduces the balancing length and makes it harder to measure precisely, thus decreasing sensitivity.", "misconception": "Thinking shorter wire improves sensitivity"}, {"option_key": "B", "hint": "Halving the wire length would double the potential gradient and reduce sensitivity, not increase it.", "misconception": null}, {"option_key": "D", "hint": "If the length is unchanged, the sensitivity remains the same. To improve sensitivity, the length must be increased.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["potentiometer", "sensitivity", "wire-length", "potential-gradient"]}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "medium", "question_text": "A student uses a metre bridge to find an unknown resistance X. She places a standard resistance of 10 Ω in the right gap and the unknown resistance X in the left gap. The balance point is obtained at the 33.3 cm mark from the left end. She then swaps the resistances (X in right gap, 10 Ω in left gap) and finds the new balance point.\n\nWhere will the new balance point be located?", "explanation": "First measurement: X/10 = 33.3/(100 - 33.3) = 33.3/66.7 ≈ 1/2, so X ≈ 5 Ω. When resistances are swapped: 10/5 = l/(100 - l), giving 2(100 - l) = l, so 200 = 3l, hence l = 66.7 cm from the left end. Swapping the resistances causes the balance point to shift to the complementary position (100 - 33.3 = 66.7 cm).", "payload": {"question_id": "cuet-phy-current-instruments-20", "subtopic": "Wheatstone Bridge, Potentiometer, and Meters", "topic_name": "Wheatstone Bridge, Potentiometer, and Meters", "bloom_level": "apply", "options": [{"key": "A", "text": "33.3 cm from the left end", "is_correct": false}, {"key": "B", "text": "50 cm from the left end", "is_correct": false}, {"key": "C", "text": "25 cm from the left end", "is_correct": false}, {"key": "D", "text": "66.7 cm from the left end", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "33.3 cm was the original balance point. When resistances are swapped, the ratio inverts, and the balance point shifts to the complementary position at 66.7 cm.", "misconception": "Thinking swapping resistances does not change the balance point"}, {"option_key": "B", "hint": "50 cm would be the balance point only if both resistances were equal. Here X ≈ 5 Ω and R = 10 Ω, so they are unequal.", "misconception": "Assuming the balance point always moves to the midpoint"}, {"option_key": "C", "hint": "25 cm does not satisfy the balance condition for the swapped configuration. The new balance length = 100 - 33.3 = 66.7 cm.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["metre-bridge", "balance-point", "swapping-resistances", "unknown-resistance"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-5');

