SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The de Broglie wavelength associated with a particle of mass m moving with velocity v is given by:", "explanation": "According to de Broglie''s hypothesis, every moving particle has an associated wave whose wavelength is given by λ = h/p = h/(mv), where h is Planck''s constant, m is the mass, and v is the velocity of the particle. This relation connects the wave and particle properties of matter.", "payload": {"question_id": "cuet-phy-dual-debroglie-01", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "remember", "options": [{"key": "A", "text": "h/(mv)", "is_correct": true}, {"key": "B", "text": "hv/m", "is_correct": false}, {"key": "C", "text": "mh/v", "is_correct": false}, {"key": "D", "text": "mv/h", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This expression has dimensions of J·s·(m/s)/kg = m³/s², which is not the dimension of wavelength (m).", "misconception": "Incorrectly rearranging the de Broglie relation"}, {"option_key": "C", "hint": "Dimensionally mh/v gives kg·J·s/(m/s) = kg²·m, which is not a length unit.", "misconception": "Confusing which quantities appear in numerator and denominator"}, {"option_key": "D", "hint": "mv/h is the reciprocal of the correct answer. The wavelength is inversely proportional to momentum, not directly proportional.", "misconception": "Inverting the de Broglie formula"}]}, "correct_answer": "A", "concept_tags": ["de-broglie-wavelength", "matter-waves", "wave-particle-duality"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In the Davisson-Germer experiment, the wave nature of electrons was confirmed by observing:", "explanation": "The Davisson-Germer experiment directed a beam of electrons at a nickel crystal and observed a strong diffraction peak at a specific angle. This electron diffraction pattern confirmed that electrons exhibit wave-like behaviour, as predicted by de Broglie''s hypothesis. The diffraction pattern could only be explained by treating electrons as waves.", "payload": {"question_id": "cuet-phy-dual-debroglie-02", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "remember", "options": [{"key": "A", "text": "Photoelectric emission from the nickel surface", "is_correct": false}, {"key": "B", "text": "Interference of X-rays scattered by electrons", "is_correct": false}, {"key": "C", "text": "Diffraction of electrons by a nickel crystal", "is_correct": true}, {"key": "D", "text": "Compton scattering of electrons", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Photoelectric emission demonstrates the particle nature of light, not the wave nature of electrons.", "misconception": "Confusing photoelectric effect with electron diffraction"}, {"option_key": "B", "hint": "The Davisson-Germer experiment used electrons, not X-rays, as the incident beam on the crystal.", "misconception": "Confusing electron diffraction with X-ray diffraction"}, {"option_key": "D", "hint": "Compton scattering involves photons scattering off electrons and demonstrates the particle nature of electromagnetic radiation, not the wave nature of electrons.", "misconception": "Mixing up Compton effect with Davisson-Germer experiment"}]}, "correct_answer": "C", "concept_tags": ["davisson-germer-experiment", "electron-diffraction", "wave-nature-of-electrons"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The de Broglie wavelength of an electron accelerated through a potential difference V (in volts) is approximately:", "explanation": "When an electron is accelerated through a potential difference V, its kinetic energy equals eV. Using λ = h/√(2meV) and substituting the values of h, m, and e, we get λ = 1.227/√V nm. This is a standard result frequently used in NEET problems involving electron de Broglie wavelength.", "payload": {"question_id": "cuet-phy-dual-debroglie-03", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "remember", "options": [{"key": "A", "text": "1.227/V nm", "is_correct": false}, {"key": "B", "text": "1.227/√V nm", "is_correct": true}, {"key": "C", "text": "1.227 × √V nm", "is_correct": false}, {"key": "D", "text": "1.227 × V nm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The wavelength depends on 1/√V, not 1/V, because kinetic energy is proportional to V and λ ∝ 1/√(KE).", "misconception": "Forgetting the square root in the relation between λ and V"}, {"option_key": "C", "hint": "Wavelength decreases with increasing potential difference; this option suggests wavelength increases with V.", "misconception": "Inverting the relationship between λ and V"}, {"option_key": "D", "hint": "This would mean wavelength increases with voltage, which contradicts the fact that higher voltage gives higher momentum and shorter wavelength.", "misconception": "Completely reversing the proportionality"}]}, "correct_answer": "B", "concept_tags": ["de-broglie-wavelength", "accelerating-potential", "electron"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following has the largest de Broglie wavelength if all are moving with the same velocity?", "explanation": "The de Broglie wavelength is given by λ = h/(mv). For the same velocity, the particle with the smallest mass will have the largest de Broglie wavelength. Among the given options, an electron has the smallest mass (9.1 × 10⁻³¹ kg), which is much less than a proton (1.67 × 10⁻²⁷ kg), a neutron (1.67 × 10⁻²⁷ kg), or an alpha particle (6.64 × 10⁻²⁷ kg). Hence the electron has the largest wavelength.", "payload": {"question_id": "cuet-phy-dual-debroglie-04", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "understand", "options": [{"key": "A", "text": "Proton", "is_correct": false}, {"key": "B", "text": "Neutron", "is_correct": false}, {"key": "C", "text": "Alpha particle", "is_correct": false}, {"key": "D", "text": "Electron", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A proton has a mass about 1836 times that of an electron, giving it a much smaller wavelength at the same speed.", "misconception": null}, {"option_key": "B", "hint": "A neutron has nearly the same mass as a proton and is much heavier than an electron.", "misconception": null}, {"option_key": "C", "hint": "An alpha particle has a mass about 4 times that of a proton and roughly 7300 times that of an electron, so its wavelength is the smallest.", "misconception": "Thinking heavier particles have longer wavelengths"}]}, "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "mass-dependence", "comparison"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron and a proton are accelerated through the same potential difference. The ratio of their de Broglie wavelengths (λ_e/λ_p) is:", "explanation": "When a charged particle is accelerated through potential difference V, its KE = qV. Since both electron and proton have the same charge magnitude, KE_e = KE_p = eV. Using λ = h/√(2mKE), the ratio λ_e/λ_p = √(m_p/m_e). Since m_p/m_e ≈ 1836, λ_e/λ_p = √1836 ≈ 42.8. The electron has a much larger wavelength because of its smaller mass.", "payload": {"question_id": "cuet-phy-dual-debroglie-05", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "apply", "options": [{"key": "A", "text": "√(m_p/m_e)", "is_correct": true}, {"key": "B", "text": "√(m_e/m_p)", "is_correct": false}, {"key": "C", "text": "m_p/m_e", "is_correct": false}, {"key": "D", "text": "m_e/m_p", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This would give a ratio less than 1, meaning the electron has a shorter wavelength than the proton, which contradicts the fact that lighter particles have longer wavelengths at same KE.", "misconception": "Inverting the mass ratio in the wavelength formula"}, {"option_key": "C", "hint": "The ratio involves the square root of the mass ratio because λ ∝ 1/√m at constant kinetic energy, not 1/m.", "misconception": "Forgetting the square root dependence"}, {"option_key": "D", "hint": "This gives a very small number, implying the electron wavelength is negligible compared to the proton''s, which is the opposite of reality.", "misconception": "Confusing which mass goes in the numerator"}]}, "correct_answer": "A", "concept_tags": ["de-broglie-wavelength", "electron-proton-comparison", "accelerating-potential"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The de Broglie wavelength of an electron accelerated through a potential difference of 100 V is approximately:", "explanation": "Using the formula λ = 1.227/√V nm, where V = 100 V: λ = 1.227/√100 = 1.227/10 = 0.1227 nm ≈ 0.123 nm. This wavelength is comparable to inter-atomic distances, which is why electron beams can be diffracted by crystals.", "payload": {"question_id": "cuet-phy-dual-debroglie-06", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "apply", "options": [{"key": "A", "text": "0.0123 nm", "is_correct": false}, {"key": "B", "text": "0.123 nm", "is_correct": true}, {"key": "C", "text": "1.23 nm", "is_correct": false}, {"key": "D", "text": "12.3 nm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This corresponds to V = 10000 V. For V = 100 V, the wavelength is larger since λ ∝ 1/√V.", "misconception": "Using V instead of √V in the calculation"}, {"option_key": "C", "hint": "This would correspond to V = 1 V. Check: 1.227/√1 = 1.227 nm ≈ 1.23 nm. For V = 100 V, the wavelength is 10 times smaller.", "misconception": "Not taking the square root of V"}, {"option_key": "D", "hint": "This value is far too large for an electron accelerated through 100 V. Such a long wavelength would correspond to an extremely low voltage.", "misconception": "Order of magnitude error in calculation"}]}, "correct_answer": "B", "concept_tags": ["de-broglie-wavelength", "numerical-calculation", "accelerating-potential"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the kinetic energy of a particle is doubled, its de Broglie wavelength becomes:", "explanation": "The de Broglie wavelength is λ = h/√(2mKE). If KE is doubled, λ'' = h/√(2m × 2KE) = h/(√2 × √(2mKE)) = λ/√2. Therefore, the wavelength becomes 1/√2 times the original wavelength.", "payload": {"question_id": "cuet-phy-dual-debroglie-07", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "apply", "options": [{"key": "A", "text": "Doubled", "is_correct": false}, {"key": "B", "text": "Halved", "is_correct": false}, {"key": "C", "text": "1/√2 times", "is_correct": true}, {"key": "D", "text": "√2 times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Wavelength is inversely related to momentum. Doubling KE increases momentum, so wavelength must decrease, not double.", "misconception": "Thinking wavelength is directly proportional to kinetic energy"}, {"option_key": "B", "hint": "Halving would require KE to be quadrupled, not doubled, since λ ∝ 1/√(KE).", "misconception": "Assuming λ ∝ 1/KE instead of λ ∝ 1/√(KE)"}, {"option_key": "D", "hint": "This would mean wavelength increases when KE increases, contradicting the inverse relationship λ ∝ 1/√(KE).", "misconception": "Reversing the relationship between wavelength and kinetic energy"}]}, "correct_answer": "C", "concept_tags": ["de-broglie-wavelength", "kinetic-energy", "proportionality"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The de Broglie wavelength associated with a gas molecule of mass m at temperature T is given by (k is Boltzmann constant):", "explanation": "For a gas molecule at temperature T, the average kinetic energy is (3/2)kT. Using the de Broglie relation λ = h/√(2mKE) = h/√(2m × (3/2)kT) = h/√(3mkT). This expression connects the thermal energy of gas molecules with their wave-like properties.", "payload": {"question_id": "cuet-phy-dual-debroglie-08", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "apply", "options": [{"key": "A", "text": "h/√(2mkT)", "is_correct": false}, {"key": "B", "text": "h/√(mkT)", "is_correct": false}, {"key": "C", "text": "h × √(3mkT)", "is_correct": false}, {"key": "D", "text": "h/√(3mkT)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This expression uses KE = kT instead of (3/2)kT. The factor of 3 in the denominator comes from using the correct average KE of a gas molecule.", "misconception": "Using KE = kT instead of (3/2)kT for average kinetic energy"}, {"option_key": "B", "hint": "This formula omits the factor of 3 from the average kinetic energy (3/2)kT and also misses the factor of 2 from the momentum-energy relation.", "misconception": "Incorrect substitution of kinetic energy in the de Broglie formula"}, {"option_key": "C", "hint": "Planck''s constant must be divided by the square root term, not multiplied. Wavelength decreases with increasing temperature.", "misconception": "Inverting the de Broglie relation"}]}, "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "thermal-wavelength", "kinetic-theory"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the Davisson-Germer experiment, the maximum intensity of diffracted electrons was observed at an accelerating voltage of 54 V and a scattering angle of 50°. The experimental de Broglie wavelength of the electron is closest to:", "explanation": "Using the formula λ = 1.227/√V nm: λ = 1.227/√54 = 1.227/7.35 ≈ 0.167 nm = 1.67 Å. This value agreed closely with the wavelength calculated from the Bragg diffraction condition using the known lattice spacing of nickel crystal (d = 0.91 Å), providing strong confirmation of de Broglie''s hypothesis.", "payload": {"question_id": "cuet-phy-dual-debroglie-09", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "apply", "options": [{"key": "A", "text": "0.567 Å", "is_correct": false}, {"key": "B", "text": "1.00 Å", "is_correct": false}, {"key": "C", "text": "1.67 Å", "is_correct": true}, {"key": "D", "text": "2.67 Å", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value is too small. It would correspond to an accelerating voltage of about 467 V, not 54 V.", "misconception": "Calculation error in applying the formula"}, {"option_key": "B", "hint": "λ = 1.227/√54 ≈ 1.227/7.35 ≈ 0.167 nm = 1.67 Å, not 1.00 Å.", "misconception": "Rounding errors or incorrect square root calculation"}, {"option_key": "D", "hint": "This would correspond to √V ≈ 4.6, i.e., V ≈ 21 V, which is not the 54 V used in the experiment.", "misconception": "Arithmetic error in division"}]}, "correct_answer": "C", "concept_tags": ["davisson-germer-experiment", "de-broglie-wavelength", "numerical-calculation"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An electron and a photon have the same de Broglie wavelength λ. If p_e and p_ph denote their momenta and E_e and E_ph denote their energies respectively, then which of the following is correct?", "explanation": "Since both have the same wavelength λ, their momenta are equal: p_e = p_ph = h/λ. For the electron, E_e = p²/(2m_e). For the photon, E_ph = pc = hc/λ. Since p_e = p_ph, but their energy-momentum relations differ (E = p²/2m for electron vs E = pc for photon), their energies are different. Specifically, E_e/E_ph = p/(2m_e c), which is less than 1 for typical wavelengths, so E_e < E_ph.", "payload": {"question_id": "cuet-phy-dual-debroglie-10", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "analyze", "options": [{"key": "A", "text": "p_e = p_ph but E_e ≠ E_ph", "is_correct": true}, {"key": "B", "text": "p_e ≠ p_ph but E_e = E_ph", "is_correct": false}, {"key": "C", "text": "p_e = p_ph and E_e = E_ph", "is_correct": false}, {"key": "D", "text": "p_e/p_ph = E_e/E_ph", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Since both have the same wavelength, by p = h/λ their momenta must be equal. Their energies differ because the energy-momentum relation is different for massive and massless particles.", "misconception": "Thinking that same wavelength means same energy"}, {"option_key": "C", "hint": "While momenta are equal (both given by h/λ), the energy of an electron is p²/(2m) while that of a photon is pc. These are not the same.", "misconception": "Assuming identical wave properties imply identical particle properties"}, {"option_key": "D", "hint": "Since p_e = p_ph, the ratio p_e/p_ph = 1. But E_e/E_ph = p/(2m_e c) ≠ 1 in general.", "misconception": "Assuming proportionality between momentum ratio and energy ratio"}]}, "correct_answer": "A", "concept_tags": ["photon-vs-matter-wave", "momentum", "energy-comparison"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton and an alpha particle are accelerated through the same potential difference. The ratio of the de Broglie wavelengths associated with the proton to the alpha particle (λ_p/λ_α) is:", "explanation": "For a charged particle accelerated through potential difference V, KE = qV. So λ = h/√(2m·qV). For a proton: mass = m, charge = e. For an alpha particle: mass = 4m, charge = 2e. Therefore λ_p/λ_α = √(m_α × q_α)/(m_p × q_p)) = √((4m × 2e)/(m × e)) = √8 = 2√2.", "payload": {"question_id": "cuet-phy-dual-debroglie-11", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 : 2", "is_correct": false}, {"key": "B", "text": "2 : 1", "is_correct": false}, {"key": "C", "text": "1 : 2√2", "is_correct": false}, {"key": "D", "text": "2√2 : 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This ignores the charge difference. The alpha particle has charge 2e and mass 4m. Both must be accounted for in the KE = qV relation.", "misconception": "Only considering mass ratio and ignoring charge"}, {"option_key": "B", "hint": "The ratio should account for both mass and charge differences. λ ∝ 1/√(mq), so the lighter particle with smaller charge has a longer wavelength.", "misconception": "Partially correct reasoning but missing charge factor"}, {"option_key": "C", "hint": "This is the inverse of the correct ratio. The proton, being lighter and having smaller charge, has the longer wavelength.", "misconception": "Inverting the ratio"}]}, "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "proton-alpha-comparison", "accelerating-potential"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron microscope uses electrons accelerated through a potential of 10000 V. The resolving power of this microscope is high because the de Broglie wavelength of the electrons is approximately:", "explanation": "Using λ = 1.227/√V nm = 1.227/√10000 = 1.227/100 = 0.01227 nm ≈ 0.0123 nm = 0.123 Å. This wavelength is much smaller than that of visible light (400-700 nm), which is why electron microscopes can resolve much finer details than optical microscopes.", "payload": {"question_id": "cuet-phy-dual-debroglie-12", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "apply", "options": [{"key": "A", "text": "12.3 nm", "is_correct": false}, {"key": "B", "text": "1.23 nm", "is_correct": false}, {"key": "C", "text": "0.0123 nm", "is_correct": true}, {"key": "D", "text": "0.00123 nm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "12.3 nm corresponds to V ≈ 0.01 V. For V = 10000 V, the wavelength is much smaller.", "misconception": "Forgetting to take the square root of V"}, {"option_key": "B", "hint": "1.23 nm corresponds to V ≈ 1 V. Check: 1.227/√1 = 1.227 nm ≈ 1.23 nm.", "misconception": "Using V = 1 instead of V = 10000"}, {"option_key": "D", "hint": "This would correspond to V ≈ 10⁶ V, which is 100 times the given voltage.", "misconception": "Calculation error with powers of 10"}]}, "correct_answer": "C", "concept_tags": ["electron-microscope", "de-broglie-wavelength", "resolving-power"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): The Davisson-Germer experiment provided direct experimental evidence for the wave nature of electrons.\nReason (R): In this experiment, electrons were diffracted by a nickel crystal, and the measured wavelength agreed with the de Broglie relation λ = h/(mv).", "explanation": "Both the Assertion and Reason are correct. The Davisson-Germer experiment demonstrated electron diffraction from a nickel crystal surface. The wavelength measured from the diffraction pattern (using Bragg''s law) agreed closely with the value predicted by the de Broglie relation, thus confirming the wave nature of electrons. The Reason correctly explains why the Assertion is true.", "payload": {"question_id": "cuet-phy-dual-debroglie-13", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion — the diffraction of electrons and agreement with de Broglie''s formula is precisely what constituted the evidence for the wave nature of electrons.", "misconception": "Thinking the reason is unrelated to the assertion"}, {"option_key": "C", "hint": "The reason accurately describes what happened in the Davisson-Germer experiment. Electrons were indeed diffracted by nickel crystal, and the wavelength matched de Broglie''s prediction.", "misconception": "Doubting the factual accuracy of the reason"}, {"option_key": "D", "hint": "The assertion is historically and scientifically correct — the Davisson-Germer experiment is the landmark experiment that confirmed electron wave nature.", "misconception": "Questioning the significance of the Davisson-Germer experiment"}]}, "correct_answer": "A", "concept_tags": ["davisson-germer-experiment", "wave-nature-of-electrons", "de-broglie-hypothesis"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): A heavier particle always has a smaller de Broglie wavelength than a lighter particle.\nReason (R): The de Broglie wavelength is given by λ = h/p, where p is the momentum of the particle.", "explanation": "The Assertion is incorrect. A heavier particle does NOT always have a smaller de Broglie wavelength. The wavelength depends on momentum (p = mv), not mass alone. A heavy particle moving very slowly can have a smaller momentum (and hence larger wavelength) than a light particle moving very fast. The Reason is correct — λ = h/p is the de Broglie relation. However, since the Assertion is wrong, option D applies.", "payload": {"question_id": "cuet-phy-dual-debroglie-14", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The assertion is not always true. A slow-moving heavy particle can have a larger wavelength than a fast-moving light particle. Wavelength depends on momentum, not mass alone.", "misconception": "Thinking wavelength depends only on mass"}, {"option_key": "B", "hint": "The assertion is incorrect. Consider a heavy particle at rest (λ → ∞) versus a fast-moving light particle (small λ). Mass alone does not determine wavelength.", "misconception": "Partially accepting an incorrect assertion"}, {"option_key": "C", "hint": "The reason λ = h/p is the correct de Broglie relation. It is a fundamental formula in quantum mechanics.", "misconception": "Doubting the de Broglie formula"}]}, "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "momentum", "mass-velocity-dependence"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) de Broglie wavelength in terms of momentum\n(Q) de Broglie wavelength in terms of KE\n(R) de Broglie wavelength of electron (V in volts)\n(S) de Broglie wavelength in terms of temperature\n\nColumn II:\n(1) h/√(3mkT)\n(2) 1.227/√V nm\n(3) h/p\n(4) h/√(2mKE)", "explanation": "P → 3: The fundamental de Broglie relation is λ = h/p. Q → 4: Since p = √(2mKE), λ = h/√(2mKE). R → 2: Substituting electron mass and charge values, λ = 1.227/√V nm. S → 1: Using average KE = (3/2)kT, λ = h/√(3mkT). The correct matching is P-3, Q-4, R-2, S-1.", "payload": {"question_id": "cuet-phy-dual-debroglie-15", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "understand", "options": [{"key": "A", "text": "P-3, Q-1, R-2, S-4", "is_correct": false}, {"key": "B", "text": "P-3, Q-4, R-2, S-1", "is_correct": true}, {"key": "C", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}, {"key": "D", "text": "P-2, Q-4, R-3, S-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly matches Q with the temperature formula and S with the KE formula. Q should match with h/√(2mKE) and S with h/√(3mkT).", "misconception": "Swapping kinetic energy and temperature formulae"}, {"option_key": "C", "hint": "P is the most basic form λ = h/p which matches (3), not (4). Also R is the electron-specific formula which matches (2), not (1).", "misconception": "Confusing the basic momentum formula with the KE formula"}, {"option_key": "D", "hint": "P matches the fundamental relation λ = h/p = (3), not the electron-specific formula (2). R is the electron-specific result matching (2), not (3).", "misconception": "Swapping the fundamental and electron-specific formulae"}]}, "correct_answer": "B", "concept_tags": ["de-broglie-wavelength", "formulas", "matching"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Davisson-Germer experiment\n(Q) Heisenberg''s uncertainty principle\n(R) Electron microscope\n(S) Photoelectric effect\n\nColumn II:\n(1) Δx · Δp ≥ h/(4π)\n(2) Confirms wave nature of electrons experimentally\n(3) Uses small de Broglie wavelength of electrons for high resolution\n(4) Demonstrates particle nature of light", "explanation": "P → 2: The Davisson-Germer experiment confirmed the wave nature of electrons through electron diffraction by nickel crystal. Q → 1: Heisenberg''s uncertainty principle states Δx · Δp ≥ ℏ/2 = h/(4π). R → 3: Electron microscopes exploit the very small de Broglie wavelength of high-energy electrons to achieve resolution far superior to optical microscopes. S → 4: The photoelectric effect demonstrates the particle nature of light (photons).", "payload": {"question_id": "cuet-phy-dual-debroglie-16", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-3, R-1, S-4", "is_correct": false}, {"key": "B", "text": "P-4, Q-1, R-3, S-2", "is_correct": false}, {"key": "C", "text": "P-2, Q-1, R-3, S-4", "is_correct": true}, {"key": "D", "text": "P-3, Q-1, R-2, S-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps Q and R. The uncertainty principle is Δx · Δp ≥ h/(4π), which is (1), not (3). The electron microscope uses small wavelengths for resolution, which is (3), not (1).", "misconception": "Confusing the uncertainty principle with the electron microscope principle"}, {"option_key": "B", "hint": "The Davisson-Germer experiment confirms wave nature of electrons (2), not particle nature of light (4). The photoelectric effect demonstrates particle nature of light.", "misconception": "Confusing wave nature of electrons with particle nature of light"}, {"option_key": "D", "hint": "P is about electron diffraction confirming wave nature (2), not about using small wavelength for resolution (3). R uses de Broglie wavelength for resolution (3), not confirming wave nature (2).", "misconception": "Swapping the Davisson-Germer experiment with the electron microscope"}]}, "correct_answer": "C", "concept_tags": ["davisson-germer-experiment", "uncertainty-principle", "electron-microscope", "photoelectric-effect"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The de Broglie wavelength of a moving particle is inversely proportional to its momentum.", "explanation": "This statement is TRUE. According to the de Broglie relation, λ = h/p, the wavelength is inversely proportional to the momentum p. As the momentum of a particle increases, its associated de Broglie wavelength decreases. This is a direct consequence of de Broglie''s hypothesis connecting wave and particle properties.", "payload": {"question_id": "cuet-phy-dual-debroglie-17", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The de Broglie relation λ = h/p clearly shows that wavelength and momentum are inversely related. This is a fundamental and correct relationship.", "misconception": "Misunderstanding the de Broglie relation"}, {"option_key": "C", "hint": "This option is not applicable.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["de-broglie-wavelength", "momentum", "inverse-proportionality"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The de Broglie wavelength of a cricket ball moving at 30 m/s is easily observable and measurable in daily life.", "explanation": "This statement is FALSE. For a cricket ball (mass ≈ 0.16 kg) moving at 30 m/s, λ = h/(mv) = 6.63 × 10⁻³⁴/(0.16 × 30) ≈ 1.38 × 10⁻³⁴ m. This is an incredibly small wavelength — far smaller than any known physical dimension — and is completely undetectable by any instrument. The wave nature of macroscopic objects is negligible, which is why wave-particle duality is only significant at the atomic and subatomic scale.", "payload": {"question_id": "cuet-phy-dual-debroglie-18", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Calculate: λ = 6.63 × 10⁻³⁴/(0.16 × 30) ≈ 10⁻³⁴ m. This is about 10⁻¹⁹ times smaller than a proton. Such wavelengths cannot be observed.", "misconception": "Thinking wave nature is significant for macroscopic objects"}, {"option_key": "C", "hint": "This option is not applicable.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["de-broglie-wavelength", "macroscopic-objects", "wave-particle-duality"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_the_blanks", "difficulty": "medium", "question_text": "According to Heisenberg''s uncertainty principle, the product of the uncertainty in position (Δx) and the uncertainty in momentum (Δp) of a particle is always greater than or equal to _____.", "explanation": "Heisenberg''s uncertainty principle states that Δx · Δp ≥ ℏ/2 = h/(4π), where ℏ = h/(2π) is the reduced Planck constant. This means it is fundamentally impossible to simultaneously measure both the exact position and exact momentum of a particle. The product of their uncertainties has a lower bound of h/(4π) ≈ 5.27 × 10⁻³⁵ J·s.", "payload": {"question_id": "cuet-phy-dual-debroglie-19", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "remember", "options": [{"key": "A", "text": "h/(2π)", "is_correct": false}, {"key": "B", "text": "h/(4π)", "is_correct": true}, {"key": "C", "text": "h", "is_correct": false}, {"key": "D", "text": "h/(8π)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "h/(2π) is ℏ (h-bar). The uncertainty principle states Δx · Δp ≥ ℏ/2, which equals h/(4π), not h/(2π).", "misconception": "Confusing ℏ with ℏ/2"}, {"option_key": "C", "hint": "Using the full Planck constant h overestimates the minimum uncertainty product by a factor of 4π.", "misconception": "Omitting the 4π factor"}, {"option_key": "D", "hint": "h/(8π) is too small. The correct minimum is h/(4π) = ℏ/2.", "misconception": "Adding an extra factor of 2 in the denominator"}]}, "correct_answer": "B", "concept_tags": ["heisenberg-uncertainty-principle", "position", "momentum"]}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "medium", "question_text": "A physics laboratory has an electron gun that can accelerate electrons through adjustable potential differences. A researcher needs to study the crystal structure of a sample with inter-atomic spacing of approximately 2.5 Å. For the electrons to be effectively diffracted by this crystal, the de Broglie wavelength of the electrons should be comparable to the inter-atomic spacing. The potential difference through which the electrons should be accelerated is approximately:", "explanation": "For effective diffraction, we need λ ≈ 2.5 Å = 0.25 nm. Using the formula λ = 1.227/√V nm: 0.25 = 1.227/√V, so √V = 1.227/0.25 = 4.908, hence V = (4.908)² ≈ 24.1 V ≈ 24 V. This demonstrates the practical application of the de Broglie wavelength concept — electrons accelerated through modest potential differences have wavelengths comparable to crystal lattice spacings, making them ideal probes for crystal structure analysis.", "payload": {"question_id": "cuet-phy-dual-debroglie-20", "subtopic": "de Broglie Wavelength and Davisson-Germer Experiment", "topic_name": "de Broglie Wavelength and Davisson-Germer Experiment", "bloom_level": "apply", "options": [{"key": "A", "text": "2.4 V", "is_correct": false}, {"key": "B", "text": "54 V", "is_correct": false}, {"key": "C", "text": "100 V", "is_correct": false}, {"key": "D", "text": "24 V", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "At 2.4 V, λ = 1.227/√2.4 ≈ 0.79 nm = 7.9 Å, which is much larger than the required 2.5 Å.", "misconception": "Confusing V with √V in the formula"}, {"option_key": "B", "hint": "At 54 V, λ = 1.227/√54 ≈ 0.167 nm = 1.67 Å. This is too small compared to the required 2.5 Å spacing.", "misconception": "Remembering the Davisson-Germer voltage without calculating for the given spacing"}, {"option_key": "C", "hint": "At 100 V, λ = 1.227/√100 = 0.123 nm = 1.23 Å, which is about half the required wavelength.", "misconception": "Overestimating the required voltage"}]}, "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "electron-diffraction", "crystal-structure", "numerical-calculation"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-8');

