SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a half-wave rectifier, the output frequency is equal to:", "explanation": "In a half-wave rectifier, only one half (positive or negative) of the input AC signal passes through the diode per cycle. Therefore, for each complete cycle of the input, there is one pulse in the output. The output frequency equals the input frequency. If the input AC has frequency f, the output also has frequency f.", "payload": {"question_id": "cuet-phy-semi-diode-01", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "remember", "options": [{"key": "A", "text": "The input frequency f", "is_correct": true}, {"key": "B", "text": "Twice the input frequency (2f)", "is_correct": false}, {"key": "C", "text": "Half the input frequency (f/2)", "is_correct": false}, {"key": "D", "text": "Zero (pure DC)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "An output frequency of 2f occurs in a full-wave rectifier, not a half-wave rectifier. In a full-wave rectifier both halves of the cycle produce output pulses.", "misconception": "Confusing half-wave rectifier output frequency with that of a full-wave rectifier"}, {"option_key": "C", "hint": "Half the input frequency would mean one output pulse every two input cycles, which does not happen. Each input cycle produces exactly one output pulse.", "misconception": "Incorrectly halving the frequency for a half-wave rectifier"}, {"option_key": "D", "hint": "The output of a rectifier is pulsating DC, not pure DC. It still has a ripple at a definite frequency. Only after ideal filtering does it approach pure DC.", "misconception": "Confusing pulsating DC with pure DC"}]}, "correct_answer": "A", "concept_tags": ["half-wave-rectifier", "output-frequency", "rectification"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A Zener diode is primarily used as:", "explanation": "A Zener diode is specifically designed to operate in the reverse breakdown region at a well-defined voltage called the Zener voltage. When reverse biased beyond this voltage, it maintains an almost constant voltage across its terminals regardless of current variations. This property makes it ideal for voltage regulation in electronic circuits.", "payload": {"question_id": "cuet-phy-semi-diode-02", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "remember", "options": [{"key": "A", "text": "An amplifier", "is_correct": false}, {"key": "B", "text": "A voltage regulator", "is_correct": true}, {"key": "C", "text": "A current amplifier", "is_correct": false}, {"key": "D", "text": "A rectifier in power supplies", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Amplification requires active devices like transistors that can provide power gain. A Zener diode is a two-terminal passive device used for voltage stabilisation, not amplification.", "misconception": "Confusing voltage regulation with amplification"}, {"option_key": "C", "hint": "Current amplification is a property of transistors (defined by current gain beta). A Zener diode regulates voltage, not current.", "misconception": "Attributing transistor properties to a diode"}, {"option_key": "D", "hint": "Ordinary p-n junction diodes are used as rectifiers. A Zener diode is specially designed for the reverse breakdown region to regulate voltage, not for rectification.", "misconception": "Confusing the function of a Zener diode with that of a rectifier diode"}]}, "correct_answer": "B", "concept_tags": ["zener-diode", "voltage-regulation", "reverse-breakdown"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a full-wave rectifier using two diodes with a centre-tapped transformer, if the input AC frequency is 50 Hz, the ripple frequency of the output is:", "explanation": "In a full-wave rectifier, both halves of the AC input cycle are rectified. During the positive half-cycle, one diode conducts, and during the negative half-cycle, the other diode conducts. This produces two output pulses for every one complete input cycle. Therefore, the ripple frequency is twice the input frequency: 2 x 50 = 100 Hz.", "payload": {"question_id": "cuet-phy-semi-diode-03", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "25 Hz", "is_correct": false}, {"key": "B", "text": "50 Hz", "is_correct": false}, {"key": "C", "text": "100 Hz", "is_correct": true}, {"key": "D", "text": "200 Hz", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "25 Hz is half the input frequency. The ripple frequency in a full-wave rectifier is always greater than the input frequency, not less.", "misconception": "Incorrectly halving the frequency instead of doubling it"}, {"option_key": "B", "hint": "50 Hz is the ripple frequency for a half-wave rectifier (same as input frequency). A full-wave rectifier produces two pulses per cycle, so the ripple frequency is doubled.", "misconception": "Confusing half-wave and full-wave rectifier output frequencies"}, {"option_key": "D", "hint": "200 Hz would be four times the input frequency. A full-wave rectifier produces exactly two output pulses per input cycle, giving 2f = 100 Hz.", "misconception": "Incorrectly multiplying the frequency by a factor of 4"}]}, "correct_answer": "C", "concept_tags": ["full-wave-rectifier", "ripple-frequency", "centre-tapped-transformer"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "An LED (Light Emitting Diode) emits light when it is:", "explanation": "An LED emits light when it is forward biased. Under forward bias, electrons from the n-side and holes from the p-side are injected across the junction. When these minority carriers recombine with majority carriers, the energy is released in the form of photons (light). The wavelength (colour) of light depends on the band gap of the semiconductor material used.", "payload": {"question_id": "cuet-phy-semi-diode-04", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "remember", "options": [{"key": "A", "text": "Reverse biased", "is_correct": false}, {"key": "B", "text": "Unbiased", "is_correct": false}, {"key": "C", "text": "At breakdown voltage", "is_correct": false}, {"key": "D", "text": "Forward biased", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Under reverse bias, the depletion region widens and very little current flows. Reverse bias is used for photodiodes, not LEDs. LEDs require forward bias for electron-hole recombination.", "misconception": "Confusing LED operation with photodiode operation"}, {"option_key": "B", "hint": "In the unbiased condition, there is no net current flow and hence no significant carrier injection or recombination. Light emission requires carrier recombination driven by forward current.", "misconception": "Thinking that a diode can emit light without external bias"}, {"option_key": "C", "hint": "Breakdown voltage applies to reverse-biased operation (as in Zener diodes). Operating an LED at breakdown would likely damage it, and the mechanism is entirely different from light emission.", "misconception": "Confusing Zener breakdown operation with LED light emission"}]}, "correct_answer": "D", "concept_tags": ["LED", "forward-bias", "recombination", "photon-emission"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A photodiode is operated under reverse bias because:", "explanation": "When a photodiode is reverse biased, the depletion region is widened. This is advantageous because light-generated electron-hole pairs in the depletion region are quickly swept to opposite sides by the strong electric field, producing a measurable photocurrent. The wide depletion region also increases the volume where photon absorption can contribute to the current, and the fast carrier sweep leads to a quick response time. The reverse bias ensures that even a small change in light intensity produces a detectable change in current.", "payload": {"question_id": "cuet-phy-semi-diode-05", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "It increases the forward current significantly", "is_correct": false}, {"key": "B", "text": "It narrows the depletion layer for better absorption", "is_correct": false}, {"key": "C", "text": "It causes the diode to emit light", "is_correct": false}, {"key": "D", "text": "It widens the depletion layer, increasing the sensitivity to light and making the change in current easily measurable", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Reverse bias does not increase forward current. In reverse bias, only a small reverse saturation current flows, which changes with light intensity. This is the detection mechanism.", "misconception": "Confusing forward and reverse bias current behaviour"}, {"option_key": "B", "hint": "Reverse bias widens (not narrows) the depletion layer. A wider depletion region exposes a larger volume to incident photons, increasing the detection sensitivity.", "misconception": "Incorrectly thinking reverse bias narrows the depletion region"}, {"option_key": "C", "hint": "Light emission occurs in forward-biased LEDs through electron-hole recombination. A photodiode under reverse bias detects light; it does not emit light.", "misconception": "Confusing photodiode (light detection) with LED (light emission)"}]}, "correct_answer": "D", "concept_tags": ["photodiode", "reverse-bias", "depletion-region", "photocurrent"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a Zener diode voltage regulator circuit, if the input voltage increases while the load resistance remains constant, then:", "explanation": "In a Zener regulator circuit, a series resistance is connected between the input and the Zener diode (which is in parallel with the load). When the input voltage increases, the Zener diode maintains a constant voltage across itself (equal to the Zener voltage). The excess voltage appears across the series resistance. To accommodate the increased input voltage at constant output voltage, the current through the series resistance increases. Since the load voltage (equal to Zener voltage) and load resistance remain constant, the load current stays the same, and the extra current flows through the Zener diode.", "payload": {"question_id": "cuet-phy-semi-diode-06", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "analyze", "options": [{"key": "A", "text": "The voltage across the load remains constant and the current through the Zener diode increases", "is_correct": true}, {"key": "B", "text": "The voltage across the load increases proportionally", "is_correct": false}, {"key": "C", "text": "The current through the Zener diode decreases", "is_correct": false}, {"key": "D", "text": "The Zener diode stops conducting", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The entire purpose of a Zener regulator is to maintain a constant output voltage. The Zener diode clamps the voltage at V_Z regardless of input voltage variations (within design limits).", "misconception": "Not understanding the voltage-clamping action of a Zener diode"}, {"option_key": "C", "hint": "When input voltage increases, the total current from the source increases. Since load current is constant (constant V_Z and R_L), the excess current must flow through the Zener diode, so its current increases, not decreases.", "misconception": "Incorrectly analysing current distribution in a Zener regulator circuit"}, {"option_key": "D", "hint": "The Zener diode continues to conduct in the breakdown region as long as the input voltage exceeds V_Z. An increase in input voltage keeps it well within the conducting range.", "misconception": "Confusing increased input voltage with loss of Zener conduction"}]}, "correct_answer": "A", "concept_tags": ["zener-diode", "voltage-regulator", "series-resistance", "load-current"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The colour of light emitted by an LED depends on:", "explanation": "The colour (wavelength) of light emitted by an LED is determined by the band gap energy (E_g) of the semiconductor material. When electrons recombine with holes across the junction, photons are emitted with energy approximately equal to the band gap: E = hc/lambda = E_g. Different semiconductor materials have different band gaps, producing different colours. For example, GaAs emits infrared, GaAsP emits red/yellow, and GaN emits blue light.", "payload": {"question_id": "cuet-phy-semi-diode-07", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "The forward current through the LED", "is_correct": false}, {"key": "B", "text": "The reverse bias voltage applied", "is_correct": false}, {"key": "C", "text": "The band gap of the semiconductor material used", "is_correct": true}, {"key": "D", "text": "The doping concentration of the semiconductor", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Increasing forward current increases the intensity (brightness) of the emitted light but does not change its colour. The wavelength is determined by the energy gap, not the current magnitude.", "misconception": "Confusing light intensity with light wavelength/colour"}, {"option_key": "B", "hint": "LEDs operate under forward bias, not reverse bias. Furthermore, the colour is an intrinsic property of the semiconductor material''s band gap, not of the applied voltage.", "misconception": "Incorrectly associating reverse bias with LED operation and colour"}, {"option_key": "D", "hint": "While doping affects conductivity and the Fermi level position, the emitted photon energy is primarily determined by the band gap energy of the host semiconductor material, not the doping concentration.", "misconception": "Confusing doping effects on conductivity with band gap energy determining emission wavelength"}]}, "correct_answer": "C", "concept_tags": ["LED", "band-gap", "wavelength", "semiconductor-materials"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solar cell is based on the photovoltaic effect. It works most efficiently when made from a semiconductor whose band gap is approximately:", "explanation": "A solar cell converts sunlight directly into electricity. The solar spectrum peaks in the visible region (around 1.5 eV photon energy). If the band gap is too small, the output voltage will be low and excess photon energy is wasted as heat. If the band gap is too large, most solar photons will not have enough energy to create electron-hole pairs. The optimal band gap for maximum efficiency (Shockley-Queisser limit) is approximately 1.5 eV, which corresponds to materials like GaAs (1.43 eV) and is close to CdTe (1.44 eV).", "payload": {"question_id": "cuet-phy-semi-diode-08", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "0.1 eV", "is_correct": false}, {"key": "B", "text": "1.5 eV", "is_correct": true}, {"key": "C", "text": "5.0 eV", "is_correct": false}, {"key": "D", "text": "10.0 eV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A band gap of 0.1 eV is far too small. While most solar photons would be absorbed, the output voltage would be extremely low and most photon energy would be lost as heat, resulting in very poor efficiency.", "misconception": "Thinking a smaller band gap always means better solar cell performance"}, {"option_key": "C", "hint": "A 5.0 eV band gap corresponds to ultraviolet photon energies. Most visible and infrared solar photons (which carry the bulk of solar energy) would not have enough energy to generate electron-hole pairs.", "misconception": "Not relating the band gap to the solar spectrum distribution"}, {"option_key": "D", "hint": "10.0 eV is in the deep UV range. Essentially no solar photons reaching Earth''s surface have this energy, so such a material would produce virtually no photocurrent.", "misconception": "Not understanding the relationship between band gap and useful solar absorption"}]}, "correct_answer": "B", "concept_tags": ["solar-cell", "photovoltaic-effect", "band-gap", "efficiency"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a Zener diode regulator circuit, the Zener voltage is 6 V, the series resistance is 200 ohm, the load resistance is 1 kohm, and the unregulated input voltage varies from 10 V to 16 V. The minimum and maximum currents through the Zener diode are respectively:", "explanation": "The load current I_L = V_Z / R_L = 6/1000 = 6 mA (constant since V_Z and R_L are constant). At minimum input voltage (10 V): Total current I_S = (V_in - V_Z)/R_S = (10 - 6)/200 = 4/200 = 20 mA. Zener current I_Z = I_S - I_L = 20 - 6 = 14 mA. At maximum input voltage (16 V): I_S = (16 - 6)/200 = 10/200 = 50 mA. Zener current I_Z = 50 - 6 = 44 mA. Therefore, minimum I_Z = 14 mA and maximum I_Z = 44 mA.", "payload": {"question_id": "cuet-phy-semi-diode-09", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "apply", "options": [{"key": "A", "text": "6 mA and 20 mA", "is_correct": false}, {"key": "B", "text": "20 mA and 50 mA", "is_correct": false}, {"key": "C", "text": "10 mA and 40 mA", "is_correct": false}, {"key": "D", "text": "14 mA and 44 mA", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "6 mA is the load current, not the Zener current. The Zener current is the difference between the total series current and the load current: I_Z = I_S - I_L.", "misconception": "Confusing load current with Zener diode current"}, {"option_key": "B", "hint": "20 mA and 50 mA are the total currents through the series resistance at 10 V and 16 V inputs respectively. You must subtract the load current (6 mA) to get the Zener current.", "misconception": "Forgetting to subtract the load current from the total series current"}, {"option_key": "C", "hint": "Check the calculation: I_S(min) = (10-6)/200 = 20 mA, not 16 mA. The Zener current is 20 - 6 = 14 mA, not 10 mA.", "misconception": "Arithmetic error in computing the series current"}]}, "correct_answer": "D", "concept_tags": ["zener-diode", "voltage-regulator", "numerical", "series-resistance", "current-calculation"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a full-wave rectifier circuit using a centre-tapped transformer, the peak voltage across each half of the secondary winding is V_m. If the diodes are ideal, the peak inverse voltage (PIV) that each diode must withstand is:", "explanation": "In a centre-tapped full-wave rectifier, when one diode (say D1) is conducting, the full voltage of that half-secondary (V_m) appears across the load. The non-conducting diode (D2) has its cathode at +V_m (the output voltage across the load) and its anode at -V_m (the voltage of the other half-secondary, which is in the opposite phase). Therefore, the reverse voltage across the non-conducting diode is V_m + V_m = 2V_m. This is the peak inverse voltage each diode must withstand.", "payload": {"question_id": "cuet-phy-semi-diode-10", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "analyze", "options": [{"key": "A", "text": "V_m / 2", "is_correct": false}, {"key": "B", "text": "V_m", "is_correct": false}, {"key": "C", "text": "2V_m", "is_correct": true}, {"key": "D", "text": "4V_m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V_m/2 is much too low. The non-conducting diode sees the entire voltage across the full secondary winding (both halves), which sums to 2V_m.", "misconception": "Incorrectly dividing the voltage instead of summing across both halves"}, {"option_key": "B", "hint": "V_m is the PIV for a half-wave rectifier. In a centre-tapped full-wave rectifier, the non-conducting diode has its anode at -V_m and cathode at +V_m, so PIV = 2V_m.", "misconception": "Confusing the PIV of a half-wave rectifier with that of a full-wave rectifier"}, {"option_key": "D", "hint": "4V_m is not correct for any standard rectifier configuration. For a centre-tapped full-wave rectifier, PIV = 2V_m exactly.", "misconception": "Incorrectly doubling the PIV value"}]}, "correct_answer": "C", "concept_tags": ["full-wave-rectifier", "peak-inverse-voltage", "centre-tapped-transformer", "diode-rating"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An LED is fabricated from a semiconductor with a band gap of 2.0 eV. The wavelength of light emitted by this LED is approximately: (Given: h = 6.63 x 10⁻³⁴ J·s, c = 3 x 10⁸ m/s, 1 eV = 1.6 x 10⁻¹⁹ J)", "explanation": "The photon emitted during electron-hole recombination has energy approximately equal to the band gap: E = E_g = 2.0 eV. Using E = hc/λ, we get λ = hc/E = (6.63 x 10⁻³⁴ x 3 x 10⁸) / (2.0 x 1.6 x 10⁻¹⁹) = (19.89 x 10⁻²⁶) / (3.2 x 10⁻¹⁹) = 6.22 x 10⁻⁷ m = 6220 angstrom = 620 nm. This wavelength corresponds to orange-red light.", "payload": {"question_id": "cuet-phy-semi-diode-11", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "apply", "options": [{"key": "A", "text": "310 nm", "is_correct": false}, {"key": "B", "text": "620 nm", "is_correct": true}, {"key": "C", "text": "1240 nm", "is_correct": false}, {"key": "D", "text": "2480 nm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "310 nm corresponds to a photon energy of about 4.0 eV (double the band gap). Ensure you divide hc by E_g, not multiply: λ = hc/E_g = 1240/2.0 = 620 nm.", "misconception": "Using 2E_g instead of E_g in the calculation"}, {"option_key": "C", "hint": "1240 nm would correspond to a band gap of 1.0 eV. You may have divided the band gap by 2 instead of using it directly. The formula is λ(nm) = 1240/E_g(eV).", "misconception": "Arithmetic error: using E_g/2 instead of E_g"}, {"option_key": "D", "hint": "2480 nm corresponds to a photon energy of only 0.5 eV. This would require a band gap four times smaller. Check: λ = 1240/2.0 = 620 nm.", "misconception": "Major calculation error in applying the energy-wavelength relation"}]}, "correct_answer": "B", "concept_tags": ["LED", "band-gap", "wavelength-calculation", "photon-energy", "numerical"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a rectifier circuit, a capacitor filter is connected across the load. The function of this filter capacitor is to:", "explanation": "The output of a rectifier is pulsating DC containing both a DC component and AC ripple. A capacitor connected in parallel (shunt) with the load charges up to the peak voltage during the conducting phase and discharges through the load during the non-conducting phase, filling in the gaps between pulses. This smooths out the ripple and produces a more nearly constant DC output voltage. The larger the capacitance and the load resistance, the smaller the ripple.", "payload": {"question_id": "cuet-phy-semi-diode-12", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "Reduce the ripple in the output and produce a smoother DC voltage", "is_correct": true}, {"key": "B", "text": "Increase the output voltage above the peak AC voltage", "is_correct": false}, {"key": "C", "text": "Convert DC back to AC for further processing", "is_correct": false}, {"key": "D", "text": "Increase the output current of the rectifier", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A filter capacitor charges up to the peak voltage but cannot exceed it (in a simple rectifier circuit). The output voltage remains at or below V_m, never above.", "misconception": "Thinking a capacitor can boost voltage beyond the peak value in a passive circuit"}, {"option_key": "C", "hint": "Converting DC to AC requires an inverter circuit. A filter capacitor does the opposite: it removes the AC component from pulsating DC to produce smoother DC.", "misconception": "Reversing the role of a filter capacitor"}, {"option_key": "D", "hint": "A filter capacitor smooths voltage, but does not increase the average current delivered. In fact, it may reduce the average diode conduction time while maintaining a steadier voltage.", "misconception": "Confusing voltage smoothing with current amplification"}]}, "correct_answer": "A", "concept_tags": ["filter-circuit", "capacitor", "ripple", "smoothing", "rectifier"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): A solar cell does not require an external bias to operate and can directly convert light energy into electrical energy.\nReason (R): The built-in electric field at the p-n junction of a solar cell separates the light-generated electron-hole pairs, creating a potential difference across the cell.", "explanation": "Both the assertion and reason are correct, and the reason correctly explains the assertion. A solar cell is an unbiased p-n junction device. When photons with energy greater than the band gap are absorbed near the junction, electron-hole pairs are generated. The built-in electric field in the depletion region sweeps electrons towards the n-side and holes towards the p-side, creating a photovoltage (open-circuit voltage). This is the photovoltaic effect. No external bias is needed because the junction''s own internal field performs the charge separation.", "payload": {"question_id": "cuet-phy-semi-diode-13", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion. The built-in electric field is the very mechanism by which the solar cell generates voltage without external bias. The reason is causally linked to the assertion.", "misconception": "Failing to see the direct causal connection between the built-in field and bias-free operation"}, {"option_key": "C", "hint": "The reason is scientifically correct. The depletion region of any p-n junction has a built-in electric field that can separate charge carriers, and this is well-established physics.", "misconception": "Doubting the existence of the built-in electric field at the p-n junction"}, {"option_key": "D", "hint": "The assertion is correct. Solar cells are widely used as bias-free energy conversion devices. They generate an EMF (typically 0.5-0.6 V for silicon) when illuminated without any external power supply.", "misconception": "Incorrectly thinking solar cells need external bias to function"}]}, "correct_answer": "A", "concept_tags": ["solar-cell", "photovoltaic-effect", "built-in-field", "p-n-junction", "charge-separation"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): The semiconductor materials used for fabricating LEDs must have a direct band gap.\nReason (R): In direct band gap semiconductors, the electron-hole recombination is predominantly radiative, emitting photons efficiently, whereas in indirect band gap semiconductors like silicon, recombination is mainly non-radiative.", "explanation": "Both the assertion and reason are correct, and the reason is the correct explanation of the assertion. In a direct band gap semiconductor (like GaAs, GaN, GaAsP), the conduction band minimum and valence band maximum occur at the same value of crystal momentum (k). This allows direct electron-hole recombination with photon emission (radiative recombination) without needing a phonon for momentum conservation. In indirect band gap semiconductors (like Si, Ge), recombination requires a phonon to conserve momentum, making the process predominantly non-radiative (energy released as heat). Therefore, LEDs must use direct band gap materials for efficient light emission.", "payload": {"question_id": "cuet-phy-semi-diode-14", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains why a direct band gap is necessary: efficient radiative recombination. This is the precise mechanism that makes direct band gap materials essential for LEDs, so R is the correct explanation of A.", "misconception": "Not recognising that radiative recombination efficiency is the reason for choosing direct band gap materials"}, {"option_key": "C", "hint": "The reason is scientifically accurate. Direct band gap semiconductors do produce predominantly radiative recombination, and silicon (indirect band gap) is indeed a poor light emitter.", "misconception": "Doubting the distinction between radiative and non-radiative recombination in direct vs indirect gap materials"}, {"option_key": "D", "hint": "The assertion is correct and well-established. All commercially successful LEDs use direct band gap semiconductors (GaAs, GaN, InGaN, GaP with nitrogen isoelectronic traps, etc.) for efficient light emission.", "misconception": "Incorrectly thinking LEDs can be made efficiently from any semiconductor"}]}, "correct_answer": "A", "concept_tags": ["LED", "direct-band-gap", "indirect-band-gap", "radiative-recombination", "GaAs", "silicon"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the devices in Column I with their primary operating characteristics in Column II:\n\nColumn I:\nA. Half-wave rectifier\nB. Zener diode\nC. LED\nD. Photodiode\n\nColumn II:\n1. Operates in reverse bias; current depends on light intensity\n2. Forward biased p-n junction emitting light by electron-hole recombination\n3. Conducts only during one half of the AC input cycle\n4. Operates in reverse breakdown to maintain constant voltage", "explanation": "A half-wave rectifier uses a diode that conducts only during one half (positive or negative) of the AC input cycle (A-3). A Zener diode operates in the reverse breakdown region to maintain a constant voltage across the load (B-4). An LED is a forward-biased p-n junction that emits light when electrons and holes recombine across the junction (C-2). A photodiode operates in reverse bias, where the photocurrent varies with the intensity of incident light (D-1).", "payload": {"question_id": "cuet-phy-semi-diode-15", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-3, B-4, C-2, D-1", "is_correct": true}, {"key": "C", "text": "A-3, B-2, C-4, D-1", "is_correct": false}, {"key": "D", "text": "A-1, B-4, C-3, D-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-4 incorrectly pairs the half-wave rectifier with reverse breakdown operation. Reverse breakdown is the characteristic of a Zener diode, not a rectifier diode.", "misconception": "Confusing rectifier diode operation with Zener diode breakdown operation"}, {"option_key": "C", "hint": "B-2 incorrectly pairs the Zener diode with light emission. Light emission by recombination is the property of an LED. The Zener diode operates in reverse breakdown for voltage regulation (B-4).", "misconception": "Confusing Zener diode function with LED function"}, {"option_key": "D", "hint": "A-1 incorrectly states that a half-wave rectifier operates in reverse bias with light-dependent current. That describes a photodiode. A rectifier conducts during forward bias in one half-cycle.", "misconception": "Mixing up the fundamental operating principles of different diode devices"}]}, "correct_answer": "B", "concept_tags": ["half-wave-rectifier", "zener-diode", "LED", "photodiode", "device-comparison"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the semiconductor materials in Column I with the typical colour/type of light emitted by LEDs made from them in Column II:\n\nColumn I:\nA. Gallium Arsenide (GaAs)\nB. Gallium Arsenide Phosphide (GaAsP)\nC. Gallium Nitride (GaN)\nD. Gallium Phosphide (GaP)\n\nColumn II:\n1. Blue light\n2. Red/Yellow light\n3. Green light\n4. Infrared radiation", "explanation": "GaAs has a band gap of about 1.4 eV, which corresponds to infrared radiation (A-4). GaAsP is a ternary alloy whose band gap can be tuned; it commonly emits red to yellow light depending on composition (B-2). GaN has a wide band gap of about 3.4 eV, producing blue light (C-1). GaP with appropriate dopants (like nitrogen) emits green light (D-3).", "payload": {"question_id": "cuet-phy-semi-diode-16", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "remember", "options": [{"key": "A", "text": "A-1, B-2, C-4, D-3", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-1, D-3", "is_correct": false}, {"key": "C", "text": "A-4, B-3, C-1, D-2", "is_correct": false}, {"key": "D", "text": "A-4, B-2, C-1, D-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A-1 incorrectly assigns blue light to GaAs. GaAs has a band gap of only 1.4 eV, which corresponds to infrared radiation (not visible blue light). Blue LEDs require wide band gap materials like GaN.", "misconception": "Not knowing that GaAs emits in the infrared region due to its small band gap"}, {"option_key": "B", "hint": "A-2 and B-4 are swapped. GaAs (1.4 eV band gap) emits infrared, while GaAsP (tunable band gap around 1.9-2.0 eV) emits red/yellow visible light.", "misconception": "Confusing GaAs (infrared) with GaAsP (visible red/yellow)"}, {"option_key": "C", "hint": "B-3 and D-2 are swapped. GaAsP emits red/yellow light (not green), and GaP with nitrogen doping emits green light (not red/yellow).", "misconception": "Interchanging the emission colours of GaAsP and GaP"}]}, "correct_answer": "D", "concept_tags": ["LED-materials", "GaAs", "GaAsP", "GaN", "GaP", "emission-wavelength"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "In a full-wave rectifier, both halves of the AC input cycle are utilised to produce output across the load, resulting in a higher average DC output voltage compared to a half-wave rectifier.", "explanation": "This statement is true. In a full-wave rectifier, both the positive and negative half-cycles of the input AC are rectified to produce unidirectional current through the load. The average DC output voltage of a full-wave rectifier is 2V_m/pi (approximately 0.636V_m), which is exactly double that of a half-wave rectifier (V_m/pi, approximately 0.318V_m). Therefore, a full-wave rectifier produces a higher average DC output voltage.", "payload": {"question_id": "cuet-phy-semi-diode-17", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The average DC output of a full-wave rectifier (2V_m/pi) is indeed double that of a half-wave rectifier (V_m/pi). This is because both half-cycles contribute to the output.", "misconception": "Not recognising that utilising both half-cycles doubles the average output"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["full-wave-rectifier", "half-wave-rectifier", "average-voltage", "comparison"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "A photodiode is operated in forward bias to detect light, because forward bias increases the sensitivity to incident photons.", "explanation": "This statement is false. A photodiode is operated in reverse bias, not forward bias. Under reverse bias, the depletion region is widened, which increases the volume available for photon absorption and charge carrier generation. The strong electric field in the wide depletion region efficiently sweeps the photo-generated carriers, producing a measurable photocurrent that is proportional to light intensity. Forward bias would inject majority carriers, producing a large forward current that would overwhelm the small photocurrent signal.", "payload": {"question_id": "cuet-phy-semi-diode-18", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Photodiodes are operated in reverse bias. Forward bias produces a large majority carrier current that masks the small photocurrent, making light detection impractical.", "misconception": "Confusing the bias condition of a photodiode with that of an LED"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["photodiode", "reverse-bias", "forward-bias", "light-detection"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_blanks", "difficulty": "medium", "question_text": "A half-wave rectifier circuit uses an AC input of peak voltage 311 V (220 V rms) at 50 Hz. If the diode is ideal, the average DC output voltage is approximately _____ V. (Use V_dc = V_m / pi)", "explanation": "For a half-wave rectifier with an ideal diode, the average (mean) DC output voltage is given by V_dc = V_m / pi, where V_m is the peak voltage. Here V_m = 311 V. Therefore, V_dc = 311 / pi = 311 / 3.14 = 99 V (approximately). This is the standard formula for the average output of a half-wave rectifier.", "payload": {"question_id": "cuet-phy-semi-diode-19", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "apply", "options": [{"key": "A", "text": "70", "is_correct": false}, {"key": "B", "text": "155", "is_correct": false}, {"key": "C", "text": "99", "is_correct": true}, {"key": "D", "text": "220", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "70 V would be approximately V_rms/pi. The correct formula uses the peak voltage, not the rms voltage: V_dc = V_m/pi = 311/3.14 = 99 V.", "misconception": "Using rms voltage instead of peak voltage in the average DC formula"}, {"option_key": "B", "hint": "155 V is approximately V_m/2 = 311/2. The average output of a half-wave rectifier is V_m/pi, not V_m/2.", "misconception": "Using V_m/2 instead of V_m/pi for average DC output"}, {"option_key": "D", "hint": "220 V is the rms value of the input AC, not the DC output. The half-wave rectified DC average is V_m/pi = 311/3.14 = 99 V.", "misconception": "Confusing the rms input voltage with the average DC output voltage"}]}, "correct_answer": "C", "concept_tags": ["half-wave-rectifier", "average-voltage", "numerical", "peak-voltage"]}, {"chapter_id": "cuet-phy-electronic-devices", "topic_id": "cuet-phy-semi-diode", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "medium", "question_text": "A student designs a Zener diode voltage regulator circuit to power a sensitive electronic device. The circuit uses a Zener diode with Zener voltage V_Z = 9 V, a series resistance R_S = 100 ohm, and a load resistance R_L = 300 ohm. The unregulated DC input voltage is 15 V.\n\nAssuming the Zener diode is ideal, the current flowing through the Zener diode is:", "explanation": "Since the Zener diode maintains V_Z = 9 V across the load, the load current is I_L = V_Z / R_L = 9 / 300 = 0.03 A = 30 mA. The current through the series resistance is I_S = (V_in - V_Z) / R_S = (15 - 9) / 100 = 6/100 = 0.06 A = 60 mA. By Kirchhoff''s current law at the junction: I_Z = I_S - I_L = 60 - 30 = 30 mA.", "payload": {"question_id": "cuet-phy-semi-diode-20", "subtopic": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "topic_name": "Diode Applications (Rectifier, Zener, LED, Photodiode)", "bloom_level": "apply", "options": [{"key": "A", "text": "10 mA", "is_correct": false}, {"key": "B", "text": "20 mA", "is_correct": false}, {"key": "C", "text": "30 mA", "is_correct": true}, {"key": "D", "text": "60 mA", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 mA is incorrect. Recalculate: I_S = (15-9)/100 = 60 mA, I_L = 9/300 = 30 mA, so I_Z = 60 - 30 = 30 mA, not 10 mA.", "misconception": "Arithmetic error in current calculation"}, {"option_key": "B", "hint": "20 mA does not match the correct calculation. The series current is 60 mA and load current is 30 mA, giving I_Z = 30 mA.", "misconception": "Error in applying Kirchhoff''s current law at the junction"}, {"option_key": "D", "hint": "60 mA is the total current through the series resistance, not the Zener current. You must subtract the load current: I_Z = I_S - I_L = 60 - 30 = 30 mA.", "misconception": "Confusing total series current with Zener diode current"}]}, "correct_answer": "C", "concept_tags": ["zener-diode", "voltage-regulator", "numerical", "kirchhoff-current-law", "scenario"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-10');

