SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The dimension of capacitance is:", "explanation": "C = Q/V. Dimension of Q = [AT], V = [ML²T⁻³A⁻¹]. So C = [AT]/[ML²T⁻³A⁻¹] = [M⁻¹L⁻²T⁴A²]. This can also be verified: 1 farad = 1 C/V = 1 C²/(J) = 1 A²s⁴/(kg·m²).", "payload": {"question_id": "cuet-phy-elec-capacitor-01", "subtopic": "Capacitance basics", "topic_name": "Capacitors and Dielectrics", "bloom_level": "remember", "options": [{"key": "A", "text": "[ML²T⁻²A⁻²]", "is_correct": false}, {"key": "B", "text": "[M⁻¹L⁻²T³A²]", "is_correct": false}, {"key": "C", "text": "[M⁻¹L⁻²T⁴A²]", "is_correct": true}, {"key": "D", "text": "[MLT⁻²A⁻¹]", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "[ML²T⁻²A⁻²] is the dimension of inductance (L = V·s/A), not capacitance.", "misconception": "Confusing capacitance with inductance dimensions"}, {"option_key": "B", "hint": "T³ is incorrect — the time exponent should be T⁴ (from T in charge and T⁻³ in voltage denominator).", "misconception": "Arithmetic error in exponent calculation"}, {"option_key": "D", "hint": "[MLT⁻²A⁻¹] is the dimension of magnetic field (B), not capacitance.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["capacitance-dimension", "dimensional-analysis"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A conducting slab of thickness t is introduced between the plates of a parallel plate capacitor with plate separation d (t < d). The new capacitance is:", "explanation": "A conducting slab has infinite dielectric constant. It effectively reduces the gap to (d − t), as the field inside the conductor is zero. The capacitance becomes C'' = ε₀A/(d − t). Unlike a dielectric, a conductor completely eliminates the field in its interior.", "payload": {"question_id": "cuet-phy-elec-capacitor-02", "subtopic": "Conducting slab in capacitor", "topic_name": "Capacitors and Dielectrics", "bloom_level": "understand", "options": [{"key": "A", "text": "ε₀A/d (unchanged)", "is_correct": false}, {"key": "B", "text": "ε₀A/(d − t)", "is_correct": true}, {"key": "C", "text": "ε₀A/(d + t)", "is_correct": false}, {"key": "D", "text": "ε₀A/t", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The conducting slab eliminates the field in its interior, reducing the effective gap. Capacitance must increase, not remain the same.", "misconception": "Thinking the slab has no effect"}, {"option_key": "C", "hint": "d + t would mean the gap increases, but the slab is placed inside the existing gap, reducing the effective air gap to d − t.", "misconception": "Adding instead of subtracting the slab thickness"}, {"option_key": "D", "hint": "ε₀A/t would apply if the conducting slab filled the entire gap except a vanishingly small space. The effective gap is d − t, not t.", "misconception": "Using slab thickness instead of remaining gap"}]}, "correct_answer": "B", "concept_tags": ["conducting-slab", "effective-gap", "capacitance-increase"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The energy stored in a capacitor of capacitance C charged to voltage V is equivalent to the energy stored in the electric field between the plates. The energy per unit volume (energy density) is:", "explanation": "Energy U = ½CV² = ½(ε₀A/d)(Ed)² = ½ε₀E² × (Ad). Volume between plates = Ad. So energy density u = U/(Ad) = ½ε₀E². This is a general result — the energy density of any electric field is ½ε₀E².", "payload": {"question_id": "cuet-phy-elec-capacitor-03", "subtopic": "Energy density", "topic_name": "Capacitors and Dielectrics", "bloom_level": "remember", "options": [{"key": "A", "text": "ε₀E", "is_correct": false}, {"key": "B", "text": "ε₀E²", "is_correct": false}, {"key": "C", "text": "½ε₀²E²", "is_correct": false}, {"key": "D", "text": "½ε₀E²", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "ε₀E has dimensions of charge/area (surface charge density), not energy/volume.", "misconception": "Dimensional error"}, {"option_key": "B", "hint": "Missing the factor of ½. The correct expression is ½ε₀E², derived from integrating the work to build the field.", "misconception": "Forgetting the factor of ½ in energy density"}, {"option_key": "C", "hint": "½ε₀²E² has ε₀ squared, which gives wrong dimensions. Energy density requires exactly one power of ε₀.", "misconception": "Squaring ε₀ instead of E"}]}, "correct_answer": "D", "concept_tags": ["energy-density", "electric-field-energy"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The capacitance of a cylindrical capacitor of length L with inner radius a and outer radius b is:", "explanation": "For a cylindrical capacitor, V = (λ/2πε₀)ln(b/a), where λ = Q/L. So C = Q/V = 2πε₀L/ln(b/a). This is analogous to the parallel plate formula but adapted for cylindrical geometry. The capacitance is proportional to length L.", "payload": {"question_id": "cuet-phy-elec-capacitor-04", "subtopic": "Cylindrical capacitor", "topic_name": "Capacitors and Dielectrics", "bloom_level": "remember", "options": [{"key": "A", "text": "2πε₀L/ln(b/a)", "is_correct": true}, {"key": "B", "text": "4πε₀L/ln(b/a)", "is_correct": false}, {"key": "C", "text": "2πε₀L/(b − a)", "is_correct": false}, {"key": "D", "text": "ε₀L/(b − a)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "4πε₀ appears in the spherical capacitor formula, not the cylindrical one. The cylindrical geometry uses 2πε₀.", "misconception": "Confusing cylindrical with spherical geometry factor"}, {"option_key": "C", "hint": "The denominator should be ln(b/a), not (b − a). The logarithm arises from integrating E = λ/(2πε₀r) from a to b.", "misconception": "Using linear gap instead of logarithmic ratio"}, {"option_key": "D", "hint": "This lacks the 2π factor and uses (b−a) instead of ln(b/a). Both are incorrect for a cylindrical geometry.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["cylindrical-capacitor", "logarithmic-formula"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor has capacitance C. If the distance between the plates is halved and a dielectric of constant K = 4 is filled in the entire space, the new capacitance is:", "explanation": "Original: C = ε₀A/d. New: d'' = d/2, K = 4. C'' = Kε₀A/d'' = 4ε₀A/(d/2) = 8ε₀A/d = 8C. Both changes (halving distance and inserting dielectric) independently multiply the capacitance.", "payload": {"question_id": "cuet-phy-elec-capacitor-05", "subtopic": "Combined changes in capacitor", "topic_name": "Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "2C", "is_correct": false}, {"key": "B", "text": "4C", "is_correct": false}, {"key": "C", "text": "6C", "is_correct": false}, {"key": "D", "text": "8C", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2C accounts for halving the distance (×2) but ignores the dielectric (×4). Both effects multiply.", "misconception": "Considering only the distance change"}, {"option_key": "B", "hint": "4C accounts for the dielectric (×4) but ignores the halved distance (×2). The total factor is 4 × 2 = 8.", "misconception": "Considering only the dielectric effect"}, {"option_key": "C", "hint": "6C would come from adding 4 + 2 = 6, but the effects multiply (4 × 2 = 8), not add.", "misconception": "Adding individual factors instead of multiplying"}]}, "correct_answer": "D", "concept_tags": ["combined-effect", "dielectric-distance"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force of attraction between the plates of a parallel plate capacitor charged to voltage V with plate area A and separation d is:", "explanation": "The electric field due to one plate is E₁ = σ/(2ε₀). Force on the other plate (charge Q = σA) is F = QE₁ = σA × σ/(2ε₀) = σ²A/(2ε₀). Using σ = ε₀V/d: F = ε₀V²A/(2d²). Alternatively, F = Q²/(2ε₀A) = ε₀AV²/(2d²).", "payload": {"question_id": "cuet-phy-elec-capacitor-06", "subtopic": "Force on capacitor plates", "topic_name": "Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀AV²/d²", "is_correct": false}, {"key": "B", "text": "ε₀AV/d", "is_correct": false}, {"key": "C", "text": "ε₀AV²/(2d²)", "is_correct": true}, {"key": "D", "text": "ε₀AV²/(4d²)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Missing the factor of ½. Each plate creates field σ/(2ε₀), not σ/ε₀ — only one plate''s field acts on the other.", "misconception": "Using the total field between plates instead of field due to one plate"}, {"option_key": "B", "hint": "This has V to the first power instead of V². Force depends on E² and E = V/d, so F ∝ V².", "misconception": "Using V instead of V²"}, {"option_key": "D", "hint": "The factor should be 1/2, not 1/4. F = σ²A/(2ε₀) = ε₀AV²/(2d²).", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["force-between-plates", "attractive-force"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor is charged and disconnected from the battery. A dielectric slab of constant K is now inserted fully between the plates. Which of the following quantities increases?", "explanation": "With battery disconnected: Q = constant. Inserting dielectric: C → KC, V = Q/C → Q/(KC) = V/K (decreases), E = V/d → V/(Kd) (decreases), U = Q²/(2C) → Q²/(2KC) = U/K (decreases). Capacitance increases; V, E, and U all decrease.", "payload": {"question_id": "cuet-phy-elec-capacitor-07", "subtopic": "Dielectric with battery disconnected", "topic_name": "Capacitors and Dielectrics", "bloom_level": "analyze", "options": [{"key": "A", "text": "Capacitance", "is_correct": true}, {"key": "B", "text": "Voltage across the plates", "is_correct": false}, {"key": "C", "text": "Electric field between the plates", "is_correct": false}, {"key": "D", "text": "Energy stored", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "V = Q/C. With Q constant and C increasing (×K), V must decrease to V/K.", "misconception": "Thinking voltage stays constant without the battery"}, {"option_key": "C", "hint": "E = V/d. Since V decreases (V/K) and d is unchanged, E also decreases. The dielectric polarization opposes the original field.", "misconception": "Ignoring field reduction by dielectric polarization"}, {"option_key": "D", "hint": "U = Q²/(2C). With Q constant and C increasing, U decreases. The energy goes into pulling the slab in (work done by the force of attraction).", "misconception": "Not tracking where the lost energy goes"}]}, "correct_answer": "A", "concept_tags": ["battery-disconnected", "dielectric-insertion", "quantity-changes"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two capacitors of capacitances C₁ and C₂ (C₁ > C₂) are charged to the same voltage V and then connected in parallel with like plates together. The common voltage after connection is:", "explanation": "Initial charges: Q₁ = C₁V, Q₂ = C₂V. Total charge = (C₁ + C₂)V. Total capacitance = C₁ + C₂. Common voltage V'' = (C₁ + C₂)V/(C₁ + C₂) = V. When both capacitors have the same initial voltage and are connected with like plates, no charge flows and the voltage remains V.", "payload": {"question_id": "cuet-phy-elec-capacitor-08", "subtopic": "Charge redistribution", "topic_name": "Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "V/2", "is_correct": false}, {"key": "B", "text": "V", "is_correct": true}, {"key": "C", "text": "2V", "is_correct": false}, {"key": "D", "text": "C₁V/(C₁ + C₂)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V/2 would occur if only one capacitor were charged and the other uncharged, with equal capacitances. Here both are already at V.", "misconception": "Applying the unequal charge formula without checking initial conditions"}, {"option_key": "C", "hint": "The voltages don''t add. In parallel, the common voltage is total charge / total capacitance = V.", "misconception": "Adding voltages in parallel"}, {"option_key": "D", "hint": "This formula applies when only C₁ is charged to V and C₂ is uncharged. When both are at V, the answer simplifies to V.", "misconception": "Using the formula for one charged + one uncharged capacitor"}]}, "correct_answer": "B", "concept_tags": ["charge-sharing", "same-voltage", "parallel-connection"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A dielectric slab of thickness t and dielectric constant K is placed between the plates of a parallel plate capacitor of plate separation d (t < d). The capacitance becomes:", "explanation": "The capacitor is split into two in series: air gap of (d − t) and dielectric of t. C = ε₀A / [d − t + t/K] = ε₀A / [d − t(1 − 1/K)]. This reduces to ε₀A/d when K = 1 and to ε₀A/(d − t) when K → ∞ (conductor).", "payload": {"question_id": "cuet-phy-elec-capacitor-09", "subtopic": "Partial dielectric filling", "topic_name": "Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "Kε₀A/d", "is_correct": false}, {"key": "B", "text": "ε₀A/(d − t)", "is_correct": false}, {"key": "C", "text": "Kε₀A/(d − t + Kt)", "is_correct": false}, {"key": "D", "text": "ε₀A/(d − t + t/K)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Kε₀A/d applies when the dielectric fills the entire gap. Here it fills only thickness t, leaving (d − t) as air.", "misconception": "Using the fully-filled formula for partially-filled capacitor"}, {"option_key": "B", "hint": "ε₀A/(d − t) would apply for a conducting slab (K → ∞). A dielectric with finite K doesn''t reduce the gap to (d − t).", "misconception": "Treating a dielectric slab as a conductor"}, {"option_key": "C", "hint": "Check the series formula: 1/C = (d−t)/(ε₀A) + t/(Kε₀A) = [d − t + t/K]/(ε₀A). The denominator is d − t + t/K, not d − t + Kt.", "misconception": "Multiplying by K instead of dividing by K for the dielectric region"}]}, "correct_answer": "D", "concept_tags": ["partial-dielectric", "series-combination", "effective-gap"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A parallel plate capacitor of capacitance C is connected to a battery of EMF V. A dielectric slab of constant K is inserted. The battery remains connected. The ratio of energy stored after to before insertion is:", "explanation": "With battery connected: V = constant. Before: U₁ = ½CV². After: C'' = KC, U₂ = ½KCV². Ratio = U₂/U₁ = K. The energy increases because the battery supplies additional charge (Q₂ = KCV > Q₁ = CV), doing work. Part of this work goes to increasing U and part to pulling in the dielectric.", "payload": {"question_id": "cuet-phy-elec-capacitor-10", "subtopic": "Dielectric with battery connected", "topic_name": "Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "1/K", "is_correct": false}, {"key": "B", "text": "1/K²", "is_correct": false}, {"key": "C", "text": "K", "is_correct": true}, {"key": "D", "text": "K²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/K is the energy ratio when the battery is disconnected (U = Q²/2C, Q constant, C increases). With battery connected, V is constant, so U = ½CV² increases by K.", "misconception": "Using the battery-disconnected result for battery-connected case"}, {"option_key": "B", "hint": "1/K² has no physical basis in this scenario. With V constant and C → KC: U → ½KCV² = KU.", "misconception": null}, {"option_key": "D", "hint": "K² would arise if both C and V changed, but with the battery connected, V stays constant. Only C changes by factor K.", "misconception": "Squaring K without justification"}]}, "correct_answer": "C", "concept_tags": ["battery-connected", "energy-ratio", "dielectric"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A spherical capacitor has inner sphere of radius a and outer sphere of radius b. Its capacitance is:", "explanation": "The potential difference between spheres: V = kQ(1/a − 1/b) = kQ(b − a)/(ab). Capacitance C = Q/V = ab/(k(b − a)) = 4πε₀ab/(b − a). When b → ∞, C → 4πε₀a (isolated sphere). When (b − a) << a, it approximates a parallel plate capacitor.", "payload": {"question_id": "cuet-phy-elec-capacitor-11", "subtopic": "Spherical capacitor", "topic_name": "Capacitors and Dielectrics", "bloom_level": "remember", "options": [{"key": "A", "text": "4πε₀ab/(b − a)", "is_correct": true}, {"key": "B", "text": "4πε₀(b − a)/ab", "is_correct": false}, {"key": "C", "text": "4πε₀a", "is_correct": false}, {"key": "D", "text": "4πε₀(a + b)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This inverts the fraction. C = Q/V = ab/[k(b−a)] = 4πε₀ab/(b−a), not (b−a)/ab.", "misconception": "Inverting the expression for capacitance"}, {"option_key": "C", "hint": "4πε₀a is the capacitance of an isolated sphere (outer radius → ∞). A spherical capacitor with finite b has a different formula.", "misconception": "Using isolated sphere formula for a spherical capacitor"}, {"option_key": "D", "hint": "4πε₀(a + b) doesn''t arise from the potential difference calculation. The correct formula has ab/(b − a).", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["spherical-capacitor", "concentric-spheres"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A parallel plate capacitor has two dielectric slabs of equal area A/2 each, placed side by side between the plates. Their dielectric constants are K₁ and K₂. The effective capacitance is:", "explanation": "Side-by-side placement means the two halves are in parallel. Each half has area A/2 and gap d. C₁ = K₁ε₀(A/2)/d, C₂ = K₂ε₀(A/2)/d. Total C = C₁ + C₂ = ε₀A(K₁ + K₂)/(2d). This is equivalent to using an effective K = (K₁ + K₂)/2.", "payload": {"question_id": "cuet-phy-elec-capacitor-12", "subtopic": "Multiple dielectrics", "topic_name": "Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀A·K₁K₂/[d(K₁ + K₂)]", "is_correct": false}, {"key": "B", "text": "ε₀A(K₁ + K₂)/(2d)", "is_correct": true}, {"key": "C", "text": "2ε₀A(K₁ + K₂)/d", "is_correct": false}, {"key": "D", "text": "ε₀AK₁K₂/d", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the harmonic mean formula, which applies when dielectrics are stacked on top of each other (in series). Side-by-side gives the arithmetic mean.", "misconception": "Confusing series (stacked) with parallel (side-by-side) arrangement of dielectrics"}, {"option_key": "C", "hint": "The factor should be (K₁ + K₂)/2, not 2(K₁ + K₂). Each slab covers only half the area.", "misconception": "Using full area A for each half"}, {"option_key": "D", "hint": "K₁K₂ (product) is not the relevant operation. Side-by-side means parallel combination: add the individual capacitances.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["parallel-dielectrics", "side-by-side", "effective-capacitance"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "n identical capacitors, each of capacitance C, are first connected in series and then in parallel. The ratio of energy stored in the series combination to the parallel combination, when connected to the same battery of EMF V, is:", "explanation": "Series: C_s = C/n. U_s = ½(C/n)V². Parallel: C_p = nC. U_p = ½(nC)V². Ratio = U_s/U_p = (C/n)/(nC) = 1/n². The parallel combination stores n² times more energy because it has n² times the capacitance.", "payload": {"question_id": "cuet-phy-elec-capacitor-13", "subtopic": "Energy in combinations", "topic_name": "Capacitors and Dielectrics", "bloom_level": "analyze", "options": [{"key": "A", "text": "1/n", "is_correct": false}, {"key": "B", "text": "n", "is_correct": false}, {"key": "C", "text": "n²", "is_correct": false}, {"key": "D", "text": "1/n²", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1/n is the capacitance ratio C_s/C_p = (C/n)/(nC) = 1/n². The energy ratio equals the capacitance ratio (since V is the same), which is 1/n², not 1/n.", "misconception": "Computing n × (1/n) instead of (1/n) × (1/n)"}, {"option_key": "B", "hint": "n would mean the series combination stores more energy, but series has smaller capacitance and therefore less energy for the same V.", "misconception": "Inverting the ratio"}, {"option_key": "C", "hint": "n² is the ratio U_p/U_s, not U_s/U_p. The question asks series/parallel.", "misconception": "Computing the ratio in the wrong order"}]}, "correct_answer": "D", "concept_tags": ["series-parallel-energy", "ratio", "n-capacitors"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A parallel plate capacitor with a dielectric slab partially inserted is pulled inward — the dielectric slab experiences a force pulling it into the space between the plates.\nReason (R): The system tends to move toward a state of lower energy, and energy is lower with the dielectric fully inside when the battery is disconnected.", "explanation": "Both A and R are true, and R correctly explains A. When the battery is disconnected: Q is constant, and inserting the dielectric increases C, reducing U = Q²/(2C). The system seeks minimum energy, so the slab is pulled in. (When the battery is connected, U increases, but the battery does extra work — the slab is still pulled in.)", "payload": {"question_id": "cuet-phy-elec-capacitor-14", "subtopic": "Force on dielectric slab", "topic_name": "Capacitors and Dielectrics", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A — the energy minimization principle is precisely why the force acts to pull the slab in.", "misconception": "Not seeing the causal connection between energy minimization and the force"}, {"option_key": "C", "hint": "R is correct — with battery disconnected, U = Q²/(2C). As C increases (dielectric inserted), U decreases, confirming the system moves to lower energy.", "misconception": null}, {"option_key": "D", "hint": "A is correct — this is experimentally observed. A dielectric slab is always pulled into the capacitor gap.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["dielectric-force", "energy-minimization", "slab-insertion"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When two capacitors charged to different voltages are connected in parallel, the total energy after connection is less than the total energy before connection.\nReason (R): Energy is lost as heat in the connecting wires due to transient current flow during charge redistribution.", "explanation": "Both A and R are true, and R correctly explains A. If C₁ at V₁ and C₂ at V₂ are connected, charge flows until voltages equalize. The energy loss ΔU = C₁C₂(V₁ − V₂)²/[2(C₁ + C₂)] > 0 whenever V₁ ≠ V₂. This energy is dissipated as Joule heating in the wires, regardless of wire resistance (lower R means faster current but same total heat).", "payload": {"question_id": "cuet-phy-elec-capacitor-15", "subtopic": "Energy loss in redistribution", "topic_name": "Capacitors and Dielectrics", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R explains A directly — the energy deficit (ΔU > 0) is accounted for exactly by the heat generated in the connecting wires.", "misconception": "Thinking the energy loss and heat are unrelated"}, {"option_key": "C", "hint": "R is correct — transient currents always flow when capacitors at different voltages are connected, and I²R heating occurs in any real wire.", "misconception": null}, {"option_key": "D", "hint": "A is correct — ΔU = C₁C₂(V₁−V₂)²/2(C₁+C₂) is always positive for V₁ ≠ V₂, confirming energy loss.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["energy-loss", "charge-redistribution", "joule-heating"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The capacitance of a capacitor depends on the charge stored or the voltage applied across it.", "explanation": "FALSE. Capacitance C = ε₀A/d (for a parallel plate capacitor) depends only on the geometry (plate area, separation) and the medium (dielectric constant). It does NOT depend on Q or V. The ratio Q/V is always constant for a given capacitor.", "payload": {"question_id": "cuet-phy-elec-capacitor-16", "subtopic": "Definition of capacitance", "topic_name": "Capacitors and Dielectrics", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Although C = Q/V, the capacitance is a constant for a given capacitor. Doubling Q doubles V, keeping C unchanged. Capacitance depends on geometry and medium, not on Q or V.", "misconception": "Confusing the definition C = Q/V with dependence on Q or V"}]}, "correct_answer": "B", "concept_tags": ["capacitance-independence", "geometry-dependent"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In a parallel combination of capacitors, the voltage across each capacitor is the same.", "explanation": "TRUE. In a parallel combination, both plates of each capacitor are connected to the same two nodes (same two wires). Therefore, the potential difference across each capacitor equals the potential difference between the nodes — all capacitors have the same voltage.", "payload": {"question_id": "cuet-phy-elec-capacitor-17", "subtopic": "Parallel combination", "topic_name": "Capacitors and Dielectrics", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "In parallel, both terminals of each capacitor connect to the same nodes. By definition, voltage between two nodes is unique — so all capacitors share the same voltage.", "misconception": "Confusing parallel (same voltage) with series (same charge)"}]}, "correct_answer": "A", "concept_tags": ["parallel-combination", "same-voltage"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The energy lost when a capacitor of capacitance C charged to voltage V is connected to an identical uncharged capacitor is _____.", "explanation": "Initial energy: U₁ = ½CV². After connection: total charge = CV shared between 2C → common voltage = V/2. Final energy: U₂ = ½(2C)(V/2)² = CV²/4. Energy lost = U₁ − U₂ = CV²/2 − CV²/4 = CV²/4 = U₁/2. Exactly half the initial energy is lost as heat.", "payload": {"question_id": "cuet-phy-elec-capacitor-18", "subtopic": "Energy loss in charge sharing", "topic_name": "Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "CV²/2", "is_correct": false}, {"key": "C", "text": "CV²/4", "is_correct": true}, {"key": "D", "text": "CV²/8", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero energy loss would violate energy conservation — the voltages are different before connection (V and 0), so current flows and energy is dissipated.", "misconception": "Thinking no energy is lost in charge redistribution"}, {"option_key": "B", "hint": "CV²/2 is the total initial energy. Not all of it is lost — half remains in the two capacitors at V/2 each.", "misconception": "Thinking all the energy is lost"}, {"option_key": "D", "hint": "CV²/8 would be the final energy in one of the capacitors, not the total energy lost.", "misconception": "Confusing the energy of one capacitor with the total energy loss"}]}, "correct_answer": "C", "concept_tags": ["energy-loss", "identical-capacitors", "half-energy"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A network consists of three capacitors: C₁ = 2 μF, C₂ = 4 μF, and C₃ = 4 μF. C₁ and C₂ are in series, and their combination is in parallel with C₃. This network is connected to a 12 V battery. Calculate the total charge supplied by the battery and the voltage across C₁.", "explanation": "C₁ and C₂ in series: 1/C₁₂ = 1/2 + 1/4 = 3/4, so C₁₂ = 4/3 μF. C₁₂ in parallel with C₃: C_total = 4/3 + 4 = 16/3 μF. Total charge Q = C_total × V = (16/3) × 12 = 64 μC. For C₁₂ branch: Q₁₂ = C₁₂ × 12 = (4/3) × 12 = 16 μC. This is also Q₁ (series). Voltage across C₁: V₁ = Q₁/C₁ = 16/2 = 8 V.", "payload": {"question_id": "cuet-phy-elec-capacitor-19", "subtopic": "Capacitor networks", "topic_name": "Capacitors and Dielectrics", "bloom_level": "apply", "options": [{"key": "A", "text": "Q_total = 64 μC; V₁ = 4 V", "is_correct": false}, {"key": "B", "text": "Q_total = 64 μC; V₁ = 8 V", "is_correct": true}, {"key": "C", "text": "Q_total = 48 μC; V₁ = 8 V", "is_correct": false}, {"key": "D", "text": "Q_total = 48 μC; V₁ = 6 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q_total is correct (64 μC), but V₁ = Q₁₂/C₁ = 16/2 = 8 V, not 4 V. The 4 V is V₂ = Q₁₂/C₂ = 16/4 = 4 V (across C₂, not C₁).", "misconception": "Confusing V₁ with V₂ in the series branch"}, {"option_key": "C", "hint": "48 μC would be from C_total = 4 μF (just C₃ alone). C₁₂ = 4/3 μF adds to C₃ in parallel, giving 16/3 μF.", "misconception": "Forgetting the series combination contribution to total capacitance"}, {"option_key": "D", "hint": "Both values are incorrect. Q_total = (16/3) × 12 = 64 μC, not 48, and V₁ = 8 V, not 6 V.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["network", "series-parallel", "voltage-charge"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-capacitor", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in the correct order for finding the equivalent capacitance of a complex capacitor network:\n\n1. Identify which capacitors are in series and which are in parallel\n2. Redraw the circuit showing simplified equivalent capacitors\n3. Check for Wheatstone bridge symmetry or balanced conditions\n4. Assign node labels and trace the current path from positive to negative terminal of the battery", "explanation": "The correct approach is: First assign nodes and trace the path (4) to understand the topology. Then check for special symmetries like Wheatstone bridge (3), which can simplify the network. Then identify series/parallel groups (1). Finally redraw with equivalents (2) and repeat if needed. Order: 4 → 3 → 1 → 2.", "payload": {"question_id": "cuet-phy-elec-capacitor-20", "subtopic": "Network analysis method", "topic_name": "Capacitors and Dielectrics", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 → 2 → 3 → 4", "is_correct": false}, {"key": "B", "text": "1 → 3 → 4 → 2", "is_correct": false}, {"key": "C", "text": "4 → 1 → 3 → 2", "is_correct": false}, {"key": "D", "text": "4 → 3 → 1 → 2", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "You can''t identify series/parallel (step 1) without first labelling nodes (step 4). Node labelling must come first to understand the topology.", "misconception": "Jumping to series/parallel identification without understanding the circuit topology"}, {"option_key": "B", "hint": "Step 4 (node labelling) must come before step 1 (series/parallel identification), not after.", "misconception": "Incorrect ordering of node identification"}, {"option_key": "C", "hint": "After labelling nodes (4), check for symmetry (3) before identifying series/parallel (1). A Wheatstone bridge eliminates one capacitor, simplifying subsequent steps.", "misconception": "Not prioritizing symmetry check before brute-force identification"}]}, "correct_answer": "D", "concept_tags": ["network-analysis", "methodology", "systematic-approach"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-13');

