SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric potential at a distance r from a point charge q is given by:", "explanation": "The electric potential due to a point charge q at a distance r is V = kq/r = q/(4πε₀r). This is a scalar quantity and can be positive or negative depending on the sign of the charge.", "payload": {"question_id": "cuet-phy-pot-potential-01", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "V = kq/r", "is_correct": true}, {"key": "B", "text": "V = kq/r²", "is_correct": false}, {"key": "C", "text": "V = kq²/r", "is_correct": false}, {"key": "D", "text": "V = kr/q", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "kq/r² is the expression for electric field magnitude, not electric potential. Potential varies as 1/r, not 1/r².", "misconception": "Confusing electric field with electric potential"}, {"option_key": "C", "hint": "The charge appears to the first power in the potential formula, not squared.", "misconception": null}, {"option_key": "D", "hint": "This expression has incorrect dimensional analysis and does not represent any standard electrostatic quantity.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["electric potential", "point charge", "Coulomb constant"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Electric potential is a scalar quantity. What is the SI unit of electric potential?", "explanation": "The SI unit of electric potential is the volt (V). One volt is defined as one joule per coulomb (1 V = 1 J/C). It represents the potential energy per unit charge at a point in the electric field.", "payload": {"question_id": "cuet-phy-pot-potential-02", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "Newton per coulomb (N/C)", "is_correct": false}, {"key": "B", "text": "Volt (V)", "is_correct": true}, {"key": "C", "text": "Coulomb per metre (C/m)", "is_correct": false}, {"key": "D", "text": "Joule (J)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Newton per coulomb (N/C) is the unit of electric field intensity, not electric potential.", "misconception": "Confusing units of electric field and electric potential"}, {"option_key": "C", "hint": "Coulomb per metre is not a standard unit for any common electrostatic quantity.", "misconception": null}, {"option_key": "D", "hint": "Joule is the unit of energy. Electric potential is energy per unit charge, so its unit is J/C = V, not just J.", "misconception": "Confusing potential energy with potential"}]}, "correct_answer": "B", "concept_tags": ["electric potential", "SI unit", "volt"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The work done in moving a charge of 5 μC between two points having a potential difference of 20 V is:", "explanation": "The work done in moving a charge q through a potential difference ΔV is W = qΔV. Here q = 5 μC = 5 × 10⁻⁶ C and ΔV = 20 V. So W = 5 × 10⁻⁶ × 20 = 100 × 10⁻⁶ J = 100 μJ = 1 × 10⁻⁴ J.", "payload": {"question_id": "cuet-phy-pot-potential-03", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "1 × 10⁻³ J", "is_correct": false}, {"key": "B", "text": "4 × 10⁻⁶ J", "is_correct": false}, {"key": "C", "text": "1 × 10⁻⁴ J", "is_correct": true}, {"key": "D", "text": "2.5 × 10⁻⁷ J", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 × 10⁻³ J would result from using 50 μC instead of 5 μC, which is ten times the given charge.", "misconception": null}, {"option_key": "B", "hint": "4 × 10⁻⁶ J does not follow from multiplying 5 × 10⁻⁶ C by 20 V.", "misconception": null}, {"option_key": "D", "hint": "2.5 × 10⁻⁷ J would result from dividing charge by potential difference instead of multiplying.", "misconception": "Dividing instead of multiplying q and V"}]}, "correct_answer": "C", "concept_tags": ["work done", "potential difference", "charge"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Eight identical point charges q are placed at the eight corners of a cube of side a. The electrostatic potential energy of the system is (k = 1/4πε₀):", "explanation": "A cube has 8 vertices. Total pairs = C(8,2) = 28. There are three types of pairs by distance: 12 edge pairs (distance a), 12 face-diagonal pairs (distance a√2), and 4 body-diagonal pairs (distance a√3). Total PE = kq²[12/a + 12/(a√2) + 4/(a√3)] = (kq²/a)[12 + 12/√2 + 4/√3] = (kq²/a)[12 + 6√2 + 4√3/3].", "payload": {"question_id": "cuet-phy-pot-potential-04", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "(kq²/a)(12 + 6√2)", "is_correct": false}, {"key": "B", "text": "(kq²/a)(24 + 12√2 + 4√3)", "is_correct": false}, {"key": "C", "text": "(kq²/a)(12 + 12√2 + 4√3)", "is_correct": false}, {"key": "D", "text": "(kq²/a)(12 + 6√2 + 4√3/3)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This expression omits the 4 body-diagonal pairs entirely. A cube has edge, face-diagonal, and body-diagonal pairs — all must be included.", "misconception": "Forgetting body-diagonal pairs in a cube"}, {"option_key": "B", "hint": "The coefficients 24 and 12 are twice the actual number of edge and face-diagonal pairs. There are 12 edges and 12 face diagonals, not 24 and 12.", "misconception": "Double-counting pairs"}, {"option_key": "C", "hint": "The face-diagonal contribution should be 12/(a√2) = 6√2·(kq²/a), not 12√2. Also 4/√3 = 4√3/3, not 4√3.", "misconception": "Error in rationalizing denominators"}]}, "correct_answer": "D", "concept_tags": ["potential energy of system", "cube arrangement", "multiple charge pairs"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two point charges +4 μC and −4 μC are placed 20 cm apart. The electric potential at the midpoint of the line joining the two charges is:", "explanation": "At the midpoint, the distance from each charge is 10 cm = 0.1 m. Potential due to +4 μC is V₁ = kq/r = 9 × 10⁹ × 4 × 10⁻⁶/0.1 = +3.6 × 10⁵ V. Potential due to −4 μC is V₂ = 9 × 10⁹ × (−4 × 10⁻⁶)/0.1 = −3.6 × 10⁵ V. Total V = V₁ + V₂ = 0.", "payload": {"question_id": "cuet-phy-pot-potential-05", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "3.6 × 10⁵ V", "is_correct": false}, {"key": "C", "text": "7.2 × 10⁵ V", "is_correct": false}, {"key": "D", "text": "−3.6 × 10⁵ V", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "3.6 × 10⁵ V is the potential due to only the positive charge. You must add the contribution from both charges.", "misconception": "Ignoring the contribution of the negative charge"}, {"option_key": "C", "hint": "7.2 × 10⁵ V would result from adding the magnitudes without considering the sign of the charges.", "misconception": "Treating potential as always positive like electric field magnitude"}, {"option_key": "D", "hint": "−3.6 × 10⁵ V is the potential due to only the negative charge; the positive charge contribution must also be included.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["superposition of potential", "point charges", "midpoint"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric potential at a point on the axial line of a short electric dipole at distance r from the centre is proportional to:", "explanation": "The potential due to a short electric dipole at a point on its axial line is V = kp cos θ/r², where θ = 0° for the axial line. Thus V = kp/r², which means V is proportional to 1/r². The potential falls off faster for a dipole compared to a point charge.", "payload": {"question_id": "cuet-phy-pot-potential-06", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "1/r", "is_correct": false}, {"key": "B", "text": "1/r²", "is_correct": true}, {"key": "C", "text": "1/r³", "is_correct": false}, {"key": "D", "text": "1/r⁴", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/r dependence is characteristic of the potential due to a point charge, not a dipole.", "misconception": "Confusing point charge potential with dipole potential"}, {"option_key": "C", "hint": "1/r³ dependence is characteristic of the electric field of a dipole, not the potential.", "misconception": "Confusing dipole electric field variation with dipole potential variation"}, {"option_key": "D", "hint": "No standard electrostatic quantity for a dipole varies as 1/r⁴ in the far-field approximation.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["electric dipole", "axial potential", "inverse square"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric potential at a point on the equatorial plane of a short electric dipole is:", "explanation": "On the equatorial plane of a dipole, the angle θ = 90°. The potential is V = kp cos θ/r² = kp cos 90°/r² = 0. The contributions from the positive and negative charges exactly cancel at every point on the equatorial plane.", "payload": {"question_id": "cuet-phy-pot-potential-07", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "Positive", "is_correct": false}, {"key": "B", "text": "Negative", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "Depends on the dipole moment", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Both charges are equidistant from any point on the equatorial plane, so the positive and negative potentials cancel exactly.", "misconception": null}, {"option_key": "B", "hint": "The negative charge does not dominate since it is at the same distance as the positive charge from any equatorial point.", "misconception": null}, {"option_key": "D", "hint": "While the individual potentials depend on dipole moment, their sum on the equatorial plane is always zero regardless of the dipole moment magnitude.", "misconception": "Thinking the result depends on dipole moment magnitude"}]}, "correct_answer": "C", "concept_tags": ["electric dipole", "equatorial potential", "zero potential"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The relation between electric field E and electric potential V is given by E = −dV/dr. If V = 4x² volt (where x is in metres), the electric field at x = 1 m is:", "explanation": "Given V = 4x², the electric field component along x is E = −dV/dx = −d(4x²)/dx = −8x. At x = 1 m, E = −8(1) = −8 V/m. The magnitude is 8 V/m directed in the negative x-direction.", "payload": {"question_id": "cuet-phy-pot-potential-08", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "4 V/m in negative x-direction", "is_correct": false}, {"key": "B", "text": "4 V/m in positive x-direction", "is_correct": false}, {"key": "C", "text": "8 V/m in positive x-direction", "is_correct": false}, {"key": "D", "text": "8 V/m in negative x-direction", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4 V/m would result from forgetting to apply the power rule correctly during differentiation of 4x².", "misconception": "Incorrect differentiation of polynomial"}, {"option_key": "B", "hint": "The direction is wrong. E = −dV/dx gives a negative sign, indicating the field points in the negative x-direction.", "misconception": null}, {"option_key": "C", "hint": "While the magnitude 8 V/m is correct, the direction should be negative x since E = −dV/dx and dV/dx is positive.", "misconception": "Forgetting the negative sign in E = −dV/dr"}]}, "correct_answer": "D", "concept_tags": ["relation between E and V", "potential gradient", "differentiation"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Three charges of +q, +q, and +q are placed at the three vertices of an equilateral triangle of side a. The electric potential at the centroid of the triangle is:", "explanation": "The distance from each vertex to the centroid of an equilateral triangle with side a is r = a/√3. Since potential is a scalar, the total potential at the centroid is V = 3 × kq/(a/√3) = 3√3 kq/a.", "payload": {"question_id": "cuet-phy-pot-potential-09", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "3kq/a", "is_correct": false}, {"key": "B", "text": "3√3 kq/a", "is_correct": true}, {"key": "C", "text": "√3 kq/a", "is_correct": false}, {"key": "D", "text": "9kq/a", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3kq/a would be correct only if the distance from vertex to centroid were a, but it is actually a/√3.", "misconception": "Using side length instead of centroid distance"}, {"option_key": "C", "hint": "√3 kq/a accounts for only one charge contribution with the correct distance, not all three.", "misconception": null}, {"option_key": "D", "hint": "9kq/a is too large and does not follow from the correct distance formula for the centroid.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["superposition of potential", "equilateral triangle", "centroid"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electrostatic potential energy of a system of two point charges q₁ = +2 μC and q₂ = −3 μC separated by a distance of 30 cm is:", "explanation": "The potential energy of two point charges is U = kq₁q₂/r. Here U = 9 × 10⁹ × (2 × 10⁻⁶) × (−3 × 10⁻⁶)/0.3 = 9 × 10⁹ × (−6 × 10⁻¹²)/0.3 = −54 × 10⁻³/0.3 = −0.18 J.", "payload": {"question_id": "cuet-phy-pot-potential-10", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "+0.18 J", "is_correct": false}, {"key": "B", "text": "−0.06 J", "is_correct": false}, {"key": "C", "text": "−0.18 J", "is_correct": true}, {"key": "D", "text": "+0.06 J", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "+0.18 J has the correct magnitude but wrong sign. Since the charges are opposite, the potential energy must be negative.", "misconception": "Ignoring the sign of charges in potential energy calculation"}, {"option_key": "B", "hint": "−0.06 J would result from using r = 0.9 m or an incorrect charge product.", "misconception": null}, {"option_key": "D", "hint": "+0.06 J is both the wrong magnitude and wrong sign for this charge configuration.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["potential energy", "two charge system", "negative energy"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric potential V in a region varies with distance x as V = 6x² − 4x + 3 (in volts, x in metres). The electric field at x = 2 m in V/m is:", "explanation": "The electric field is E = −dV/dx = −d(6x² − 4x + 3)/dx = −(12x − 4). At x = 2 m, E = −(12 × 2 − 4) = −(24 − 4) = −20 V/m. The magnitude is 20 V/m directed in the negative x-direction.", "payload": {"question_id": "cuet-phy-pot-potential-11", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "−12 V/m", "is_correct": false}, {"key": "B", "text": "+20 V/m", "is_correct": false}, {"key": "C", "text": "+12 V/m", "is_correct": false}, {"key": "D", "text": "−20 V/m", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "−12 V/m would result from differentiating only the first term (6x²) and ignoring the −4x term.", "misconception": "Incomplete differentiation"}, {"option_key": "B", "hint": "+20 V/m has the correct magnitude but wrong sign. Remember E = −dV/dx, so the negative sign is essential.", "misconception": "Forgetting the negative sign in E = −dV/dx"}, {"option_key": "C", "hint": "+12 V/m results from both incomplete differentiation and a sign error.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["potential gradient", "electric field", "differentiation"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Four charges +q, +q, −q, and −q are placed at the four corners of a square of side a, with like charges on opposite corners. The total electrostatic potential energy of the system is:", "explanation": "There are 6 pairs in a 4-charge system. The side pairs: 4 pairs of unlike charges at distance a give 4 × k(+q)(−q)/a = −4kq²/a. The diagonal pairs: 2 pairs of like charges at distance a√2 give kq²/(a√2) + kq²/(a√2) = 2kq²/(a√2) = √2 kq²/a. Total U = −4kq²/a + √2 kq²/a = kq²/a(√2 − 4).", "payload": {"question_id": "cuet-phy-pot-potential-12", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "(kq²/a)(√2 − 4)", "is_correct": true}, {"key": "B", "text": "(kq²/a)(4 − √2)", "is_correct": false}, {"key": "C", "text": "−4kq²/a", "is_correct": false}, {"key": "D", "text": "(kq²/a)(2√2 − 4)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "(4 − √2) has the wrong sign. The adjacent unlike-charge pairs contribute negative energy that dominates over the diagonal like-charge pairs.", "misconception": "Sign error in summing pair-wise potential energies"}, {"option_key": "C", "hint": "−4kq²/a accounts for only the 4 side pairs and neglects the 2 diagonal pairs entirely.", "misconception": "Forgetting diagonal pairs in the energy calculation"}, {"option_key": "D", "hint": "2√2 − 4 would arise from incorrectly counting the diagonal pairs or using wrong distances.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["potential energy of system", "multiple charges", "square arrangement"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): The electric field is always perpendicular to the equipotential surface at every point.\nReason (R): No work is done in moving a charge along an equipotential surface.", "explanation": "Both the assertion and the reason are correct. If the electric field had a component along the equipotential surface, work would be done in moving a charge along the surface, contradicting the definition of an equipotential surface. Hence R correctly explains A — the perpendicularity ensures zero work along the surface.", "payload": {"question_id": "cuet-phy-pot-potential-13", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains why E must be perpendicular — if E had a tangential component, work would be done along the surface, violating the equipotential condition.", "misconception": "Not recognizing the causal link between zero work and perpendicularity"}, {"option_key": "C", "hint": "R is indeed correct; by definition, no work is done in moving a charge on an equipotential surface since ΔV = 0.", "misconception": null}, {"option_key": "D", "hint": "A is a well-established fact in electrostatics — the electric field lines are always normal to equipotential surfaces.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["equipotential surface", "electric field direction", "work done"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): The electrostatic potential energy of two like charges is positive.\nReason (R): Electric potential is always positive in the region surrounding a positive charge.", "explanation": "The assertion is correct: for two like charges (both positive or both negative), U = kq₁q₂/r is positive since the product q₁q₂ is positive. The reason is also correct: the potential around a positive charge is indeed positive (V = kq/r > 0 when q > 0). However, R does not explain A because A applies to both like positive and like negative charges, and the positivity of PE comes from the product of charges, not from the potential of a single charge.", "payload": {"question_id": "cuet-phy-pot-potential-14", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are independently true, R does not explain A. Two negative charges also have positive PE, but R talks about potential near positive charges only.", "misconception": "Assuming any two correct statements must be causally related"}, {"option_key": "C", "hint": "R is a correct statement — the potential around a positive point charge is indeed positive at all points.", "misconception": null}, {"option_key": "D", "hint": "A is correct — like charges (++ or −−) always give a positive product q₁q₂, making U = kq₁q₂/r positive.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["potential energy sign", "like charges", "electric potential sign"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the following physical situations (Column I) with the corresponding electric potential (Column II):\n\nColumn I:\nA. Inside a uniformly charged spherical shell\nB. At the surface of a uniformly charged spherical shell of radius R\nC. At a distance 2R from the centre of a uniformly charged spherical shell\nD. At infinity\n\nColumn II:\n1. Zero\n2. kQ/R\n3. kQ/2R\n4. kQ/R (same as at surface)", "explanation": "Inside the shell (A), the potential is constant and equal to the surface potential: kQ/R, so A→4. At the surface (B), V = kQ/R, so B→2. At distance 2R (C), V = kQ/2R, so C→3. At infinity (D), V = 0, so D→1.", "payload": {"question_id": "cuet-phy-pot-potential-15", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "C", "text": "A-4, B-2, C-3, D-1", "is_correct": true}, {"key": "D", "text": "A-3, B-2, C-4, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-1 implies zero potential inside the shell, which is incorrect. The potential inside is constant and equal to the surface potential kQ/R.", "misconception": "Confusing zero electric field inside shell with zero potential"}, {"option_key": "B", "hint": "A-2 and B-4 both give kQ/R but the match labels are swapped incorrectly in the list structure.", "misconception": null}, {"option_key": "D", "hint": "A-3 would give kQ/2R inside the shell, which is wrong. The potential inside is kQ/R, not kQ/2R.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["spherical shell potential", "potential variation", "matching"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the following quantities (Column I) with their distance dependence from a point charge (Column II):\n\nColumn I:\nA. Electric field due to point charge\nB. Electric potential due to point charge\nC. Electric field due to dipole (far field)\nD. Electric potential due to dipole (far field)\n\nColumn II:\n1. ∝ 1/r\n2. ∝ 1/r²\n3. ∝ 1/r³\n4. ∝ 1/r⁴", "explanation": "Electric field due to a point charge E = kq/r², so A→2. Electric potential due to a point charge V = kq/r, so B→1. Electric field due to a dipole varies as 1/r³, so C→3. Electric potential due to a dipole varies as 1/r², so D→2. Hence the correct matching is A-2, B-1, C-3, D-2.", "payload": {"question_id": "cuet-phy-pot-potential-16", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-3, D-2", "is_correct": true}, {"key": "C", "text": "A-2, B-1, C-4, D-3", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-4, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-1 would mean E ∝ 1/r for a point charge, but the correct dependence is E ∝ 1/r² (Coulomb''s law).", "misconception": "Confusing potential and field dependence for point charge"}, {"option_key": "C", "hint": "C-4 would mean dipole field varies as 1/r⁴, which is incorrect. Dipole field varies as 1/r³.", "misconception": null}, {"option_key": "D", "hint": "A-1 and B-2 are swapped — field goes as 1/r² and potential goes as 1/r for a point charge.", "misconception": "Mixing up field and potential dependencies"}]}, "correct_answer": "B", "concept_tags": ["distance dependence", "point charge", "dipole", "field and potential"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "Equipotential surfaces due to a point charge are concentric spheres centred on the charge.", "explanation": "This statement is TRUE. For a point charge, the potential V = kq/r depends only on the distance r from the charge. All points at the same distance r have the same potential, forming concentric spherical surfaces centred on the charge.", "payload": {"question_id": "cuet-phy-pot-potential-17", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is correct. Since V = kq/r, all points at equal distance r from the charge have the same potential, forming concentric spheres.", "misconception": "Thinking equipotential surfaces might have a different geometry for point charges"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["equipotential surface", "point charge", "spherical symmetry"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "Two equipotential surfaces can intersect each other.", "explanation": "This statement is FALSE. If two equipotential surfaces intersected, the point of intersection would have two different values of potential simultaneously, which is physically impossible since potential is a single-valued function of position.", "payload": {"question_id": "cuet-phy-pot-potential-18", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If two equipotential surfaces intersected, the point of intersection would have two different potential values, which violates the definition of a scalar field.", "misconception": "Thinking equipotential surfaces can cross like field lines in some cases"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["equipotential surface", "properties", "intersection"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_the_blank", "difficulty": "medium", "question_text": "A charge of 10 μC is placed at the origin. The potential at a point 0.3 m from the charge is _____ V. (Take k = 9 × 10⁹ N m² C⁻²)", "explanation": "Using V = kq/r = 9 × 10⁹ × 10 × 10⁻⁶ / 0.3 = 9 × 10⁹ × 10⁻⁵ / 0.3 = 9 × 10⁴ / 0.3 = 3 × 10⁵ V. The potential is 3 × 10⁵ V or 300000 V.", "payload": {"question_id": "cuet-phy-pot-potential-19", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "3 × 10⁴", "is_correct": false}, {"key": "B", "text": "9 × 10⁵", "is_correct": false}, {"key": "C", "text": "3 × 10⁶", "is_correct": false}, {"key": "D", "text": "3 × 10⁵", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "3 × 10⁴ is ten times too small. Check the power of ten in the calculation: 9 × 10⁹ × 10⁻⁵ = 9 × 10⁴, and dividing by 0.3 gives 3 × 10⁵.", "misconception": "Error in handling powers of ten"}, {"option_key": "B", "hint": "9 × 10⁵ would result from not dividing by 0.3 or using an incorrect distance.", "misconception": null}, {"option_key": "C", "hint": "3 × 10⁶ is ten times too large, likely from using the charge as 100 μC instead of 10 μC.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["electric potential calculation", "point charge", "numerical"]}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "scenario", "difficulty": "medium", "question_text": "In a laboratory experiment, a student places a +5 μC charge at point A and a +10 μC charge at point B, separated by a distance of 1 m. She wants to find a point on the line joining A and B where the electric potential is zero. She assumes both charges are in free space.\n\nThe student''s observation should be that:", "explanation": "Since both charges are positive, the potential V = kq₁/r₁ + kq₂/r₂ is always positive at every point on the line joining them (and everywhere in space, since both terms are positive). There is no point where the net potential is zero. For potential to be zero between two charges, the charges must be of opposite sign.", "payload": {"question_id": "cuet-phy-pot-potential-20", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential and Potential Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "The zero potential point lies between A and B at 1/3 m from A", "is_correct": false}, {"key": "B", "text": "The zero potential point lies between A and B at the midpoint", "is_correct": false}, {"key": "C", "text": "No point on the line joining A and B has zero potential", "is_correct": true}, {"key": "D", "text": "The zero potential point lies outside AB at 1 m from B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the null point for electric field (not potential) between charges of different magnitudes, and even then only for opposite charges would potential be zero between them.", "misconception": "Confusing zero field point with zero potential point"}, {"option_key": "B", "hint": "At the midpoint, both positive charges contribute positive potentials, so the net potential is positive, not zero.", "misconception": "Assuming symmetry implies zero potential"}, {"option_key": "D", "hint": "Even outside the charges, both positive charges contribute positive potentials at all points, so the potential cannot be zero anywhere.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["superposition of potential", "like charges", "zero potential"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-23');

