SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The self-inductance of a coil is defined as L = NΦ/I. The SI unit of self-inductance is:", "explanation": "Self-inductance L = NΦ/I has units of (Wb)/(A) = Wb/A. This unit is called the henry (H), named after Joseph Henry. 1 H = 1 Wb/A = 1 V·s/A = 1 kg·m²·s⁻²·A⁻².", "payload": {"question_id": "cuet-phy-emi-inductance-01", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "remember", "options": [{"key": "A", "text": "Henry (H)", "is_correct": true}, {"key": "B", "text": "Weber (Wb)", "is_correct": false}, {"key": "C", "text": "Tesla (T)", "is_correct": false}, {"key": "D", "text": "Farad (F)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Weber is the SI unit of magnetic flux (Φ), not inductance. Inductance L = NΦ/I, so its unit is Wb/A = Henry.", "misconception": "Confusing the unit of magnetic flux with that of inductance"}, {"option_key": "C", "hint": "Tesla is the SI unit of magnetic field B (magnetic flux density), not inductance. 1 T = 1 Wb/m².", "misconception": "Confusing magnetic field unit with inductance unit"}, {"option_key": "D", "hint": "Farad is the SI unit of capacitance (C = Q/V), not inductance. Though both farad and henry are properties of circuit elements, they describe different quantities.", "misconception": "Mixing up capacitance and inductance units"}]}, "correct_answer": "A", "concept_tags": ["self-inductance", "SI-unit", "henry"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A solenoid has 500 turns, length 0.5 m, and cross-sectional area 10 cm². Its self-inductance is (μ₀ = 4π × 10⁻⁷ H/m):", "explanation": "For a solenoid, L = μ₀n²Al, where n = N/l = 500/0.5 = 1000 turns/m, A = 10 cm² = 10 × 10⁻⁴ m² = 10⁻³ m², and l = 0.5 m. So L = 4π × 10⁻⁷ × (1000)² × 10⁻³ × 0.5 = 4π × 10⁻⁷ × 10⁶ × 5 × 10⁻⁴ = 4π × 10⁻⁷ × 500 = 2000π × 10⁻⁷ = 6.28 × 10⁻⁴ H ≈ 0.63 mH.", "payload": {"question_id": "cuet-phy-emi-inductance-02", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 × 10⁻³ H", "is_correct": false}, {"key": "B", "text": "6.28 × 10⁻⁵ H", "is_correct": false}, {"key": "C", "text": "6.28 × 10⁻⁴ H", "is_correct": true}, {"key": "D", "text": "3.14 × 10⁻⁴ H", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is 10 times too large. Recheck the area conversion: 10 cm² = 10 × 10⁻⁴ m² = 10⁻³ m², not 10⁻² m².", "misconception": "Incorrect unit conversion of area from cm² to m²"}, {"option_key": "B", "hint": "This is 10 times too small. Verify: L = 4π × 10⁻⁷ × (1000)² × 10⁻³ × 0.5 = 2π × 10⁻⁴ ≈ 6.28 × 10⁻⁴ H.", "misconception": "Error in powers of 10 during calculation"}, {"option_key": "D", "hint": "3.14 × 10⁻⁴ = π × 10⁻⁴, but the correct answer is 2π × 10⁻⁴ ≈ 6.28 × 10⁻⁴. A missing factor of 2 suggests an error in computing n² or the length.", "misconception": "Losing a factor of 2 in the calculation"}]}, "correct_answer": "C", "concept_tags": ["self-inductance", "solenoid", "numerical-problem"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The energy stored in an inductor of inductance 5 mH when a current of 4 A flows through it is:", "explanation": "Energy stored in an inductor is U = ½LI². Substituting L = 5 mH = 5 × 10⁻³ H and I = 4 A: U = ½ × 5 × 10⁻³ × (4)² = ½ × 5 × 10⁻³ × 16 = 40 × 10⁻³ J = 0.04 J = 40 mJ.", "payload": {"question_id": "cuet-phy-emi-inductance-03", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "apply", "options": [{"key": "A", "text": "20 mJ", "is_correct": false}, {"key": "B", "text": "40 mJ", "is_correct": true}, {"key": "C", "text": "80 mJ", "is_correct": false}, {"key": "D", "text": "10 mJ", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "20 mJ would result from using U = ½LI instead of ½LI². Remember energy depends on the square of current: U = ½ × 5 × 10⁻³ × 16 = 40 mJ.", "misconception": "Forgetting to square the current in energy formula"}, {"option_key": "C", "hint": "80 mJ = LI², which omits the factor of ½. The correct formula is U = ½LI², giving 40 mJ.", "misconception": "Forgetting the factor of ½ in the energy formula"}, {"option_key": "D", "hint": "10 mJ = ½LI, which uses I instead of I². With I = 4 A, I² = 16, so U = ½ × 5 × 10⁻³ × 16 = 40 mJ.", "misconception": "Using I instead of I² and also miscalculating"}]}, "correct_answer": "B", "concept_tags": ["energy-stored", "inductor", "numerical-problem"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A coil has a self-inductance of 0.2 H. If the current through it changes from 5 A to 2 A in 0.1 s, the magnitude of the induced EMF is:", "explanation": "The self-induced EMF is |ε| = L|dI/dt| = L × |ΔI/Δt| = 0.2 × |2 − 5|/0.1 = 0.2 × 3/0.1 = 0.2 × 30 = 6 V. The negative sign indicates the EMF opposes the change in current (Lenz''s law), but we are asked for the magnitude.", "payload": {"question_id": "cuet-phy-emi-inductance-04", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "apply", "options": [{"key": "A", "text": "0.6 V", "is_correct": false}, {"key": "B", "text": "1 V", "is_correct": false}, {"key": "C", "text": "3 V", "is_correct": false}, {"key": "D", "text": "6 V", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.6 V = L × ΔI = 0.2 × 3, which omits division by Δt. The EMF is L × ΔI/Δt = 0.2 × 3/0.1 = 6 V.", "misconception": "Forgetting to divide by the time interval"}, {"option_key": "B", "hint": "1 V = L/Δt = 0.2/0.1 × (some factor). Recheck: ΔI = |5 − 2| = 3 A, so ε = 0.2 × 3/0.1 = 6 V.", "misconception": "Using ΔI = 1 A instead of 3 A"}, {"option_key": "C", "hint": "3 V could result from computing ΔI/Δt = 30 but then multiplying by L = 0.1 instead of 0.2, or from omitting the Δt entirely.", "misconception": "Using incorrect inductance value or skipping time division"}]}, "correct_answer": "D", "concept_tags": ["self-inductance", "induced-emf", "rate-of-change", "numerical-problem"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two coils have self-inductances L₁ = 4 mH and L₂ = 9 mH. If the coefficient of coupling between them is 0.5, the mutual inductance is:", "explanation": "Mutual inductance M = k√(L₁L₂), where k is the coefficient of coupling. Substituting: M = 0.5 × √(4 × 10⁻³ × 9 × 10⁻³) = 0.5 × √(36 × 10⁻⁶) = 0.5 × 6 × 10⁻³ = 3 × 10⁻³ H = 3 mH.", "payload": {"question_id": "cuet-phy-emi-inductance-05", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "apply", "options": [{"key": "A", "text": "3 mH", "is_correct": true}, {"key": "B", "text": "6 mH", "is_correct": false}, {"key": "C", "text": "1.5 mH", "is_correct": false}, {"key": "D", "text": "9 mH", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "6 mH = √(L₁L₂), which means you forgot to multiply by the coupling coefficient k = 0.5. M = k√(L₁L₂) = 0.5 × 6 = 3 mH.", "misconception": "Omitting the coefficient of coupling"}, {"option_key": "C", "hint": "1.5 mH might result from using k² instead of k. The formula is M = k√(L₁L₂), not M = k²√(L₁L₂).", "misconception": "Squaring the coupling coefficient erroneously"}, {"option_key": "D", "hint": "9 mH = L₂, suggesting a confusion with one of the given self-inductances. M depends on both L₁ and L₂ through M = k√(L₁L₂).", "misconception": "Confusing mutual inductance with self-inductance of one coil"}]}, "correct_answer": "A", "concept_tags": ["mutual-inductance", "coefficient-of-coupling", "numerical-problem"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the number of turns in a solenoid is doubled while keeping its length and cross-sectional area the same, the self-inductance becomes:", "explanation": "The self-inductance of a solenoid is L = μ₀n²Al = μ₀(N/l)²Al = μ₀N²A/l. If N is doubled (N → 2N), then L → μ₀(2N)²A/l = 4μ₀N²A/l = 4L. Therefore, the self-inductance becomes four times the original value.", "payload": {"question_id": "cuet-phy-emi-inductance-06", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "understand", "options": [{"key": "A", "text": "Doubled", "is_correct": false}, {"key": "B", "text": "Halved", "is_correct": false}, {"key": "C", "text": "Four times", "is_correct": true}, {"key": "D", "text": "Eight times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "L depends on N² (or n²), not N. Since L ∝ N², doubling N gives L → 4L, not 2L.", "misconception": "Assuming inductance is linearly proportional to number of turns"}, {"option_key": "B", "hint": "Halving would mean L decreases, but adding more turns always increases inductance. L ∝ N², so doubling N gives 4L.", "misconception": "Inversely relating inductance with turns"}, {"option_key": "D", "hint": "Eight times (2³) would apply if L ∝ N³, but the correct relation is L ∝ N², giving 4L when N is doubled.", "misconception": "Using an incorrect power dependence on N"}]}, "correct_answer": "C", "concept_tags": ["self-inductance", "solenoid", "proportionality"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two coaxial solenoids S₁ and S₂ have the same length l. S₁ has radius r₁, n₁ turns per unit length, and S₂ (surrounding S₁) has radius r₂, n₂ turns per unit length. The mutual inductance between them is:", "explanation": "The magnetic field due to S₂ inside it is B₂ = μ₀n₂I₂. The flux through each turn of S₁ (which lies entirely inside S₂) is Φ = B₂ × πr₁² = μ₀n₂I₂πr₁². The total flux linkage with S₁ (having n₁l turns) is N₁Φ = n₁l × μ₀n₂I₂πr₁². By definition, M = N₁Φ/I₂ = μ₀n₁n₂πr₁²l. Note: the relevant area is that of the inner solenoid r₁, not r₂.", "payload": {"question_id": "cuet-phy-emi-inductance-07", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "understand", "options": [{"key": "A", "text": "μ₀n₁n₂πr₂²l", "is_correct": false}, {"key": "B", "text": "μ₀n₁n₂πr₁²l", "is_correct": true}, {"key": "C", "text": "μ₀n₁n₂π(r₁² + r₂²)l", "is_correct": false}, {"key": "D", "text": "μ₀n₁n₂πr₁r₂l", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Using r₂² assumes the flux through the outer solenoid''s area, but the relevant flux is only through the cross-section of the inner solenoid (area = πr₁²), since that is where S₁''s turns are located.", "misconception": "Using the area of the outer solenoid instead of the inner one"}, {"option_key": "C", "hint": "There is no reason to add the two areas. The flux through S₁ depends only on S₁''s cross-section πr₁², which is entirely immersed in the uniform field of S₂.", "misconception": "Incorrectly combining both areas"}, {"option_key": "D", "hint": "The geometric mean r₁r₂ does not appear in this derivation. The flux through each turn of S₁ is B₂ × πr₁², where r₁ is the radius of the inner solenoid.", "misconception": "Using geometric mean of radii instead of inner solenoid area"}]}, "correct_answer": "B", "concept_tags": ["mutual-inductance", "coaxial-solenoids", "flux-linkage"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LR circuit with a battery of EMF ε, resistance R, and inductance L, the time constant τ is defined as:", "explanation": "The time constant of an LR circuit is τ = L/R. During growth of current, I = (ε/R)(1 − e^(−Rt/L)) = I₀(1 − e^(−t/τ)). At t = τ = L/R, the current reaches (1 − 1/e) ≈ 63.2% of its maximum value I₀ = ε/R. The time constant has units of H/Ω = (V·s/A)/(V/A) = s.", "payload": {"question_id": "cuet-phy-emi-inductance-08", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "remember", "options": [{"key": "A", "text": "R/L", "is_correct": false}, {"key": "B", "text": "RL", "is_correct": false}, {"key": "C", "text": "√(L/R)", "is_correct": false}, {"key": "D", "text": "L/R", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "R/L has units of Ω/H = (V/A)/(V·s/A) = 1/s, which is the reciprocal of time. The time constant must have units of time, so τ = L/R, not R/L.", "misconception": "Inverting the L/R ratio"}, {"option_key": "B", "hint": "RL has units of Ω·H = (V/A)(V·s/A) = V²·s/A², which is not a unit of time. The correct time constant is L/R.", "misconception": "Multiplying instead of dividing L and R"}, {"option_key": "C", "hint": "√(L/R) has units of √(H/Ω) = √s, which is not a time unit. The time constant for an LR circuit is simply τ = L/R. (Compare: the time constant for an RC circuit is τ = RC.)", "misconception": "Confusing LR time constant with some other expression"}]}, "correct_answer": "D", "concept_tags": ["LR-circuit", "time-constant", "exponential-growth"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two coils have a mutual inductance of 0.5 H. If the current in the first coil changes at the rate of 10 A/s, the EMF induced in the second coil is:", "explanation": "The EMF induced in the second coil due to changing current in the first coil is |ε₂| = M × |dI₁/dt| = 0.5 × 10 = 5 V. The negative sign in ε₂ = −M(dI₁/dt) indicates the direction of induced EMF opposes the change, by Lenz''s law.", "payload": {"question_id": "cuet-phy-emi-inductance-09", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "apply", "options": [{"key": "A", "text": "0.5 V", "is_correct": false}, {"key": "B", "text": "10 V", "is_correct": false}, {"key": "C", "text": "5 V", "is_correct": true}, {"key": "D", "text": "20 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.5 V equals just M. The EMF is not simply the mutual inductance; it is ε = M × dI/dt = 0.5 × 10 = 5 V.", "misconception": "Forgetting to multiply by the rate of change of current"}, {"option_key": "B", "hint": "10 V equals dI/dt alone. The EMF depends on M as well: ε = M × dI/dt = 0.5 × 10 = 5 V.", "misconception": "Ignoring the mutual inductance and using only the rate of change"}, {"option_key": "D", "hint": "20 V = M × (dI/dt)² / some factor. Simply apply ε = M × dI/dt = 0.5 × 10 = 5 V. No squaring is needed.", "misconception": "Squaring the rate of change or making arithmetic error"}]}, "correct_answer": "C", "concept_tags": ["mutual-inductance", "induced-emf", "rate-of-change"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In an LR circuit, a battery of EMF 12 V is connected in series with a resistance of 4 Ω and an inductor of 2 H. The maximum (steady-state) current in the circuit is:", "explanation": "At steady state (t → ∞), the inductor behaves as a short circuit (since dI/dt = 0, the back EMF = 0). The steady-state current is I₀ = ε/R = 12/4 = 3 A. The current growth follows I = 3(1 − e^(−2t)) A, where τ = L/R = 2/4 = 0.5 s.", "payload": {"question_id": "cuet-phy-emi-inductance-10", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "apply", "options": [{"key": "A", "text": "6 A", "is_correct": false}, {"key": "B", "text": "3 A", "is_correct": true}, {"key": "C", "text": "2 A", "is_correct": false}, {"key": "D", "text": "24 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 A = ε/L = 12/2, but inductance does not limit the steady-state current. At steady state, dI/dt = 0, so the inductor has zero impedance and I = ε/R = 12/4 = 3 A.", "misconception": "Using inductance instead of resistance to find steady-state current"}, {"option_key": "C", "hint": "2 A = ε/(R + L) = 12/6, but inductance and resistance cannot be simply added. At steady state, only resistance limits current: I = ε/R = 3 A.", "misconception": "Adding inductance and resistance as if they were both resistances"}, {"option_key": "D", "hint": "24 A = ε × L = 12 × 2, which is dimensionally incorrect. Maximum current = ε/R = 12/4 = 3 A.", "misconception": "Multiplying EMF by inductance instead of dividing by resistance"}]}, "correct_answer": "B", "concept_tags": ["LR-circuit", "steady-state-current", "ohms-law"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An inductor of self-inductance L carries a current I. If the current is reduced to half in time t, the average power dissipated by the circuit as the magnetic energy is released is:", "explanation": "The energy stored at current I is U₁ = ½LI². The energy at current I/2 is U₂ = ½L(I/2)² = ½LI²/4 = LI²/8. The energy released is ΔU = U₁ − U₂ = LI²/2 − LI²/8 = 4LI²/8 − LI²/8 = 3LI²/8. The average power dissipated = ΔU/t = 3LI²/(8t).", "payload": {"question_id": "cuet-phy-emi-inductance-11", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "analyze", "options": [{"key": "A", "text": "LI²/(2t)", "is_correct": false}, {"key": "B", "text": "LI²/(4t)", "is_correct": false}, {"key": "C", "text": "LI²/(8t)", "is_correct": false}, {"key": "D", "text": "3LI²/(8t)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "LI²/(2t) = U₁/t, which assumes all the stored energy is released. But the current is only reduced to I/2, not to zero. Remaining energy = LI²/8.", "misconception": "Assuming all stored energy is released when current is halved"}, {"option_key": "B", "hint": "LI²/(4t) would be (U₁ − U₂)/t only if U₂ = LI²/4. But U₂ = ½L(I/2)² = LI²/8, so ΔU = LI²/2 − LI²/8 = 3LI²/8.", "misconception": "Incorrectly computing the final stored energy"}, {"option_key": "C", "hint": "LI²/(8t) = U₂/t, the remaining energy divided by time. The dissipated energy is the difference: U₁ − U₂ = 3LI²/8, not U₂.", "misconception": "Confusing remaining energy with dissipated energy"}]}, "correct_answer": "D", "concept_tags": ["energy-stored", "inductor", "power", "numerical-problem"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A solenoid of inductance L = 2 H and resistance R = 10 Ω is connected to a 20 V battery at t = 0. The current in the circuit at t = 0.2 s is approximately (given e⁻¹ ≈ 0.37):", "explanation": "For an LR circuit, I = (ε/R)(1 − e^(−Rt/L)). Here ε/R = 20/10 = 2 A, and Rt/L = 10 × 0.2/2 = 1. So I = 2(1 − e⁻¹) = 2(1 − 0.37) = 2 × 0.63 = 1.26 A.", "payload": {"question_id": "cuet-phy-emi-inductance-12", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "apply", "options": [{"key": "A", "text": "1.26 A", "is_correct": true}, {"key": "B", "text": "0.74 A", "is_correct": false}, {"key": "C", "text": "2 A", "is_correct": false}, {"key": "D", "text": "0.37 A", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "0.74 A = 2 × 0.37 = 2e⁻¹, which would be the current if the formula were I = I₀e⁻ᵗ/τ (decay). But this is a growth problem: I = I₀(1 − e⁻ᵗ/τ) = 2 × 0.63 = 1.26 A.", "misconception": "Using the decay formula instead of growth formula"}, {"option_key": "C", "hint": "2 A is the maximum steady-state current (ε/R). At t = 0.2 s = τ, the current has reached only 63.2% of this value, i.e., 1.26 A.", "misconception": "Assuming current reaches maximum instantaneously"}, {"option_key": "D", "hint": "0.37 A = e⁻¹ × 1 A. This confuses several quantities. The correct calculation is I = 2(1 − 0.37) = 1.26 A.", "misconception": "Misapplying the exponential factor"}]}, "correct_answer": "A", "concept_tags": ["LR-circuit", "current-growth", "exponential", "numerical-problem"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The self-inductance of a solenoid depends on the number of turns, cross-sectional area, and length, but not on the current flowing through it.\nReason (R): Self-inductance is a geometric property of the coil and depends only on its shape, size, and the medium in which it is placed.", "explanation": "Both Assertion and Reason are correct, and R is the correct explanation of A. The formula L = μ₀n²Al = μ₀N²A/l for a solenoid shows that L depends on n (turns per unit length), A (area), l (length), and μ₀ (medium property). Current I does not appear in this expression. This is because L is a geometric property — it characterises the coil''s ability to produce flux linkage per unit current, which is independent of the actual current flowing.", "payload": {"question_id": "cuet-phy-emi-inductance-13", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly explains why L does not depend on current — because L is a geometric property depending only on the coil''s physical configuration and the medium. This is exactly the explanation for the Assertion.", "misconception": "Failing to see the direct causal link between L being a geometric property and its independence from current"}, {"option_key": "C", "hint": "The Reason is correct. Self-inductance is indeed a geometric property, analogous to how capacitance depends on the geometry of the capacitor, not on the charge stored.", "misconception": "Incorrectly thinking inductance depends on current"}, {"option_key": "D", "hint": "The Assertion is correct. L = μ₀N²A/l clearly shows no dependence on current I. This is a standard NCERT result.", "misconception": "Believing self-inductance changes with current"}]}, "correct_answer": "A", "concept_tags": ["self-inductance", "solenoid", "geometric-property", "assertion-reasoning"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Eddy currents produced in a metallic conductor placed in a changing magnetic field always oppose the change in magnetic flux through the conductor.\nReason (R): Eddy currents flow only on the surface of the conductor and never penetrate into its interior.", "explanation": "A is correct: eddy currents are induced due to changing magnetic flux and, by Lenz''s law, they always act to oppose the change in flux that produces them. R is incorrect: eddy currents are not restricted to the surface; they flow throughout the bulk of the conductor. The depth to which they penetrate (skin depth) depends on the frequency of the changing field, the conductivity, and permeability of the material. At low frequencies, eddy currents penetrate deep into the conductor''s volume.", "payload": {"question_id": "cuet-phy-emi-inductance-14", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The Reason is factually wrong — eddy currents do not flow only on the surface. They circulate through the bulk of the conductor. Since R is incorrect, this option cannot be right.", "misconception": "Believing eddy currents are purely a surface phenomenon"}, {"option_key": "B", "hint": "This option requires both A and R to be correct. While A is correct (Lenz''s law), R is incorrect because eddy currents penetrate into the conductor''s interior, not just the surface.", "misconception": "Accepting the false claim that eddy currents are surface-only"}, {"option_key": "D", "hint": "The Assertion is correct. Eddy currents opposing the change in flux is a direct consequence of Lenz''s law, which is well-established physics.", "misconception": "Doubting that Lenz''s law governs eddy current direction"}]}, "correct_answer": "C", "concept_tags": ["eddy-currents", "lenz-law", "skin-depth", "assertion-reasoning"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Self-inductance of a solenoid\n(Q) Energy stored in an inductor\n(R) Mutual inductance between coupled coils\n(S) EMF induced by self-inductance\n\nColumn II:\n(1) −L(dI/dt)\n(2) μ₀n²Al\n(3) ½LI²\n(4) k√(L₁L₂)", "explanation": "P-2: The self-inductance of a solenoid is L = μ₀n²Al, where n is turns per unit length, A is cross-sectional area, and l is length. Q-3: Energy stored in an inductor is U = ½LI². R-4: Mutual inductance M = k√(L₁L₂), where k is the coefficient of coupling. S-1: The self-induced EMF is ε = −L(dI/dt). The correct matching is P-2, Q-3, R-4, S-1.", "payload": {"question_id": "cuet-phy-emi-inductance-15", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "understand", "options": [{"key": "A", "text": "P-2, Q-4, R-3, S-1", "is_correct": false}, {"key": "B", "text": "P-1, Q-3, R-4, S-2", "is_correct": false}, {"key": "C", "text": "P-2, Q-3, R-1, S-4", "is_correct": false}, {"key": "D", "text": "P-2, Q-3, R-4, S-1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Q-4 assigns k√(L₁L₂) to energy stored, but that is the formula for mutual inductance. Energy stored is ½LI² (option 3).", "misconception": "Swapping energy formula with mutual inductance formula"}, {"option_key": "B", "hint": "P-1 assigns −L(dI/dt) to self-inductance, but that is the induced EMF, not the inductance itself. Self-inductance of a solenoid is μ₀n²Al (option 2).", "misconception": "Confusing the definition of inductance with the formula for induced EMF"}, {"option_key": "C", "hint": "R-1 assigns −L(dI/dt) to mutual inductance, but that is the self-induced EMF. Mutual inductance is M = k√(L₁L₂) (option 4).", "misconception": "Confusing self-induced EMF with mutual inductance"}]}, "correct_answer": "D", "concept_tags": ["self-inductance", "energy-stored", "mutual-inductance", "induced-emf", "formulas"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I (Phenomenon/Application) with Column II (Principle involved):\n\nColumn I:\n(P) Induction furnace for melting metals\n(Q) Laminated core in a transformer\n(R) Electromagnetic damping of a galvanometer\n(S) Spark plug in automobile ignition system\n\nColumn II:\n(1) Reducing eddy current losses by increasing resistance of eddy current paths\n(2) Large induced EMF due to rapid change of current in an inductor (back-EMF)\n(3) Heating effect of eddy currents in a conductor placed in a changing magnetic field\n(4) Retarding force due to eddy currents opposing motion, in accordance with Lenz''s law", "explanation": "P-3: An induction furnace uses the heating effect of eddy currents — alternating magnetic fields induce large eddy currents in the metal, and resistive heating (I²R) melts it. Q-1: Laminated cores use thin insulated sheets to break up eddy current loops, increasing resistance and reducing energy loss. R-4: Electromagnetic damping uses eddy currents induced in the coil frame to create a retarding force that dampens oscillations. S-2: A spark plug uses the large back-EMF generated when current through an inductor is suddenly interrupted (ε = −LdI/dt with very large dI/dt).", "payload": {"question_id": "cuet-phy-emi-inductance-16", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-3, Q-4, R-1, S-2", "is_correct": false}, {"key": "B", "text": "P-1, Q-3, R-4, S-2", "is_correct": false}, {"key": "C", "text": "P-3, Q-1, R-4, S-2", "is_correct": true}, {"key": "D", "text": "P-3, Q-1, R-2, S-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q-4 assigns eddy current retarding force to laminated cores, but lamination reduces eddy currents by increasing the resistance of eddy current paths (option 1). The retarding force applies to electromagnetic damping (R).", "misconception": "Confusing the purpose of lamination with electromagnetic damping"}, {"option_key": "B", "hint": "P-1 assigns eddy current loss reduction to the induction furnace, but the furnace deliberately uses heating by eddy currents (option 3). Lamination (Q) is where loss reduction applies.", "misconception": "Reversing induction furnace and lamination principles"}, {"option_key": "D", "hint": "R-2 assigns back-EMF to galvanometer damping, but damping uses the retarding force of eddy currents (option 4). The spark plug (S) uses back-EMF from rapid current interruption.", "misconception": "Swapping electromagnetic damping and spark plug principles"}]}, "correct_answer": "C", "concept_tags": ["eddy-currents", "induction-furnace", "laminated-core", "electromagnetic-damping", "spark-plug", "applications"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The coefficient of coupling k between two coils always lies in the range 0 ≤ k ≤ 1.", "explanation": "This is TRUE. The coefficient of coupling k = M/√(L₁L₂) ranges from 0 (no magnetic flux linkage between coils) to 1 (all flux from one coil links with the other, i.e., perfect coupling). By the energy method, it can be shown that M cannot exceed √(L₁L₂), ensuring k ≤ 1. In practice, k < 1 due to flux leakage.", "payload": {"question_id": "cuet-phy-emi-inductance-17", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is correct. By definition, k = M/√(L₁L₂), and since M cannot exceed √(L₁L₂) (proven from energy considerations), k always lies between 0 and 1 inclusive.", "misconception": "Thinking the coupling coefficient can exceed 1 or be negative"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["coefficient-of-coupling", "mutual-inductance", "range"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Eddy currents can be completely eliminated by using laminated cores in transformers.", "explanation": "This is FALSE. Laminated cores reduce eddy currents significantly but do not eliminate them completely. Lamination works by dividing the core into thin insulated sheets, which increases the resistance of eddy current paths and thereby reduces their magnitude. However, small eddy currents still flow within each lamination. Complete elimination would require a non-conducting core, which would lose the advantage of high permeability.", "payload": {"question_id": "cuet-phy-emi-inductance-18", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Lamination reduces eddy currents but cannot eliminate them completely. Within each thin lamination, small eddy currents still circulate. The key word ''completely'' makes this statement false.", "misconception": "Believing lamination completely eliminates eddy currents rather than just reducing them"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["eddy-currents", "laminated-core", "transformer", "reduction"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A solenoid of length 1 m has 2000 turns and a cross-sectional area of 5 × 10⁻⁴ m². The energy stored in it when a current of 2 A flows through it is _____ J. (μ₀ = 4π × 10⁻⁷ H/m)", "explanation": "First, calculate the self-inductance: L = μ₀n²Al = μ₀(N/l)²Al = μ₀N²A/l = 4π × 10⁻⁷ × (2000)² × 5 × 10⁻⁴ / 1 = 4π × 10⁻⁷ × 4 × 10⁶ × 5 × 10⁻⁴ = 4π × 10⁻⁷ × 2000 = 8000π × 10⁻⁷ = 8π × 10⁻⁴ H ≈ 2.513 × 10⁻³ H. Energy: U = ½LI² = ½ × 2.513 × 10⁻³ × 4 = 5.026 × 10⁻³ J ≈ 5.03 × 10⁻³ J.", "payload": {"question_id": "cuet-phy-emi-inductance-19", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "apply", "options": [{"key": "A", "text": "5.03 × 10⁻³", "is_correct": true}, {"key": "B", "text": "2.51 × 10⁻³", "is_correct": false}, {"key": "C", "text": "1.01 × 10⁻²", "is_correct": false}, {"key": "D", "text": "5.03 × 10⁻⁴", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "2.51 × 10⁻³ equals ½LI = ½ × 2.513 × 10⁻³ × 2, which uses I instead of I². The correct formula is U = ½LI² = ½L × 4 = 2L ≈ 5.03 × 10⁻³ J.", "misconception": "Using I instead of I² in the energy formula"}, {"option_key": "C", "hint": "1.01 × 10⁻² = LI², which omits the factor of ½. The energy stored is U = ½LI², not LI².", "misconception": "Forgetting the factor of ½ in the energy expression"}, {"option_key": "D", "hint": "5.03 × 10⁻⁴ is ten times too small. Recheck: L ≈ 2.513 × 10⁻³ H, so U = ½ × 2.513 × 10⁻³ × 4 = 5.03 × 10⁻³ J.", "misconception": "Error in powers of 10"}]}, "correct_answer": "A", "concept_tags": ["self-inductance", "solenoid", "energy-stored", "numerical-problem"]}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-emi-inductance", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a physics laboratory, a student wraps a small coil (coil S) of 20 turns and area 4 cm² tightly around the centre of a long solenoid (coil P) of 1000 turns, length 0.5 m, and cross-sectional area 25 cm². The current in coil P changes at a constant rate of 5 A/s. The magnitude of EMF induced in coil S is (μ₀ = 4π × 10⁻⁷ H/m):", "explanation": "The mutual inductance between the solenoid (P) and the small coil (S) is M = μ₀ × n_P × N_S × A_S, where n_P = N_P/l = 1000/0.5 = 2000 turns/m, N_S = 20, and A_S = 4 cm² = 4 × 10⁻⁴ m² (the relevant area is of the smaller coil S, which is entirely inside P). So M = 4π × 10⁻⁷ × 2000 × 20 × 4 × 10⁻⁴ = 4π × 10⁻⁷ × 16 = 64π × 10⁻⁷ = 6.4π × 10⁻⁶ H ≈ 2.01 × 10⁻⁵ H. The induced EMF: |ε| = M × |dI/dt| = 2.01 × 10⁻⁵ × 5 ≈ 1.005 × 10⁻⁴ V ≈ 0.1 mV.", "payload": {"question_id": "cuet-phy-emi-inductance-20", "subtopic": "Self and Mutual Inductance, Eddy Currents", "topic_name": "Self and Mutual Inductance, Eddy Currents", "bloom_level": "apply", "options": [{"key": "A", "text": "0.63 mV", "is_correct": false}, {"key": "B", "text": "0.10 mV", "is_correct": true}, {"key": "C", "text": "1.0 mV", "is_correct": false}, {"key": "D", "text": "0.025 mV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.63 mV would result from using the solenoid''s cross-sectional area (25 cm²) instead of the small coil''s area (4 cm²). Since coil S is smaller than P, the flux through each turn of S depends on its own area, A_S = 4 cm².", "misconception": "Using the larger solenoid''s area instead of the smaller coil''s area for flux calculation"}, {"option_key": "C", "hint": "1.0 mV is about 10 times too large. Recheck: M = 4π × 10⁻⁷ × 2000 × 20 × 4 × 10⁻⁴ ≈ 2.01 × 10⁻⁵ H, and ε = M × 5 ≈ 1.0 × 10⁻⁴ V = 0.10 mV.", "misconception": "Power of 10 error in computation"}, {"option_key": "D", "hint": "0.025 mV is about 4 times too small. This could result from omitting N_S (using 1 turn instead of 20) and other arithmetic errors. M depends on both n_P and N_S.", "misconception": "Omitting the number of turns of the secondary coil"}]}, "correct_answer": "B", "concept_tags": ["mutual-inductance", "coaxial-solenoids", "induced-emf", "numerical-problem", "laboratory"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-27');

