SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic dipole moment of a bar magnet of pole strength m and magnetic length 2l is:", "explanation": "The magnetic dipole moment M of a bar magnet is defined as the product of pole strength (m) and the magnetic length (2l), i.e., M = m × 2l. The direction of M is from the south pole to the north pole inside the magnet.", "payload": {"question_id": "cuet-phy-magmat-dipole-01", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "remember", "options": [{"key": "A", "text": "m/2l", "is_correct": false}, {"key": "B", "text": "m × 2l", "is_correct": true}, {"key": "C", "text": "m × l", "is_correct": false}, {"key": "D", "text": "m²× 2l", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Dividing pole strength by length gives units of A (ampere), not A·m². The dipole moment is a product, not a ratio.", "misconception": "Confusing dipole moment formula as a ratio"}, {"option_key": "C", "hint": "The magnetic length of the bar magnet is 2l, not l. Using l would give only half the correct magnetic moment.", "misconception": "Using half-length instead of full magnetic length"}, {"option_key": "D", "hint": "The pole strength appears to the first power in the dipole moment formula, not squared. M = m × 2l, not m² × 2l.", "misconception": "Incorrectly squaring the pole strength"}]}, "correct_answer": "B", "concept_tags": ["magnetic-dipole-moment", "bar-magnet", "pole-strength"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of magnetic dipole moment is:", "explanation": "Magnetic dipole moment M = NIA (for a current loop) or M = m × 2l (for a bar magnet). Its SI unit is A·m² (ampere-metre squared). This can be verified from M = NIA where current is in amperes and area in m².", "payload": {"question_id": "cuet-phy-magmat-dipole-02", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "remember", "options": [{"key": "A", "text": "A·m²", "is_correct": true}, {"key": "B", "text": "A/m²", "is_correct": false}, {"key": "C", "text": "A·m", "is_correct": false}, {"key": "D", "text": "A/m", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A/m² is the SI unit of magnetisation (magnetic moment per unit volume), not the magnetic dipole moment itself.", "misconception": "Confusing magnetic moment with magnetisation"}, {"option_key": "C", "hint": "A·m is the unit of pole strength, not magnetic dipole moment. The moment equals pole strength times length, giving A·m × m = A·m².", "misconception": "Confusing pole strength unit with dipole moment unit"}, {"option_key": "D", "hint": "A/m is the SI unit of magnetic field intensity H, not the magnetic dipole moment.", "misconception": "Confusing with unit of magnetic field intensity"}]}, "correct_answer": "A", "concept_tags": ["magnetic-moment-unit", "SI-unit", "current-loop"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The angle of declination at a place is defined as the angle between:", "explanation": "Declination (or magnetic declination) is the angle between the geographic north (true north) and the magnetic north at a given location on the Earth''s surface. It is one of the three elements of Earth''s magnetism, along with dip and horizontal component.", "payload": {"question_id": "cuet-phy-magmat-dipole-03", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "remember", "options": [{"key": "A", "text": "The magnetic meridian and the horizontal plane", "is_correct": false}, {"key": "B", "text": "The geographic meridian and the horizontal plane", "is_correct": false}, {"key": "C", "text": "The geographic meridian and the magnetic meridian", "is_correct": true}, {"key": "D", "text": "The magnetic axis and the rotational axis of Earth", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The angle between the magnetic meridian and the horizontal plane describes the angle of dip (inclination), not declination.", "misconception": "Confusing declination with dip"}, {"option_key": "B", "hint": "The geographic meridian is a vertical plane; its angle with the horizontal is always 90°. Declination is measured in the horizontal plane between two meridians.", "misconception": "Confusing the definition of meridian with horizontal plane"}, {"option_key": "D", "hint": "While the magnetic axis is tilted relative to Earth''s rotational axis (~11.3°), declination is measured locally at each point on the surface between the two meridians.", "misconception": "Confusing global axis tilt with local declination angle"}]}, "correct_answer": "C", "concept_tags": ["declination", "earth-magnetism", "geographic-north", "magnetic-north"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A current loop carrying current I and having area A behaves as a magnetic dipole with moment:", "explanation": "A planar current loop of N turns, each carrying current I and enclosing area A, acts as a magnetic dipole with magnetic moment M = NIA. For a single turn (N = 1), M = IA. The direction of M is given by the right-hand rule: curl the fingers in the direction of current, and the thumb points along M.", "payload": {"question_id": "cuet-phy-magmat-dipole-04", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "remember", "options": [{"key": "A", "text": "M = I/A", "is_correct": false}, {"key": "B", "text": "M = I²A", "is_correct": false}, {"key": "C", "text": "M = IA²", "is_correct": false}, {"key": "D", "text": "M = IA", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Dividing current by area gives A/m², which is the unit of current density, not magnetic moment. The moment is the product I × A.", "misconception": "Confusing dipole moment with current density"}, {"option_key": "B", "hint": "The current appears to the first power in M = IA. Squaring the current has no physical basis in the magnetic moment formula.", "misconception": "Incorrectly squaring the current"}, {"option_key": "C", "hint": "The area appears to the first power. IA² would have units of A·m⁴, which is not the unit of magnetic moment (A·m²).", "misconception": "Incorrectly squaring the area"}]}, "correct_answer": "D", "concept_tags": ["current-loop", "magnetic-dipole", "magnetic-moment"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field on the axial line of a short bar magnet at a distance r from its centre is B₁, and the field on the equatorial line at the same distance is B₂. The ratio B₁/B₂ is:", "explanation": "For a short bar magnet (magnetic dipole), the axial field is B_axial = (μ₀/4π)(2M/r³) and the equatorial field is B_equatorial = (μ₀/4π)(M/r³). Therefore, B₁/B₂ = 2M/r³ ÷ M/r³ = 2. The axial field is always twice the equatorial field at the same distance.", "payload": {"question_id": "cuet-phy-magmat-dipole-05", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "understand", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "1/2", "is_correct": false}, {"key": "C", "text": "2", "is_correct": true}, {"key": "D", "text": "4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A ratio of 1 would mean the axial and equatorial fields are equal, but the axial field formula has an extra factor of 2 compared to the equatorial field.", "misconception": "Thinking axial and equatorial fields are equal"}, {"option_key": "B", "hint": "A ratio of 1/2 would mean the axial field is weaker than the equatorial field. In fact, the axial field is stronger (has the factor 2).", "misconception": "Inverting the axial-to-equatorial ratio"}, {"option_key": "D", "hint": "A ratio of 4 would require the axial field to have a factor of 4M instead of 2M. The correct axial field is (μ₀/4π)(2M/r³).", "misconception": "Squaring the factor of 2"}]}, "correct_answer": "C", "concept_tags": ["axial-field", "equatorial-field", "bar-magnet", "field-ratio"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A short bar magnet of magnetic moment 0.4 J/T is placed in a uniform magnetic field of 0.16 T. The torque on the magnet when it makes an angle of 30° with the field is:", "explanation": "Torque τ = MB sinθ = 0.4 × 0.16 × sin30° = 0.4 × 0.16 × 0.5 = 0.032 N·m. The torque acts to align the magnetic moment with the external field direction.", "payload": {"question_id": "cuet-phy-magmat-dipole-06", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "apply", "options": [{"key": "A", "text": "0.064 N·m", "is_correct": false}, {"key": "B", "text": "0.032 N·m", "is_correct": true}, {"key": "C", "text": "0.016 N·m", "is_correct": false}, {"key": "D", "text": "0.08 N·m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.064 = 0.4 × 0.16, which omits the sin30° = 0.5 factor. The torque formula is MB sinθ, not just MB.", "misconception": "Forgetting to multiply by sinθ"}, {"option_key": "C", "hint": "0.016 would result from an extra factor of 1/2, perhaps from using sin30° twice. The correct calculation is 0.4 × 0.16 × 0.5 = 0.032.", "misconception": "Applying an extra factor of 1/2"}, {"option_key": "D", "hint": "0.08 = 0.4 × 0.2. Check the field value: it is 0.16 T, not 0.2 T.", "misconception": "Misreading the given field value"}]}, "correct_answer": "B", "concept_tags": ["torque-on-dipole", "magnetic-field", "numerical-problem"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "At a place, the horizontal component of Earth''s magnetic field is Bₕ = 0.3 G and the angle of dip is 60°. The total magnetic field of the Earth at that place is:", "explanation": "The relation between horizontal component and total field is Bₕ = B cosδ, where δ is the angle of dip. Therefore B = Bₕ/cosδ = 0.3/cos60° = 0.3/0.5 = 0.6 G. The total field B has both horizontal (Bₕ) and vertical (Bᵥ) components.", "payload": {"question_id": "cuet-phy-magmat-dipole-07", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "apply", "options": [{"key": "A", "text": "0.15 G", "is_correct": false}, {"key": "B", "text": "0.3 G", "is_correct": false}, {"key": "C", "text": "0.45 G", "is_correct": false}, {"key": "D", "text": "0.6 G", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.15 G = Bₕ × cos60°, which would give Bₕ × cosδ = a component, not the total field. You need to divide by cosδ, not multiply.", "misconception": "Multiplying by cosδ instead of dividing"}, {"option_key": "B", "hint": "0.3 G is the horizontal component itself, not the total field. The total field is always greater than or equal to the horizontal component.", "misconception": "Confusing horizontal component with total field"}, {"option_key": "C", "hint": "0.45 G = 0.3 × 1.5, which doesn''t follow from any correct formula. Use B = Bₕ/cos60° = 0.3/0.5 = 0.6 G.", "misconception": "Arithmetic error in the division"}]}, "correct_answer": "D", "concept_tags": ["earth-magnetic-field", "dip-angle", "horizontal-component", "numerical"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A bar magnet of magnetic moment M is cut into two equal halves along its length. The magnetic moment of each half is:", "explanation": "When a bar magnet is cut into two equal halves along its length (longitudinally), the pole strength of each half becomes m/2 (since the cross-section is halved), but the magnetic length remains 2l. Therefore, the magnetic moment of each half = (m/2) × 2l = M/2.", "payload": {"question_id": "cuet-phy-magmat-dipole-08", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "understand", "options": [{"key": "A", "text": "M/2", "is_correct": true}, {"key": "B", "text": "M", "is_correct": false}, {"key": "C", "text": "2M", "is_correct": false}, {"key": "D", "text": "M/4", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The moment cannot remain M because the pole strength is halved when the cross-section is divided. M = (m/2) × 2l = M/2.", "misconception": "Thinking that cutting along length does not change the moment"}, {"option_key": "C", "hint": "Cutting a magnet cannot increase its magnetic moment. The total moment of all pieces cannot exceed the original moment.", "misconception": "Incorrectly doubling the moment"}, {"option_key": "D", "hint": "M/4 would result if both pole strength and length were halved, but longitudinal cutting only halves the pole strength, not the length.", "misconception": "Confusing longitudinal cutting with a combination of longitudinal and transverse cuts"}]}, "correct_answer": "A", "concept_tags": ["bar-magnet-cutting", "magnetic-moment", "pole-strength"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The potential energy of a magnetic dipole in a uniform magnetic field B is minimum when the angle between M and B is:", "explanation": "The potential energy of a magnetic dipole is U = −M·B = −MB cosθ. This is minimum when cosθ is maximum, i.e., cosθ = 1, which gives θ = 0°. At this position, the dipole is aligned with the field and is in stable equilibrium.", "payload": {"question_id": "cuet-phy-magmat-dipole-09", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "understand", "options": [{"key": "A", "text": "0°", "is_correct": true}, {"key": "B", "text": "90°", "is_correct": false}, {"key": "C", "text": "180°", "is_correct": false}, {"key": "D", "text": "45°", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "At θ = 90°, U = −MB cos90° = 0, which is neither the minimum nor the maximum value of potential energy.", "misconception": "Confusing zero energy with minimum energy"}, {"option_key": "C", "hint": "At θ = 180°, U = −MB cos180° = +MB, which is the maximum potential energy (unstable equilibrium), not the minimum.", "misconception": "Confusing unstable equilibrium with stable equilibrium"}, {"option_key": "D", "hint": "At θ = 45°, U = −MB cos45° = −MB/√2, which is less than zero but not the minimum. The minimum occurs at θ = 0° where U = −MB.", "misconception": "Choosing an arbitrary intermediate angle"}]}, "correct_answer": "A", "concept_tags": ["potential-energy", "stable-equilibrium", "magnetic-dipole"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at a point on the axial line of a short bar magnet at a distance of 20 cm is 4 × 10⁻⁶ T. The magnetic field at a point on the equatorial line at the same distance is:", "explanation": "For a short bar magnet, B_axial = (μ₀/4π)(2M/r³) and B_equatorial = (μ₀/4π)(M/r³). Therefore B_equatorial = B_axial/2 = 4 × 10⁻⁶/2 = 2 × 10⁻⁶ T. The equatorial field is always half the axial field at the same distance from the centre.", "payload": {"question_id": "cuet-phy-magmat-dipole-10", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "apply", "options": [{"key": "A", "text": "4 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "2 × 10⁻⁶ T", "is_correct": true}, {"key": "C", "text": "8 × 10⁻⁶ T", "is_correct": false}, {"key": "D", "text": "1 × 10⁻⁶ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assumes the axial and equatorial fields are equal. The equatorial field is half the axial field at the same distance.", "misconception": "Thinking axial and equatorial fields are equal"}, {"option_key": "C", "hint": "8 × 10⁻⁶ T = 2 × B_axial. The equatorial field is smaller than the axial field, not larger.", "misconception": "Inverting the relationship and doubling instead of halving"}, {"option_key": "D", "hint": "1 × 10⁻⁶ T = B_axial/4. The correct ratio is B_eq = B_axial/2, not B_axial/4.", "misconception": "Using an incorrect division factor"}]}, "correct_answer": "B", "concept_tags": ["axial-equatorial-field", "numerical", "bar-magnet-field"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A short bar magnet has a magnetic moment of 0.48 J/T. The magnetic field at a point on the axial line at a distance of 10 cm from the centre of the magnet is: (Given: μ₀/4π = 10⁻⁷ T·m/A)", "explanation": "B_axial = (μ₀/4π)(2M/r³) = 10⁻⁷ × 2 × 0.48 / (0.1)³ = 10⁻⁷ × 0.96 / 10⁻³ = 10⁻⁷ × 960 = 9.6 × 10⁻⁵ T. Converting: 9.6 × 10⁻⁵ T = 0.96 × 10⁻⁴ T.", "payload": {"question_id": "cuet-phy-magmat-dipole-11", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "apply", "options": [{"key": "A", "text": "4.8 × 10⁻⁵ T", "is_correct": false}, {"key": "B", "text": "2.4 × 10⁻⁵ T", "is_correct": false}, {"key": "C", "text": "9.6 × 10⁻⁵ T", "is_correct": true}, {"key": "D", "text": "19.2 × 10⁻⁵ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4.8 × 10⁻⁵ T uses M/r³ instead of 2M/r³. The axial field formula has a factor of 2: B = (μ₀/4π)(2M/r³).", "misconception": "Forgetting the factor of 2 in the axial field formula"}, {"option_key": "B", "hint": "2.4 × 10⁻⁵ T = (μ₀/4π)(M/2r³). This uses neither the correct axial formula nor the equatorial formula.", "misconception": "Using an incorrect formula"}, {"option_key": "D", "hint": "19.2 × 10⁻⁵ T = 2 × 9.6 × 10⁻⁵ T. This doubles the correct answer, suggesting an error in handling powers of ten or an extra factor of 2.", "misconception": "Arithmetic error in powers of 10"}]}, "correct_answer": "C", "concept_tags": ["axial-field", "numerical-problem", "bar-magnet-field-calculation"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The work done in turning a magnetic needle from the direction of the horizontal component Bₕ of Earth''s field to a direction making an angle of 60° with Bₕ is W. The torque required to hold the needle in that position is:", "explanation": "Work done: W = MBₕ(1 − cos60°) = MBₕ(1 − 1/2) = MBₕ/2. Therefore MBₕ = 2W. The torque at 60° is τ = MBₕ sin60° = 2W × (√3/2) = √3 W. Hence τ = √3 W.", "payload": {"question_id": "cuet-phy-magmat-dipole-12", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "analyze", "options": [{"key": "A", "text": "W", "is_correct": false}, {"key": "B", "text": "2W", "is_correct": false}, {"key": "C", "text": "W/2", "is_correct": false}, {"key": "D", "text": "√3 W", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This assumes τ = W, but the torque and work done have different angular dependencies (sinθ vs 1−cosθ). You must express MBₕ from the work equation and substitute into the torque formula.", "misconception": "Equating torque directly with work done"}, {"option_key": "B", "hint": "2W = MBₕ is the product of moment and field, not the torque. The torque has an additional sin60° = √3/2 factor.", "misconception": "Confusing MBₕ with torque"}, {"option_key": "C", "hint": "W/2 would result from an incorrect formula. From MBₕ = 2W, the torque is MBₕ sin60° = 2W × √3/2 = √3 W.", "misconception": "Arithmetic error in combining the expressions"}]}, "correct_answer": "D", "concept_tags": ["torque", "work-done", "earth-field", "numerical-reasoning"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): A bar magnet is equivalent to a solenoid carrying current.\nReason (R): The magnetic field lines of a bar magnet and a current-carrying solenoid have identical patterns, with field lines emerging from one end and entering the other.", "explanation": "The assertion is correct: a bar magnet behaves identically to a solenoid in terms of its external magnetic field. The reason is also correct and directly explains the assertion: both produce the same field pattern — field lines emerge from the north pole (or the end where current flows anticlockwise) and enter the south pole (or the end where current flows clockwise). The mathematical expressions for the fields at axial and equatorial points are also identical when M = NIA.", "payload": {"question_id": "cuet-phy-magmat-dipole-13", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The identical field line pattern is exactly what establishes the equivalence of a bar magnet and a solenoid, so R is indeed the correct explanation of A.", "misconception": "Failing to see that identical field patterns establish the equivalence"}, {"option_key": "C", "hint": "The reason is a correct statement. Both bar magnets and solenoids produce the same dipolar field pattern outside.", "misconception": "Doubting the field pattern similarity"}, {"option_key": "D", "hint": "The assertion is well-established in physics. A bar magnet is indeed equivalent to a solenoid, and this is a standard result in magnetism.", "misconception": "Not recognizing the bar-magnet-solenoid equivalence"}]}, "correct_answer": "A", "concept_tags": ["bar-magnet-solenoid-equivalence", "magnetic-field-pattern", "current-loop"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): At the magnetic equator, the angle of dip is 0° and a freely suspended magnetic needle rests horizontally.\nReason (R): At the magnetic equator, the vertical component of Earth''s magnetic field is zero.", "explanation": "The assertion is correct: at the magnetic equator, the dip angle δ = 0°, and a freely suspended needle aligns horizontally. The reason is also correct and directly explains the assertion: since Bᵥ = B sinδ, at δ = 0° we get Bᵥ = 0. With no vertical component to pull the needle downward, it rests horizontally. The entire Earth''s field at the magnetic equator is horizontal (Bₕ = B).", "payload": {"question_id": "cuet-phy-magmat-dipole-14", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion: the needle rests horizontally precisely because the vertical component is zero. The causal connection is clear.", "misconception": "Not connecting zero vertical component with the horizontal resting position"}, {"option_key": "C", "hint": "The reason is correct. At δ = 0°, Bᵥ = B sin0° = 0. This is a direct consequence of the dip angle being zero.", "misconception": "Incorrectly thinking the vertical component is non-zero at the magnetic equator"}, {"option_key": "D", "hint": "The assertion is correct and verifiable. At the magnetic equator, dip is indeed 0° and the needle does rest horizontally.", "misconception": "Confusing magnetic equator with geographic equator and doubting the assertion"}]}, "correct_answer": "A", "concept_tags": ["magnetic-equator", "dip-angle", "vertical-component", "horizontal-component"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the elements of Earth''s magnetism in Column I with their definitions in Column II:\n\nColumn I:\nA. Declination\nB. Angle of dip (Inclination)\nC. Horizontal component Bₕ\nD. Vertical component Bᵥ\n\nColumn II:\n1. B sinδ, where δ is the dip angle\n2. The angle between the geographic meridian and the magnetic meridian\n3. B cosδ, where δ is the dip angle\n4. The angle between the total Earth''s field and the horizontal direction in the magnetic meridian", "explanation": "Declination is the angle between geographic and magnetic meridians → A-2. Dip is the angle between the total field vector and the horizontal in the magnetic meridian → B-4. The horizontal component is Bₕ = B cosδ → C-3. The vertical component is Bᵥ = B sinδ → D-1.", "payload": {"question_id": "cuet-phy-magmat-dipole-15", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "understand", "options": [{"key": "A", "text": "A-4, B-2, C-3, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-1, D-3", "is_correct": false}, {"key": "C", "text": "A-2, B-4, C-3, D-1", "is_correct": true}, {"key": "D", "text": "A-2, B-3, C-4, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps A and B. Declination is the angle between meridians (definition 2), while dip is the angle of the total field with horizontal (definition 4).", "misconception": "Confusing declination with dip"}, {"option_key": "B", "hint": "This swaps C and D. The horizontal component uses cosδ (C-3), and the vertical component uses sinδ (D-1), not the other way around.", "misconception": "Interchanging sinδ and cosδ for horizontal and vertical components"}, {"option_key": "D", "hint": "This assigns definition 3 (B cosδ) to dip, but dip is an angle (definition 4), not a field component.", "misconception": "Confusing the dip angle with a field component formula"}]}, "correct_answer": "C", "concept_tags": ["earth-magnetism-elements", "declination", "dip", "horizontal-vertical-components"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the physical situations in Column I with the correct magnetic field expressions or properties in Column II:\n\nColumn I:\nA. Axial point of a magnetic dipole (far field)\nB. Equatorial point of a magnetic dipole (far field)\nC. Neutral point when N-pole points north (bar magnet on table)\nD. Neutral point when N-pole points south (bar magnet on table)\n\nColumn II:\n1. Located on the axial line of the magnet\n2. (μ₀/4π)(M/r³), directed opposite to M\n3. Located on the equatorial line of the magnet\n4. (μ₀/4π)(2M/r³), directed along M", "explanation": "The axial field at far distance is (μ₀/4π)(2M/r³), directed along M → A-4. The equatorial field at far distance is (μ₀/4π)(M/r³), directed opposite to M → B-2. When the N-pole of a bar magnet points geographic north, the magnet''s field opposes Earth''s field on the equatorial line, so neutral points are on the equatorial line → C-3. When the N-pole points south, neutral points lie on the axial line → D-1.", "payload": {"question_id": "cuet-phy-magmat-dipole-16", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "B", "text": "A-4, B-2, C-3, D-1", "is_correct": true}, {"key": "C", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "D", "text": "A-4, B-2, C-1, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps C and D. When N-pole points north, the axial field adds to Earth''s field and the equatorial field opposes it, so neutral points are on the equatorial line (C-3, not C-1).", "misconception": "Confusing which line has neutral points for N-pole pointing north vs south"}, {"option_key": "C", "hint": "This swaps A and B. The axial field has the factor 2 in the numerator and is along M; the equatorial field has factor 1 and is opposite to M.", "misconception": "Interchanging axial and equatorial field formulas"}, {"option_key": "D", "hint": "This is identical to option A with C and D swapped from the correct answer. Neutral points for N-pole north are on the equatorial line (perpendicular bisector), not the axial line.", "misconception": "Confusing the location of neutral points"}]}, "correct_answer": "B", "concept_tags": ["axial-equatorial-field", "neutral-points", "bar-magnet-earth-field"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The magnetic field lines of a bar magnet form continuous closed loops, emerging from the north pole outside the magnet and running from south to north inside the magnet.", "explanation": "This statement is TRUE. Unlike electric field lines, magnetic field lines always form continuous closed loops. Outside the magnet, they go from north pole to south pole. Inside the magnet, they continue from south pole to north pole, completing the loop. This is a consequence of Gauss''s law for magnetism (∇·B = 0), which states that magnetic monopoles do not exist.", "payload": {"question_id": "cuet-phy-magmat-dipole-17", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Magnetic field lines do form closed loops. This is a fundamental difference between electric field lines (which start and end on charges) and magnetic field lines (which have no starting or ending points because magnetic monopoles don''t exist).", "misconception": "Confusing magnetic field lines with electric field lines that do not form closed loops"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["magnetic-field-lines", "closed-loops", "gauss-law-magnetism"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The geographic north pole of the Earth and the magnetic north pole of the Earth are located at the same point.", "explanation": "This statement is FALSE. The geographic north pole (true north, defined by Earth''s rotational axis) and the magnetic north pole (where the Earth''s magnetic field points vertically downward) are NOT at the same location. The magnetic north pole is offset from the geographic north pole by about 11.3°. In fact, the Earth''s magnetic south pole is located near the geographic north pole (since field lines enter the Earth near the geographic north).", "payload": {"question_id": "cuet-phy-magmat-dipole-18", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The geographic and magnetic poles do not coincide. The angle between the geographic meridian and magnetic meridian (declination) varies across the globe, precisely because these poles are at different locations.", "misconception": "Assuming geographic and magnetic north poles are at the same location"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["geographic-pole", "magnetic-pole", "earth-magnetism"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_the_blank", "difficulty": "medium", "question_text": "At a place where the angle of dip is 45°, the horizontal and vertical components of Earth''s magnetic field are _____.", "explanation": "When the angle of dip δ = 45°, we have Bₕ = B cos45° = B/√2 and Bᵥ = B sin45° = B/√2. Since Bₕ = Bᵥ, the horizontal and vertical components are equal in magnitude. Also, tanδ = Bᵥ/Bₕ = tan45° = 1, confirming Bᵥ = Bₕ.", "payload": {"question_id": "cuet-phy-magmat-dipole-19", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "apply", "options": [{"key": "A", "text": "Bₕ = 2Bᵥ (horizontal is twice the vertical)", "is_correct": false}, {"key": "B", "text": "Bᵥ = 2Bₕ (vertical is twice the horizontal)", "is_correct": false}, {"key": "C", "text": "Equal in magnitude (Bₕ = Bᵥ)", "is_correct": true}, {"key": "D", "text": "Bₕ = 0 and Bᵥ = B (only vertical component exists)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Bₕ = 2Bᵥ would require tanδ = 1/2, giving δ ≈ 26.6°, not 45°. At δ = 45°, tanδ = 1, so Bₕ = Bᵥ.", "misconception": "Incorrect trigonometric evaluation at 45°"}, {"option_key": "B", "hint": "Bᵥ = 2Bₕ would require tanδ = 2, giving δ ≈ 63.4°. At 45° dip, both components are equal.", "misconception": "Confusing 45° dip with a steeper dip angle"}, {"option_key": "D", "hint": "Bₕ = 0 occurs only at the magnetic poles where δ = 90°. At δ = 45°, both horizontal and vertical components are non-zero and equal.", "misconception": "Confusing 45° dip with 90° dip (at the poles)"}]}, "correct_answer": "C", "concept_tags": ["dip-angle", "horizontal-component", "vertical-component", "equal-components"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "scenario", "difficulty": "medium", "question_text": "A geologist is surveying a region using a dip circle. At a particular location, she measures the angle of dip to be 30° and the horizontal component of Earth''s magnetic field to be 0.36 G. She needs to determine the total magnetic field strength and the vertical component at this location.\n\nWhat is the vertical component Bᵥ of Earth''s magnetic field at this location?", "explanation": "Given: δ = 30°, Bₕ = 0.36 G. Using the relation tanδ = Bᵥ/Bₕ, we get Bᵥ = Bₕ tanδ = 0.36 × tan30° = 0.36 × (1/√3) = 0.36/1.732 ≈ 0.208 G. Alternatively, Bᵥ = 0.36/√3 = 0.12√3 G ≈ 0.208 G. The total field B = Bₕ/cosδ = 0.36/cos30° = 0.36/(√3/2) = 0.72/√3 ≈ 0.416 G.", "payload": {"question_id": "cuet-phy-magmat-dipole-20", "subtopic": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "topic_name": "Magnetic Dipole, Bar Magnet, and Earth''s Magnetism", "bloom_level": "apply", "options": [{"key": "A", "text": "0.36 G", "is_correct": false}, {"key": "B", "text": "0.72 G", "is_correct": false}, {"key": "C", "text": "0.18 G", "is_correct": false}, {"key": "D", "text": "0.12√3 G ≈ 0.208 G", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.36 G is the horizontal component, not the vertical component. With a dip of 30°, the vertical component is smaller than the horizontal component since tan30° < 1.", "misconception": "Confusing horizontal component with vertical component"}, {"option_key": "B", "hint": "0.72 G = 2 × Bₕ. This might result from using an incorrect formula. The correct relation is Bᵥ = Bₕ tan30° = 0.36 × (1/√3) ≈ 0.208 G.", "misconception": "Using an incorrect multiplying factor"}, {"option_key": "C", "hint": "0.18 G = Bₕ/2 = Bₕ × sin30°, but the correct formula is Bᵥ = Bₕ tanδ, not Bₕ sinδ.", "misconception": "Using sinδ instead of tanδ in the formula for Bᵥ"}]}, "correct_answer": "D", "concept_tags": ["earth-magnetism", "dip-angle", "vertical-component", "scenario-based", "numerical"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-29');

