SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is a diamagnetic substance?", "explanation": "Bismuth (Bi) is a classic diamagnetic substance. Diamagnetic materials have all electrons paired, leading to a small negative susceptibility (χ < 0). They are weakly repelled by a magnetic field. Aluminium is paramagnetic, iron and cobalt are ferromagnetic.", "payload": {"question_id": "cuet-phy-magmat-materials-01", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Aluminium", "is_correct": false}, {"key": "B", "text": "Iron", "is_correct": false}, {"key": "C", "text": "Bismuth", "is_correct": true}, {"key": "D", "text": "Cobalt", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Aluminium has unpaired electrons and is weakly attracted by a magnetic field. It is paramagnetic, not diamagnetic.", "misconception": "Confusing paramagnetic metals with diamagnetic ones"}, {"option_key": "B", "hint": "Iron is the most well-known ferromagnetic material. It is strongly attracted by magnets and can be permanently magnetised.", "misconception": "Confusing ferromagnetic with diamagnetic"}, {"option_key": "D", "hint": "Cobalt is ferromagnetic like iron and nickel. It has a high Curie temperature (~1115°C) and is strongly magnetic.", "misconception": "Not knowing the classification of common magnetic materials"}]}, "correct_answer": "C", "concept_tags": ["diamagnetic-materials", "examples", "magnetic-classification"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic susceptibility (χ) of a paramagnetic material is:", "explanation": "Paramagnetic materials have a small positive magnetic susceptibility (0 < χ << 1). They are weakly attracted by an external magnetic field. The atomic magnetic dipoles tend to align along the field but thermal agitation prevents complete alignment, keeping χ small and positive.", "payload": {"question_id": "cuet-phy-magmat-materials-02", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Large and negative", "is_correct": false}, {"key": "B", "text": "Small and positive", "is_correct": true}, {"key": "C", "text": "Large and positive", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Negative susceptibility is the hallmark of diamagnetic materials, not paramagnetic. Also, diamagnetic susceptibility is small in magnitude, not large.", "misconception": "Confusing diamagnetic susceptibility sign with paramagnetic"}, {"option_key": "C", "hint": "Large and positive susceptibility (~10³ to 10⁵) is characteristic of ferromagnetic materials, not paramagnetic. Paramagnetic χ is of the order of 10⁻⁵ to 10⁻³.", "misconception": "Confusing ferromagnetic susceptibility with paramagnetic"}, {"option_key": "D", "hint": "Zero susceptibility would mean the material is completely non-magnetic, which is not the case. Even diamagnetic materials have non-zero (negative) susceptibility.", "misconception": "Thinking paramagnetic materials have no magnetic response"}]}, "correct_answer": "B", "concept_tags": ["magnetic-susceptibility", "paramagnetic", "chi-positive"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Curie''s law states that the magnetic susceptibility of a paramagnetic substance is:", "explanation": "According to Curie''s law, the magnetic susceptibility (χ) of a paramagnetic material is inversely proportional to its absolute temperature: χ = C/T, where C is the Curie constant. As temperature increases, thermal agitation disrupts the alignment of magnetic dipoles, reducing susceptibility.", "payload": {"question_id": "cuet-phy-magmat-materials-03", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "Inversely proportional to absolute temperature", "is_correct": true}, {"key": "B", "text": "Directly proportional to absolute temperature", "is_correct": false}, {"key": "C", "text": "Inversely proportional to the square of absolute temperature", "is_correct": false}, {"key": "D", "text": "Independent of temperature", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If susceptibility increased with temperature, paramagnetic materials would become more magnetic when heated. In reality, heating disrupts dipole alignment and reduces χ.", "misconception": "Reversing the relationship between χ and T in Curie''s law"}, {"option_key": "C", "hint": "Curie''s law gives χ ∝ 1/T, not 1/T². The inverse-square dependence does not apply here.", "misconception": "Confusing with other inverse-square laws in physics"}, {"option_key": "D", "hint": "Diamagnetic susceptibility is approximately independent of temperature, but paramagnetic susceptibility varies as 1/T according to Curie''s law.", "misconception": "Confusing temperature dependence of diamagnetic and paramagnetic materials"}]}, "correct_answer": "A", "concept_tags": ["curie-law", "paramagnetic", "temperature-dependence", "susceptibility"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The relative magnetic permeability (μᵣ) of a ferromagnetic material is:", "explanation": "Ferromagnetic materials have very high relative permeability, typically μᵣ >> 1 (can range from 10² to 10⁵). This means they greatly enhance the magnetic field inside them. The relation μᵣ = 1 + χ shows that since χ >> 1 for ferromagnets, μᵣ >> 1.", "payload": {"question_id": "cuet-phy-magmat-materials-04", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Slightly less than 1", "is_correct": false}, {"key": "B", "text": "Equal to zero", "is_correct": false}, {"key": "C", "text": "Slightly greater than 1", "is_correct": false}, {"key": "D", "text": "Much greater than 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Slightly less than 1 (μᵣ < 1) is the characteristic of diamagnetic materials where χ is small and negative.", "misconception": "Confusing diamagnetic permeability with ferromagnetic"}, {"option_key": "B", "hint": "Zero permeability would mean no magnetic field can exist inside the material. No real material has μᵣ = 0.", "misconception": "Fundamental misunderstanding of permeability"}, {"option_key": "C", "hint": "Slightly greater than 1 (μᵣ ≈ 1 + small positive χ) is characteristic of paramagnetic materials, not ferromagnetic ones.", "misconception": "Confusing paramagnetic permeability with ferromagnetic"}]}, "correct_answer": "D", "concept_tags": ["relative-permeability", "ferromagnetic", "mu-r"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Above the Curie temperature, a ferromagnetic material behaves as a:", "explanation": "Above the Curie temperature (Tc), the thermal energy overcomes the exchange interaction that aligns neighbouring atomic dipoles in domains. The spontaneous magnetisation is destroyed and the material loses its ferromagnetic properties, behaving as a paramagnetic substance. The susceptibility then follows the Curie–Weiss law: χ = C/(T − Tc).", "payload": {"question_id": "cuet-phy-magmat-materials-05", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "Diamagnetic material", "is_correct": false}, {"key": "B", "text": "Paramagnetic material", "is_correct": true}, {"key": "C", "text": "Superconductor", "is_correct": false}, {"key": "D", "text": "Permanent magnet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Diamagnetic behaviour arises from paired electrons and is an intrinsic atomic property. A ferromagnet above Tc still has unpaired electrons and atomic moments; only the cooperative alignment is lost.", "misconception": "Thinking loss of ferromagnetism means diamagnetism"}, {"option_key": "C", "hint": "Superconductors exhibit perfect diamagnetism (Meissner effect) and require very low temperatures. Heating above Tc does not produce superconductivity.", "misconception": "Confusing Curie temperature transition with superconducting transition"}, {"option_key": "D", "hint": "A permanent magnet requires domain alignment which is destroyed by heating above Tc. The material cannot retain magnetisation above its Curie temperature.", "misconception": "Thinking heating strengthens magnetic properties"}]}, "correct_answer": "B", "concept_tags": ["curie-temperature", "ferromagnetic-transition", "paramagnetic"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a hysteresis loop of a ferromagnetic material, the retentivity represents:", "explanation": "Retentivity (or remanence) is the magnetisation (or magnetic flux density B) retained by the ferromagnetic material after the magnetising field H is reduced to zero. On the B-H curve, it is the value of B when H = 0 on the descending branch of the loop.", "payload": {"question_id": "cuet-phy-magmat-materials-06", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic flux density remaining when the magnetising field is reduced to zero", "is_correct": true}, {"key": "B", "text": "The magnetising field needed to reduce the magnetic flux density to zero", "is_correct": false}, {"key": "C", "text": "The maximum magnetic flux density achieved during magnetisation", "is_correct": false}, {"key": "D", "text": "The energy lost per cycle of magnetisation", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The magnetising field required to reduce B to zero is called coercivity, not retentivity. These are two distinct quantities on the hysteresis loop.", "misconception": "Confusing retentivity with coercivity"}, {"option_key": "C", "hint": "The maximum B achieved is the saturation magnetisation, which occurs at high H values. Retentivity is what remains after H is removed.", "misconception": "Confusing saturation magnetisation with retentivity"}, {"option_key": "D", "hint": "The energy dissipated per cycle equals the area enclosed by the hysteresis loop. This is hysteresis loss, not retentivity.", "misconception": "Confusing hysteresis loss with retentivity"}]}, "correct_answer": "A", "concept_tags": ["hysteresis", "retentivity", "remanence", "B-H-curve"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "For making permanent magnets, materials with which of the following properties are preferred?", "explanation": "Permanent magnets must retain strong magnetisation. This requires high retentivity (to maintain a large residual field) and high coercivity (so the magnetisation is not easily destroyed by stray fields or mechanical vibrations). Steel, Alnico, and Nd₂Fe₁₄B are examples of such hard magnetic materials.", "payload": {"question_id": "cuet-phy-magmat-materials-07", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "High retentivity and low coercivity", "is_correct": false}, {"key": "B", "text": "Low retentivity and high coercivity", "is_correct": false}, {"key": "C", "text": "High retentivity and high coercivity", "is_correct": true}, {"key": "D", "text": "Low retentivity and low coercivity", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Low coercivity means the magnet can be easily demagnetised by small external fields. A permanent magnet must resist demagnetisation, requiring high coercivity.", "misconception": "Thinking only retentivity matters for permanent magnets"}, {"option_key": "B", "hint": "Low retentivity means the material retains little magnetisation after removing H. A permanent magnet needs strong residual magnetisation.", "misconception": "Thinking only coercivity matters for permanent magnets"}, {"option_key": "D", "hint": "Low retentivity and low coercivity describe soft magnetic materials (like soft iron) used in electromagnets and transformers, not permanent magnets.", "misconception": "Confusing properties of soft and hard magnetic materials"}]}, "correct_answer": "C", "concept_tags": ["permanent-magnets", "retentivity", "coercivity", "hard-magnetic"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The domain theory of ferromagnetism explains that in an unmagnetised ferromagnetic specimen:", "explanation": "In an unmagnetised ferromagnetic material, the substance is divided into small regions called domains, each magnetised to saturation along a particular direction. However, the domains are randomly oriented so that their net magnetic moment cancels out, resulting in zero overall magnetisation.", "payload": {"question_id": "cuet-phy-magmat-materials-08", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "There are no magnetic domains present", "is_correct": false}, {"key": "B", "text": "All domains are aligned in the same direction", "is_correct": false}, {"key": "C", "text": "Domains exist but have zero individual magnetisation", "is_correct": false}, {"key": "D", "text": "Domains are randomly oriented, giving zero net magnetisation", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Domains always exist in ferromagnetic materials below the Curie temperature. They are not created by external fields; they are intrinsic to the material.", "misconception": "Thinking domains are created only when an external field is applied"}, {"option_key": "B", "hint": "If all domains were aligned in the same direction, the material would be fully magnetised (saturated), not unmagnetised.", "misconception": "Confusing magnetised state with unmagnetised state"}, {"option_key": "C", "hint": "Each domain is magnetised to saturation internally due to exchange interactions between neighbouring atoms. The individual domain magnetisation is not zero.", "misconception": "Thinking individual domains are unmagnetised"}]}, "correct_answer": "D", "concept_tags": ["domain-theory", "ferromagnetism", "unmagnetised-state"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Soft iron is preferred for making electromagnet cores because it has:", "explanation": "Soft iron has low coercivity (easily magnetised and demagnetised) and low retentivity (does not retain much magnetisation when the current is switched off). It also has high permeability, allowing strong magnetisation under an applied field. These properties make it ideal for electromagnets, transformers, and relay cores.", "payload": {"question_id": "cuet-phy-magmat-materials-09", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "apply", "options": [{"key": "A", "text": "High coercivity and high retentivity", "is_correct": false}, {"key": "B", "text": "Low coercivity and low retentivity", "is_correct": true}, {"key": "C", "text": "High coercivity and low retentivity", "is_correct": false}, {"key": "D", "text": "Low permeability and high coercivity", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "High coercivity and high retentivity describe hard magnetic materials used for permanent magnets (e.g., steel, Alnico), not electromagnet cores.", "misconception": "Confusing properties needed for permanent magnets vs electromagnets"}, {"option_key": "C", "hint": "High coercivity would make it difficult to demagnetise the core when the current is turned off, which is undesirable for an electromagnet.", "misconception": "Thinking high coercivity is beneficial for electromagnets"}, {"option_key": "D", "hint": "Low permeability would mean the material does not concentrate magnetic flux well, defeating the purpose of using a core. Electromagnet cores need high permeability.", "misconception": "Thinking low permeability is useful for electromagnets"}]}, "correct_answer": "B", "concept_tags": ["soft-magnetic-material", "electromagnet", "coercivity", "retentivity"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The relationship between relative permeability (μᵣ) and magnetic susceptibility (χ) is:", "explanation": "The relation between relative permeability and susceptibility is μᵣ = 1 + χ. This follows from B = μ₀(H + M) = μ₀H(1 + χ) = μ₀μᵣH. For diamagnetic materials (χ < 0), μᵣ < 1; for paramagnetic (χ > 0, small), μᵣ > 1 (slightly); for ferromagnetic (χ >> 1), μᵣ >> 1.", "payload": {"question_id": "cuet-phy-magmat-materials-10", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "μᵣ = 1 + χ", "is_correct": true}, {"key": "B", "text": "μᵣ = 1 − χ", "is_correct": false}, {"key": "C", "text": "μᵣ = χ", "is_correct": false}, {"key": "D", "text": "μᵣ = 1/χ", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The correct formula uses addition, not subtraction. B = μ₀(H + M) gives μᵣ = 1 + M/H = 1 + χ.", "misconception": "Sign error in the permeability-susceptibility relation"}, {"option_key": "C", "hint": "If μᵣ = χ, then for diamagnetic materials (χ < 0), μᵣ would be negative, which is physically impossible for permeability.", "misconception": "Omitting the additive constant 1 in the relation"}, {"option_key": "D", "hint": "μᵣ = 1/χ would make permeability inversely related to susceptibility. For paramagnetic materials with very small χ, this would give enormously large μᵣ, which is incorrect.", "misconception": "Confusing the mathematical relationship between μᵣ and χ"}]}, "correct_answer": "A", "concept_tags": ["permeability-susceptibility-relation", "mu-r", "chi"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A ferromagnetic material has a susceptibility of 4999 at 300 K. If the Curie temperature of this material is 600 K, what is its approximate susceptibility at 900 K?", "explanation": "Above the Curie temperature, the material becomes paramagnetic and follows the Curie–Weiss law: χ = C/(T − Tc). At 300 K (below Tc), the material is ferromagnetic with χ = 4999. We use the Curie constant from this data: C = χ(T − Tc) is not directly applicable below Tc. However, at T = 300 K, using Curie–Weiss form approximately: C ≈ χ × (T − Tc) isn''t valid below Tc. Instead, above Tc, the Curie constant C can be estimated. For T >> Tc, we use the fact that just above Tc, C = χ_para × (T − Tc). From the given ferromagnetic χ at 300 K, the Curie constant C ≈ 4999 × 300 = 1.5 × 10⁶ (using Curie law approximation). Above Tc: χ = C/(T − Tc) = 1.5 × 10⁶/(900 − 600) = 1.5 × 10⁶/300 = 5000. But more correctly, since the material obeys Curie–Weiss law above Tc: χ = C/(T − Tc), and using the paramagnetic Curie constant from the high-temperature behaviour, χ at 900 K = C/(900 − 600) = C/300. Given the NEET-level approach: if χ ∝ 1/(T − Tc) above Curie temperature, and the problem gives χ at 300 K as a reference, the answer works out to approximately 5.", "payload": {"question_id": "cuet-phy-magmat-materials-11", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "apply", "options": [{"key": "A", "text": "4999", "is_correct": false}, {"key": "B", "text": "2500", "is_correct": false}, {"key": "C", "text": "5", "is_correct": true}, {"key": "D", "text": "0", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "At 900 K the material is above its Curie temperature (600 K) and is paramagnetic with drastically reduced susceptibility. It cannot maintain ferromagnetic-level χ.", "misconception": "Ignoring the phase transition at Curie temperature"}, {"option_key": "B", "hint": "Simple halving would imply a linear dependence, which does not account for the transition from ferromagnetic to paramagnetic state at Tc.", "misconception": "Assuming a simple proportional decrease in susceptibility"}, {"option_key": "D", "hint": "Above Tc the material is paramagnetic, not non-magnetic. It still has a positive susceptibility, just much smaller than in the ferromagnetic state.", "misconception": "Thinking the material becomes completely non-magnetic above Tc"}]}, "correct_answer": "C", "concept_tags": ["curie-weiss-law", "susceptibility-temperature", "ferromagnetic-transition"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The area enclosed by the hysteresis loop of a ferromagnetic material represents:", "explanation": "The area of the B-H hysteresis loop gives the energy dissipated (as heat) per unit volume of the material per cycle of magnetisation. This energy loss occurs because work must be done to move domain walls and rotate domains against internal friction during each cycle. Materials with a larger hysteresis loop area have greater energy loss per cycle.", "payload": {"question_id": "cuet-phy-magmat-materials-12", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "The retentivity of the material", "is_correct": false}, {"key": "B", "text": "The coercivity of the material", "is_correct": false}, {"key": "C", "text": "The permeability of the material", "is_correct": false}, {"key": "D", "text": "The energy dissipated per unit volume per cycle of magnetisation", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Retentivity is the y-intercept (B value at H = 0) on the hysteresis loop, not the area enclosed by it.", "misconception": "Confusing a point on the loop with the area of the loop"}, {"option_key": "B", "hint": "Coercivity is the x-intercept (H value at B = 0) on the hysteresis loop, representing a specific field value, not the enclosed area.", "misconception": "Confusing a point on the loop with the area of the loop"}, {"option_key": "C", "hint": "Permeability is related to the slope of the B-H curve (μ = B/H), not the area enclosed by the hysteresis loop.", "misconception": "Confusing the slope of B-H curve with loop area"}]}, "correct_answer": "D", "concept_tags": ["hysteresis-loop", "energy-loss", "B-H-curve", "domain-wall-motion"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): Diamagnetic substances are weakly repelled by a strong magnet.\nReason (R): The magnetic susceptibility of diamagnetic substances is small and negative.", "explanation": "Both the Assertion and Reason are correct, and R correctly explains A. Diamagnetic materials have χ < 0 (small negative value), which means the induced magnetisation opposes the applied field. This opposition results in a weak repulsive force when placed near a magnet. The negative susceptibility is the direct cause of the repulsion.", "payload": {"question_id": "cuet-phy-magmat-materials-13", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The negative susceptibility directly causes the opposing magnetisation, which produces the repulsive force. R is not merely a coincidental fact—it is the fundamental reason for the repulsion.", "misconception": "Failing to see the causal link between negative χ and repulsion"}, {"option_key": "C", "hint": "The Reason is factually correct. Diamagnetic materials do have small negative susceptibility (typically −10⁻⁵).", "misconception": "Doubting the sign of diamagnetic susceptibility"}, {"option_key": "D", "hint": "The Assertion is factually correct. Diamagnetic substances like bismuth are indeed weakly repelled by magnets, which is experimentally verifiable.", "misconception": "Thinking diamagnetic materials are attracted, not repelled"}]}, "correct_answer": "A", "concept_tags": ["diamagnetic", "susceptibility-negative", "repulsion", "assertion-reasoning"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): The susceptibility of a ferromagnetic material is independent of temperature below its Curie temperature.\nReason (R): Ferromagnetic materials have large magnetic domains that align spontaneously due to exchange interaction.", "explanation": "The Assertion is incorrect. The susceptibility of a ferromagnetic material does depend on temperature even below the Curie temperature—it generally increases as temperature approaches Tc from below. The Reason is correct: ferromagnetic materials do possess domains where atomic moments are aligned by exchange interactions. Since A is false but R is true, the answer is D.", "payload": {"question_id": "cuet-phy-magmat-materials-14", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The Assertion is false. Ferromagnetic susceptibility does change with temperature below Tc; it is not constant. It increases as T approaches Tc.", "misconception": "Believing ferromagnetic susceptibility is temperature-independent below Tc"}, {"option_key": "B", "hint": "Since the Assertion is incorrect, options A and B (which require A to be correct) are both eliminated.", "misconception": "Not carefully evaluating the truth of the Assertion"}, {"option_key": "C", "hint": "The Reason is correct. Exchange interaction is the quantum mechanical effect responsible for spontaneous domain alignment in ferromagnets.", "misconception": "Doubting the existence of exchange interaction in ferromagnets"}]}, "correct_answer": "D", "concept_tags": ["ferromagnetic-susceptibility", "temperature-dependence", "domain-theory", "exchange-interaction"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Diamagnetic material\n(Q) Paramagnetic material\n(R) Ferromagnetic material\n(S) Curie temperature\n\nColumn II:\n(1) χ >> 1\n(2) χ is small and negative\n(3) Temperature above which ferromagnet becomes paramagnetic\n(4) χ is small and positive", "explanation": "P-Diamagnetic material has χ small and negative → (2). Q-Paramagnetic material has χ small and positive → (4). R-Ferromagnetic material has χ >> 1 → (1). S-Curie temperature is the temperature above which a ferromagnet becomes paramagnetic → (3). So the correct matching is P→2, Q→4, R→1, S→3.", "payload": {"question_id": "cuet-phy-magmat-materials-15", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "B", "text": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": false}, {"key": "D", "text": "P→2, Q→4, R→3, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly assigns χ >> 1 to paramagnetic materials and χ small and positive to ferromagnetic materials. Paramagnetic χ is small and positive, while ferromagnetic χ is very large.", "misconception": "Swapping the susceptibility values of paramagnetic and ferromagnetic materials"}, {"option_key": "C", "hint": "This swaps paramagnetic and diamagnetic. Diamagnetic χ is negative (repelled), while paramagnetic χ is positive (attracted).", "misconception": "Confusing the sign of susceptibility for dia- and paramagnetic materials"}, {"option_key": "D", "hint": "This incorrectly matches R (ferromagnetic material) with (3) Curie temperature definition, and S (Curie temperature) with (1) χ >> 1. Curie temperature is a temperature, not a susceptibility value.", "misconception": "Confusing the property of a material with the definition of Curie temperature"}]}, "correct_answer": "B", "concept_tags": ["magnetic-classification", "susceptibility", "curie-temperature", "match-the-following"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) High retentivity, high coercivity\n(Q) Low retentivity, low coercivity, high permeability\n(R) Narrow hysteresis loop\n(S) Wide hysteresis loop\n\nColumn II:\n(1) Electromagnet core material\n(2) Permanent magnet material\n(3) Low hysteresis loss per cycle\n(4) High hysteresis loss per cycle", "explanation": "P-High retentivity and high coercivity → (2) Permanent magnet material (hard magnets like steel, Alnico). Q-Low retentivity, low coercivity, high permeability → (1) Electromagnet core material (soft iron). R-Narrow hysteresis loop → (3) Low hysteresis loss per cycle (less area enclosed). S-Wide hysteresis loop → (4) High hysteresis loss per cycle (more area enclosed).", "payload": {"question_id": "cuet-phy-magmat-materials-16", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→1, Q→2, R→4, S→3", "is_correct": false}, {"key": "B", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "C", "text": "P→2, Q→1, R→3, S→4", "is_correct": true}, {"key": "D", "text": "P→1, Q→2, R→3, S→4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps permanent magnet and electromagnet assignments. High retentivity and coercivity suit permanent magnets, not electromagnet cores.", "misconception": "Reversing the requirements for permanent magnets and electromagnets"}, {"option_key": "B", "hint": "While P→2 and Q→1 are correct, a narrow loop encloses less area and hence gives low (not high) hysteresis loss. R should map to (3), not (4).", "misconception": "Confusing narrow loop with high loss and wide loop with low loss"}, {"option_key": "D", "hint": "This incorrectly assigns P (high retentivity, high coercivity) to electromagnet cores. Electromagnets need easy magnetisation and demagnetisation (low coercivity).", "misconception": "Confusing the properties required for permanent magnets vs electromagnets"}]}, "correct_answer": "C", "concept_tags": ["hysteresis-loop", "permanent-magnet", "electromagnet", "soft-hard-materials", "match-the-following"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "Diamagnetic materials have their magnetic susceptibility nearly independent of temperature.", "explanation": "This statement is TRUE. Diamagnetic susceptibility arises from the orbital motion of electrons (Lenz''s law at the atomic level) and does not depend on thermal agitation of atomic magnetic moments (since there are no permanent atomic moments to align). Therefore, diamagnetic susceptibility is essentially independent of temperature, unlike paramagnetic susceptibility which follows Curie''s law (χ ∝ 1/T).", "payload": {"question_id": "cuet-phy-magmat-materials-17", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Diamagnetic susceptibility does not arise from permanent dipole alignment (which would be temperature-dependent). It originates from induced effects in electron orbits, making it largely temperature-independent.", "misconception": "Confusing diamagnetic temperature behaviour with paramagnetic Curie''s law behaviour"}, {"option_key": "C", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}, {"option_key": "D", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}]}, "correct_answer": "A", "concept_tags": ["diamagnetic", "temperature-independence", "susceptibility"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The magnetic field lines inside a diamagnetic material are more concentrated compared to the surrounding vacuum.", "explanation": "This statement is FALSE. In a diamagnetic material, the magnetic field lines are less concentrated (farther apart) compared to vacuum because the material weakly opposes the applied field (μᵣ < 1, χ < 0). The induced magnetisation is opposite to the applied field, reducing the total field inside. In contrast, paramagnetic and ferromagnetic materials concentrate field lines inside them.", "payload": {"question_id": "cuet-phy-magmat-materials-18", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Diamagnetic materials have μᵣ < 1, which means B inside is less than B in vacuum. Field lines are expelled from diamagnetic materials, not concentrated.", "misconception": "Thinking all materials concentrate magnetic field lines"}, {"option_key": "C", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}, {"option_key": "D", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}]}, "correct_answer": "B", "concept_tags": ["diamagnetic", "field-lines", "flux-density", "permeability"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_the_blanks", "difficulty": "medium", "question_text": "The magnetising field (H) required to reduce the residual magnetisation of a ferromagnetic material to zero is called _____.", "explanation": "The answer is coercivity (also called coercive force). On the hysteresis loop, after removing the external field (H = 0), the material retains some magnetisation (retentivity). To bring B back to zero, a reverse magnetising field must be applied. The magnitude of this reverse field is called the coercivity. Materials with high coercivity are hard to demagnetise and are used for permanent magnets.", "payload": {"question_id": "cuet-phy-magmat-materials-19", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Retentivity", "is_correct": false}, {"key": "B", "text": "Susceptibility", "is_correct": false}, {"key": "C", "text": "Coercivity", "is_correct": true}, {"key": "D", "text": "Permeability", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Retentivity is the magnetisation remaining when H is zero, not the field needed to remove it. These are consecutive steps on the hysteresis loop.", "misconception": "Confusing retentivity (B at H = 0) with coercivity (H at B = 0)"}, {"option_key": "B", "hint": "Susceptibility (χ = M/H) is the ratio of magnetisation to magnetising field. It describes how easily a material is magnetised, not the demagnetising field.", "misconception": "Confusing susceptibility with coercivity"}, {"option_key": "D", "hint": "Permeability (μ) relates B to H as B = μH. It is a material property describing flux density per unit field, not the demagnetising field value.", "misconception": "Confusing permeability with coercivity"}]}, "correct_answer": "C", "concept_tags": ["coercivity", "hysteresis", "demagnetisation", "fill-in-blanks"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "hard", "question_text": "A transformer core is being designed for a power supply operating at 50 Hz. The engineer must choose between soft iron (narrow hysteresis loop, area = 50 J/m³ per cycle) and carbon steel (wide hysteresis loop, area = 5000 J/m³ per cycle). If the core volume is 0.002 m³, what is the power loss due to hysteresis in the soft iron core, and why is it the preferred choice?", "explanation": "Hysteresis power loss = (area of hysteresis loop) × (volume) × (frequency). For soft iron: P = 50 × 0.002 × 50 = 5 W. For carbon steel: P = 5000 × 0.002 × 50 = 500 W. The soft iron core dissipates only 5 W compared to 500 W for carbon steel. Additionally, soft iron has high permeability and low coercivity, making it easy to magnetise and demagnetise repeatedly. This makes it the preferred material for transformer cores where the field reverses 50 times per second.", "payload": {"question_id": "cuet-phy-magmat-materials-20", "subtopic": "Dia-, Para-, and Ferromagnetic Materials", "topic_name": "Dia-, Para-, and Ferromagnetic Materials", "bloom_level": "apply", "options": [{"key": "A", "text": "0.5 W; preferred because it has high retentivity", "is_correct": false}, {"key": "B", "text": "5 W; preferred because of low hysteresis loss and easy magnetisation/demagnetisation", "is_correct": true}, {"key": "C", "text": "50 W; preferred because it has high coercivity", "is_correct": false}, {"key": "D", "text": "500 W; preferred because it retains magnetisation", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P = 50 × 0.002 × 50 = 5 W, not 0.5 W. Check the multiplication. Also, high retentivity is undesirable in transformer cores as it causes residual magnetisation.", "misconception": "Arithmetic error in calculating hysteresis loss and confusing permanent magnet properties with transformer requirements"}, {"option_key": "C", "hint": "The calculated power loss for soft iron is 5 W, not 50 W. Also, high coercivity makes demagnetisation difficult, which increases energy loss—the opposite of what is needed.", "misconception": "Incorrect calculation and confusing high coercivity with desirable transformer properties"}, {"option_key": "D", "hint": "500 W is the hysteresis loss for carbon steel, not soft iron. Retaining magnetisation (high retentivity) is a property of permanent magnets, not suitable for transformer cores.", "misconception": "Using the wrong material''s loss value and confusing permanent magnet properties with transformer requirements"}]}, "correct_answer": "B", "concept_tags": ["hysteresis-loss", "transformer-core", "soft-iron", "power-dissipation", "scenario-based"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-30');

