SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Biot-Savart law, the magnetic field dB due to a small current element Idl at a point P is proportional to:", "explanation": "The Biot-Savart law states dB = (μ₀/4π)(Idl × r̂)/r². The magnitude of dB is proportional to sinθ (from the cross product) and inversely proportional to r². Here θ is the angle between the current element dl and the position vector r pointing from the element to the point P.", "payload": {"question_id": "cuet-phy-magmov-biot-01", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "remember", "options": [{"key": "A", "text": "sinθ/r², where θ is the angle between dl and r", "is_correct": true}, {"key": "B", "text": "cosθ/r², where θ is the angle between dl and r", "is_correct": false}, {"key": "C", "text": "sinθ/r, where θ is the angle between dl and r", "is_correct": false}, {"key": "D", "text": "cosθ/r, where θ is the angle between dl and r", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Biot-Savart law involves a cross product (Idl × r̂), which gives sinθ, not cosθ. The cosθ dependence appears in electrostatics (e.g., electric flux), not here.", "misconception": "Confusing cross product with dot product"}, {"option_key": "C", "hint": "The field falls off as 1/r², not 1/r. The inverse-square dependence is analogous to Coulomb''s law.", "misconception": "Incorrect distance dependence"}, {"option_key": "D", "hint": "This has both the wrong angular dependence (cosθ instead of sinθ) and the wrong distance dependence (1/r instead of 1/r²).", "misconception": "Multiple errors in Biot-Savart law recall"}]}, "correct_answer": "A", "concept_tags": ["biot-savart-law", "magnetic-field", "current-element"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field at the centre of a circular loop of radius R carrying current I is:", "explanation": "Using the Biot-Savart law and integrating over the entire circular loop, every element dl is perpendicular to the position vector r (θ = 90°) and at a distance R from the centre. The integration gives B = μ₀I/(2R). This is a standard result frequently used in NEET problems.", "payload": {"question_id": "cuet-phy-magmov-biot-02", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I/(4πR)", "is_correct": false}, {"key": "B", "text": "μ₀I/(2R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀IR²/2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(4πR) would result from integrating only a quarter of the loop. The full circular loop gives μ₀I/(2R).", "misconception": "Incomplete integration of the loop"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the magnetic field due to a long straight conductor at perpendicular distance R, not at the centre of a circular loop.", "misconception": "Confusing straight wire formula with circular loop formula"}, {"option_key": "D", "hint": "This expression has incorrect dimensions. μ₀IR²/2 has units of T·m³, not Tesla. The correct formula is μ₀I/(2R).", "misconception": "Dimensional error in the formula"}]}, "correct_answer": "B", "concept_tags": ["circular-loop", "magnetic-field-centre", "biot-savart-law"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A long straight wire carries a current of 10 A. The magnetic field at a perpendicular distance of 0.1 m from the wire is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a long straight conductor, B = μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = (4π × 10⁻⁶)/(0.2π) = 2 × 10⁻⁵ T = 20 μT.", "payload": {"question_id": "cuet-phy-magmov-biot-03", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "2 × 10⁻⁴ T", "is_correct": false}, {"key": "C", "text": "2 × 10⁻⁵ T", "is_correct": true}, {"key": "D", "text": "2 × 10⁻⁷ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Recheck the calculation: μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = 2 × 10⁻⁵ T.", "misconception": "Arithmetic error with powers of 10"}, {"option_key": "B", "hint": "This is 100 times too large. The denominator 2πd = 2π × 0.1 ≈ 0.628, and dividing 4π × 10⁻⁶ by this gives 2 × 10⁻⁵, not 2 × 10⁻⁴.", "misconception": "Error in handling decimal distance"}, {"option_key": "D", "hint": "This equals μ₀/2π, which would correspond to I = 1 A at d = 1 m. With I = 10 A and d = 0.1 m, the field is much larger.", "misconception": "Using default values instead of given values"}]}, "correct_answer": "C", "concept_tags": ["straight-conductor", "magnetic-field", "numerical-problem"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ampere''s circuital law states that the line integral of magnetic field B around a closed loop equals:", "explanation": "Ampere''s circuital law states ∮B·dl = μ₀I_enclosed, where I_enclosed is the total current threading through the closed Amperian loop. This law is analogous to Gauss''s law in electrostatics and is most useful when the magnetic field has high symmetry.", "payload": {"question_id": "cuet-phy-magmov-biot-04", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀ times the total current in the circuit", "is_correct": false}, {"key": "B", "text": "The total magnetic flux through the loop", "is_correct": false}, {"key": "C", "text": "μ₀ε₀ times the rate of change of electric flux", "is_correct": false}, {"key": "D", "text": "μ₀ times the net current enclosed by the loop", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Ampere''s law considers only the current enclosed by (threading through) the Amperian loop, not the total current in the entire circuit.", "misconception": "Confusing enclosed current with total circuit current"}, {"option_key": "B", "hint": "The line integral ∮B·dl gives μ₀I_enclosed, not magnetic flux. Magnetic flux is the surface integral ∫B·dA.", "misconception": "Confusing line integral of B with surface integral of B"}, {"option_key": "C", "hint": "This is Maxwell''s displacement current term, which is an addition to Ampere''s law. The basic Ampere''s circuital law relates ∮B·dl to μ₀I_enclosed.", "misconception": "Confusing Ampere''s law with Maxwell''s modification"}]}, "correct_answer": "D", "concept_tags": ["ampere-law", "line-integral", "enclosed-current"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A circular loop of radius 0.1 m carries a current of 5 A. The magnetic field on the axis of the loop at a distance of 0.1 m from the centre is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "Using B = μ₀IR²/[2(R² + x²)^(3/2)] with R = 0.1 m, x = 0.1 m, I = 5 A: R² + x² = 0.01 + 0.01 = 0.02, so (R² + x²)^(3/2) = (0.02)^(3/2) = (0.02)^1 × √0.02 = 0.02 × 0.1414 = 2.828 × 10⁻³. Then B = (4π × 10⁻⁷ × 5 × 0.01)/(2 × 2.828 × 10⁻³) = (2π × 10⁻⁸)/(5.656 × 10⁻³) = 6.28 × 10⁻⁸/5.656 × 10⁻³ ≈ 1.11 × 10⁻⁵ T ≈ 11.1 μT.", "payload": {"question_id": "cuet-phy-magmov-biot-05", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1.11 × 10⁻⁵ T", "is_correct": true}, {"key": "B", "text": "3.14 × 10⁻⁵ T", "is_correct": false}, {"key": "C", "text": "2.22 × 10⁻⁵ T", "is_correct": false}, {"key": "D", "text": "5.55 × 10⁻⁶ T", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the value of μ₀I/(2R) = the field at the centre. At x = R on the axis, the field is reduced by a factor of 1/(2√2) compared to the centre field.", "misconception": "Using centre formula instead of axial formula"}, {"option_key": "C", "hint": "This is exactly double the correct answer. Check the factor of 2 in the denominator of B = μ₀IR²/[2(R² + x²)^(3/2)].", "misconception": "Missing the factor of 2 in the denominator"}, {"option_key": "D", "hint": "This is half the correct answer. Check the evaluation of (R² + x²)^(3/2) carefully.", "misconception": "Error in computing (R² + x²)^(3/2)"}]}, "correct_answer": "A", "concept_tags": ["circular-loop", "axial-field", "numerical-problem"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a semicircular wire of radius R carrying current I is:", "explanation": "A semicircular arc subtends an angle π at the centre. The field due to a circular arc subtending angle φ at the centre is B = μ₀Iφ/(4πR). For a semicircle, φ = π, so B = μ₀Iπ/(4πR) = μ₀I/(4R). The direction is perpendicular to the plane of the semicircle, determined by the right-hand rule.", "payload": {"question_id": "cuet-phy-magmov-biot-06", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A semicircle is half the loop, so its contribution is half: μ₀I/(4R).", "misconception": "Using full loop formula for semicircle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field due to a long straight wire at distance R. The semicircular arc formula is μ₀I/(4R).", "misconception": "Confusing straight wire formula with arc formula"}, {"option_key": "D", "hint": "μ₀I/(8R) would be the field due to a quarter-circle arc, not a semicircle. A semicircle subtends angle π, giving μ₀I/(4R).", "misconception": "Using quarter-circle result instead of semicircle"}]}, "correct_answer": "B", "concept_tags": ["semicircular-arc", "magnetic-field", "biot-savart-law"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 0.5 m has 1000 turns and carries a current of 2 A. The magnetic field inside the solenoid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a solenoid, B = μ₀nI where n = N/L = 1000/0.5 = 2000 turns/m. B = 4π × 10⁻⁷ × 2000 × 2 = 4π × 10⁻⁷ × 4000 = 16π × 10⁻⁴ = 16 × 3.14 × 10⁻⁴ ≈ 5.03 × 10⁻³ T ≈ 5.03 mT.", "payload": {"question_id": "cuet-phy-magmov-biot-07", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "2.51 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻³ T", "is_correct": false}, {"key": "C", "text": "5.03 × 10⁻³ T", "is_correct": true}, {"key": "D", "text": "5.03 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is exactly half the correct answer, suggesting you used N = 1000 instead of n = N/L = 2000 turns/m, or missed the current value.", "misconception": "Using total turns instead of turns per unit length"}, {"option_key": "B", "hint": "This would correspond to n = 1000 and I = 1, indicating errors in both n and I. Use n = N/L = 2000 turns/m and I = 2 A.", "misconception": "Multiple calculation errors"}, {"option_key": "D", "hint": "This is off by a factor of 10. Check the power of 10 in your calculation: μ₀nI = 4π × 10⁻⁷ × 2000 × 2 = 16π × 10⁻⁴ ≈ 5.03 × 10⁻³.", "misconception": "Power of 10 arithmetic error"}]}, "correct_answer": "C", "concept_tags": ["solenoid", "ampere-law", "numerical-problem"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a quarter-circle arc of radius R carrying current I is:", "explanation": "A quarter-circle arc subtends an angle π/2 at the centre. Using the formula B = μ₀Iφ/(4πR) for an arc of angle φ: B = μ₀I(π/2)/(4πR) = μ₀I/(8R). The straight portions (if connected along radii) contribute zero field at the centre because the current element is parallel to the position vector (sin0° = 0).", "payload": {"question_id": "cuet-phy-magmov-biot-08", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A quarter arc is one-fourth of the loop, giving μ₀I/(8R).", "misconception": "Using full loop formula for quarter arc"}, {"option_key": "B", "hint": "μ₀I/(4R) is the field due to a semicircular arc (half loop). A quarter arc gives half of this value: μ₀I/(8R).", "misconception": "Confusing semicircle with quarter circle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field of a long straight wire at distance R. The arc formula uses the angle subtended, not the straight-wire formula.", "misconception": "Applying straight wire formula to a curved conductor"}]}, "correct_answer": "D", "concept_tags": ["quarter-arc", "magnetic-field", "biot-savart-law"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A toroid has 500 turns, a mean radius of 0.2 m, and carries a current of 3 A. The magnetic field inside the toroid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a toroid, applying Ampere''s law: B × 2πr = μ₀NI, so B = μ₀NI/(2πr). B = (4π × 10⁻⁷ × 500 × 3)/(2π × 0.2) = (4π × 1.5 × 10⁻⁴)/(0.4π) = (6π × 10⁻⁴)/(0.4π) = 6 × 10⁻⁴/0.4 = 1.5 × 10⁻³ T = 1.5 mT.", "payload": {"question_id": "cuet-phy-magmov-biot-09", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "3.0 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.5 × 10⁻³ T", "is_correct": true}, {"key": "C", "text": "7.5 × 10⁻⁴ T", "is_correct": false}, {"key": "D", "text": "1.5 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is double the correct value. You may have used r = 0.1 m instead of the given mean radius r = 0.2 m in B = μ₀NI/(2πr).", "misconception": "Using radius instead of diameter, or halving the radius"}, {"option_key": "C", "hint": "This is half the correct answer. Check if you accidentally doubled the radius or halved the current in your calculation.", "misconception": "Arithmetic error in substitution"}, {"option_key": "D", "hint": "This is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 500 × 3 = 6π × 10⁻⁴, and dividing by 2π × 0.2 = 0.4π gives 1.5 × 10⁻³.", "misconception": "Power of 10 error in computation"}]}, "correct_answer": "B", "concept_tags": ["toroid", "ampere-law", "numerical-problem"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two concentric coplanar circular loops have radii R and 2R. The smaller loop carries current I in the anticlockwise direction and the larger loop carries current 2I in the clockwise direction, as seen from the same side. The magnetic field at the common centre is:", "explanation": "Field due to smaller loop (anticlockwise, out of plane): B₁ = μ₀I/(2R), directed outward. Field due to larger loop (clockwise, into plane): B₂ = μ₀(2I)/(2 × 2R) = μ₀I/(2R), directed inward. Since B₁ and B₂ are equal in magnitude but opposite in direction, the net field at the centre is zero.", "payload": {"question_id": "cuet-phy-magmov-biot-10", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "μ₀I/(2R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/R, directed into the plane", "is_correct": false}, {"key": "D", "text": "3μ₀I/(4R), directed out of the plane", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This ignores the contribution of the larger loop. Both loops contribute fields at the centre; you must find the vector sum. The two fields are equal and opposite, giving zero.", "misconception": "Considering only the smaller loop"}, {"option_key": "C", "hint": "The magnitudes are B₁ = μ₀I/(2R) (out) and B₂ = μ₀(2I)/(4R) = μ₀I/(2R) (in). These cancel out; they do not add to μ₀I/R.", "misconception": "Adding magnitudes instead of using vector directions"}, {"option_key": "D", "hint": "This does not correspond to any correct combination of the two fields. Compute each field using B = μ₀I/(2R) and apply superposition with correct directions.", "misconception": "Error in applying superposition principle"}]}, "correct_answer": "A", "concept_tags": ["concentric-loops", "superposition", "magnetic-field-direction"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire is bent into a shape consisting of a semicircular arc of radius R connected to two straight segments, each extending radially from the ends of the arc to a point at distance 2R from the centre, and then connected by another semicircular arc of radius 2R (same centre). A current I flows through this composite loop. The magnetic field at the common centre is:", "explanation": "The straight radial segments contribute zero field at the centre because for them, dl is parallel to r̂ (sinθ = 0). The inner semicircle of radius R contributes B₁ = μ₀I/(4R) (using the semicircle formula μ₀I/(4R), directed out of the plane, say). The outer semicircle of radius 2R contributes B₂ = μ₀I/(4 × 2R) = μ₀I/(8R) in the opposite direction (since current flows in the opposite sense around the centre). Net field = μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), directed out of the plane.", "payload": {"question_id": "cuet-phy-magmov-biot-11", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "B", "text": "3μ₀I/(8R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/(8R), directed out of the plane", "is_correct": true}, {"key": "D", "text": "3μ₀I/(4R), directed into the plane", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the field due to only the inner semicircular arc. You must also subtract the contribution of the outer semicircular arc, which opposes the inner one.", "misconception": "Ignoring the contribution of the outer semicircular arc"}, {"option_key": "B", "hint": "3μ₀I/(8R) would result from adding the two semicircular contributions instead of subtracting. The current traverses the two arcs in opposite senses relative to the centre, so the fields oppose each other.", "misconception": "Adding fields instead of subtracting due to opposite current directions"}, {"option_key": "D", "hint": "The magnitude and direction are both incorrect. The net field is μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), and its direction is that of the larger contribution (inner arc).", "misconception": "Errors in both magnitude and direction determination"}]}, "correct_answer": "C", "concept_tags": ["composite-loop", "semicircular-arcs", "superposition", "biot-savart-law"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A comparison between Biot-Savart law and Coulomb''s law shows that both:", "explanation": "Both the Biot-Savart law (dB = μ₀Idl×r̂/(4πr²)) and Coulomb''s law (E = q r̂/(4πε₀r²)) exhibit an inverse-square dependence on distance. However, the Biot-Savart law involves a cross product (giving an angular dependence and a field perpendicular to the plane of dl and r), while Coulomb''s law produces a field along the line joining the source and point. Both also have a similar constant structure: μ₀/4π in Biot-Savart and 1/4πε₀ in Coulomb''s law.", "payload": {"question_id": "cuet-phy-magmov-biot-12", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Produce fields along the line joining source and field point", "is_correct": false}, {"key": "B", "text": "Are valid only for static charges", "is_correct": false}, {"key": "C", "text": "Involve a dot product between source vector and displacement", "is_correct": false}, {"key": "D", "text": "Obey the inverse-square law of distance dependence", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s law gives a field along the line joining source and point, but Biot-Savart law gives a field perpendicular to the plane containing dl and r (due to the cross product).", "misconception": "Assuming both laws give fields in the same direction relative to source"}, {"option_key": "B", "hint": "Biot-Savart law deals with moving charges (current), not static charges. Coulomb''s law is for static charges. They are not both valid for the same scenario.", "misconception": "Confusing the domain of applicability of the two laws"}, {"option_key": "C", "hint": "Biot-Savart law involves a cross product (dl × r̂), not a dot product. This is a key difference from Coulomb''s law.", "misconception": "Confusing cross product with dot product in Biot-Savart law"}]}, "correct_answer": "D", "concept_tags": ["biot-savart-law", "coulomb-law", "comparison", "inverse-square"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The magnetic field outside an ideal solenoid is zero. Reason (R): Applying Ampere''s circuital law to a rectangular Amperian loop with one side inside and one side outside the solenoid, the contribution from the outside segment is zero because the field there is zero.", "explanation": "Both Assertion and Reason are correct, and R is the correct explanation of A. For an ideal (infinitely long) solenoid, using Ampere''s law with a rectangular loop: ∮B·dl = B_inside × l + 0 + B_outside × l + 0 = μ₀nIl. Since the field is confined inside (by symmetry and superposition arguments), B_outside = 0, and B_inside = μ₀nI. The Reason correctly describes how Ampere''s law is applied with the field outside being zero.", "payload": {"question_id": "cuet-phy-magmov-biot-13", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly describes the Amperian loop analysis that leads to the conclusion in the Assertion. It is not an unrelated fact; it is the specific explanation for why B = 0 outside.", "misconception": "Failing to see the direct causal link between Ampere''s law application and the result"}, {"option_key": "C", "hint": "The Reason is a correct description of how Ampere''s law is applied to an ideal solenoid. The zero field outside is both used as input (from symmetry) and confirmed by the law.", "misconception": "Incorrectly judging the Reason as false"}, {"option_key": "D", "hint": "The Assertion is well-established physics: an ideal infinite solenoid has zero external field. This is a standard NCERT result.", "misconception": "Incorrectly thinking a solenoid produces field outside"}]}, "correct_answer": "A", "concept_tags": ["solenoid", "ampere-law", "ideal-solenoid", "assertion-reasoning"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Biot-Savart law can be used to determine the magnetic field due to any arbitrary current distribution. Reason (R): Ampere''s circuital law can be conveniently used to calculate magnetic fields only when the system has sufficient symmetry.", "explanation": "Both A and R are correct statements. Biot-Savart law is a general law applicable to any current configuration (though integration may be complex). Ampere''s law, while always true, is practically useful for calculating B only in highly symmetric situations (infinite straight wire, solenoid, toroid). However, R is NOT the explanation for A. The reason Biot-Savart law is general is because it directly integrates the contribution of each current element, not because Ampere''s law has symmetry limitations.", "payload": {"question_id": "cuet-phy-magmov-biot-14", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are true, the limitation of Ampere''s law (needing symmetry) does not explain why Biot-Savart law is general. They are independent facts about two different laws.", "misconception": "Assuming that one law''s limitation automatically explains another law''s generality"}, {"option_key": "C", "hint": "The Reason is a correct statement. Ampere''s law is indeed only practically useful for field calculation when high symmetry exists (e.g., infinite wire, solenoid, toroid).", "misconception": "Thinking Ampere''s law always allows easy field computation"}, {"option_key": "D", "hint": "The Assertion is correct. Biot-Savart law is indeed a general law that can be applied to any current distribution by integrating dB contributions from each element.", "misconception": "Thinking Biot-Savart law has limited applicability"}]}, "correct_answer": "B", "concept_tags": ["biot-savart-law", "ampere-law", "symmetry", "assertion-reasoning"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Long straight conductor carrying current I\n(Q) Circular loop of radius R at its centre\n(R) Solenoid with n turns per unit length\n(S) Toroid of mean radius r with N total turns\n\nColumn II:\n(1) B = μ₀nI\n(2) B = μ₀I/(2πd)\n(3) B = μ₀NI/(2πr)\n(4) B = μ₀I/(2R)", "explanation": "P-2: A long straight conductor produces B = μ₀I/(2πd) at perpendicular distance d. Q-4: At the centre of a circular loop, B = μ₀I/(2R). R-1: Inside an ideal solenoid, B = μ₀nI. S-3: Inside a toroid, B = μ₀NI/(2πr). The correct matching is P-2, Q-4, R-1, S-3.", "payload": {"question_id": "cuet-phy-magmov-biot-15", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "understand", "options": [{"key": "A", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "B", "text": "P-2, Q-3, R-1, S-4", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": true}, {"key": "D", "text": "P-3, Q-4, R-1, S-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P-1 would assign B = μ₀nI to a straight conductor, but that is the solenoid formula. A straight conductor gives B = μ₀I/(2πd).", "misconception": "Confusing solenoid formula with straight wire formula"}, {"option_key": "B", "hint": "Q-3 assigns the toroid formula to the circular loop. The circular loop at centre gives B = μ₀I/(2R), not μ₀NI/(2πr).", "misconception": "Swapping circular loop and toroid formulas"}, {"option_key": "D", "hint": "P-3 assigns the toroid formula to a straight conductor and S-2 assigns the straight wire formula to the toroid. These are swapped.", "misconception": "Interchanging straight conductor and toroid formulas"}]}, "correct_answer": "C", "concept_tags": ["magnetic-field-formulas", "straight-conductor", "circular-loop", "solenoid", "toroid"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field on the axis of a circular loop at distance x >> R from centre\n(Q) Magnetic field at the centre of a circular arc subtending angle θ\n(R) Magnetic field inside a solenoid at a point near its end\n(S) Magnetic field at the centre of two concentric coplanar loops of radii R and 2R carrying equal current I in the same direction\n\nColumn II:\n(1) μ₀Iθ/(4πR)\n(2) Approximately μ₀nI/2\n(3) 3μ₀I/(4R)\n(4) Varies as 1/x³ (magnetic dipole behaviour)", "explanation": "P-4: For x >> R, B = μ₀IR²/[2(R² + x²)^(3/2)] ≈ μ₀IR²/(2x³), which varies as 1/x³ like a magnetic dipole. Q-1: The field at the centre of an arc of angle θ is B = μ₀Iθ/(4πR). R-2: At the end of a solenoid, the field is approximately half the interior value, i.e., ≈μ₀nI/2. S-3: B = μ₀I/(2R) + μ₀I/(2×2R) = μ₀I/(2R) + μ₀I/(4R) = 3μ₀I/(4R).", "payload": {"question_id": "cuet-phy-magmov-biot-16", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-4, Q-1, R-3, S-2", "is_correct": false}, {"key": "B", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "C", "text": "P-4, Q-3, R-2, S-1", "is_correct": false}, {"key": "D", "text": "P-4, Q-1, R-2, S-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "R-3 assigns 3μ₀I/(4R) to the solenoid end field, but that expression involves R (loop radius), not the solenoid parameters. The solenoid end field is ≈μ₀nI/2.", "misconception": "Confusing solenoid end field with concentric loop superposition"}, {"option_key": "B", "hint": "P-1 assigns the arc formula to the far-axis field. The far-axis field follows the dipole 1/x³ dependence, not the arc formula.", "misconception": "Mixing up axial field behaviour with arc field formula"}, {"option_key": "C", "hint": "Q-3 assigns 3μ₀I/(4R) to an arc, but that result comes from superposition of two concentric loops, not a single arc. The arc formula is μ₀Iθ/(4πR).", "misconception": "Confusing arc formula with superposition result"}]}, "correct_answer": "D", "concept_tags": ["axial-field", "magnetic-dipole", "arc-formula", "solenoid-end", "superposition"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside an ideal solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This is TRUE. By applying Ampere''s circuital law to an ideal (infinitely long) solenoid, the magnetic field inside is found to be B = μ₀nI, which is constant and does not depend on the position inside the solenoid. The field is directed along the axis of the solenoid, as determined by the right-hand rule. Outside the ideal solenoid, the field is zero.", "payload": {"question_id": "cuet-phy-magmov-biot-17", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is a well-known result from Ampere''s law. The field B = μ₀nI is independent of position inside the solenoid and is directed along the axis.", "misconception": "Thinking the field varies inside a solenoid or is not axial"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["solenoid", "uniform-field", "ampere-law"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field at a point on the axis of a current-carrying circular loop is always perpendicular to the axis of the loop.", "explanation": "This is FALSE. The magnetic field at any point on the axis of a current-carrying circular loop is directed along the axis of the loop (either towards or away from the loop depending on current direction), not perpendicular to it. By symmetry, the perpendicular components from opposite current elements cancel out, leaving only the axial component. The field is given by B = μ₀IR²/[2(R² + x²)^(3/2)] along the axis.", "payload": {"question_id": "cuet-phy-magmov-biot-18", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field on the axis is along the axis, not perpendicular to it. By symmetry, the perpendicular components cancel. Think of the right-hand thumb rule: curling fingers in the direction of current, the thumb points along the axis.", "misconception": "Confusing axial direction with perpendicular direction for on-axis field"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["circular-loop", "axial-field", "symmetry", "field-direction"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "If a circular coil of 200 turns and radius 0.05 m carries a current of 0.5 A, the magnetic field at its centre is _____ T. (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a flat coil of N turns, the magnetic field at the centre is B = μ₀NI/(2R). Substituting: B = (4π × 10⁻⁷ × 200 × 0.5)/(2 × 0.05) = (4π × 10⁻⁷ × 100)/0.1 = (4π × 10⁻⁵)/0.1 = 4π × 10⁻⁴ = 12.57 × 10⁻⁴ T ≈ 1.26 × 10⁻³ T.", "payload": {"question_id": "cuet-phy-magmov-biot-19", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 × 10⁻³", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻⁴", "is_correct": false}, {"key": "C", "text": "1.26 × 10⁻³", "is_correct": true}, {"key": "D", "text": "6.28 × 10⁻⁴", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6.28 × 10⁻³ is five times too large. Check if you used the correct radius: R = 0.05 m, not 0.01 m.", "misconception": "Using incorrect radius value"}, {"option_key": "B", "hint": "1.26 × 10⁻⁴ is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 200 × 0.5 = 4π × 10⁻⁵, and dividing by 2R = 0.1 gives 4π × 10⁻⁴ ≈ 1.26 × 10⁻³.", "misconception": "Power of 10 error"}, {"option_key": "D", "hint": "6.28 × 10⁻⁴ = 2π × 10⁻⁴, which suggests using N = 100 or I = 0.25. With the given values, B = 4π × 10⁻⁴ ≈ 1.26 × 10⁻³ T.", "misconception": "Halving one of the given quantities"}]}, "correct_answer": "C", "concept_tags": ["circular-coil", "multiple-turns", "magnetic-field-centre", "numerical-problem"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot-savart", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "An MRI (Magnetic Resonance Imaging) machine uses a large solenoid to produce a strong, uniform magnetic field for medical imaging. A particular MRI solenoid is 2 m long, has 10,000 turns, and produces a magnetic field of 1.5 T inside. What is the current flowing through the solenoid? (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a solenoid, B = μ₀nI, where n = N/L = 10000/2 = 5000 turns/m. Rearranging for current: I = B/(μ₀n) = 1.5/(4π × 10⁻⁷ × 5000) = 1.5/(2π × 10⁻³) = 1.5/(6.283 × 10⁻³) ≈ 238.7 A ≈ 239 A. This illustrates why MRI machines require superconducting coils to sustain such large currents without resistive heating.", "payload": {"question_id": "cuet-phy-magmov-biot-20", "subtopic": "Biot-Savart Law and Ampere''s Law", "topic_name": "Biot-Savart Law and Ampere''s Law", "bloom_level": "apply", "options": [{"key": "A", "text": "23.9 A", "is_correct": false}, {"key": "B", "text": "119 A", "is_correct": false}, {"key": "C", "text": "477 A", "is_correct": false}, {"key": "D", "text": "239 A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "23.9 A is ten times too small. Check n = N/L = 10000/2 = 5000 turns/m, not 50000. Then I = 1.5/(4π × 10⁻⁷ × 5000) ≈ 239 A.", "misconception": "Error in calculating turns per unit length"}, {"option_key": "B", "hint": "119 A is half the correct answer. This could result from using L = 1 m instead of 2 m (making n = 10000 instead of 5000), then dividing again incorrectly.", "misconception": "Using incorrect length or extra factor of 2"}, {"option_key": "C", "hint": "477 A is double the correct answer, suggesting n = N/L was calculated as 2500 instead of 5000, or an error in length. Use L = 2 m to get n = 5000.", "misconception": "Halving the turns per unit length"}]}, "correct_answer": "D", "concept_tags": ["solenoid", "MRI-application", "ampere-law", "numerical-problem", "real-world"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-31');

