SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A cyclotron is used to accelerate:", "explanation": "A cyclotron is used to accelerate charged particles such as protons, deuterons, and alpha particles. It cannot accelerate neutral particles (no Lorentz force) or electrons (their small mass causes relativistic effects at modest energies, making the cyclotron frequency condition invalid). The device uses a combination of electric and magnetic fields to accelerate charged particles to high energies.", "payload": {"question_id": "cuet-phy-magmov-devices-01", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "remember", "options": [{"key": "A", "text": "Electrons", "is_correct": false}, {"key": "B", "text": "Protons and deuterons", "is_correct": true}, {"key": "C", "text": "Neutral atoms", "is_correct": false}, {"key": "D", "text": "Neutrons", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small mass (9.1 x 10^-31 kg), so they quickly reach relativistic speeds where their mass increases significantly, violating the constant cyclotron frequency condition.", "misconception": "Thinking cyclotron works for all charged particles regardless of mass"}, {"option_key": "C", "hint": "Neutral atoms have no net charge, so they experience no Lorentz force (F = qv x B = 0) and cannot be accelerated by electric or magnetic fields.", "misconception": "Forgetting that cyclotron requires charged particles"}, {"option_key": "D", "hint": "Neutrons are uncharged particles. The cyclotron relies on the magnetic force (qvB) to bend particle paths, which is zero for neutral particles.", "misconception": "Confusing neutrons with charged particles"}]}, "correct_answer": "B", "concept_tags": ["cyclotron", "charged-particles", "particle-accelerator"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The time period of a charged particle revolving in a cyclotron is independent of:", "explanation": "In a cyclotron, the time period T = 2πm/(qB). This expression shows that T depends only on mass (m), charge (q), and magnetic field (B). It does not depend on the speed or energy of the particle (non-relativistic case). This is the key principle that makes the cyclotron work -- particles take the same time per revolution regardless of their speed, allowing a fixed-frequency oscillating electric field to accelerate them.", "payload": {"question_id": "cuet-phy-magmov-devices-02", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "remember", "options": [{"key": "A", "text": "Mass of the particle", "is_correct": false}, {"key": "B", "text": "Magnetic field strength", "is_correct": false}, {"key": "C", "text": "Speed of the particle", "is_correct": true}, {"key": "D", "text": "Charge of the particle", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The formula T = 2πm/(qB) explicitly contains mass m in the numerator, so the time period directly depends on mass.", "misconception": "Overlooking the mass dependence in the cyclotron frequency formula"}, {"option_key": "B", "hint": "Magnetic field B appears in the denominator of T = 2πm/(qB). Increasing B decreases the time period, so T depends on B.", "misconception": "Ignoring the role of magnetic field in determining the cyclotron period"}, {"option_key": "D", "hint": "Charge q is in the denominator of T = 2πm/(qB). A particle with larger charge has a shorter time period, so T does depend on charge.", "misconception": "Forgetting that charge influences the cyclotron frequency"}]}, "correct_answer": "C", "concept_tags": ["cyclotron-frequency", "time-period", "independence-of-speed"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "To convert a galvanometer into a voltmeter, one should connect:", "explanation": "A galvanometer is converted into a voltmeter by connecting a high resistance in series with it. This limits the current through the galvanometer to its full-scale deflection current (Ig) when the desired maximum voltage V is applied. The required series resistance R = V/Ig - G, where G is the galvanometer resistance. The high series resistance ensures that the voltmeter draws negligible current from the circuit.", "payload": {"question_id": "cuet-phy-magmov-devices-03", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "remember", "options": [{"key": "A", "text": "A high resistance in series", "is_correct": true}, {"key": "B", "text": "A low resistance in series", "is_correct": false}, {"key": "C", "text": "A high resistance in parallel", "is_correct": false}, {"key": "D", "text": "A low resistance in parallel", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A low resistance in series would barely increase the total resistance, so the galvanometer would still draw too much current and could be damaged. The resistance must be high to limit current to Ig.", "misconception": "Not understanding that a voltmeter must have very high resistance"}, {"option_key": "C", "hint": "A high resistance in parallel would have little effect since most current would still flow through the lower-resistance galvanometer. Parallel connection is used for ammeter conversion.", "misconception": "Confusing series and parallel configurations for meter conversion"}, {"option_key": "D", "hint": "A low resistance in parallel (shunt) is used to convert a galvanometer into an ammeter, not a voltmeter.", "misconception": "Confusing ammeter and voltmeter conversion methods"}]}, "correct_answer": "A", "concept_tags": ["galvanometer-conversion", "voltmeter", "series-resistance"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a moving coil galvanometer, the restoring torque is provided by:", "explanation": "In a moving coil galvanometer, the coil experiences a deflecting torque (τ = NIAB) due to the magnetic field. The restoring torque is provided by a pair of phosphor-bronze springs (hair springs) attached to the coil. At equilibrium, the restoring torque (kθ) equals the deflecting torque (NIAB), giving θ = NIAB/k. The springs also serve as leads to carry current to and from the coil.", "payload": {"question_id": "cuet-phy-magmov-devices-04", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic field", "is_correct": false}, {"key": "B", "text": "Gravity", "is_correct": false}, {"key": "C", "text": "The soft iron core", "is_correct": false}, {"key": "D", "text": "The phosphor-bronze spring", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic field produces the deflecting torque (τ = NIAB), not the restoring torque. The restoring mechanism must oppose the deflection.", "misconception": "Confusing deflecting torque with restoring torque"}, {"option_key": "B", "hint": "Gravity is not used as the restoring mechanism in a moving coil galvanometer. The instrument can work in any orientation because springs provide the restoring torque.", "misconception": "Confusing with gravity-based instruments"}, {"option_key": "C", "hint": "The soft iron core makes the magnetic field radial (uniform in all positions of the coil) to ensure linear deflection, but it does not provide the restoring torque.", "misconception": "Confusing the role of the iron core with the spring"}]}, "correct_answer": "D", "concept_tags": ["moving-coil-galvanometer", "restoring-torque", "spring", "equilibrium"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A cyclotron''s oscillator frequency is 10 MHz. If the magnetic field is 0.5 T, the charge-to-mass ratio (q/m) of the particle being accelerated is approximately:", "explanation": "The cyclotron frequency is given by f = qB/(2πm), so q/m = 2πf/B. Substituting the values: q/m = 2π x 10 x 10^6 / 0.5 = 2 x 3.14 x 10^7 / 0.5 = 6.28 x 10^7 / 0.5 = 1.256 x 10^8 C/kg ≈ 1.26 x 10^8 C/kg. This is close to the q/m ratio of a proton (e/mp = 1.6 x 10^-19 / 1.67 x 10^-27 ≈ 0.96 x 10^8 C/kg), suggesting a slightly different ion.", "payload": {"question_id": "cuet-phy-magmov-devices-05", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 x 10^7 C/kg", "is_correct": false}, {"key": "B", "text": "1.26 x 10^8 C/kg", "is_correct": true}, {"key": "C", "text": "3.14 x 10^8 C/kg", "is_correct": false}, {"key": "D", "text": "2.0 x 10^7 C/kg", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value (6.28 x 10^7) equals 2πf but forgets to divide by B. The correct formula is q/m = 2πf/B, and you must divide by 0.5 T.", "misconception": "Forgetting to divide by the magnetic field B"}, {"option_key": "C", "hint": "This value (3.14 x 10^8) corresponds to dividing by B but using πf instead of 2πf, or an arithmetic error in the multiplication.", "misconception": "Incorrect substitution in the cyclotron frequency formula"}, {"option_key": "D", "hint": "This value is significantly off from the correct calculation. With f = 10^7 Hz and B = 0.5 T, q/m = 2π x 10^7 / 0.5 = 4π x 10^7 ≈ 1.26 x 10^8.", "misconception": "Major arithmetic error or using the wrong formula"}]}, "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "charge-to-mass-ratio", "numerical"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 Ω and gives full-scale deflection for a current of 1 mA. To convert it into an ammeter of range 0 to 5 A, the shunt resistance required is:", "explanation": "To convert a galvanometer to an ammeter, a shunt resistance S is connected in parallel. Using the formula S = Ig x G/(I - Ig), where Ig = 1 mA = 0.001 A, G = 50 Ω, and I = 5 A: S = 0.001 x 50 / (5 - 0.001) = 0.05 / 4.999 ≈ 0.01 Ω. Since Ig << I, we can approximate S ≈ Ig x G / I = 0.001 x 50 / 5 = 0.01 Ω.", "payload": {"question_id": "cuet-phy-magmov-devices-06", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 Ω", "is_correct": true}, {"key": "B", "text": "0.05 Ω", "is_correct": false}, {"key": "C", "text": "1.0 Ω", "is_correct": false}, {"key": "D", "text": "50 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "0.05 Ω = Ig x G = 0.001 x 50. This is the numerator of the formula but you must divide by (I - Ig) ≈ 5 to get the shunt value.", "misconception": "Using S = Ig x G instead of the complete formula S = Ig x G/(I - Ig)"}, {"option_key": "C", "hint": "1.0 Ω is too high for a shunt. The shunt must be much smaller than the galvanometer resistance to divert most current away from the coil.", "misconception": "Not understanding that shunt resistance should be very small"}, {"option_key": "D", "hint": "Using S = G = 50 Ω means equal resistance in parallel, which would only double the range, not increase it 5000 times.", "misconception": "Thinking the shunt should equal the galvanometer resistance"}]}, "correct_answer": "A", "concept_tags": ["galvanometer-to-ammeter", "shunt-resistance", "numerical-problem"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current sensitivity of a moving coil galvanometer can be increased by:", "explanation": "Current sensitivity Is = NAB/k, where N is the number of turns, A is the area of the coil, B is the magnetic field strength, and k is the torsional spring constant. To increase current sensitivity, we can increase N, A, or B, or decrease k (use a weaker spring). Increasing the spring constant k would decrease the sensitivity, not increase it.", "payload": {"question_id": "cuet-phy-magmov-devices-07", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "understand", "options": [{"key": "A", "text": "Increasing the spring constant k", "is_correct": false}, {"key": "B", "text": "Decreasing the number of turns N", "is_correct": false}, {"key": "C", "text": "Increasing the magnetic field strength B", "is_correct": true}, {"key": "D", "text": "Decreasing the area of the coil A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since Is = NAB/k, increasing k (denominator) would decrease the sensitivity, making the galvanometer less sensitive to small currents.", "misconception": "Confusing direct and inverse proportionality in the sensitivity formula"}, {"option_key": "B", "hint": "N appears in the numerator of Is = NAB/k. Decreasing N would reduce sensitivity, not increase it.", "misconception": "Incorrectly identifying N as being in the denominator"}, {"option_key": "D", "hint": "Area A is in the numerator of Is = NAB/k. A larger coil area increases the torque for a given current, increasing sensitivity.", "misconception": "Thinking smaller area gives better sensitivity"}]}, "correct_answer": "C", "concept_tags": ["current-sensitivity", "galvanometer", "NAB-by-k"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer of resistance 100 Ω gives full-scale deflection for a current of 10 mA. The resistance to be connected in series to convert it into a voltmeter of range 0-100 V is:", "explanation": "To convert a galvanometer to a voltmeter, a high resistance R is connected in series. Using R = V/Ig - G, where V = 100 V, Ig = 10 mA = 0.01 A, and G = 100 Ω: R = 100/0.01 - 100 = 10000 - 100 = 9900 Ω. The total resistance of the voltmeter becomes G + R = 10000 Ω, ensuring that only Ig flows when V is applied across it.", "payload": {"question_id": "cuet-phy-magmov-devices-08", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "apply", "options": [{"key": "A", "text": "10000 Ω", "is_correct": false}, {"key": "B", "text": "1000 Ω", "is_correct": false}, {"key": "C", "text": "10 Ω", "is_correct": false}, {"key": "D", "text": "9900 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10000 Ω is V/Ig = 100/0.01, which is the total resistance needed. But the question asks for the series resistance R alone, so you must subtract G: R = 10000 - 100 = 9900 Ω.", "misconception": "Forgetting to subtract the galvanometer resistance G from V/Ig"}, {"option_key": "B", "hint": "1000 Ω would give a total resistance of 1100 Ω, limiting the voltmeter range to only V = Ig x (G + R) = 0.01 x 1100 = 11 V, not 100 V.", "misconception": "Arithmetic error or using wrong formula"}, {"option_key": "C", "hint": "10 Ω is far too small. With R = 10 Ω, total resistance = 110 Ω, giving range V = 0.01 x 110 = 1.1 V only.", "misconception": "Confusing voltmeter conversion with ammeter conversion (where low resistance is used)"}]}, "correct_answer": "D", "concept_tags": ["galvanometer-to-voltmeter", "series-resistance", "numerical-problem"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum kinetic energy of a charged particle emerging from a cyclotron of radius R, magnetic field B, charge q, and mass m is:", "explanation": "In a cyclotron, the charged particle moves in a circular path where the magnetic force provides centripetal force: qvB = mv^2/R, giving v = qBR/m. The maximum kinetic energy is KE = (1/2)mv^2 = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m). Here R is the radius of the largest semicircular path (the dee radius).", "payload": {"question_id": "cuet-phy-magmov-devices-09", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "apply", "options": [{"key": "A", "text": "q²B²R²/(2m)", "is_correct": true}, {"key": "B", "text": "qBR/(2m)", "is_correct": false}, {"key": "C", "text": "q²B²R²/(m)", "is_correct": false}, {"key": "D", "text": "qB²R²/(2m)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This expression has dimensions of velocity (m/s), not energy (kg m^2/s^2). The kinetic energy must involve squared terms of q, B, and R.", "misconception": "Confusing the expression for velocity with kinetic energy"}, {"option_key": "C", "hint": "This is twice the correct answer. KE = (1/2)mv^2 has the factor of 1/2, so the result should be q^2B^2R^2/(2m), not q^2B^2R^2/m.", "misconception": "Forgetting the factor of 1/2 in the kinetic energy formula"}, {"option_key": "D", "hint": "This expression is missing one factor of q. Since v = qBR/m, the KE = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m), requiring q squared.", "misconception": "Error in squaring the velocity expression"}]}, "correct_answer": "A", "concept_tags": ["cyclotron", "kinetic-energy", "maximum-energy", "dee-radius"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The voltage sensitivity of a galvanometer of resistance G, having N turns of area A in magnetic field B with spring constant k is given by:", "explanation": "Voltage sensitivity Vs = deflection per unit voltage = θ/V. Since θ/I (current sensitivity) = NAB/k, and V = IR (where R is the total resistance = G for the galvanometer alone), we get Vs = θ/V = (θ/I) x (1/G) = NAB/(kG). Thus voltage sensitivity depends inversely on the galvanometer resistance, unlike current sensitivity.", "payload": {"question_id": "cuet-phy-magmov-devices-10", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "understand", "options": [{"key": "A", "text": "NAB/k", "is_correct": false}, {"key": "B", "text": "NABk/G", "is_correct": false}, {"key": "C", "text": "NAB/(kG)", "is_correct": true}, {"key": "D", "text": "NAG/(kB)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "NAB/k is the current sensitivity (θ/I), not the voltage sensitivity. Voltage sensitivity = current sensitivity / G = NAB/(kG).", "misconception": "Confusing current sensitivity with voltage sensitivity"}, {"option_key": "B", "hint": "This expression has k in the numerator. Since higher spring constant k means lower deflection per unit current, k must be in the denominator.", "misconception": "Placing k incorrectly in the formula"}, {"option_key": "D", "hint": "This expression has G in the numerator and B in the denominator, both of which are inverted. Higher B gives more torque (hence more sensitivity), and higher G gives less voltage sensitivity.", "misconception": "Swapping the positions of B and G"}]}, "correct_answer": "C", "concept_tags": ["voltage-sensitivity", "galvanometer", "NAB-by-kG"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton is accelerated in a cyclotron with magnetic field 1.5 T. The radius of the dees is 0.5 m. The maximum kinetic energy gained by the proton is approximately (mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C):", "explanation": "Maximum KE = q^2B^2R^2/(2m). Substituting: KE = (1.6 x 10^-19)^2 x (1.5)^2 x (0.5)^2 / (2 x 1.67 x 10^-27) = (2.56 x 10^-38) x 2.25 x 0.25 / (3.34 x 10^-27) = (2.56 x 10^-38 x 0.5625) / (3.34 x 10^-27) = 1.44 x 10^-38 / 3.34 x 10^-27 = 4.31 x 10^-12 J. Converting to MeV: 4.31 x 10^-12 / 1.6 x 10^-13 ≈ 26.9 MeV ≈ 27 MeV.", "payload": {"question_id": "cuet-phy-magmov-devices-11", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "apply", "options": [{"key": "A", "text": "7 MeV", "is_correct": false}, {"key": "B", "text": "14 MeV", "is_correct": false}, {"key": "C", "text": "27 MeV", "is_correct": true}, {"key": "D", "text": "54 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "7 MeV is approximately 1/4 of the correct answer. Check if you used R = 0.25 m instead of 0.5 m, or missed squaring one of the terms.", "misconception": "Using R instead of R^2 in the kinetic energy formula"}, {"option_key": "B", "hint": "14 MeV is half the correct answer. Ensure you have squared both q and B correctly in q^2B^2R^2/(2m).", "misconception": "Forgetting to square one of the quantities"}, {"option_key": "D", "hint": "54 MeV is double the correct answer. Check that you included the factor of 2 in the denominator of KE = q^2B^2R^2/(2m).", "misconception": "Forgetting the factor of 1/2 in the kinetic energy expression"}]}, "correct_answer": "C", "concept_tags": ["cyclotron", "maximum-kinetic-energy", "proton", "numerical-calculation"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer of resistance 50 Ω and full-scale deflection current 2 mA is to be converted into an ammeter of range 0-10 A and a voltmeter of range 0-200 V. The ratio of shunt resistance to series resistance is:", "explanation": "For ammeter: S = Ig x G/(I - Ig) = 0.002 x 50/(10 - 0.002) ≈ 0.1/9.998 ≈ 0.01 Ω. For voltmeter: R = V/Ig - G = 200/0.002 - 50 = 100000 - 50 = 99950 Ω. Ratio S/R = 0.01/99950 ≈ 1 x 10^-7. Alternatively, S/R = [Ig x G/(I - Ig)] / [V/Ig - G] ≈ [Ig x G/I] / [V/Ig] = Ig^2 x G / (IV) = (0.002)^2 x 50 / (10 x 200) = 2 x 10^-7 / 2000 = 1 x 10^-7.", "payload": {"question_id": "cuet-phy-magmov-devices-12", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 x 10^-3", "is_correct": false}, {"key": "B", "text": "1 x 10^-5", "is_correct": false}, {"key": "C", "text": "1 x 10^-6", "is_correct": false}, {"key": "D", "text": "1 x 10^-7", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would imply the shunt is only 1000 times smaller than the series resistance. Given the huge difference in conversion (ammeter needs ~0.01 Ω, voltmeter needs ~100000 Ω), the ratio should be much smaller.", "misconception": "Rough estimation without proper calculation"}, {"option_key": "B", "hint": "Verify your calculation: S ≈ 0.01 Ω and R ≈ 99950 Ω. The ratio 0.01/99950 is approximately 10^-7, not 10^-5.", "misconception": "Arithmetic error in the order of magnitude"}, {"option_key": "C", "hint": "Close but off by a factor of 10. Carefully recalculate: S/R = 0.01/99950 ≈ 1.0 x 10^-7.", "misconception": "Small arithmetic or rounding error"}]}, "correct_answer": "D", "concept_tags": ["ammeter-voltmeter-conversion", "shunt", "series-resistance", "ratio"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): The cyclotron frequency does not depend on the speed of the charged particle. Reason (R): In a cyclotron, as the particle gains speed, the radius of its circular path increases proportionally, keeping the time period constant.", "explanation": "Both the Assertion and Reason are correct, and the Reason correctly explains the Assertion. The cyclotron frequency f = qB/(2πm) is independent of speed. This is because when a particle gains energy and moves faster (v increases), it moves to a larger radius orbit (r = mv/(qB)), so r increases proportionally with v. Since T = 2πr/v = 2πm/(qB), the v cancels out, making the period constant. This is the fundamental principle that allows the cyclotron to use a fixed-frequency oscillating electric field.", "payload": {"question_id": "cuet-phy-magmov-devices-13", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly explains why the frequency is independent of speed: the increase in radius exactly compensates for the increase in speed, so the time per revolution stays constant. This is a causal explanation.", "misconception": "Not recognizing the causal connection between the radius-speed relationship and constant frequency"}, {"option_key": "C", "hint": "The Reason is factually correct. In a cyclotron, r = mv/(qB), so r is directly proportional to v. The circumference (2πr) grows in proportion to v, keeping T = 2πr/v constant.", "misconception": "Doubting the relationship between radius and speed"}, {"option_key": "D", "hint": "The Assertion is correct: from f = qB/(2πm), the frequency clearly does not contain velocity v, confirming it is independent of speed.", "misconception": "Thinking cyclotron frequency depends on speed"}]}, "correct_answer": "A", "concept_tags": ["cyclotron-frequency", "radius-speed-relation", "assertion-reasoning"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): Increasing the number of turns in a moving coil galvanometer always increases both its current sensitivity and voltage sensitivity. Reason (R): Current sensitivity is NAB/k and voltage sensitivity is NAB/(kG), and increasing N increases the resistance G of the coil.", "explanation": "The Assertion is incorrect. While increasing N does increase current sensitivity (Is = NAB/k), it also increases the coil resistance G (since G is proportional to N for a given wire). Voltage sensitivity Vs = NAB/(kG) = Is/G. As N increases, both NAB/k and G increase, and the net effect on Vs depends on the relative rates. In fact, since G is proportional to N (longer wire), Vs = NAB/(kG) may remain roughly constant or even decrease. So increasing N does NOT always increase voltage sensitivity. The Reason is correct: it correctly states both formulas and that increasing N increases G.", "payload": {"question_id": "cuet-phy-magmov-devices-14", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The Assertion claims increasing N always increases both sensitivities. But since G also increases with N, voltage sensitivity Vs = NAB/(kG) may not increase. The Assertion is therefore incorrect.", "misconception": "Ignoring the effect of increased resistance when adding more turns"}, {"option_key": "B", "hint": "Since the Assertion is incorrect (voltage sensitivity does not necessarily increase with N), options involving ''A is correct'' cannot be right.", "misconception": "Not analyzing the voltage sensitivity formula carefully"}, {"option_key": "C", "hint": "The Reason correctly states the formulas and the fact that G increases with N. This is physically accurate since more turns mean longer wire and greater resistance.", "misconception": "Thinking the Reason is wrong about resistance increasing with turns"}]}, "correct_answer": "D", "concept_tags": ["current-sensitivity", "voltage-sensitivity", "number-of-turns", "galvanometer-design"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Cyclotron frequency\n(Q) Shunt resistance for ammeter\n(R) Series resistance for voltmeter\n(S) Current sensitivity of galvanometer\n\nColumn II:\n(1) NAB/k\n(2) V/Ig - G\n(3) qB/(2πm)\n(4) Ig·G/(I - Ig)", "explanation": "P-3: Cyclotron frequency f = qB/(2πm). Q-4: Shunt resistance S = Ig·G/(I - Ig) for converting galvanometer to ammeter. R-2: Series resistance R = V/Ig - G for converting galvanometer to voltmeter. S-1: Current sensitivity = NAB/k, which is the deflection per unit current in a galvanometer.", "payload": {"question_id": "cuet-phy-magmov-devices-15", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "understand", "options": [{"key": "A", "text": "P-3, Q-2, R-4, S-1", "is_correct": false}, {"key": "B", "text": "P-3, Q-4, R-2, S-1", "is_correct": true}, {"key": "C", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}, {"key": "D", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps Q and R. The shunt resistance formula contains Ig·G/(I - Ig) which is (4), while the series resistance formula is V/Ig - G which is (2). So Q matches 4, not 2.", "misconception": "Swapping the ammeter and voltmeter conversion formulas"}, {"option_key": "C", "hint": "P-4 would match cyclotron frequency to the shunt formula, which is dimensionally inconsistent. Cyclotron frequency has units of Hz = 1/s, while Ig·G/(I-Ig) has units of Ω.", "misconception": "Not checking dimensional consistency of the formulas"}, {"option_key": "D", "hint": "P-1 matches cyclotron frequency with NAB/k, which is the current sensitivity formula. Cyclotron frequency f = qB/(2πm) matches with (3).", "misconception": "Confusing cyclotron frequency with galvanometer sensitivity"}]}, "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "ammeter-conversion", "voltmeter-conversion", "current-sensitivity", "match-the-following"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field inside a long solenoid\n(Q) Magnetic field of a toroid (inside)\n(R) Cyclotron maximum KE\n(S) Deflecting torque in a galvanometer\n\nColumn II:\n(1) NIAB\n(2) μ₀nI (n = turns per unit length)\n(3) q²B²R²/(2m)\n(4) μ₀NI/(2πr)", "explanation": "P-2: The magnetic field inside a long solenoid is B = μ₀nI, where n is the number of turns per unit length. Q-4: Inside a toroid, B = μ₀NI/(2πr), where N is total turns and r is the radius of the toroidal path. R-3: Maximum kinetic energy from a cyclotron is q²B²R²/(2m). S-1: The deflecting torque on the coil in a galvanometer is τ = NIAB.", "payload": {"question_id": "cuet-phy-magmov-devices-16", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-4, R-3, S-1", "is_correct": true}, {"key": "B", "text": "P-4, Q-2, R-3, S-1", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": false}, {"key": "D", "text": "P-2, Q-1, R-3, S-4", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This swaps P and Q. The solenoid field B = μ₀nI uses turns per unit length (n), while the toroid field B = μ₀NI/(2πr) uses total turns N and has r in the denominator.", "misconception": "Confusing the solenoid and toroid magnetic field formulas"}, {"option_key": "C", "hint": "R-1 would match cyclotron KE with NIAB (torque). The cyclotron KE expression q²B²R²/(2m) is (3), and NIAB is the galvanometer torque (1).", "misconception": "Swapping the cyclotron energy and galvanometer torque expressions"}, {"option_key": "D", "hint": "Q-1 would match toroid field with NIAB, which is the torque expression for a galvanometer. The toroid field is μ₀NI/(2πr), which is (4).", "misconception": "Not distinguishing between the torque formula and the toroid field formula"}]}, "correct_answer": "A", "concept_tags": ["solenoid", "toroid", "cyclotron-energy", "galvanometer-torque", "match-the-following"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The magnetic field inside a solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This statement is TRUE. Inside a long solenoid (ideal case), the magnetic field is uniform in both magnitude and direction. The field lines run parallel to the axis of the solenoid. This can be derived using Ampere''s law, which gives B = μ₀nI inside the solenoid (where n = N/L is the number of turns per unit length). Outside the solenoid, the field is approximately zero.", "payload": {"question_id": "cuet-phy-magmov-devices-17", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The field inside an ideal long solenoid is indeed uniform and axial. This is a standard result from Ampere''s law applied to a rectangular Amperian loop.", "misconception": "Confusing solenoid field with that of a bar magnet, where the field is non-uniform"}]}, "correct_answer": "A", "concept_tags": ["solenoid", "uniform-magnetic-field", "field-direction"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "A cyclotron can be used to accelerate electrons to high energies efficiently.", "explanation": "This statement is FALSE. A cyclotron cannot efficiently accelerate electrons because electrons have very small mass (9.1 x 10^-31 kg). Due to their low mass, electrons quickly reach relativistic speeds, at which point their mass increases significantly (relativistic mass increase). This causes the cyclotron frequency f = qB/(2πm) to decrease, and the particles go out of synchronization with the fixed-frequency oscillating electric field. This is a well-known limitation of the cyclotron.", "payload": {"question_id": "cuet-phy-magmov-devices-18", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small rest mass, so they reach relativistic speeds at relatively low energies. At relativistic speeds, the effective mass increases, changing the cyclotron frequency and causing loss of synchronization.", "misconception": "Thinking the cyclotron works for all charged particles without considering relativistic effects"}]}, "correct_answer": "B", "concept_tags": ["cyclotron", "electrons", "relativistic-effects", "limitation"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_the_blanks", "difficulty": "medium", "question_text": "In a moving coil galvanometer, a radial magnetic field is produced by using concave-shaped pole pieces and a _____ placed inside the coil.", "explanation": "A soft iron core is placed inside the coil of a moving coil galvanometer. The soft iron core, along with the concave-shaped (cylindrical) pole pieces of the permanent magnet, creates a radial magnetic field. In a radial field, the plane of the coil is always parallel to the magnetic field direction, so the torque τ = NIAB sin(90°) = NIAB for all angular positions. This ensures a linear relationship between the current and the deflection angle (θ ∝ I).", "payload": {"question_id": "cuet-phy-magmov-devices-19", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "remember", "options": [{"key": "A", "text": "Hard iron core", "is_correct": false}, {"key": "B", "text": "Copper cylinder", "is_correct": false}, {"key": "C", "text": "Soft iron core", "is_correct": true}, {"key": "D", "text": "Permanent magnet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Hard iron retains magnetism (used for permanent magnets) and is not suitable for the core. Soft iron is used because it has high permeability, low retentivity, and strengthens the radial field without permanent magnetization.", "misconception": "Confusing soft iron (high permeability, low retentivity) with hard iron (permanent magnets)"}, {"option_key": "B", "hint": "A copper cylinder is not used as the core. Copper is non-magnetic and would not help in creating a radial magnetic field. Soft iron''s high magnetic permeability is essential for concentrating field lines.", "misconception": "Confusing copper damping mechanism with the iron core"}, {"option_key": "D", "hint": "The permanent magnet provides the external magnetic field and is located outside the coil (as pole pieces). The core inside the coil is soft iron, which helps make this external field radial.", "misconception": "Confusing the location and role of the permanent magnet with the core"}]}, "correct_answer": "C", "concept_tags": ["moving-coil-galvanometer", "radial-field", "soft-iron-core", "construction"]}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "hard", "question_text": "A medical research lab uses a cyclotron to produce radioactive isotopes for PET (Positron Emission Tomography) scans. The cyclotron accelerates protons using a magnetic field of 2.0 T. The protons are extracted when they reach a radius of 0.4 m from the centre. If the cyclotron''s oscillating electric field operates at a fixed frequency, what is the frequency of the oscillating electric field, and what is the kinetic energy of the extracted protons? (Given: mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C)", "explanation": "The cyclotron frequency f = qB/(2πm) = (1.6 x 10^-19 x 2.0)/(2π x 1.67 x 10^-27) = 3.2 x 10^-19 / (1.049 x 10^-26) = 3.05 x 10^7 Hz ≈ 30.5 MHz. The maximum kinetic energy KE = q²B²R²/(2m) = (1.6 x 10^-19)² x (2.0)² x (0.4)² / (2 x 1.67 x 10^-27) = (2.56 x 10^-38 x 4 x 0.16) / (3.34 x 10^-27) = 1.638 x 10^-38 / 3.34 x 10^-27 = 4.9 x 10^-12 J. Converting: 4.9 x 10^-12 / 1.6 x 10^-13 ≈ 30.6 MeV. So the frequency is approximately 30.5 MHz and KE is approximately 30.6 MeV.", "payload": {"question_id": "cuet-phy-magmov-devices-20", "subtopic": "Cyclotron, Galvanometer, and Solenoid", "topic_name": "Cyclotron, Galvanometer, and Solenoid", "bloom_level": "apply", "options": [{"key": "A", "text": "Frequency ≈ 15.2 MHz, KE ≈ 15 MeV", "is_correct": false}, {"key": "B", "text": "Frequency ≈ 30.5 MHz, KE ≈ 30.6 MeV", "is_correct": true}, {"key": "C", "text": "Frequency ≈ 30.5 MHz, KE ≈ 61 MeV", "is_correct": false}, {"key": "D", "text": "Frequency ≈ 61 MHz, KE ≈ 30.6 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "15.2 MHz is half the correct frequency. Check your calculation: f = qB/(2πm). With B = 2.0 T, the numerator is qB = 3.2 x 10^-19, not 1.6 x 10^-19. Ensure you use B = 2.0 T, not 1.0 T.", "misconception": "Using B = 1.0 T instead of 2.0 T in the frequency formula"}, {"option_key": "C", "hint": "The frequency is correct at 30.5 MHz, but 61 MeV is double the actual KE. Verify the factor of 2 in the denominator: KE = q²B²R²/(2m), not q²B²R²/m.", "misconception": "Forgetting the factor of 2 in the kinetic energy denominator"}, {"option_key": "D", "hint": "61 MHz is double the correct frequency. The formula is f = qB/(2πm), and 2π ≈ 6.28, not π ≈ 3.14. Using π instead of 2π would give the wrong answer.", "misconception": "Using π instead of 2π in the cyclotron frequency formula"}]}, "correct_answer": "B", "concept_tags": ["cyclotron", "frequency", "kinetic-energy", "PET-scan", "medical-application", "numerical"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-32');

