SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnifying power of a simple microscope is given by:", "explanation": "A simple microscope (magnifying glass) is a convex lens of short focal length. Its magnifying power when the final image is at the least distance of distinct vision (D = 25 cm) is M = 1 + D/f. This formula assumes the image is formed at the near point.", "payload": {"question_id": "cuet-phy-ray-instruments-01", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "remember", "options": [{"key": "A", "text": "M = D/f", "is_correct": false}, {"key": "B", "text": "M = 1 + D/f", "is_correct": true}, {"key": "C", "text": "M = f/D", "is_correct": false}, {"key": "D", "text": "M = 1 + f/D", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "M = D/f gives the magnifying power when the image is at infinity (relaxed eye), not at the near point.", "misconception": "Confusing the formula for image at infinity with image at near point"}, {"option_key": "C", "hint": "M = f/D would give a value less than 1 for typical lenses (f < D), which contradicts the purpose of magnification.", "misconception": "Inverting the D/f ratio"}, {"option_key": "D", "hint": "M = 1 + f/D incorrectly swaps f and D. The correct formula has D in the numerator since D > f for useful magnification.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["simple-microscope", "magnifying-power", "convex-lens"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The near point of a normal human eye is at a distance of:", "explanation": "The near point (least distance of distinct vision) of a normal healthy eye is 25 cm. This is the closest distance at which the eye can focus on an object comfortably. The far point of a normal eye is at infinity.", "payload": {"question_id": "cuet-phy-ray-instruments-02", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "remember", "options": [{"key": "A", "text": "10 cm", "is_correct": false}, {"key": "B", "text": "15 cm", "is_correct": false}, {"key": "C", "text": "25 cm", "is_correct": true}, {"key": "D", "text": "50 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 cm is too close for the normal eye to focus. A person who can see clearly at 10 cm would have an abnormally high accommodation.", "misconception": null}, {"option_key": "B", "hint": "15 cm is less than the standard near point of 25 cm for a normal eye.", "misconception": null}, {"option_key": "D", "hint": "50 cm would be the near point of a person with presbyopia or hypermetropia, not a normal eye.", "misconception": "Confusing normal near point with that of a defective eye"}]}, "correct_answer": "C", "concept_tags": ["near-point", "human-eye", "least-distance-of-distinct-vision"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Myopia (short-sightedness) can be corrected by using a:", "explanation": "In myopia, the eye can see near objects clearly but distant objects appear blurred because the image is formed in front of the retina. A concave (diverging) lens of appropriate focal length diverges the incoming rays before they enter the eye, so the image shifts back to the retina.", "payload": {"question_id": "cuet-phy-ray-instruments-03", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "remember", "options": [{"key": "A", "text": "Concave lens", "is_correct": true}, {"key": "B", "text": "Convex lens", "is_correct": false}, {"key": "C", "text": "Cylindrical lens", "is_correct": false}, {"key": "D", "text": "Bifocal lens", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A convex lens converges light further, which would worsen myopia. Convex lenses are used to correct hypermetropia.", "misconception": "Confusing the corrective lens for myopia and hypermetropia"}, {"option_key": "C", "hint": "Cylindrical lenses are used to correct astigmatism, not myopia.", "misconception": "Confusing correction for astigmatism with myopia"}, {"option_key": "D", "hint": "Bifocal lenses are used for presbyopia, where both near and far vision need correction, not for simple myopia.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["myopia", "concave-lens", "defects-of-vision", "correction"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of power of a lens is:", "explanation": "The power of a lens is defined as P = 1/f, where f is the focal length in metres. The SI unit of lens power is the dioptre (D), where 1 D = 1 m⁻¹.", "payload": {"question_id": "cuet-phy-ray-instruments-04", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "remember", "options": [{"key": "A", "text": "Metre", "is_correct": false}, {"key": "B", "text": "Watt", "is_correct": false}, {"key": "C", "text": "Centimetre", "is_correct": false}, {"key": "D", "text": "Dioptre", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Metre is the unit of focal length, not power. Power is the reciprocal of focal length.", "misconception": "Confusing focal length unit with power unit"}, {"option_key": "B", "hint": "Watt is the unit of power in mechanics/electricity (energy per unit time), not optical power.", "misconception": "Confusing optical power with mechanical/electrical power"}, {"option_key": "C", "hint": "Centimetre is a unit of length and is not used as the unit of lens power.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["power-of-lens", "dioptre", "SI-unit"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnifying power of an astronomical telescope in normal adjustment is 20. If the focal length of the objective is 100 cm, the focal length of the eyepiece is:", "explanation": "For an astronomical telescope in normal adjustment (image at infinity), the magnifying power M = fₒ/fₑ. Given M = 20 and fₒ = 100 cm: 20 = 100/fₑ, so fₑ = 100/20 = 5 cm.", "payload": {"question_id": "cuet-phy-ray-instruments-05", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "apply", "options": [{"key": "A", "text": "2 cm", "is_correct": false}, {"key": "B", "text": "5 cm", "is_correct": true}, {"key": "C", "text": "10 cm", "is_correct": false}, {"key": "D", "text": "20 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "fₑ = 2 cm would give M = 100/2 = 50, not 20.", "misconception": null}, {"option_key": "C", "hint": "fₑ = 10 cm would give M = 100/10 = 10, not 20.", "misconception": null}, {"option_key": "D", "hint": "fₑ = 20 cm would give M = 100/20 = 5, not 20. Do not confuse the magnification value with the focal length.", "misconception": "Confusing the magnifying power value with the eyepiece focal length"}]}, "correct_answer": "B", "concept_tags": ["astronomical-telescope", "magnifying-power", "focal-length"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A compound microscope consists of an objective of focal length 1 cm and an eyepiece of focal length 5 cm. If the length of the tube is 20 cm and the image is formed at the least distance of distinct vision (25 cm), the magnifying power is approximately:", "explanation": "For a compound microscope, M = (L/fₒ) × (1 + D/fₑ), where L is the image distance from the objective (approximately the tube length minus fₑ for rough calculation). More precisely, L ≈ 20 − 5 = 15 cm (separation between objective image and eyepiece). So M = (15/1) × (1 + 25/5) = 15 × 6 = 90. The magnifying power is approximately 90.", "payload": {"question_id": "cuet-phy-ray-instruments-06", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "apply", "options": [{"key": "A", "text": "30", "is_correct": false}, {"key": "B", "text": "60", "is_correct": false}, {"key": "C", "text": "90", "is_correct": true}, {"key": "D", "text": "120", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "30 would result from using M = L/fₒ × D/fₑ without the +1 term and with incorrect L.", "misconception": null}, {"option_key": "B", "hint": "60 results from using L = 20 cm directly instead of subtracting fₑ to get the image distance from the objective.", "misconception": "Using total tube length instead of image distance from objective"}, {"option_key": "D", "hint": "120 would require L/fₒ = 20, implying L = 20 cm without subtracting fₑ, combined with the full eyepiece magnification.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["compound-microscope", "magnifying-power", "objective", "eyepiece"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The length of an astronomical telescope in normal adjustment is 105 cm. If the magnifying power is 20, the focal lengths of the objective and eyepiece are:", "explanation": "In normal adjustment, the tube length L = fₒ + fₑ = 105 cm and M = fₒ/fₑ = 20. From M: fₒ = 20fₑ. Substituting: 20fₑ + fₑ = 105, so 21fₑ = 105, giving fₑ = 5 cm and fₒ = 100 cm.", "payload": {"question_id": "cuet-phy-ray-instruments-07", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "apply", "options": [{"key": "A", "text": "fₒ = 100 cm, fₑ = 5 cm", "is_correct": true}, {"key": "B", "text": "fₒ = 95 cm, fₑ = 10 cm", "is_correct": false}, {"key": "C", "text": "fₒ = 84 cm, fₑ = 21 cm", "is_correct": false}, {"key": "D", "text": "fₒ = 105 cm, fₑ = 5.25 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "fₒ + fₑ = 95 + 10 = 105 cm (correct sum), but fₒ/fₑ = 95/10 = 9.5, not 20.", "misconception": null}, {"option_key": "C", "hint": "fₒ + fₑ = 84 + 21 = 105 cm (correct sum), but fₒ/fₑ = 84/21 = 4, not 20.", "misconception": null}, {"option_key": "D", "hint": "fₒ + fₑ = 105 + 5.25 = 110.25 cm, which does not equal the tube length of 105 cm.", "misconception": "Ignoring the constraint that fₒ + fₑ = L"}]}, "correct_answer": "A", "concept_tags": ["astronomical-telescope", "tube-length", "magnifying-power", "focal-length"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A person with hypermetropia has a near point at 75 cm. The power of the corrective lens required to bring the near point to the normal position (25 cm) is:", "explanation": "The corrective lens must form a virtual image at 75 cm (the defective near point) of an object placed at 25 cm (the normal near point). Using the thin lens formula: 1/f = 1/v − 1/u = 1/(−75) − 1/(−25) = −1/75 + 1/25 = (−1 + 3)/75 = 2/75. So f = 75/2 = 37.5 cm = 0.375 m. Power P = 1/f = 1/0.375 ≈ +2.67 D.", "payload": {"question_id": "cuet-phy-ray-instruments-08", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "apply", "options": [{"key": "A", "text": "+1.33 D", "is_correct": false}, {"key": "B", "text": "−2.67 D", "is_correct": false}, {"key": "C", "text": "+4.0 D", "is_correct": false}, {"key": "D", "text": "+2.67 D", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "+1.33 D corresponds to f = 75 cm, which would result from using P = 1/v only, without applying the full lens formula.", "misconception": null}, {"option_key": "B", "hint": "A negative power (concave lens) would further diverge light, making hypermetropia worse. Correction requires a converging (positive) lens.", "misconception": "Using a concave lens for hypermetropia"}, {"option_key": "C", "hint": "+4.0 D corresponds to f = 25 cm. This would result from using only the object distance, ignoring the image distance constraint.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["hypermetropia", "corrective-lens", "power-of-lens", "lens-formula"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A convex lens of focal length 10 cm is used as a magnifying glass. The maximum magnifying power when the image is formed at the least distance of distinct vision is:", "explanation": "The magnifying power of a simple microscope with the image at the near point is M = 1 + D/f = 1 + 25/10 = 1 + 2.5 = 3.5. This is the maximum magnifying power achievable with this lens.", "payload": {"question_id": "cuet-phy-ray-instruments-09", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "apply", "options": [{"key": "A", "text": "2.5", "is_correct": false}, {"key": "B", "text": "3.0", "is_correct": false}, {"key": "C", "text": "3.5", "is_correct": true}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2.5 = D/f, which is the magnifying power when the image is at infinity, not at the near point.", "misconception": "Using M = D/f instead of M = 1 + D/f for near point image"}, {"option_key": "B", "hint": "3.0 does not correspond to any standard formula for this configuration.", "misconception": null}, {"option_key": "D", "hint": "10 is the focal length in cm, not the magnifying power. M = 1 + D/f, not f itself.", "misconception": "Confusing focal length with magnifying power"}]}, "correct_answer": "C", "concept_tags": ["simple-microscope", "magnifying-power", "near-point"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The accommodation of the human eye refers to the ability of the eye to:", "explanation": "Accommodation is the ability of the eye lens to change its focal length by altering its curvature through the action of ciliary muscles. When viewing near objects, the ciliary muscles contract, making the lens thicker and decreasing its focal length. For distant objects, the muscles relax, making the lens thinner and increasing the focal length.", "payload": {"question_id": "cuet-phy-ray-instruments-10", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "understand", "options": [{"key": "A", "text": "Change the size of the pupil", "is_correct": false}, {"key": "B", "text": "Adjust the focal length of the eye lens", "is_correct": true}, {"key": "C", "text": "Change the distance between the lens and retina", "is_correct": false}, {"key": "D", "text": "Change the refractive index of the eye lens", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Changing pupil size controls the amount of light entering the eye (like an aperture), not the focusing ability.", "misconception": "Confusing pupil adjustment with accommodation"}, {"option_key": "C", "hint": "In the human eye, the distance between the lens and retina is fixed. The eye focuses by changing the lens curvature, not by moving the lens.", "misconception": "Applying camera focusing mechanism to the human eye"}, {"option_key": "D", "hint": "The refractive index of the eye lens material does not change during accommodation; only its curvature changes.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["accommodation", "human-eye", "ciliary-muscles", "focal-length"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A Galilean telescope has an objective of focal length 30 cm and an eyepiece of focal length 6 cm. For a normal adjustment, the magnifying power and the length of the telescope are:", "explanation": "A Galilean telescope uses a concave lens as the eyepiece. The magnifying power M = fₒ/fₑ = 30/6 = 5. The length of the telescope in normal adjustment is L = fₒ − fₑ = 30 − 6 = 24 cm (since the eyepiece is a diverging lens placed inside the focal point of the objective).", "payload": {"question_id": "cuet-phy-ray-instruments-11", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "analyze", "options": [{"key": "A", "text": "M = 5, L = 36 cm", "is_correct": false}, {"key": "B", "text": "M = 6, L = 24 cm", "is_correct": false}, {"key": "C", "text": "M = 5, L = 30 cm", "is_correct": false}, {"key": "D", "text": "M = 5, L = 24 cm", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "L = 36 cm = fₒ + fₑ is the tube length for an astronomical telescope (with a convex eyepiece), not a Galilean telescope.", "misconception": "Using L = fₒ + fₑ for a Galilean telescope instead of L = fₒ − fₑ"}, {"option_key": "B", "hint": "M = 6 would require fₒ/fₑ = 6, but 30/6 = 5, not 6.", "misconception": null}, {"option_key": "C", "hint": "L = 30 cm equals fₒ alone. The tube length of a Galilean telescope is fₒ − fₑ, not just fₒ.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["galilean-telescope", "magnifying-power", "tube-length", "concave-eyepiece"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A reflecting telescope uses a concave mirror of focal length 100 cm as its objective. If the magnifying power is 50 and the final image is at infinity, the focal length of the eyepiece is:", "explanation": "For a reflecting telescope with the final image at infinity, the magnifying power M = fₒ/fₑ, same as for a refracting telescope. Given M = 50 and fₒ = 100 cm: fₑ = fₒ/M = 100/50 = 2 cm.", "payload": {"question_id": "cuet-phy-ray-instruments-12", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "analyze", "options": [{"key": "A", "text": "2 cm", "is_correct": true}, {"key": "B", "text": "5 cm", "is_correct": false}, {"key": "C", "text": "50 cm", "is_correct": false}, {"key": "D", "text": "0.5 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "fₑ = 5 cm gives M = 100/5 = 20, not 50.", "misconception": null}, {"option_key": "C", "hint": "fₑ = 50 cm gives M = 100/50 = 2, not 50. This confuses the magnification value with the focal length.", "misconception": "Confusing magnifying power with eyepiece focal length"}, {"option_key": "D", "hint": "fₑ = 0.5 cm gives M = 100/0.5 = 200, which is much larger than 50.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["reflecting-telescope", "magnifying-power", "concave-mirror", "eyepiece"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): In an astronomical telescope, the objective has a large focal length and the eyepiece has a small focal length.\nReason (R): The magnifying power of an astronomical telescope in normal adjustment is M = fₒ/fₑ.", "explanation": "Both A and R are correct. The magnifying power M = fₒ/fₑ shows that to achieve high magnification, fₒ should be large and fₑ should be small. The reason directly explains why the objective has a large focal length and the eyepiece a small one, so R is the correct explanation of A.", "payload": {"question_id": "cuet-phy-ray-instruments-13", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: the formula M = fₒ/fₑ shows that large fₒ and small fₑ maximise magnification.", "misconception": null}, {"option_key": "C", "hint": "R is the standard and correct formula for the magnifying power of an astronomical telescope in normal adjustment.", "misconception": null}, {"option_key": "D", "hint": "A is correct; any standard astronomical telescope is designed with a long focal length objective and a short focal length eyepiece.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["astronomical-telescope", "magnifying-power", "objective", "eyepiece"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): A reflecting telescope is preferred over a refracting telescope for large aperture instruments.\nReason (R): Large lenses suffer from chromatic aberration and are difficult to manufacture without sagging, whereas large mirrors do not have chromatic aberration and can be supported from behind.", "explanation": "Both A and R are correct, and R is the correct explanation of A. Large aperture refracting telescopes suffer from chromatic aberration (since lenses disperse light) and mechanical issues like sagging due to gravity. Reflecting telescopes use mirrors, which have no chromatic aberration and can be supported from behind to prevent sagging. These are the primary reasons why reflecting telescopes are preferred for large instruments.", "payload": {"question_id": "cuet-phy-ray-instruments-14", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly addresses the advantages of mirrors over lenses for large apertures, which is exactly why reflecting telescopes are preferred. R explains A.", "misconception": null}, {"option_key": "C", "hint": "R is factually correct — large lenses do suffer from chromatic aberration and sagging, and mirrors avoid both issues.", "misconception": null}, {"option_key": "D", "hint": "A is correct; all major astronomical observatories use reflecting telescopes for their large instruments.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["reflecting-telescope", "refracting-telescope", "chromatic-aberration", "advantages"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the eye defects in Column I with their corrective lenses in Column II:\n\nColumn I:\nA. Myopia\nB. Hypermetropia\nC. Astigmatism\nD. Presbyopia\n\nColumn II:\n1. Bifocal lens\n2. Cylindrical lens\n3. Concave lens\n4. Convex lens", "explanation": "Myopia is corrected using a concave lens to diverge light (A-3). Hypermetropia is corrected using a convex lens to converge light (B-4). Astigmatism, caused by a non-spherical cornea, is corrected using a cylindrical lens (C-2). Presbyopia, affecting both near and far vision in old age, is corrected using bifocal lenses (D-1).", "payload": {"question_id": "cuet-phy-ray-instruments-15", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "understand", "options": [{"key": "A", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-3, B-4, C-2, D-1", "is_correct": true}, {"key": "C", "text": "A-3, B-4, C-1, D-2", "is_correct": false}, {"key": "D", "text": "A-2, B-1, C-3, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps the corrective lenses for myopia and hypermetropia. Myopia requires a concave (diverging) lens, not convex.", "misconception": "Interchanging corrective lenses for myopia and hypermetropia"}, {"option_key": "C", "hint": "This swaps astigmatism and presbyopia corrections. Astigmatism uses cylindrical lenses (2), not bifocal (1).", "misconception": null}, {"option_key": "D", "hint": "This assigns completely incorrect lenses to all defects and has no basis in optics.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["myopia", "hypermetropia", "astigmatism", "presbyopia", "corrective-lens"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the optical instruments in Column I with the correct expression for their magnifying power in Column II:\n\nColumn I:\nA. Simple microscope (image at near point)\nB. Astronomical telescope (normal adjustment)\nC. Compound microscope (image at infinity)\nD. Galilean telescope (normal adjustment)\n\nColumn II:\n1. fₒ/fₑ\n2. (L/fₒ)(D/fₑ)\n3. 1 + D/f\n4. fₒ/fₑ (erect image)", "explanation": "A simple microscope with image at the near point has M = 1 + D/f (A-3). An astronomical telescope in normal adjustment has M = fₒ/fₑ (B-1). A compound microscope with image at infinity has M = (L/fₒ)(D/fₑ) where L is the tube length (C-2). A Galilean telescope in normal adjustment also has M = fₒ/fₑ but produces an erect image (D-4).", "payload": {"question_id": "cuet-phy-ray-instruments-16", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-4, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "C", "text": "A-3, B-1, C-2, D-4", "is_correct": true}, {"key": "D", "text": "A-1, B-3, C-4, D-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and D. The astronomical telescope (B) matches fₒ/fₑ (1), while the Galilean telescope (D) matches fₒ/fₑ with erect image (4).", "misconception": null}, {"option_key": "B", "hint": "A-2 assigns the compound microscope formula to the simple microscope, which is incorrect. The simple microscope uses M = 1 + D/f.", "misconception": "Confusing simple and compound microscope formulas"}, {"option_key": "D", "hint": "This assigns completely incorrect formulas to all instruments. The simple microscope does not use M = fₒ/fₑ.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["magnifying-power", "simple-microscope", "compound-microscope", "astronomical-telescope", "galilean-telescope"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The magnifying power of an astronomical telescope increases if the focal length of the objective is increased.", "explanation": "This statement is true. The magnifying power of an astronomical telescope in normal adjustment is M = fₒ/fₑ. If fₒ (focal length of the objective) increases while fₑ remains constant, the magnifying power increases proportionally.", "payload": {"question_id": "cuet-phy-ray-instruments-17", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Since M = fₒ/fₑ, increasing fₒ directly increases M. The statement is therefore true.", "misconception": "Thinking magnifying power decreases with larger objective focal length"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["astronomical-telescope", "magnifying-power", "focal-length"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "A person suffering from myopia can see distant objects clearly without any corrective lens.", "explanation": "This statement is false. Myopia (short-sightedness) means the person can see nearby objects clearly but distant objects appear blurred. The far point of a myopic eye is at a finite distance (not at infinity). A concave lens is needed to see distant objects clearly.", "payload": {"question_id": "cuet-phy-ray-instruments-18", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Myopia specifically means inability to see distant objects clearly. The image of distant objects falls in front of the retina.", "misconception": "Confusing myopia with normal vision or hypermetropia"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["myopia", "defects-of-vision", "far-point"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_blanks", "difficulty": "medium", "question_text": "The power of a concave lens of focal length 50 cm is _____ dioptre.", "explanation": "The power of a lens is P = 1/f, where f is in metres. For a concave (diverging) lens, the focal length is negative: f = −50 cm = −0.50 m. Therefore P = 1/(−0.50) = −2 D. The negative sign indicates a diverging lens.", "payload": {"question_id": "cuet-phy-ray-instruments-19", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "apply", "options": [{"key": "A", "text": "+2", "is_correct": false}, {"key": "B", "text": "−2", "is_correct": true}, {"key": "C", "text": "−0.5", "is_correct": false}, {"key": "D", "text": "+50", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "+2 D would be the power of a convex lens of focal length 50 cm. A concave lens has negative power.", "misconception": "Ignoring the sign convention for concave lens power"}, {"option_key": "C", "hint": "−0.5 would result from using P = −f (in metres) instead of P = 1/f.", "misconception": "Confusing focal length with power"}, {"option_key": "D", "hint": "+50 results from not converting cm to metres and ignoring the sign. P = 1/f where f must be in metres.", "misconception": "Forgetting to convert cm to metres and ignoring sign"}]}, "correct_answer": "B", "concept_tags": ["power-of-lens", "concave-lens", "dioptre", "focal-length"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "medium", "question_text": "A biology student uses a compound microscope to observe a cell. The objective lens has a focal length of 0.5 cm and the eyepiece has a focal length of 6.25 cm. The object is placed at a distance of 0.55 cm from the objective. The final image is formed at the least distance of distinct vision (25 cm).\n\nWhat is the approximate magnifying power of the microscope?", "explanation": "First, find the image formed by the objective using 1/v − 1/u = 1/f: 1/v = 1/fₒ + 1/uₒ = 1/0.5 + 1/(−0.55) = 2 − 1.818 = 0.182, so v ≈ 5.5 cm. Magnification by objective: mₒ = v/u = 5.5/(−0.55) = −10. Magnification by eyepiece: mₑ = 1 + D/fₑ = 1 + 25/6.25 = 1 + 4 = 5. Total magnifying power M = mₒ × mₑ = −10 × 5 = −50. The magnitude is 50.", "payload": {"question_id": "cuet-phy-ray-instruments-20", "subtopic": "Microscope, Telescope, and Human Eye", "topic_name": "Microscope, Telescope, and Human Eye", "bloom_level": "apply", "options": [{"key": "A", "text": "10", "is_correct": false}, {"key": "B", "text": "25", "is_correct": false}, {"key": "C", "text": "40", "is_correct": false}, {"key": "D", "text": "50", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10 is only the magnification produced by the objective alone. The total magnification includes the eyepiece contribution as well.", "misconception": "Ignoring the eyepiece magnification"}, {"option_key": "B", "hint": "25 does not correspond to any meaningful calculation. The eyepiece magnification alone is 5, not 25.", "misconception": null}, {"option_key": "C", "hint": "40 would result from using mₑ = D/fₑ = 4 instead of mₑ = 1 + D/fₑ = 5, missing the +1 term.", "misconception": "Using M = D/fₑ instead of M = 1 + D/fₑ for near-point image"}]}, "correct_answer": "D", "concept_tags": ["compound-microscope", "magnifying-power", "objective", "eyepiece", "lens-formula"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-34');

