SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Total internal reflection can occur when light travels from:", "explanation": "Total internal reflection occurs only when light travels from a denser medium (higher refractive index) to a rarer medium (lower refractive index) and the angle of incidence exceeds the critical angle. It cannot occur when light goes from a rarer to a denser medium.", "payload": {"question_id": "cuet-phy-ray-prism-01", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "A rarer medium to a denser medium", "is_correct": false}, {"key": "B", "text": "A denser medium to a rarer medium", "is_correct": true}, {"key": "C", "text": "Any medium to any other medium", "is_correct": false}, {"key": "D", "text": "Vacuum to any material medium", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "When light goes from rarer to denser medium, it bends towards the normal and can never reach the critical angle for TIR.", "misconception": "Reversing the condition for total internal reflection"}, {"option_key": "C", "hint": "TIR does not occur in all cases; it requires light to go from a denser to a rarer medium at an angle greater than the critical angle.", "misconception": null}, {"option_key": "D", "hint": "Vacuum has the lowest refractive index (n = 1), so light cannot go from vacuum to a material medium and undergo TIR.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["total-internal-reflection", "denser-rarer-medium", "critical-angle"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The critical angle for a medium of refractive index √2 is:", "explanation": "The critical angle C is given by sin C = 1/n. For n = √2, sin C = 1/√2, which gives C = 45°. At this angle, the refracted ray grazes along the surface of separation.", "payload": {"question_id": "cuet-phy-ray-prism-02", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "30°", "is_correct": false}, {"key": "B", "text": "60°", "is_correct": false}, {"key": "C", "text": "45°", "is_correct": true}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "sin 30° = 0.5 = 1/2, which would correspond to n = 2, not √2.", "misconception": "Using wrong value of refractive index"}, {"option_key": "B", "hint": "sin 60° = √3/2 ≈ 0.866, which gives n = 2/√3 ≈ 1.155, not √2.", "misconception": null}, {"option_key": "D", "hint": "A critical angle of 90° would mean sin C = 1, giving n = 1, which corresponds to vacuum — not a medium with n = √2.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["critical-angle", "refractive-index", "total-internal-reflection"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following phenomena is responsible for the formation of a mirage in deserts?", "explanation": "Mirages in deserts are caused by total internal reflection. The air near the hot ground is less dense (lower refractive index) than the cooler air above. Light from distant objects travelling downward through layers of progressively rarer air gets totally internally reflected, creating an illusion of water on the ground.", "payload": {"question_id": "cuet-phy-ray-prism-03", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "Total internal reflection", "is_correct": true}, {"key": "B", "text": "Diffraction", "is_correct": false}, {"key": "C", "text": "Interference", "is_correct": false}, {"key": "D", "text": "Polarisation", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Diffraction involves bending of light around obstacles and does not explain the inverted image seen in mirages.", "misconception": null}, {"option_key": "C", "hint": "Interference involves superposition of coherent light waves and produces fringe patterns, not mirage-like effects.", "misconception": null}, {"option_key": "D", "hint": "Polarisation deals with the orientation of the electric field vector and does not cause visual illusions like mirages.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["mirage", "total-internal-reflection", "atmospheric-refraction"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In the visible spectrum, which colour of light is deviated the most by a glass prism?", "explanation": "Violet light has the shortest wavelength among visible colours and hence the highest refractive index in glass. Since deviation increases with refractive index, violet light is deviated the most by a glass prism. Red light, having the longest wavelength, is deviated the least.", "payload": {"question_id": "cuet-phy-ray-prism-04", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "Red", "is_correct": false}, {"key": "B", "text": "Yellow", "is_correct": false}, {"key": "C", "text": "Green", "is_correct": false}, {"key": "D", "text": "Violet", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Red light has the longest wavelength and therefore the lowest refractive index in glass, resulting in the least deviation.", "misconception": "Confusing maximum and minimum deviation colours"}, {"option_key": "B", "hint": "Yellow lies in the middle of the visible spectrum and experiences moderate deviation, not the maximum.", "misconception": null}, {"option_key": "C", "hint": "Green, like yellow, is in the middle of the spectrum and does not experience the maximum deviation.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["dispersion", "prism", "deviation", "violet-light"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A ray of light passes through an equilateral prism such that the angle of incidence equals the angle of emergence and each equals 60°. The angle of minimum deviation is:", "explanation": "For an equilateral prism, A = 60°. At minimum deviation, i = e. Using the prism formula δ = i + e − A, we get δ_min = 60° + 60° − 60° = 60°. Also, at minimum deviation i = (A + δ_min)/2 = (60° + 60°)/2 = 60°, which is consistent.", "payload": {"question_id": "cuet-phy-ray-prism-05", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "30°", "is_correct": false}, {"key": "B", "text": "60°", "is_correct": true}, {"key": "C", "text": "45°", "is_correct": false}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "30° would result if you incorrectly used δ = i − A/2 or some other wrong formula. The correct formula is δ = i + e − A.", "misconception": null}, {"option_key": "C", "hint": "45° does not follow from the prism formula with the given values of i, e, and A.", "misconception": null}, {"option_key": "D", "hint": "90° exceeds the angle of the prism and is far too large for this configuration.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["prism", "minimum-deviation", "equilateral-prism"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Optical fibres work on the principle of:", "explanation": "Optical fibres use total internal reflection to transmit light signals over long distances with minimal loss. The fibre consists of a core with a higher refractive index surrounded by cladding with a lower refractive index, ensuring that light undergoes TIR repeatedly as it propagates through the fibre.", "payload": {"question_id": "cuet-phy-ray-prism-06", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "Refraction", "is_correct": false}, {"key": "B", "text": "Diffraction", "is_correct": false}, {"key": "C", "text": "Total internal reflection", "is_correct": true}, {"key": "D", "text": "Scattering", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Simple refraction would cause light to exit the fibre at each boundary. TIR keeps the light confined within the core.", "misconception": "Confusing refraction with total internal reflection"}, {"option_key": "B", "hint": "Diffraction involves spreading of light around obstacles and has no role in guiding light through optical fibres.", "misconception": null}, {"option_key": "D", "hint": "Scattering disperses light in random directions and would cause signal loss, not signal transmission.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["optical-fibre", "total-internal-reflection", "applications"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The refractive index of a prism material is √3 and the angle of the prism is 60°. The angle of minimum deviation is:", "explanation": "Using the prism formula: n = sin[(A + δ_min)/2] / sin(A/2). Substituting: √3 = sin[(60° + δ_min)/2] / sin 30° = sin[(60° + δ_min)/2] / 0.5. So sin[(60° + δ_min)/2] = √3/2, giving (60° + δ_min)/2 = 60°, hence δ_min = 60°.", "payload": {"question_id": "cuet-phy-ray-prism-07", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "60°", "is_correct": true}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "30°", "is_correct": false}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Substituting δ_min = 45° gives sin(52.5°)/sin(30°) ≈ 0.793/0.5 = 1.586, which is not √3 ≈ 1.732.", "misconception": null}, {"option_key": "C", "hint": "Substituting δ_min = 30° gives sin(45°)/sin(30°) = (1/√2)/(1/2) = √2 ≈ 1.414, not √3.", "misconception": null}, {"option_key": "D", "hint": "δ_min = 90° gives sin(75°)/sin(30°) ≈ 0.966/0.5 = 1.932, which exceeds √3.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["prism", "minimum-deviation", "refractive-index"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The dispersive power of a prism depends on:", "explanation": "Dispersive power ω = (n_v − n_r)/(n_y − 1), where n_v, n_r, and n_y are the refractive indices for violet, red, and yellow light respectively. It depends solely on the material of the prism (i.e., how much the refractive index varies with wavelength) and is independent of the angle of the prism.", "payload": {"question_id": "cuet-phy-ray-prism-08", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "The angle of the prism only", "is_correct": false}, {"key": "B", "text": "The angle of incidence only", "is_correct": false}, {"key": "C", "text": "Both the angle of the prism and the material", "is_correct": false}, {"key": "D", "text": "The material of the prism only", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The angle of the prism affects the angular dispersion but not the dispersive power, which is a ratio independent of A.", "misconception": "Confusing angular dispersion with dispersive power"}, {"option_key": "B", "hint": "The angle of incidence affects the deviation but the dispersive power is a material property independent of the incident angle.", "misconception": null}, {"option_key": "C", "hint": "Although angular dispersion depends on A, the dispersive power ω = (n_v − n_r)/(n_y − 1) does not depend on the prism angle.", "misconception": "Confusing dispersive power with angular dispersion"}]}, "correct_answer": "D", "concept_tags": ["dispersive-power", "prism-material", "dispersion"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A thin prism of angle 6° produces a deviation of 3°. The refractive index of the prism material is:", "explanation": "For a thin prism, the deviation is given by δ = (n − 1)A. Substituting δ = 3° and A = 6°: 3 = (n − 1) × 6, so n − 1 = 0.5, giving n = 1.5.", "payload": {"question_id": "cuet-phy-ray-prism-09", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "1.33", "is_correct": false}, {"key": "B", "text": "1.5", "is_correct": true}, {"key": "C", "text": "2.0", "is_correct": false}, {"key": "D", "text": "1.6", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "n = 1.33 would give δ = (1.33 − 1) × 6 = 0.33 × 6 = 1.98°, not 3°.", "misconception": null}, {"option_key": "C", "hint": "n = 2.0 would give δ = (2.0 − 1) × 6 = 1 × 6 = 6°, not 3°.", "misconception": null}, {"option_key": "D", "hint": "n = 1.6 would give δ = (1.6 − 1) × 6 = 0.6 × 6 = 3.6°, which is close but not exactly 3°.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["thin-prism", "deviation", "refractive-index"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the formation of a rainbow, the light undergoes:", "explanation": "A rainbow is formed when sunlight enters a water droplet, undergoes refraction at the surface, total internal reflection inside the droplet, and then refraction again as it exits. The dispersion during refraction splits white light into its component colours.", "payload": {"question_id": "cuet-phy-ray-prism-10", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "Only refraction", "is_correct": false}, {"key": "B", "text": "Only total internal reflection", "is_correct": false}, {"key": "C", "text": "Refraction, internal reflection and dispersion", "is_correct": true}, {"key": "D", "text": "Diffraction and interference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Refraction alone cannot explain the formation of a rainbow; internal reflection inside the water droplet is essential to redirect light back towards the observer.", "misconception": null}, {"option_key": "B", "hint": "Total internal reflection alone cannot produce the spectrum of colours; refraction-induced dispersion is needed to separate the colours.", "misconception": null}, {"option_key": "D", "hint": "While diffraction and interference can produce colours (as in thin films), rainbow formation is primarily due to refraction, internal reflection and dispersion in water droplets.", "misconception": "Confusing rainbow formation with thin-film interference"}]}, "correct_answer": "C", "concept_tags": ["rainbow", "refraction", "total-internal-reflection", "dispersion"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A ray of light is incident on an equilateral glass prism (n = 1.5) placed on a horizontal surface. For the ray to undergo total internal reflection at the second face, the minimum angle of incidence at the first face must satisfy:", "explanation": "For TIR at the second face, the angle of refraction r₂ at that face must be at least equal to the critical angle C, where sin C = 1/n = 1/1.5 = 2/3. For an equilateral prism, A = 60° and r₁ + r₂ = A. For r₂ = C, r₁ = 60° − C. Using Snell''s law at the first face: sin i = n sin r₁ = 1.5 × sin(60° − C). Since sin C = 2/3, we get C ≈ 41.8°, so r₁ = 18.2°. Then sin i = 1.5 × sin 18.2° ≈ 1.5 × 0.312 ≈ 0.468, giving i ≈ 27.9° ≈ 28°.", "payload": {"question_id": "cuet-phy-ray-prism-11", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "analyze", "options": [{"key": "A", "text": "The angle of incidence must be at least approximately 28°", "is_correct": true}, {"key": "B", "text": "The angle of incidence must be at least 60°", "is_correct": false}, {"key": "C", "text": "Total internal reflection is not possible in this prism", "is_correct": false}, {"key": "D", "text": "The angle of incidence must be at least 45°", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "60° is the prism angle itself. The minimum angle of incidence for TIR at the second face is obtained by setting r₂ = C and computing i from Snell''s law.", "misconception": null}, {"option_key": "C", "hint": "TIR is possible at the second face of this prism if the angle of incidence at the first face is large enough to make r₂ ≥ C.", "misconception": "Incorrectly assuming TIR cannot occur in a prism"}, {"option_key": "D", "hint": "45° would correspond to a different prism geometry or refractive index. The calculation with n = 1.5 and A = 60° gives approximately 28°.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["total-internal-reflection", "prism", "critical-angle", "snell-law"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two thin prisms of angles 5° and 3° are made of materials with refractive indices 1.5 and 1.7 respectively. They are combined to produce dispersion without deviation. The ratio of their angular dispersions for the prism combination that achieves this is:", "explanation": "For no net deviation: (n₁ − 1)A₁ = (n₂ − 1)A₂, i.e., 0.5 × 5 = 0.7 × 3, which gives 2.5 = 2.1. Since these aren''t exactly equal, one prism must be inverted and the condition requires adjustable angles. However, in the standard NEET approach, the angular dispersion ratio equals the ratio of (n_v − n_r)A for each prism. For deviation without dispersion (or vice versa), the angular dispersions are in the ratio of the deviations: δ₁/δ₂ = (n₁ − 1)A₁ / (n₂ − 1)A₂ = 2.5/2.1 = 25:21.", "payload": {"question_id": "cuet-phy-ray-prism-12", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "analyze", "options": [{"key": "A", "text": "5 : 3", "is_correct": false}, {"key": "B", "text": "3 : 5", "is_correct": false}, {"key": "C", "text": "21 : 25", "is_correct": false}, {"key": "D", "text": "25 : 21", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "5:3 is just the ratio of prism angles and does not account for the different refractive indices of the materials.", "misconception": "Ignoring the role of refractive index in computing deviations"}, {"option_key": "B", "hint": "3:5 is the inverse of the prism angle ratio and has no physical basis for this problem.", "misconception": null}, {"option_key": "C", "hint": "21:25 is the inverse of the correct ratio. The first prism (larger δ) has the greater angular dispersion.", "misconception": "Inverting the ratio of angular dispersions"}]}, "correct_answer": "D", "concept_tags": ["combination-of-prisms", "dispersion-without-deviation", "angular-dispersion"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): Diamonds sparkle brilliantly due to total internal reflection.\nReason (R): Diamond has a very high refractive index (n ≈ 2.42) resulting in a small critical angle of about 24.4°.", "explanation": "Both the assertion and reason are correct, and the reason correctly explains the assertion. Diamond''s very high refractive index gives it a very small critical angle (sin C = 1/2.42, C ≈ 24.4°). This means light entering the diamond undergoes TIR at most internal surfaces, bouncing multiple times before emerging, which produces the brilliant sparkle.", "payload": {"question_id": "cuet-phy-ray-prism-13", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The small critical angle (from high n) is precisely why TIR occurs so readily inside diamond, directly explaining the sparkle.", "misconception": "Failing to connect high n and small critical angle to multiple TIR events"}, {"option_key": "C", "hint": "The reason is factually correct — diamond does have n ≈ 2.42 and a critical angle of about 24.4°.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; diamonds do sparkle due to multiple total internal reflections.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["diamond", "total-internal-reflection", "critical-angle", "refractive-index"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): At minimum deviation through a prism, the refracted ray inside the prism travels parallel to the base of the prism.\nReason (R): At minimum deviation, the angle of incidence at the first face equals the angle of emergence at the second face.", "explanation": "Both A and R are correct. At minimum deviation, i = e and r₁ = r₂ = A/2, which makes the ray inside the prism symmetric with respect to the prism. For a prism with its base horizontal, this symmetric path means the internal ray is parallel to the base. The reason (i = e) is the correct explanation because this symmetry condition leads to the parallel path inside.", "payload": {"question_id": "cuet-phy-ray-prism-14", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The condition i = e directly leads to r₁ = r₂ = A/2, which makes the internal ray parallel to the base. So R is the correct explanation of A.", "misconception": null}, {"option_key": "C", "hint": "The reason is correct — at minimum deviation, it is well established that the angle of incidence equals the angle of emergence.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct — at minimum deviation, the refracted ray inside the prism does travel parallel to the base, which can be verified from the symmetry condition.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["minimum-deviation", "prism-symmetry", "angle-of-incidence", "angle-of-emergence"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the optical phenomena in Column I with their correct descriptions in Column II:\n\nColumn I:\nA. Total internal reflection\nB. Dispersion\nC. Angular dispersion\nD. Dispersive power\n\nColumn II:\n1. Splitting of white light into component colours by a prism\n2. Ratio of angular dispersion to mean deviation\n3. Reflection of light when angle of incidence exceeds the critical angle in a denser medium\n4. Difference in deviations of violet and red light through a prism", "explanation": "Total internal reflection occurs when the angle of incidence in a denser medium exceeds the critical angle (A-3). Dispersion is the splitting of white light into its spectrum (B-1). Angular dispersion is the difference in deviations between violet and red light (C-4). Dispersive power is the ratio of angular dispersion to the mean deviation (D-2).", "payload": {"question_id": "cuet-phy-ray-prism-15", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "understand", "options": [{"key": "A", "text": "A-3, B-4, C-1, D-2", "is_correct": false}, {"key": "B", "text": "A-1, B-3, C-4, D-2", "is_correct": false}, {"key": "C", "text": "A-3, B-1, C-4, D-2", "is_correct": true}, {"key": "D", "text": "A-3, B-1, C-2, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Dispersion is the splitting of light (B-1), not the deviation difference, and angular dispersion is the deviation difference (C-4), not the splitting.", "misconception": "Confusing dispersion with angular dispersion"}, {"option_key": "B", "hint": "This incorrectly assigns TIR to splitting of light (A-1) and dispersion to the critical angle condition (B-3).", "misconception": null}, {"option_key": "D", "hint": "This swaps C and D. Angular dispersion is δ_v − δ_r (C-4), while dispersive power is the ratio (δ_v − δ_r)/δ_y (D-2).", "misconception": "Interchanging angular dispersion and dispersive power"}]}, "correct_answer": "C", "concept_tags": ["total-internal-reflection", "dispersion", "angular-dispersion", "dispersive-power"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the applications in Column I with the underlying principle in Column II:\n\nColumn I:\nA. Optical fibre communication\nB. Sparkling of diamond\nC. Formation of secondary rainbow\nD. Mirage in deserts\n\nColumn II:\n1. Two total internal reflections inside a water droplet\n2. Gradual refraction and TIR in air layers of varying density\n3. Repeated TIR at core-cladding interface\n4. Multiple TIR due to small critical angle", "explanation": "Optical fibres use repeated TIR at the core-cladding interface (A-3). Diamond sparkles due to multiple TIR because of its very small critical angle (B-4). A secondary rainbow involves two total internal reflections inside each water droplet (C-1). Mirages are formed by gradual refraction in hot air layers of varying density followed by TIR (D-2).", "payload": {"question_id": "cuet-phy-ray-prism-16", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-1, C-4, D-2", "is_correct": false}, {"key": "B", "text": "A-3, B-4, C-1, D-2", "is_correct": true}, {"key": "C", "text": "A-4, B-3, C-1, D-2", "is_correct": false}, {"key": "D", "text": "A-3, B-4, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Diamond sparkles due to its small critical angle (B-4), and the secondary rainbow involves two TIR events (C-1), not the reverse.", "misconception": null}, {"option_key": "C", "hint": "Optical fibres use repeated TIR at the core-cladding interface (A-3), not multiple TIR due to small critical angle (A-4).", "misconception": "Confusing optical fibre TIR mechanism with diamond''s TIR mechanism"}, {"option_key": "D", "hint": "This swaps C and D. The secondary rainbow involves two TIR events in a droplet (C-1), while mirages involve varying air density (D-2).", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["optical-fibre", "diamond", "rainbow", "mirage", "total-internal-reflection"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The critical angle for a medium with refractive index 2 with respect to air is 30°.", "explanation": "The critical angle C is given by sin C = 1/n. For n = 2, sin C = 1/2 = 0.5, so C = sin⁻¹(0.5) = 30°. This statement is true.", "payload": {"question_id": "cuet-phy-ray-prism-17", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The calculation sin C = 1/n = 1/2 gives C = 30°, confirming the statement is true.", "misconception": "Incorrectly computing the critical angle"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["critical-angle", "refractive-index", "total-internal-reflection"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The deviation produced by a prism increases continuously as the angle of incidence increases from 0° to 90°.", "explanation": "This statement is false. As the angle of incidence increases from its minimum value, the deviation first decreases, reaches a minimum value (minimum deviation), and then increases again. The deviation-vs-incidence curve is U-shaped, not monotonically increasing.", "payload": {"question_id": "cuet-phy-ray-prism-18", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The deviation first decreases to a minimum value and then increases. It does not increase continuously.", "misconception": "Assuming deviation increases monotonically with angle of incidence"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["prism", "deviation", "angle-of-incidence", "minimum-deviation"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_blanks", "difficulty": "medium", "question_text": "The angular dispersion produced by a thin prism of angle A for violet and red light is given by _____, where n_v and n_r are the refractive indices for violet and red light respectively.", "explanation": "For a thin prism, the deviation for any colour is δ = (n − 1)A. The angular dispersion is the difference in deviations of violet and red: δ_v − δ_r = (n_v − 1)A − (n_r − 1)A = (n_v − n_r)A. This formula shows angular dispersion depends on both the material (n_v − n_r) and the prism angle A.", "payload": {"question_id": "cuet-phy-ray-prism-19", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "(n_v + n_r)A", "is_correct": false}, {"key": "B", "text": "(n_v − n_r)/A", "is_correct": false}, {"key": "C", "text": "(n_v − n_r)A", "is_correct": true}, {"key": "D", "text": "(n_v × n_r)A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Adding refractive indices (n_v + n_r) has no physical meaning in the context of angular dispersion, which is the difference in deviations.", "misconception": null}, {"option_key": "B", "hint": "Angular dispersion is proportional to A, not inversely proportional. Dividing by A gives the dispersive power (after normalisation), not angular dispersion.", "misconception": "Confusing angular dispersion formula with dispersive power"}, {"option_key": "D", "hint": "The product n_v × n_r has no relevance to angular dispersion. The correct expression involves the difference (n_v − n_r).", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["angular-dispersion", "thin-prism", "violet-red-deviation"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-prism", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "medium", "question_text": "A scuba diver is at the bottom of a swimming pool of depth 4 m. The refractive index of water is 4/3. The diver shines a torch upward. The light that exits the water surface forms a bright circle on the surface.\n\nWhat is the radius of this bright circle?", "explanation": "Light exits the water surface only if the angle of incidence is less than the critical angle C. The critical angle is given by sin C = 1/n = 3/4. The radius r of the bright circle is related to the depth h by r = h × tan C. Since sin C = 3/4, cos C = √(1 − 9/16) = √(7/16) = √7/4. So tan C = sin C/cos C = (3/4)/(√7/4) = 3/√7. Therefore r = 4 × 3/√7 = 12/√7 ≈ 4.53 m ≈ 4.5 m.", "payload": {"question_id": "cuet-phy-ray-prism-20", "subtopic": "Total Internal Reflection, Prism, and Dispersion", "topic_name": "Total Internal Reflection, Prism, and Dispersion", "bloom_level": "apply", "options": [{"key": "A", "text": "3 m", "is_correct": false}, {"key": "B", "text": "12/√7 m", "is_correct": true}, {"key": "C", "text": "4 m", "is_correct": false}, {"key": "D", "text": "16/3 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 m would result from r = h × sin C = 4 × 3/4 = 3, but the correct formula uses tan C, not sin C.", "misconception": "Using sin C instead of tan C to find the radius"}, {"option_key": "C", "hint": "r = 4 m would imply tan C = 1 or C = 45°, but the critical angle for water (n = 4/3) is not 45°.", "misconception": null}, {"option_key": "D", "hint": "16/3 results from an incorrect formula. The correct approach gives r = h × tan C = 12/√7 m.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["critical-angle", "total-internal-reflection", "snell-law", "bright-circle"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-35');

