SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A ray of light is incident on a plane mirror at an angle of 30° with the mirror surface. What is the angle of reflection?", "explanation": "The angle of incidence is measured from the normal, not the surface. If the ray makes 30° with the mirror surface, the angle of incidence is 90° − 30° = 60°. By the law of reflection, the angle of reflection equals the angle of incidence, so it is 60°.", "payload": {"question_id": "cuet-phy-ray-reflection-01", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "remember", "options": [{"key": "A", "text": "30°", "is_correct": false}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "60°", "is_correct": true}, {"key": "D", "text": "90°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "30° is the angle the ray makes with the mirror surface, not with the normal. The angle of reflection is measured from the normal.", "misconception": "Confusing angle with surface and angle with normal"}, {"option_key": "B", "hint": "45° would be correct only if the ray made 45° with the surface, which is not the case here.", "misconception": null}, {"option_key": "D", "hint": "90° would mean the reflected ray is along the normal, which only happens for normal incidence.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["law-of-reflection", "angle-of-incidence", "plane-mirror"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The image formed by a plane mirror is:", "explanation": "A plane mirror always forms a virtual, erect image that is laterally inverted and of the same size as the object. The image is located as far behind the mirror as the object is in front of it.", "payload": {"question_id": "cuet-phy-ray-reflection-02", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "remember", "options": [{"key": "A", "text": "Real, erect and of same size", "is_correct": false}, {"key": "B", "text": "Virtual, erect and of same size", "is_correct": true}, {"key": "C", "text": "Virtual, inverted and magnified", "is_correct": false}, {"key": "D", "text": "Real, inverted and of same size", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A plane mirror cannot form a real image because the reflected rays diverge and only appear to meet behind the mirror.", "misconception": "Confusing virtual and real images in plane mirrors"}, {"option_key": "C", "hint": "The image in a plane mirror is erect (not inverted top-to-bottom) and of the same size, not magnified.", "misconception": "Confusing lateral inversion with top-bottom inversion"}, {"option_key": "D", "hint": "Plane mirrors do not form real images; they always produce virtual images that cannot be captured on a screen.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["plane-mirror", "virtual-image", "image-characteristics"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The focal length of a concave mirror is 15 cm. What is its radius of curvature?", "explanation": "For a spherical mirror, the radius of curvature R is related to the focal length f by the relation R = 2f. Therefore, R = 2 × 15 = 30 cm.", "payload": {"question_id": "cuet-phy-ray-reflection-03", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "remember", "options": [{"key": "A", "text": "30 cm", "is_correct": true}, {"key": "B", "text": "15 cm", "is_correct": false}, {"key": "C", "text": "7.5 cm", "is_correct": false}, {"key": "D", "text": "45 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "15 cm is the focal length itself, not the radius of curvature. R = 2f, not R = f.", "misconception": "Confusing focal length with radius of curvature"}, {"option_key": "C", "hint": "7.5 cm would result from dividing f by 2 instead of multiplying. The correct relation is R = 2f.", "misconception": "Inverting the R-f relationship"}, {"option_key": "D", "hint": "45 cm would result from R = 3f, which is not the correct relationship for spherical mirrors.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["concave-mirror", "focal-length", "radius-of-curvature"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When light travels from a denser medium to a rarer medium, it bends:", "explanation": "According to Snell''s law (n₁ sin θ₁ = n₂ sin θ₂), when light goes from a denser to a rarer medium (n₁ > n₂), the angle of refraction θ₂ is greater than the angle of incidence θ₁. Thus the refracted ray bends away from the normal.", "payload": {"question_id": "cuet-phy-ray-reflection-04", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "remember", "options": [{"key": "A", "text": "Towards the normal", "is_correct": false}, {"key": "B", "text": "Along the normal", "is_correct": false}, {"key": "C", "text": "Parallel to the surface", "is_correct": false}, {"key": "D", "text": "Away from the normal", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Light bends towards the normal when going from a rarer to a denser medium, not the other way around.", "misconception": "Reversing the direction of bending in refraction"}, {"option_key": "B", "hint": "Light travels along the normal only when the angle of incidence is 0° (normal incidence), regardless of media.", "misconception": null}, {"option_key": "C", "hint": "Light becomes parallel to the surface only at the critical angle during total internal reflection, not in general refraction.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["refraction", "snell-law", "denser-rarer-medium"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An object is placed at 20 cm in front of a concave mirror of focal length 10 cm. The magnification produced is:", "explanation": "Using the mirror formula 1/v + 1/u = 1/f with u = −20 cm and f = −10 cm: 1/v = 1/(−10) − 1/(−20) = −1/10 + 1/20 = −1/20, so v = −20 cm. Magnification m = −v/u = −(−20)/(−20) = −1. The image is real, inverted and of same size.", "payload": {"question_id": "cuet-phy-ray-reflection-05", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "apply", "options": [{"key": "A", "text": "+1", "is_correct": false}, {"key": "B", "text": "−1", "is_correct": true}, {"key": "C", "text": "−2", "is_correct": false}, {"key": "D", "text": "+2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "+1 magnification means a virtual, erect image of same size, which occurs for a plane mirror, not for an object at 2f of a concave mirror.", "misconception": "Ignoring the sign convention for magnification in mirrors"}, {"option_key": "C", "hint": "Magnification of −2 would occur when the object is placed between f and 2f (e.g., at 15 cm for f = 10 cm), not at 2f.", "misconception": null}, {"option_key": "D", "hint": "+2 would imply a virtual, erect, magnified image, which occurs when the object is between the pole and focus.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["concave-mirror", "mirror-formula", "magnification"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A convex mirror is used as a rear-view mirror in vehicles primarily because it:", "explanation": "A convex mirror always forms a virtual, erect and diminished image for all positions of the object. This gives a wider field of view compared to a plane mirror, making it ideal for rear-view mirrors in vehicles where observing a large area behind is essential for safety.", "payload": {"question_id": "cuet-phy-ray-reflection-06", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "understand", "options": [{"key": "A", "text": "Forms a real and magnified image", "is_correct": false}, {"key": "B", "text": "Forms a virtual and magnified image", "is_correct": false}, {"key": "C", "text": "Forms an erect, diminished image and provides a wider field of view", "is_correct": true}, {"key": "D", "text": "Forms an image of the same size as the object", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Convex mirrors never form real images; they always form virtual images since reflected rays diverge.", "misconception": "Confusing convex mirror properties with concave mirror properties"}, {"option_key": "B", "hint": "Convex mirrors always form diminished images, not magnified ones. Only concave mirrors can produce magnified images.", "misconception": null}, {"option_key": "D", "hint": "A convex mirror always produces a diminished image (smaller than the object), never the same size.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["convex-mirror", "field-of-view", "rear-view-mirror", "applications"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The refractive index of glass with respect to air is 1.5. What is the speed of light in glass if the speed of light in vacuum is 3 × 10⁸ m/s?", "explanation": "The refractive index n of a medium is defined as n = c/v, where c is the speed of light in vacuum and v is the speed in the medium. Therefore, v = c/n = (3 × 10⁸)/1.5 = 2 × 10⁸ m/s.", "payload": {"question_id": "cuet-phy-ray-reflection-07", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁸ m/s", "is_correct": true}, {"key": "B", "text": "4.5 × 10⁸ m/s", "is_correct": false}, {"key": "C", "text": "1.5 × 10⁸ m/s", "is_correct": false}, {"key": "D", "text": "3 × 10⁸ m/s", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "4.5 × 10⁸ m/s = c × n, which is greater than c. No material medium can allow light to travel faster than c.", "misconception": "Multiplying c by n instead of dividing"}, {"option_key": "C", "hint": "1.5 × 10⁸ m/s would correspond to n = 2, not 1.5. Check the calculation v = c/n.", "misconception": null}, {"option_key": "D", "hint": "3 × 10⁸ m/s is the speed in vacuum. Light slows down in any material medium with n > 1.", "misconception": "Assuming speed of light is the same in all media"}]}, "correct_answer": "A", "concept_tags": ["refractive-index", "speed-of-light", "optical-density"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An object is placed at 30 cm from a convex mirror of focal length 20 cm. The position of the image from the mirror is:", "explanation": "For a convex mirror, f = +20 cm and u = −30 cm. Using mirror formula: 1/v = 1/f − 1/u = 1/20 − 1/(−30) = 1/20 + 1/30 = (3 + 2)/60 = 5/60 = 1/12. So v = +12 cm. The positive sign confirms the image is behind the mirror (virtual).", "payload": {"question_id": "cuet-phy-ray-reflection-08", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "apply", "options": [{"key": "A", "text": "60 cm behind the mirror", "is_correct": false}, {"key": "B", "text": "20 cm in front of the mirror", "is_correct": false}, {"key": "C", "text": "15 cm behind the mirror", "is_correct": false}, {"key": "D", "text": "12 cm behind the mirror", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "60 cm is far too large; for a convex mirror the image always lies between the pole and the focus, i.e., within 20 cm behind the mirror.", "misconception": null}, {"option_key": "B", "hint": "A convex mirror always forms a virtual image behind the mirror, never a real image in front.", "misconception": "Confusing convex mirror with concave mirror image positions"}, {"option_key": "C", "hint": "15 cm results from an arithmetic error. Carefully compute 1/20 + 1/30 = 5/60 = 1/12, giving v = 12 cm.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["convex-mirror", "mirror-formula", "image-distance"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A ray of light passes from glass (n = 1.5) into water (n = 1.33). If the angle of incidence is 30°, the angle of refraction is approximately:", "explanation": "Applying Snell''s law: n₁ sin θ₁ = n₂ sin θ₂, so 1.5 × sin 30° = 1.33 × sin θ₂. This gives sin θ₂ = (1.5 × 0.5)/1.33 = 0.75/1.33 = 0.564. Therefore θ₂ = sin⁻¹(0.564) ≈ 34.3° ≈ 34°.", "payload": {"question_id": "cuet-phy-ray-reflection-09", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "apply", "options": [{"key": "A", "text": "26°", "is_correct": false}, {"key": "B", "text": "34°", "is_correct": true}, {"key": "C", "text": "45°", "is_correct": false}, {"key": "D", "text": "30°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "26° would correspond to bending towards the normal, but light going from a denser (glass) to a less dense medium (water) bends away from the normal.", "misconception": "Reversing the direction of bending at the interface"}, {"option_key": "C", "hint": "45° is too large; sin 45° = 0.707, but the calculation gives sin θ₂ ≈ 0.564.", "misconception": null}, {"option_key": "D", "hint": "The refracted angle equals the incident angle only if both media have the same refractive index, which is not the case here.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["snell-law", "refraction", "refractive-index"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A biconvex lens has radii of curvature R₁ = 20 cm and R₂ = 30 cm and refractive index 1.5. Its focal length using the lens maker''s equation is:", "explanation": "Using the lens maker''s equation: 1/f = (n − 1)[1/R₁ − 1/R₂] = (1.5 − 1)[1/20 − 1/(−30)] = 0.5 × [1/20 + 1/30] = 0.5 × (3 + 2)/60 = 0.5 × 5/60 = 0.5/12 = 1/24. Therefore f = 24 cm.", "payload": {"question_id": "cuet-phy-ray-reflection-10", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "apply", "options": [{"key": "A", "text": "12 cm", "is_correct": false}, {"key": "B", "text": "20 cm", "is_correct": false}, {"key": "C", "text": "24 cm", "is_correct": true}, {"key": "D", "text": "30 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "12 cm results from forgetting the (n − 1) factor and using 1/f = 1/R₁ + 1/R₂ directly.", "misconception": "Omitting the (n − 1) factor in the lens maker''s equation"}, {"option_key": "B", "hint": "20 cm is just the value of R₁; the focal length depends on both radii and the refractive index.", "misconception": null}, {"option_key": "D", "hint": "30 cm is just the value of R₂; the correct calculation involves both radii in the lens maker''s formula.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["lens-maker-equation", "biconvex-lens", "focal-length"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A concave mirror forms a real image of an object placed beyond its centre of curvature. If the object is moved towards the focus of the mirror, the image:", "explanation": "When the object is beyond C, the real image lies between F and C. As the object moves from beyond C towards F, the image moves from between F and C towards infinity. Thus the image moves farther from the mirror and its size increases (magnification increases in magnitude).", "payload": {"question_id": "cuet-phy-ray-reflection-11", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "analyze", "options": [{"key": "A", "text": "Moves towards the mirror and becomes smaller", "is_correct": false}, {"key": "B", "text": "Remains at the same position with the same size", "is_correct": false}, {"key": "C", "text": "Moves towards the mirror and becomes larger", "is_correct": false}, {"key": "D", "text": "Moves away from the mirror and becomes larger", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This is the reverse of what happens. As the object approaches the focus, the image recedes and enlarges, not the opposite.", "misconception": "Reversing the direction of image motion for concave mirrors"}, {"option_key": "B", "hint": "The image position and size remain unchanged only if the object position does not change. Moving the object changes the image.", "misconception": null}, {"option_key": "C", "hint": "The image does become larger, but it moves away from the mirror, not towards it, as the object approaches the focus.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["concave-mirror", "image-movement", "magnification", "object-at-focus"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A thin convex lens of focal length 20 cm is placed in contact with a thin concave lens of focal length 30 cm. The combination acts as a:", "explanation": "For lenses in contact, the equivalent focal length is given by 1/f = 1/f₁ + 1/f₂ = 1/20 + 1/(−30) = 3/60 − 2/60 = 1/60. So f = +60 cm. Since the focal length is positive, the combination acts as a converging (convex) lens of focal length 60 cm.", "payload": {"question_id": "cuet-phy-ray-reflection-12", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "analyze", "options": [{"key": "A", "text": "Converging lens of focal length 60 cm", "is_correct": true}, {"key": "B", "text": "Diverging lens of focal length 60 cm", "is_correct": false}, {"key": "C", "text": "Converging lens of focal length 10 cm", "is_correct": false}, {"key": "D", "text": "Diverging lens of focal length 10 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The calculated focal length is +60 cm (positive), which indicates a converging lens, not a diverging one.", "misconception": "Confusing the sign of the equivalent focal length"}, {"option_key": "C", "hint": "10 cm results from incorrectly subtracting: 1/20 − 1/30 ≠ 1/10. The correct calculation gives 1/60.", "misconception": "Arithmetic error in combining lens powers"}, {"option_key": "D", "hint": "Neither the focal length (60 cm, not 10 cm) nor the nature (converging, not diverging) matches this option.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["combination-of-lenses", "equivalent-focal-length", "convex-lens", "concave-lens"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): A concave mirror can form both real and virtual images.\nReason (R): When an object is placed between the pole and the focus of a concave mirror, the reflected rays diverge and appear to come from behind the mirror.", "explanation": "Both the assertion and reason are correct. A concave mirror forms real images when the object is beyond the focus and virtual images when the object is between the pole and focus. The reason correctly explains why a virtual image forms in the latter case — the reflected rays diverge and appear to originate from behind the mirror.", "payload": {"question_id": "cuet-phy-ray-reflection-13", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains how the virtual image forms, which is one part of the assertion. Hence R is the correct explanation of A.", "misconception": "Failing to see the causal link between R and A"}, {"option_key": "C", "hint": "The reason is physically accurate — reflected rays from an object between P and F do diverge, forming a virtual image behind the mirror.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; concave mirrors can indeed form both real and virtual images depending on object position.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["concave-mirror", "real-virtual-image", "image-formation"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): The refractive index of a medium depends on the wavelength of light used.\nReason (R): The speed of light in a medium is the same for all wavelengths.", "explanation": "The assertion is correct because the refractive index n = c/v, and the speed v of light in a dispersive medium varies with wavelength (this is the cause of dispersion). The reason is incorrect because the speed of light in a material medium does depend on wavelength — violet light travels slower than red light in glass, for example.", "payload": {"question_id": "cuet-phy-ray-reflection-14", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The reason is factually incorrect — the speed of light in a material medium does vary with wavelength, causing dispersion.", "misconception": null}, {"option_key": "B", "hint": "Since the reason is incorrect (speed does depend on wavelength in a medium), this option cannot be chosen.", "misconception": "Believing speed of light is wavelength-independent in all media"}, {"option_key": "D", "hint": "The assertion is correct; refractive index is wavelength-dependent (e.g., Cauchy''s equation describes this dependence).", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["refractive-index", "dispersion", "wavelength-dependence", "speed-of-light"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the following mirror types with the nature of the image formed:\n\nColumn I:\nA. Concave mirror (object at infinity)\nB. Convex mirror (any object position)\nC. Concave mirror (object between P and F)\nD. Plane mirror\n\nColumn II:\n1. Virtual, erect, same size\n2. Real, inverted, highly diminished (at focus)\n3. Virtual, erect, diminished\n4. Virtual, erect, magnified", "explanation": "A concave mirror forms a real, inverted, point-sized image at the focus when the object is at infinity (A-2). A convex mirror always forms a virtual, erect, diminished image (B-3). A concave mirror with the object between P and F gives a virtual, erect, magnified image (C-4). A plane mirror forms a virtual, erect, same-sized image (D-1).", "payload": {"question_id": "cuet-phy-ray-reflection-15", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "understand", "options": [{"key": "A", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-3, C-4, D-1", "is_correct": true}, {"key": "C", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-3, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly assigns a virtual magnified image to a convex mirror (B-4). Convex mirrors always form diminished images.", "misconception": "Confusing image properties of convex and concave mirrors"}, {"option_key": "C", "hint": "A-4 is wrong; a concave mirror with the object at infinity forms a real diminished image at the focus, not a virtual magnified one.", "misconception": null}, {"option_key": "D", "hint": "This option assigns completely incorrect image types to all mirrors and has no physical basis.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["mirror-types", "image-characteristics", "concave-mirror", "convex-mirror", "plane-mirror"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the optical phenomena in Column I with their correct physical basis in Column II:\n\nColumn I:\nA. Twinkling of stars\nB. Apparent depth of a swimming pool is less than actual depth\nC. Lateral displacement of a ray through a glass slab\nD. Bending of light around sharp edges\n\nColumn II:\n1. Refraction at parallel surfaces\n2. Atmospheric refraction due to varying refractive index\n3. Refraction at a plane surface\n4. Diffraction", "explanation": "Twinkling of stars is caused by atmospheric refraction due to turbulent layers with varying refractive index (A-2). The apparent decrease in depth of a pool is due to refraction at the plane water surface (B-3). Lateral displacement through a glass slab occurs because of refraction at two parallel surfaces (C-1). Bending of light around sharp edges is diffraction (D-4).", "payload": {"question_id": "cuet-phy-ray-reflection-16", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-3, B-2, C-1, D-4", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-4, D-1", "is_correct": false}, {"key": "D", "text": "A-2, B-3, C-1, D-4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Apparent depth is due to refraction at a single plane surface (B-3), while lateral displacement involves two parallel surfaces (C-1).", "misconception": null}, {"option_key": "B", "hint": "Twinkling of stars (A) is due to atmospheric refraction (2), not refraction at a single plane surface (3).", "misconception": "Confusing atmospheric refraction with simple refraction"}, {"option_key": "C", "hint": "This incorrectly assigns diffraction (4) to lateral displacement and refraction at parallel surfaces (1) to bending around edges.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["atmospheric-refraction", "apparent-depth", "lateral-displacement", "diffraction"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "The angle of incidence is equal to the angle of reflection for all reflecting surfaces.", "explanation": "This is a statement of the law of reflection, which holds true for all reflecting surfaces — whether plane, concave, convex, or irregular. The angles are measured with respect to the normal at the point of incidence.", "payload": {"question_id": "cuet-phy-ray-reflection-17", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The law of reflection (angle of incidence = angle of reflection) is universally valid for all reflecting surfaces.", "misconception": "Thinking the law of reflection applies only to plane mirrors"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["law-of-reflection", "angle-of-incidence", "angle-of-reflection"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "A convex mirror can form a real image of a real object.", "explanation": "This statement is false. A convex mirror always forms a virtual, erect and diminished image for any position of a real object. The reflected rays always diverge and only appear to meet behind the mirror, so the image is always virtual.", "payload": {"question_id": "cuet-phy-ray-reflection-18", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A convex mirror cannot form a real image of a real object. The diverging nature of the mirror ensures all images are virtual.", "misconception": "Confusing convex mirror with concave mirror capabilities"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["convex-mirror", "virtual-image", "image-formation"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_blanks", "difficulty": "medium", "question_text": "The power of a convex lens of focal length 25 cm is _____ dioptre.", "explanation": "The power of a lens is given by P = 1/f, where f is in metres. Converting 25 cm to metres: f = 0.25 m. Therefore P = 1/0.25 = +4 D. The positive sign indicates a converging lens.", "payload": {"question_id": "cuet-phy-ray-reflection-19", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "apply", "options": [{"key": "A", "text": "+0.25", "is_correct": false}, {"key": "B", "text": "+25", "is_correct": false}, {"key": "C", "text": "−4", "is_correct": false}, {"key": "D", "text": "+4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "+0.25 would be the focal length in metres, not the power. Power = 1/f, not f itself.", "misconception": "Confusing focal length (in metres) with power"}, {"option_key": "B", "hint": "+25 results from using f in cm directly in P = 1/f. The focal length must be converted to metres first.", "misconception": "Forgetting to convert cm to m when calculating power"}, {"option_key": "C", "hint": "−4 D would be the power of a concave (diverging) lens. A convex lens has positive power.", "misconception": "Using wrong sign for convex lens power"}]}, "correct_answer": "D", "concept_tags": ["power-of-lens", "focal-length", "dioptre"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-reflection", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "medium", "question_text": "A student places a 5 cm tall candle at a distance of 25 cm from a concave mirror of focal length 15 cm. She observes a clear image on a screen placed on the same side as the candle.\n\nWhat is the height of the image formed on the screen?", "explanation": "Using mirror formula with u = −25 cm and f = −15 cm: 1/v = 1/f − 1/u = 1/(−15) − 1/(−25) = −1/15 + 1/25 = (−5 + 3)/75 = −2/75. So v = −37.5 cm. Magnification m = −v/u = −(−37.5)/(−25) = −1.5. Image height = m × object height = −1.5 × 5 = −7.5 cm. The negative sign indicates the image is inverted. The magnitude of the image height is 7.5 cm.", "payload": {"question_id": "cuet-phy-ray-reflection-20", "subtopic": "Reflection, Mirrors, and Refraction at Surfaces", "topic_name": "Reflection, Mirrors, and Refraction at Surfaces", "bloom_level": "apply", "options": [{"key": "A", "text": "5 cm, erect", "is_correct": false}, {"key": "B", "text": "3.33 cm, inverted", "is_correct": false}, {"key": "C", "text": "7.5 cm, inverted", "is_correct": true}, {"key": "D", "text": "10 cm, inverted", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "An image of the same height (5 cm) would occur only when the object is at the centre of curvature (2f = 30 cm), not at 25 cm.", "misconception": "Assuming the image size equals object size for all positions"}, {"option_key": "B", "hint": "3.33 cm results from an error in computing v. Carefully re-evaluate 1/(−15) − 1/(−25) to get v = −37.5 cm.", "misconception": null}, {"option_key": "D", "hint": "10 cm would require a magnification of 2, which does not match the object distance of 25 cm and focal length of 15 cm.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["concave-mirror", "mirror-formula", "magnification", "image-height"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-36');

