SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In Young''s double slit experiment, the fringe width is given by:", "explanation": "The fringe width in Young''s double slit experiment is given by the formula beta = lambdaD/d, where lambda is the wavelength of light, D is the distance between the slits and the screen, and d is the separation between the two slits. This formula is derived from the geometry of the experiment and the condition for constructive interference.", "payload": {"question_id": "cuet-phy-waveopt-interference-01", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "remember", "options": [{"key": "A", "text": "beta = lambdaD/d", "is_correct": true}, {"key": "B", "text": "beta = lambdad/D", "is_correct": false}, {"key": "C", "text": "beta = d/lambdaD", "is_correct": false}, {"key": "D", "text": "beta = D/lambdad", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This formula has d and D interchanged. Fringe width increases with screen distance D and decreases with slit separation d, so D must be in the numerator and d in the denominator.", "misconception": "Interchanging the roles of slit separation and screen distance"}, {"option_key": "C", "hint": "This places wavelength in the denominator. Since fringe width increases with wavelength, lambda must be in the numerator.", "misconception": "Inverting the fringe width formula"}, {"option_key": "D", "hint": "This formula has all three quantities incorrectly placed. Recall that fringe width is directly proportional to both lambda and D.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["fringe-width", "ydse-formula", "wave-optics"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "For sustained interference of light, the two sources must be:", "explanation": "Sustained (or stable) interference requires coherent sources, meaning the two sources must emit light waves of the same frequency and maintain a constant phase difference. Incoherent sources produce randomly varying phase differences, causing the interference pattern to change rapidly and average out, making it invisible.", "payload": {"question_id": "cuet-phy-waveopt-interference-02", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "remember", "options": [{"key": "A", "text": "Of different frequencies with random phase", "is_correct": false}, {"key": "B", "text": "Coherent, i.e., having the same frequency and a constant phase difference", "is_correct": true}, {"key": "C", "text": "Very bright and of the same intensity", "is_correct": false}, {"key": "D", "text": "Polarised in mutually perpendicular directions", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Different frequencies mean the phase difference changes continuously, so no sustained fringe pattern can form.", "misconception": "Thinking that any two light sources can produce sustained interference"}, {"option_key": "C", "hint": "Equal intensity is not a necessary condition for interference. Unequal intensities still produce interference, only with reduced contrast (non-zero minima).", "misconception": "Confusing intensity condition with coherence condition"}, {"option_key": "D", "hint": "Perpendicular polarisations would prevent interference entirely. For interference, the waves should have the same state of polarisation, not perpendicular.", "misconception": "Confusing polarisation with coherence requirements"}]}, "correct_answer": "B", "concept_tags": ["coherent-sources", "sustained-interference", "conditions-for-interference"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In Young''s double slit experiment, if the slit separation d is doubled while keeping all other parameters constant, the fringe width will:", "explanation": "The fringe width beta = lambdaD/d. If d is doubled, beta becomes lambdaD/(2d) = beta/2. So the fringe width is halved. Increasing the slit separation brings the fringes closer together.", "payload": {"question_id": "cuet-phy-waveopt-interference-03", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "understand", "options": [{"key": "A", "text": "Become double", "is_correct": false}, {"key": "B", "text": "Remain the same", "is_correct": false}, {"key": "C", "text": "Become half", "is_correct": true}, {"key": "D", "text": "Become four times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Doubling d would double the fringe width only if d were in the numerator. Since beta = lambdaD/d, d is in the denominator, so increasing d decreases beta.", "misconception": "Thinking fringe width is directly proportional to slit separation"}, {"option_key": "B", "hint": "Fringe width depends inversely on slit separation, so changing d must change beta.", "misconception": "Ignoring the dependence of fringe width on slit separation"}, {"option_key": "D", "hint": "A fourfold change would require squaring, but the relationship is beta inversely proportional to d (first power), not d squared.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["fringe-width", "slit-separation", "ydse-parameters"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The path difference between two waves reaching a point on the screen in Young''s experiment for the third bright fringe is:", "explanation": "For bright fringes (constructive interference), the path difference = n*lambda, where n is the order of the fringe. For the third bright fringe, n = 3, so the path difference = 3*lambda.", "payload": {"question_id": "cuet-phy-waveopt-interference-04", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "remember", "options": [{"key": "A", "text": "lambda/2", "is_correct": false}, {"key": "B", "text": "lambda", "is_correct": false}, {"key": "C", "text": "5*lambda/2", "is_correct": false}, {"key": "D", "text": "3*lambda", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "lambda/2 is the path difference for the first dark fringe (first minimum), not a bright fringe.", "misconception": "Confusing conditions for bright and dark fringes"}, {"option_key": "B", "hint": "lambda corresponds to the first bright fringe (n = 1), not the third.", "misconception": "Confusing fringe order"}, {"option_key": "C", "hint": "5*lambda/2 is the path difference for the third dark fringe (n = 3 in the dark fringe formula (2n-1)*lambda/2), not the third bright fringe.", "misconception": "Using the dark fringe formula instead of the bright fringe formula"}]}, "correct_answer": "D", "concept_tags": ["path-difference", "bright-fringe", "constructive-interference"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Young''s double slit experiment, two slits are separated by 0.5 mm and the screen is placed 1 m away. If the wavelength of light used is 500 nm, the fringe width is:", "explanation": "Using beta = lambdaD/d = (500 x 10^-9 x 1) / (0.5 x 10^-3) = (5 x 10^-7) / (5 x 10^-4) = 1 x 10^-3 m = 1 mm. The fringe width is 1 mm.", "payload": {"question_id": "cuet-phy-waveopt-interference-05", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "apply", "options": [{"key": "A", "text": "0.5 mm", "is_correct": false}, {"key": "B", "text": "1 mm", "is_correct": true}, {"key": "C", "text": "2 mm", "is_correct": false}, {"key": "D", "text": "0.1 mm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Check your calculation. 0.5 mm results from an error such as using d = 1 mm instead of 0.5 mm.", "misconception": "Arithmetic error in substitution"}, {"option_key": "C", "hint": "2 mm would result from using d = 0.25 mm instead of 0.5 mm. Recheck the slit separation value.", "misconception": "Incorrect unit conversion or value substitution"}, {"option_key": "D", "hint": "0.1 mm is 10 times too small. Verify that all units are converted to SI before substituting into the formula.", "misconception": "Unit conversion error (using mm instead of m for wavelength)"}]}, "correct_answer": "B", "concept_tags": ["fringe-width", "numerical-problem", "ydse-formula"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Young''s experiment, if the intensity of light from each slit is I_0, the intensity at a point where the phase difference between the two waves is pi/2 is:", "explanation": "The resultant intensity in YDSE is given by I = 4*I_0*cos^2(phi/2). When phi = pi/2, we get I = 4*I_0*cos^2(pi/4) = 4*I_0*(1/sqrt(2))^2 = 4*I_0*(1/2) = 2*I_0.", "payload": {"question_id": "cuet-phy-waveopt-interference-06", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "apply", "options": [{"key": "A", "text": "4*I_0", "is_correct": false}, {"key": "B", "text": "I_0", "is_correct": false}, {"key": "C", "text": "2*I_0", "is_correct": true}, {"key": "D", "text": "0", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4*I_0 is the maximum intensity at a bright fringe where phi = 0 (perfectly constructive interference), not where phi = pi/2.", "misconception": "Thinking any non-zero phase difference gives maximum intensity"}, {"option_key": "B", "hint": "I_0 would require cos^2(phi/2) = 1/4, which corresponds to phi = 2*pi/3, not pi/2.", "misconception": "Incorrectly evaluating the cosine function"}, {"option_key": "D", "hint": "Zero intensity occurs at phi = pi (complete destructive interference). At phi = pi/2 the waves are partially in phase and the intensity is non-zero.", "misconception": "Confusing phi = pi/2 with destructive interference"}]}, "correct_answer": "C", "concept_tags": ["intensity-distribution", "phase-difference", "interference-pattern"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Young''s double slit experiment, if the entire apparatus is immersed in a liquid of refractive index mu, the fringe width will:", "explanation": "In a medium of refractive index mu, the wavelength becomes lambda'' = lambda/mu. Since fringe width beta = lambda*D/d, the new fringe width beta'' = (lambda/mu)*D/d = beta/mu. Since mu > 1, the fringe width decreases.", "payload": {"question_id": "cuet-phy-waveopt-interference-07", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "apply", "options": [{"key": "A", "text": "Decrease by a factor of mu", "is_correct": true}, {"key": "B", "text": "Increase by a factor of mu", "is_correct": false}, {"key": "C", "text": "Remain unchanged", "is_correct": false}, {"key": "D", "text": "Decrease by a factor of mu^2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Wavelength decreases in a denser medium, so fringe width must decrease, not increase.", "misconception": "Thinking wavelength increases in a denser medium"}, {"option_key": "C", "hint": "Fringe width depends on wavelength, which changes in a medium. The frequency remains unchanged, but the wavelength changes.", "misconception": "Forgetting that wavelength changes in a medium"}, {"option_key": "D", "hint": "The relationship is linear: beta is proportional to lambda, and lambda is proportional to 1/mu. There is no squaring involved.", "misconception": "Incorrectly squaring the refractive index"}]}, "correct_answer": "A", "concept_tags": ["fringe-width", "refractive-index", "ydse-in-medium"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the maximum to minimum intensity in an interference pattern when two coherent sources have intensity ratio 4:1 is:", "explanation": "If I_1/I_2 = 4/1, then sqrt(I_1)/sqrt(I_2) = 2/1. Maximum intensity I_max = (sqrt(I_1) + sqrt(I_2))^2 = (2 + 1)^2 = 9. Minimum intensity I_min = (sqrt(I_1) - sqrt(I_2))^2 = (2 - 1)^2 = 1. Therefore, I_max/I_min = 9:1.", "payload": {"question_id": "cuet-phy-waveopt-interference-08", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "apply", "options": [{"key": "A", "text": "4:1", "is_correct": false}, {"key": "B", "text": "5:3", "is_correct": false}, {"key": "C", "text": "25:9", "is_correct": false}, {"key": "D", "text": "9:1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4:1 is the ratio of the individual source intensities, not the maximum-to-minimum ratio. You need to use amplitude addition and subtraction.", "misconception": "Confusing source intensity ratio with fringe intensity ratio"}, {"option_key": "B", "hint": "5:3 would come from adding and subtracting intensities directly (4+1):(4-1), but intensities do not add this way in interference. Amplitudes add, and intensity is proportional to amplitude squared.", "misconception": "Adding intensities directly instead of amplitudes"}, {"option_key": "C", "hint": "25:9 would result from an incorrect formula. The correct approach uses (sqrt(I_1) + sqrt(I_2))^2 / (sqrt(I_1) - sqrt(I_2))^2.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["intensity-ratio", "constructive-destructive-interference", "amplitude-superposition"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In thin film interference, an oil film of thickness t and refractive index mu appears bright in reflected light when (for near-normal incidence):", "explanation": "In thin film interference in reflected light, there is an extra phase change of pi (equivalent to lambda/2 path difference) at the top surface where light reflects from a denser medium. The condition for constructive interference (bright film) becomes 2*mu*t = (2n - 1)*lambda/2, i.e., the optical path difference 2*mu*t equals an odd multiple of lambda/2.", "payload": {"question_id": "cuet-phy-waveopt-interference-09", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "understand", "options": [{"key": "A", "text": "2*mu*t = n*lambda", "is_correct": false}, {"key": "B", "text": "2*mu*t = (2n - 1)*lambda/2", "is_correct": true}, {"key": "C", "text": "2*t = n*lambda", "is_correct": false}, {"key": "D", "text": "mu*t = n*lambda", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2*mu*t = n*lambda is the condition for destructive interference (dark) in reflected light, because the additional phase change at the top surface shifts the constructive condition.", "misconception": "Forgetting the extra phase change of pi at the denser medium reflection"}, {"option_key": "C", "hint": "This formula ignores the refractive index mu. The optical path inside the film is 2*mu*t, not 2*t.", "misconception": "Ignoring the refractive index in thin film calculations"}, {"option_key": "D", "hint": "The light traverses the film twice (down and back up), so the path is 2*mu*t, not mu*t.", "misconception": "Forgetting the factor of 2 for double traversal"}]}, "correct_answer": "B", "concept_tags": ["thin-film-interference", "reflected-light", "optical-path-difference"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In Young''s double slit experiment with slit separation 1 mm and screen distance 1 m, two wavelengths lambda_1 = 600 nm and lambda_2 = 480 nm are used. The minimum distance from the central maximum where bright fringes of both wavelengths coincide is:", "explanation": "For the bright fringes to coincide, n_1*lambda_1 = n_2*lambda_2 (same path difference). So n_1*600 = n_2*480, giving n_1/n_2 = 480/600 = 4/5. The minimum integers satisfying this are n_1 = 4 and n_2 = 5. The distance from the central maximum = n_1*lambda_1*D/d = 4 * 600 x 10^-9 * 1 / (1 x 10^-3) = 2400 x 10^-6 m = 2.4 mm.", "payload": {"question_id": "cuet-phy-waveopt-interference-10", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "analyze", "options": [{"key": "A", "text": "1.2 mm", "is_correct": false}, {"key": "B", "text": "1.8 mm", "is_correct": false}, {"key": "C", "text": "2.4 mm", "is_correct": true}, {"key": "D", "text": "3.0 mm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.2 mm corresponds to n_1 = 2 for lambda_1. Check whether n_2 is an integer: 2 x 600/480 = 2.5, which is not an integer, so fringes do not coincide here.", "misconception": "Not checking if both fringe orders are integers"}, {"option_key": "B", "hint": "1.8 mm corresponds to n_1 = 3 for lambda_1. Check: n_2 = 3 x 600/480 = 3.75, which is not an integer.", "misconception": null}, {"option_key": "D", "hint": "3.0 mm corresponds to n_1 = 5 for lambda_1. While n_2 = 5 x 600/480 = 6.25 is not an integer, the minimum coincidence occurs at n_1 = 4, n_2 = 5.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["ydse-two-wavelengths", "fringe-coincidence", "numerical-problem"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In Newton''s rings experiment, the radius of the n-th dark ring is proportional to:", "explanation": "In Newton''s rings, the radius of the n-th dark ring is given by r_n = sqrt(n*lambda*R), where R is the radius of curvature of the plano-convex lens and lambda is the wavelength. Therefore, r_n is proportional to sqrt(n).", "payload": {"question_id": "cuet-phy-waveopt-interference-11", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "remember", "options": [{"key": "A", "text": "sqrt(n)", "is_correct": true}, {"key": "B", "text": "n", "is_correct": false}, {"key": "C", "text": "n^2", "is_correct": false}, {"key": "D", "text": "1/n", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The radius is proportional to sqrt(n), not n. The area enclosed by the ring is proportional to n, which may cause confusion.", "misconception": "Confusing ring radius with ring area proportionality"}, {"option_key": "C", "hint": "n^2 dependence would mean rings spread out rapidly, which contradicts the observation that Newton''s rings get closer together for higher orders.", "misconception": null}, {"option_key": "D", "hint": "1/n would mean higher-order rings have smaller radii, which is physically incorrect. Higher-order rings are always farther from the centre.", "misconception": "Inverting the relationship between ring number and radius"}]}, "correct_answer": "A", "concept_tags": ["newtons-rings", "dark-ring-radius", "thin-film-interference"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When white light is used in Young''s double slit experiment, the central fringe is:", "explanation": "At the central position, the path difference is zero for all wavelengths. Therefore, all wavelengths undergo constructive interference at the central point, and the central fringe appears white. Away from the centre, different wavelengths produce maxima at different positions, leading to coloured fringes.", "payload": {"question_id": "cuet-phy-waveopt-interference-12", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "understand", "options": [{"key": "A", "text": "Red", "is_correct": false}, {"key": "B", "text": "Violet", "is_correct": false}, {"key": "C", "text": "Dark", "is_correct": false}, {"key": "D", "text": "White", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Red fringes appear at positions where only red light undergoes constructive interference. The central fringe has zero path difference for all colours, not just red.", "misconception": "Thinking only one colour dominates at the centre"}, {"option_key": "B", "hint": "Similar to red, violet alone does not dominate the central position. All wavelengths constructively interfere at zero path difference.", "misconception": null}, {"option_key": "C", "hint": "A dark fringe would require destructive interference, which cannot occur at zero path difference where all wavelengths are in phase.", "misconception": "Thinking superposition of all colours causes cancellation"}]}, "correct_answer": "D", "concept_tags": ["white-light-interference", "central-fringe", "ydse"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): In Young''s double slit experiment, the fringe pattern shifts when a thin transparent glass plate is introduced in the path of one of the beams. Reason (R): The glass plate introduces an additional optical path difference because light travels slower in glass than in air.", "explanation": "Assertion is correct: introducing a glass plate of thickness t and refractive index mu in one beam introduces an extra optical path of (mu - 1)*t, shifting the central fringe to a new position. Reason is also correct: light travels slower in glass (speed = c/mu), so the optical path length increases. The Reason correctly explains the Assertion because it is precisely because of the increased optical path (due to slower speed in glass) that the fringe pattern shifts.", "payload": {"question_id": "cuet-phy-waveopt-interference-13", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion. The fringe shift occurs precisely because the glass introduces an additional optical path due to the reduced speed of light in glass.", "misconception": "Failing to see the causal link between slower light speed and fringe shift"}, {"option_key": "C", "hint": "The reason is factually correct. Light does travel slower in glass (v = c/mu, and mu > 1 for glass), increasing the optical path.", "misconception": "Thinking the speed of light does not change in glass"}, {"option_key": "D", "hint": "The assertion is correct. Inserting a glass plate in one beam path is a well-known method to shift the fringe pattern in YDSE.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["glass-plate-in-ydse", "optical-path-difference", "fringe-shift"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): Two independent laser sources of the same frequency cannot produce a sustained interference pattern. Reason (R): For sustained interference, the two sources must be derived from the same parent source to maintain a constant phase relationship.", "explanation": "Assertion is correct: even two lasers of nominally the same frequency have independent, randomly fluctuating phases. Over time, the phase difference varies, and the interference pattern averages out, so no sustained pattern is observed. Reason is also correct and is the correct explanation: deriving both beams from a single source (as in YDSE) ensures a constant phase difference, which is essential for a stable interference pattern.", "payload": {"question_id": "cuet-phy-waveopt-interference-14", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly addresses why independent sources fail: the lack of a common parent source means no constant phase relationship. This is exactly why the assertion is true.", "misconception": "Not seeing the direct causal connection between same parent source and sustained interference"}, {"option_key": "C", "hint": "The reason is correct. Deriving two beams from a single source (e.g., by splitting) does maintain coherence, which is a fundamental principle of wave optics.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. Even high-quality lasers have independent phase fluctuations, making sustained interference impossible without deriving beams from the same source.", "misconception": "Thinking that same-frequency lasers are automatically coherent with each other"}]}, "correct_answer": "A", "concept_tags": ["coherent-sources", "independent-sources", "sustained-interference", "laser-coherence"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\nA. Path difference = n*lambda\nB. Path difference = (2n - 1)*lambda/2\nC. Phase difference = 0\nD. Phase difference = pi\n\nColumn II:\n1. Destructive interference\n2. Constructive interference\n3. Maximum intensity\n4. Minimum (zero) intensity", "explanation": "A. Path difference = n*lambda corresponds to constructive interference (2). B. Path difference = (2n-1)*lambda/2 corresponds to destructive interference (1). C. Phase difference = 0 means the waves are perfectly in phase, giving maximum intensity (3). D. Phase difference = pi means the waves are completely out of phase, giving minimum/zero intensity (4). So the correct matching is A-2, B-1, C-3, D-4.", "payload": {"question_id": "cuet-phy-waveopt-interference-15", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "understand", "options": [{"key": "A", "text": "A-1, B-2, C-4, D-3", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-4, D-3", "is_correct": false}, {"key": "C", "text": "A-3, B-4, C-2, D-1", "is_correct": false}, {"key": "D", "text": "A-2, B-1, C-3, D-4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This reverses constructive and destructive interference conditions. Path difference n*lambda gives constructive (not destructive) interference.", "misconception": "Confusing conditions for constructive and destructive interference"}, {"option_key": "B", "hint": "C-4 and D-3 are reversed. Phase difference 0 means waves are in phase (maximum intensity), while phase difference pi means they cancel (minimum intensity).", "misconception": "Confusing zero phase difference with minimum intensity"}, {"option_key": "C", "hint": "Path difference n*lambda leads to constructive interference, not directly maximum intensity as a separate concept. Check each match individually.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["path-difference", "phase-difference", "constructive-destructive-interference"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\nA. Fringe width (beta) when wavelength is doubled\nB. Fringe width when slit separation is halved\nC. Fringe width when screen distance is tripled\nD. Fringe width when experiment is done in water (mu = 4/3)\n\nColumn II:\n1. beta becomes 3*beta\n2. beta becomes 2*beta\n3. beta becomes (3/4)*beta\n4. beta becomes 2*beta", "explanation": "Using beta = lambda*D/d: A. lambda doubled: beta'' = 2*lambda*D/d = 2*beta (matches 2). B. d halved: beta'' = lambda*D/(d/2) = 2*beta (matches 4). C. D tripled: beta'' = lambda*3D/d = 3*beta (matches 1). D. In water (mu = 4/3): lambda'' = lambda/mu = 3*lambda/4, so beta'' = (3/4)*beta (matches 3). Correct matching: A-2, B-4, C-1, D-3.", "payload": {"question_id": "cuet-phy-waveopt-interference-16", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-3, C-1, D-4", "is_correct": false}, {"key": "C", "text": "A-2, B-4, C-1, D-3", "is_correct": true}, {"key": "D", "text": "A-4, B-2, C-3, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Doubling lambda gives 2*beta, not 3*beta. Check the proportionality: beta is directly proportional to lambda.", "misconception": "Incorrect proportionality assessment"}, {"option_key": "B", "hint": "Halving d gives 2*beta (matches 4), not (3/4)*beta (which is 3). Check: beta is inversely proportional to d.", "misconception": "Confusing inverse and direct proportionality with slit separation"}, {"option_key": "D", "hint": "This option assigns completely incorrect factors. Systematically apply beta = lambda*D/d with each change separately.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["fringe-width-variations", "ydse-parameters", "refractive-index-effect"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "In Young''s double slit experiment, the fringe width is directly proportional to the wavelength of light used.", "explanation": "This statement is TRUE. From the fringe width formula beta = lambda*D/d, we can see that beta is directly proportional to lambda (keeping D and d constant). If the wavelength increases, the fringe width increases proportionally, and if the wavelength decreases, the fringe width decreases proportionally.", "payload": {"question_id": "cuet-phy-waveopt-interference-17", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The formula beta = lambda*D/d clearly shows lambda in the numerator with a power of 1, confirming a directly proportional relationship.", "misconception": "Thinking fringe width is inversely proportional to wavelength"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["fringe-width", "wavelength-dependence", "ydse-formula"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "medium", "question_text": "In the interference pattern produced by two coherent sources, energy is destroyed at the positions of dark fringes.", "explanation": "This statement is FALSE. Energy is NOT destroyed at dark fringes. The principle of conservation of energy holds. In interference, energy is redistributed: the energy missing from dark fringes (minima) appears at the bright fringes (maxima). The total energy remains constant; it is merely redistributed in space.", "payload": {"question_id": "cuet-phy-waveopt-interference-18", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Energy can neither be created nor destroyed. In interference, energy from dark fringes is redistributed to bright fringes, conserving total energy.", "misconception": "Thinking that zero intensity at minima means energy is lost"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["energy-conservation", "interference-pattern", "energy-redistribution"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "fill_in_the_blank", "difficulty": "medium", "question_text": "In Young''s double slit experiment, if the two slits are illuminated by monochromatic light of wavelength 600 nm with slit separation 0.3 mm and screen distance 1.5 m, the distance between the 4th bright fringe and the 4th dark fringe on the same side of the central maximum is _____.", "explanation": "Fringe width beta = lambda*D/d = (600 x 10^-9 x 1.5) / (0.3 x 10^-3) = 9 x 10^-7 / 3 x 10^-4 = 3 x 10^-3 m = 3 mm. Position of the 4th bright fringe = 4*beta = 12 mm. Position of the 4th dark fringe = (4 - 1/2)*beta = 3.5*beta = 10.5 mm. The distance between them = 12 - 10.5 = 1.5 mm = beta/2.", "payload": {"question_id": "cuet-phy-waveopt-interference-19", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "apply", "options": [{"key": "A", "text": "3 mm", "is_correct": false}, {"key": "B", "text": "1.5 mm", "is_correct": true}, {"key": "C", "text": "0.75 mm", "is_correct": false}, {"key": "D", "text": "6 mm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 mm is the fringe width itself. The distance between adjacent bright and dark fringes (of the same order, same side) is beta/2, not beta.", "misconception": "Confusing fringe width with the bright-dark fringe separation"}, {"option_key": "C", "hint": "0.75 mm = beta/4, which has no standard significance in YDSE fringe separation. The separation between the n-th bright and n-th dark fringe on the same side is always beta/2.", "misconception": null}, {"option_key": "D", "hint": "6 mm = 2*beta. This does not correspond to any standard fringe separation. Recalculate the positions of the 4th bright and 4th dark fringes.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["fringe-position", "bright-dark-fringe-distance", "numerical-problem"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-interference", "exam_ids": ["CUET", "NEET"], "question_type": "scenario_based", "difficulty": "hard", "question_text": "A student performs Young''s double slit experiment in the laboratory. The slit separation is 0.2 mm and the screen is 1 m away. Using a sodium lamp (lambda = 589 nm), the student observes a clear fringe pattern. The student then covers one of the slits. Which of the following correctly describes what happens to the pattern on the screen?", "explanation": "When one slit is blocked, there is no longer two-source interference. Instead, light passes through only a single slit, producing a single-slit diffraction pattern. This pattern has a broad central maximum with much wider and less distinct secondary maxima, and the sharp equidistant interference fringes disappear. The central diffraction maximum is much broader than the interference fringes, and the intensity distribution changes from the cos^2 modulation of YDSE to the sinc^2 pattern of single-slit diffraction.", "payload": {"question_id": "cuet-phy-waveopt-interference-20", "subtopic": "Young''s Double Slit Experiment and Interference", "topic_name": "Young''s Double Slit Experiment and Interference", "bloom_level": "evaluate", "options": [{"key": "A", "text": "The fringe width doubles because only one slit contributes", "is_correct": false}, {"key": "B", "text": "The screen becomes completely dark", "is_correct": false}, {"key": "C", "text": "The interference fringes disappear and a broad single-slit diffraction pattern is observed", "is_correct": true}, {"key": "D", "text": "The fringes become brighter but otherwise remain unchanged", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The fringe width formula beta = lambda*D/d applies only to double-slit interference. With one slit covered, there is no two-source interference and hence no interference fringes to have a ''width''.", "misconception": "Thinking double-slit interference pattern persists with one slit blocked"}, {"option_key": "B", "hint": "Light still passes through the open slit and illuminates the screen. One slit produces a diffraction pattern, not darkness.", "misconception": "Thinking interference is needed for any light to reach the screen"}, {"option_key": "D", "hint": "The pattern fundamentally changes from equidistant interference fringes to a broad diffraction envelope. The two patterns are qualitatively different.", "misconception": "Not distinguishing between interference and diffraction patterns"}]}, "correct_answer": "C", "concept_tags": ["ydse-single-slit", "diffraction-vs-interference", "experimental-observation"]}]'::jsonb, 'cuet-physics', 'json-seed-batch-38');

