SELECT insert_batch_questions_v2('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The phenomenon of polarisation of light proves that light is:", "explanation": "Polarisation is the phenomenon in which the vibrations of the electric field vector of a light wave are confined to a single plane. Only transverse waves can be polarised because longitudinal waves oscillate along the direction of propagation and cannot be restricted to a single plane. Since light can be polarised, it proves that light is a transverse wave.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-01", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "remember", "options": [{"key": "A", "text": "A transverse wave", "is_correct": true}, {"key": "B", "text": "A longitudinal wave", "is_correct": false}, {"key": "C", "text": "Both transverse and longitudinal", "is_correct": false}, {"key": "D", "text": "Neither transverse nor longitudinal", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Longitudinal waves (like sound in air) oscillate along the direction of propagation. Such waves cannot exhibit polarisation because there is no perpendicular component to restrict.", "misconception": "Confusing longitudinal and transverse wave properties"}, {"option_key": "C", "hint": "If light were longitudinal, it could not be polarised. Polarisation is exclusively a property of transverse waves.", "misconception": null}, {"option_key": "D", "hint": "Light is a well-characterised electromagnetic wave. Polarisation specifically identifies it as transverse.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["polarisation", "transverse-wave", "nature-of-light"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When unpolarised light of intensity I₀ passes through a single Polaroid, the intensity of the transmitted light is:", "explanation": "Unpolarised light has electric field vibrations in all directions perpendicular to propagation. A Polaroid transmits only the component of vibration along its pass axis. On averaging cos²θ over all angles (0 to 2π), the average value of cos²θ is 1/2. Therefore, the transmitted intensity is I₀/2.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-02", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "remember", "options": [{"key": "A", "text": "I₀", "is_correct": false}, {"key": "B", "text": "I₀/2", "is_correct": true}, {"key": "C", "text": "I₀/4", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If the full intensity were transmitted, the Polaroid would have no effect at all. A Polaroid always absorbs the component of light perpendicular to its pass axis.", "misconception": "Assuming Polaroid transmits all light"}, {"option_key": "C", "hint": "I₀/4 would be the result after passing through two crossed Polaroids with an intermediate Polaroid at 45°. A single Polaroid transmits I₀/2.", "misconception": "Confusing single Polaroid with two-Polaroid system"}, {"option_key": "D", "hint": "Zero intensity would occur only if the light were already polarised perpendicular to the Polaroid''s pass axis. Unpolarised light always has some component along the pass axis.", "misconception": "Confusing unpolarised light with cross-polarised light"}]}, "correct_answer": "B", "concept_tags": ["polaroid", "unpolarised-light", "intensity-reduction"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Brewster''s law, the polarising angle iₚ for a medium of refractive index μ is given by:", "explanation": "Brewster''s law states that when light is incident on a transparent surface at the polarising angle iₚ, the reflected light is completely plane polarised. The relationship is tan iₚ = μ, where μ is the refractive index of the medium. At this angle, the reflected and refracted rays are perpendicular to each other.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-03", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "remember", "options": [{"key": "A", "text": "sin iₚ = μ", "is_correct": false}, {"key": "B", "text": "cos iₚ = μ", "is_correct": false}, {"key": "C", "text": "tan iₚ = μ", "is_correct": true}, {"key": "D", "text": "cot iₚ = μ", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "sin iₚ = μ is Snell''s law form and would require μ ≤ 1 for any real angle, which is not generally true for denser media.", "misconception": "Confusing Brewster''s law with Snell''s law"}, {"option_key": "B", "hint": "cos iₚ = μ would also require μ ≤ 1 and has no physical basis in the derivation of Brewster''s condition.", "misconception": null}, {"option_key": "D", "hint": "cot iₚ = μ is the inverse of the correct relation. Brewster''s law uses tangent, not cotangent.", "misconception": "Inverting the Brewster''s law relation"}]}, "correct_answer": "C", "concept_tags": ["brewster-law", "polarising-angle", "refractive-index"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Polaroid sunglasses reduce glare from surfaces because they:", "explanation": "Light reflected from horizontal surfaces such as roads and water is partially polarised with the electric field vibrating predominantly in the horizontal plane. Polaroid sunglasses have their pass axis oriented vertically, which blocks this horizontally polarised glare while transmitting the vertically polarised component of light from other sources, thereby reducing glare without making everything dark.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-04", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "understand", "options": [{"key": "A", "text": "Absorb all light equally, reducing overall brightness", "is_correct": false}, {"key": "B", "text": "Reflect all incoming light back towards the source", "is_correct": false}, {"key": "C", "text": "Diffract the light around the edges of the lens", "is_correct": false}, {"key": "D", "text": "Block the horizontally polarised component of reflected light", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "If they absorbed all light equally, they would just be tinted lenses. Polaroid lenses specifically reduce glare by selectively blocking polarised light.", "misconception": "Confusing Polaroid with ordinary tinted glass"}, {"option_key": "B", "hint": "Polaroid lenses do not reflect light; they absorb one polarisation component while transmitting the other.", "misconception": null}, {"option_key": "C", "hint": "Diffraction is the bending of light around obstacles and is unrelated to glare reduction by Polaroid lenses.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["polaroid", "applications-of-polarisation", "glare-reduction"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Plane polarised light of intensity I₀ passes through a Polaroid whose pass axis makes an angle of 60° with the plane of polarisation. The intensity of the transmitted light is:", "explanation": "According to Malus''s law, when plane polarised light of intensity I₀ passes through a Polaroid (analyser), the transmitted intensity is I = I₀cos²θ, where θ is the angle between the polarisation direction and the pass axis of the analyser. Here θ = 60°, so I = I₀cos²60° = I₀ × (1/2)² = I₀/4.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-05", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "apply", "options": [{"key": "A", "text": "I₀/2", "is_correct": false}, {"key": "B", "text": "I₀/4", "is_correct": true}, {"key": "C", "text": "3I₀/4", "is_correct": false}, {"key": "D", "text": "I₀/8", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I₀/2 would be the result for θ = 45° (since cos²45° = 1/2), not for θ = 60°.", "misconception": "Using wrong angle value or confusing with single Polaroid on unpolarised light"}, {"option_key": "C", "hint": "3I₀/4 = I₀ × cos²30°, which would apply if θ = 30°, not 60°. Check the angle carefully.", "misconception": "Using the complementary angle instead of the given angle"}, {"option_key": "D", "hint": "I₀/8 does not correspond to cos²θ for any standard angle. For θ = 60°, cos²60° = (1/2)² = 1/4.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["malus-law", "plane-polarised-light", "intensity"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The Brewster''s angle for a glass surface of refractive index 1.5 is approximately:", "explanation": "Using Brewster''s law: tan iₚ = μ = 1.5. Therefore iₚ = tan⁻¹(1.5). Computing: tan⁻¹(1.5) ≈ 56.3°. At this angle, the reflected light is completely plane polarised and the reflected and refracted rays are perpendicular to each other.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-06", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "apply", "options": [{"key": "A", "text": "33.7°", "is_correct": false}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "56.3°", "is_correct": true}, {"key": "D", "text": "60°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "33.7° is the complement of the Brewster angle (90° - 56.3°). This is actually the angle of refraction at Brewster''s angle, not the Brewster angle itself.", "misconception": "Confusing the angle of refraction with the polarising angle"}, {"option_key": "B", "hint": "45° would be the Brewster angle only if μ = tan 45° = 1, which would mean both media have the same refractive index.", "misconception": "Assuming Brewster''s angle is always 45°"}, {"option_key": "D", "hint": "tan 60° = √3 ≈ 1.732, which corresponds to μ = √3, not μ = 1.5.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["brewster-angle", "refractive-index", "polarisation-by-reflection"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "At Brewster''s angle, the angle between the reflected ray and the refracted ray is:", "explanation": "At Brewster''s angle, the reflected ray and the refracted ray are perpendicular to each other, i.e., the angle between them is 90°. This is because at the polarising angle iₚ, we have iₚ + r = 90° (where r is the angle of refraction). Since the reflected ray makes angle iₚ with the normal and the refracted ray makes angle r with the normal, the angle between the reflected and refracted rays is iₚ + r = 90°. Wait -- more precisely, the reflected ray is on the same side as the incident ray making angle iₚ with the normal, while the refracted ray is on the other side making angle r with the normal. The angle between them measured from the surface is (90° - iₚ) + (90° - r) = 180° - (iₚ + r) = 180° - 90° = 90°.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-07", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "understand", "options": [{"key": "A", "text": "90°", "is_correct": true}, {"key": "B", "text": "60°", "is_correct": false}, {"key": "C", "text": "180°", "is_correct": false}, {"key": "D", "text": "It depends on the refractive index of the medium", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "60° would be the angle only for a specific refractive index, but the perpendicularity of reflected and refracted rays at Brewster''s angle holds for all media.", "misconception": null}, {"option_key": "C", "hint": "180° would mean the reflected and refracted rays are in the same direction, which is physically impossible since they are on opposite sides of the interface.", "misconception": null}, {"option_key": "D", "hint": "While the Brewster angle itself depends on μ, the angle between reflected and refracted rays at Brewster''s angle is always 90°, regardless of the medium.", "misconception": "Thinking the 90° relationship varies with material"}]}, "correct_answer": "A", "concept_tags": ["brewster-angle", "reflected-refracted-perpendicular", "polarisation-by-reflection"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two Polaroids P₁ and P₂ are placed with their pass axes perpendicular to each other. Unpolarised light of intensity I₀ is incident on P₁. A third Polaroid P₃ is placed between P₁ and P₂ with its pass axis at 45° to that of P₁. The intensity of light emerging from P₂ is:", "explanation": "After P₁: intensity = I₀/2 (unpolarised light through a Polaroid). After P₃ (at 45° to P₁): I = (I₀/2)cos²45° = (I₀/2)(1/2) = I₀/4. After P₂ (at 45° to P₃, since P₂ is perpendicular to P₁ and P₃ is at 45° to P₁): I = (I₀/4)cos²45° = (I₀/4)(1/2) = I₀/8.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-08", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "apply", "options": [{"key": "A", "text": "I₀/2", "is_correct": false}, {"key": "B", "text": "I₀/4", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "I₀/8", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "I₀/2 is only the intensity after the first Polaroid. You must apply Malus''s law at each subsequent Polaroid.", "misconception": "Forgetting to apply Malus''s law at intermediate and final stages"}, {"option_key": "B", "hint": "I₀/4 is the intensity after passing through P₃ but before passing through P₂. One more application of Malus''s law is needed.", "misconception": "Stopping the calculation after the intermediate Polaroid"}, {"option_key": "C", "hint": "Zero would be the result if only P₁ and P₂ (crossed) were present. The intermediate Polaroid P₃ at 45° allows some light to pass through.", "misconception": "Ignoring the effect of the intermediate Polaroid between crossed Polaroids"}]}, "correct_answer": "D", "concept_tags": ["malus-law", "crossed-polaroids", "intermediate-polaroid"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Unpolarised light is incident on a Polaroid. The Polaroid is then rotated about the direction of the incident light. The intensity of the transmitted light:", "explanation": "When unpolarised light passes through a Polaroid, the transmitted intensity is always I₀/2, regardless of the orientation of the Polaroid''s pass axis. This is because unpolarised light has vibrations uniformly distributed in all directions perpendicular to propagation. Rotating the Polaroid simply changes which component is transmitted, but the average intensity remains the same at I₀/2.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-09", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "understand", "options": [{"key": "A", "text": "Remains constant at I₀/2", "is_correct": true}, {"key": "B", "text": "Varies between 0 and I₀", "is_correct": false}, {"key": "C", "text": "Varies between 0 and I₀/2", "is_correct": false}, {"key": "D", "text": "Becomes zero at certain orientations", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Variation between 0 and I₀ occurs only when plane polarised light passes through a rotating analyser (Malus''s law). For unpolarised incident light, the Polaroid output is constant.", "misconception": "Confusing unpolarised light behaviour with polarised light behaviour through a rotating analyser"}, {"option_key": "C", "hint": "There is no variation at all. Unpolarised light has no preferred direction of vibration, so all orientations of the Polaroid give the same result.", "misconception": null}, {"option_key": "D", "hint": "Zero intensity occurs only when plane polarised light is incident on a Polaroid with its pass axis perpendicular to the polarisation direction. Unpolarised light always gives non-zero transmission.", "misconception": "Confusing crossed Polaroid effect with single Polaroid on unpolarised light"}]}, "correct_answer": "A", "concept_tags": ["polaroid", "unpolarised-light", "rotation-of-polaroid"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The sky appears blue due to scattering of sunlight by air molecules. The scattered light observed at 90° to the direction of sunlight is:", "explanation": "When sunlight is scattered by small air molecules (Rayleigh scattering), the scattered light is partially polarised. At exactly 90° to the direction of incident sunlight, the scattered light is completely plane polarised. This is because the oscillating electric dipoles induced in air molecules cannot radiate energy along their axis of oscillation, so light scattered at 90° has only one vibration direction.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-10", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "understand", "options": [{"key": "A", "text": "Unpolarised", "is_correct": false}, {"key": "B", "text": "Completely plane polarised", "is_correct": true}, {"key": "C", "text": "Circularly polarised", "is_correct": false}, {"key": "D", "text": "Elliptically polarised", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The scattered light is not unpolarised. Scattering by molecules introduces polarisation, and at 90° it is fully polarised.", "misconception": "Assuming scattered light retains the same polarisation state as incident light"}, {"option_key": "C", "hint": "Circularly polarised light has two perpendicular components with a 90° phase difference. Scattering does not introduce such a phase relationship.", "misconception": "Confusing different types of polarisation"}, {"option_key": "D", "hint": "Elliptical polarisation also requires a specific phase relationship between perpendicular components. Scattering at 90° produces linearly (plane) polarised light.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["polarisation-by-scattering", "rayleigh-scattering", "plane-polarised-light"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Unpolarised light of intensity I₀ passes through three Polaroids. The first Polaroid has its pass axis vertical. The second has its pass axis at 30° to the vertical, and the third has its pass axis at 60° to the vertical. The intensity of light emerging from the third Polaroid is:", "explanation": "After Polaroid 1: I₁ = I₀/2 (unpolarised to polarised). After Polaroid 2 (angle between pass axes = 30°): I₂ = (I₀/2)cos²30° = (I₀/2)(3/4) = 3I₀/8. After Polaroid 3 (angle between pass axis of Polaroid 2 and Polaroid 3 = 60° - 30° = 30°): I₃ = (3I₀/8)cos²30° = (3I₀/8)(3/4) = 9I₀/32.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-11", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "apply", "options": [{"key": "A", "text": "I₀/8", "is_correct": false}, {"key": "B", "text": "3I₀/8", "is_correct": false}, {"key": "C", "text": "9I₀/32", "is_correct": true}, {"key": "D", "text": "3I₀/32", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I₀/8 would result from using 60° as the angle at both Polaroid 2 and Polaroid 3. The angle in Malus''s law is between consecutive pass axes, not from the first.", "misconception": "Using the angle relative to the first Polaroid rather than the previous one"}, {"option_key": "B", "hint": "3I₀/8 is the intensity after the second Polaroid. You still need to apply Malus''s law for the third Polaroid.", "misconception": "Stopping the calculation prematurely"}, {"option_key": "D", "hint": "3I₀/32 results from incorrectly using cos²60° at the second stage and cos²30° at the third stage, or some other error in angles.", "misconception": "Incorrectly assigning angles between consecutive Polaroids"}]}, "correct_answer": "C", "concept_tags": ["malus-law", "multiple-polaroids", "intensity-calculation"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Light reflected from a water surface (μ = 4/3) is completely polarised. The angle of refraction of the transmitted light is:", "explanation": "For complete polarisation of reflected light, the angle of incidence equals Brewster''s angle iₚ, where tan iₚ = μ = 4/3. At Brewster''s angle, iₚ + r = 90°, so r = 90° - iₚ. Since tan iₚ = 4/3, we get iₚ = tan⁻¹(4/3) ≈ 53.1°. Therefore r = 90° - 53.1° = 36.9° ≈ 37°. Alternatively, since tan iₚ = μ and iₚ + r = 90°, then tan r = 1/μ = 3/4, giving r = tan⁻¹(3/4) ≈ 36.9°.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-12", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "apply", "options": [{"key": "A", "text": "53°", "is_correct": false}, {"key": "B", "text": "45°", "is_correct": false}, {"key": "C", "text": "30°", "is_correct": false}, {"key": "D", "text": "37°", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "53° is the Brewster''s angle (angle of incidence), not the angle of refraction. At Brewster''s angle, r = 90° - iₚ.", "misconception": "Confusing the angle of incidence with the angle of refraction at Brewster''s angle"}, {"option_key": "B", "hint": "45° would be the refraction angle if the Brewster angle were also 45°, which requires μ = 1. For μ = 4/3, this is not the case.", "misconception": null}, {"option_key": "C", "hint": "30° does not satisfy the relation r = 90° - iₚ for μ = 4/3. The correct refraction angle is 90° - 53° = 37°.", "misconception": null}]}, "correct_answer": "D", "concept_tags": ["brewster-angle", "angle-of-refraction", "complete-polarisation"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "medium", "question_text": "Assertion (A): Sound waves in air cannot be polarised.\nReason (R): Polarisation is a phenomenon exclusive to transverse waves, and sound waves in air are longitudinal in nature.", "explanation": "Both the assertion and the reason are correct. Sound waves in air are longitudinal waves where particles oscillate along the direction of propagation. Polarisation requires vibrations perpendicular to the direction of propagation, which is possible only in transverse waves. Since sound in air is longitudinal, it cannot be polarised. The reason correctly explains why the assertion is true.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-13", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion: sound in air is longitudinal, and only transverse waves can be polarised, so sound cannot be polarised.", "misconception": "Failing to recognise the direct causal link between the nature of sound waves and impossibility of polarisation"}, {"option_key": "C", "hint": "The reason is factually correct. Sound in air is indeed longitudinal, and polarisation is indeed exclusive to transverse waves.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. Sound waves in air are longitudinal and cannot be polarised. This is experimentally verified.", "misconception": null}]}, "correct_answer": "A", "concept_tags": ["polarisation", "transverse-wave", "longitudinal-wave", "sound-waves"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "assertion_reasoning", "difficulty": "hard", "question_text": "Assertion (A): When unpolarised light is reflected at Brewster''s angle from a glass surface, the reflected and refracted rays are perpendicular to each other.\nReason (R): At Brewster''s angle, the refracted light is completely plane polarised.", "explanation": "The assertion is correct. At Brewster''s angle, iₚ + r = 90°, meaning the reflected and refracted rays are indeed perpendicular. The reason, however, is incorrect. At Brewster''s angle, it is the reflected light (not the refracted light) that is completely plane polarised. The refracted light is only partially polarised. Therefore, A is correct but R is incorrect.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-14", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Check the reason carefully. At Brewster''s angle, it is the reflected light that is completely polarised, not the refracted light.", "misconception": "Confusing which ray (reflected vs refracted) is completely polarised at Brewster''s angle"}, {"option_key": "B", "hint": "The reason itself contains a factual error. The refracted light at Brewster''s angle is only partially polarised, not completely polarised.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. The perpendicularity of reflected and refracted rays at Brewster''s angle (iₚ + r = 90°) is a well-established fact.", "misconception": null}]}, "correct_answer": "C", "concept_tags": ["brewster-angle", "reflected-refracted-perpendicular", "polarisation-by-reflection"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "medium", "question_text": "Match the phenomena in Column I with their descriptions in Column II:\n\nColumn I:\nA. Malus''s law\nB. Brewster''s law\nC. Double refraction\nD. Optical activity\n\nColumn II:\n1. tan iₚ = μ\n2. I = I₀cos²θ\n3. Rotation of the plane of polarisation by certain substances\n4. Splitting of a light ray into ordinary and extraordinary rays in a crystal", "explanation": "Malus''s law gives the intensity of polarised light after passing through an analyser as I = I₀cos²θ (A-2). Brewster''s law relates the polarising angle to the refractive index as tan iₚ = μ (B-1). Double refraction is the phenomenon where a crystal splits an incident ray into ordinary and extraordinary rays (C-4). Optical activity is the property of certain substances to rotate the plane of polarisation of light passing through them (D-3).", "payload": {"question_id": "cuet-phy-waveopt-polarisation-15", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "understand", "options": [{"key": "A", "text": "A-1, B-2, C-4, D-3", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-4, D-3", "is_correct": true}, {"key": "C", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-3, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps A and B. Malus''s law is I = I₀cos²θ (A-2), and Brewster''s law is tan iₚ = μ (B-1), not the reverse.", "misconception": "Interchanging Malus''s law and Brewster''s law formulas"}, {"option_key": "C", "hint": "This swaps C and D. Double refraction involves splitting into O and E rays (C-4), and optical activity involves rotation of the polarisation plane (D-3).", "misconception": "Confusing double refraction with optical activity"}, {"option_key": "D", "hint": "This has all four matchings incorrect. Both A-B and C-D pairs are swapped compared to the correct matching.", "misconception": null}]}, "correct_answer": "B", "concept_tags": ["malus-law", "brewster-law", "double-refraction", "optical-activity"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "match_the_following", "difficulty": "hard", "question_text": "Match the polarisation methods in Column I with their key features in Column II:\n\nColumn I:\nA. Polarisation by reflection\nB. Polarisation by scattering\nC. Polarisation by selective absorption (Polaroid)\nD. Polarisation by double refraction\n\nColumn II:\n1. Uses dichroic crystals or stretched polymer sheets containing aligned molecules\n2. Produces two refracted rays with mutually perpendicular polarisations inside a birefringent crystal\n3. Completely polarises reflected light when incidence is at Brewster''s angle\n4. Light scattered at 90° to the incident beam is completely plane polarised", "explanation": "Polarisation by reflection completely polarises the reflected light at Brewster''s angle (A-3). Polarisation by scattering produces completely polarised light at 90° to the incident direction (B-4). Polaroids use dichroic materials or aligned polymer molecules for selective absorption (C-1). Double refraction in birefringent crystals produces ordinary and extraordinary rays with mutually perpendicular polarisations (D-2).", "payload": {"question_id": "cuet-phy-waveopt-polarisation-16", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-1, C-4, D-2", "is_correct": false}, {"key": "B", "text": "A-4, B-3, C-1, D-2", "is_correct": false}, {"key": "C", "text": "A-3, B-4, C-2, D-1", "is_correct": false}, {"key": "D", "text": "A-3, B-4, C-1, D-2", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. Scattering polarises light at 90° (B-4), not Polaroids. Polaroids use selective absorption (C-1), not scattering.", "misconception": "Confusing polarisation by scattering with selective absorption"}, {"option_key": "B", "hint": "This swaps A and B. Polarisation by reflection occurs at Brewster''s angle (A-3), while scattering polarises at 90° (B-4).", "misconception": null}, {"option_key": "C", "hint": "This swaps C and D. Polaroids use dichroic/aligned molecules (C-1), and double refraction produces O and E rays in birefringent crystals (D-2).", "misconception": "Interchanging Polaroid mechanism with double refraction"}]}, "correct_answer": "D", "concept_tags": ["polarisation-by-reflection", "polarisation-by-scattering", "polaroid", "double-refraction"]}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-polarisation", "exam_ids": ["CUET", "NEET"], "question_type": "true_false", "difficulty": "easy", "question_text": "According to Malus''s law, when polarised light passes through an analyser with its pass axis parallel to the polarisation direction (θ = 0°), the transmitted intensity equals the incident intensity.", "explanation": "This statement is true. According to Malus''s law, I = I₀cos²θ. When θ = 0° (pass axis parallel to polarisation direction), cos 0° = 1, so I = I₀cos²0° = I₀ × 1 = I₀. The full intensity of the polarised light is transmitted.", "payload": {"question_id": "cuet-phy-waveopt-polarisation-17", "subtopic": "Polarisation (Malus''s Law, Brewster''s Angle)", "topic_name": "Polarisation (Malus''s Law, Brewster''s Angle)", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Substituting θ = 0° into Malus''s law gives I = I₀ × cos²0° = I₀ × 1 = I₀, confirming the 